        val references = paths
            .mapNotNull { it?.trim()?.takeIf { value -> value.isNotBlank() } }
            .distinct()
            .map { path -> AssetReferenceEntity(path = path, ownerType = ownerType, ownerId = ownerId) }
        if (references.isNotEmpty()) {
            insertReferences(references)
        }
    }
