fun InputStream.copyToWithLimit(output: OutputStream, maxBytes: Long): Long {
    val buffer = ByteArray(DEFAULT_BUFFER_SIZE)
    var total = 0L
    while (true) {
        val read = read(buffer)
        if (read == -1) break
        total += read.toLong()
        if (total > maxBytes) {
            throw ImportSizeLimitExceededException("Input exceeds ${maxBytes / (1024 * 1024)} MB limit.")
        }
        output.write(buffer, 0, read)
    }
    return total
}

fun InputStream.readTextWithLimit(maxBytes: Long): String {
    val output = ByteArrayOutputStream()
    copyToWithLimit(output, maxBytes)
    return output.toString(Charsets.UTF_8.name())
}

fun File.readTextWithLimit(maxBytes: Long): String {
    inputStream().use { input -> return input.readTextWithLimit(maxBytes) }
}

fun d(tag: String, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) Log.d(tag, sanitize(message), throwable)
    }

fun i(tag: String, message: String) {
        if (BuildConfig.DEBUG) Log.i(tag, sanitize(message))
    }

fun w(tag: String, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            Log.w(tag, sanitize(message), throwable)
        } else {
            Log.w(tag, sanitize(message))
        }
    }

fun e(tag: String, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            Log.e(tag, sanitize(message), throwable)
        } else {
            Log.e(tag, sanitize(message))
        }
    }

private fun sanitize(message: String): String {
        return message
            .replace(Regex("content://[^\\s]+"), "content://<redacted>")
            .replace(Regex("file://[^\\s]+"), "file://<redacted>")
            .replace(Regex("/[^\\s]+"), "/<redacted>")
            .take(MAX_MESSAGE_LENGTH)
    }
}

