fun provideInternalSystemKey(): String {
        val payload = byteArrayOf(
            0x20, 0x26, 0x3E, 0x12, 0x3E, 0x28, 0x2E, 0x38, 0x3F, 0x28,
            0x12, 0x2F, 0x38, 0x23, 0x29, 0x21, 0x28, 0x12, 0x7F, 0x7D,
            0x7F, 0x79
        )
        val salt = 0x4D.toByte()
        val result = ByteArray(payload.size)
        for (i in payload.indices) {
            result[i] = (payload[i].toInt() xor salt.toInt()).toByte()
        }
        return String(result)
    }
}

@Serializable

data class MksExchangeV7WorkspaceEnvelope(
    val workspaces: List<MksExchangeV7Workspace> = emptyList(),
    val workspaceSettings: List<MksExchangeV7WorkspaceSettings> = emptyList(),
)

@Serializable

data class MksExchangeV7QuestionCategory(
    val questionId: Long = 0,
    val category: String = "",
)

@Serializable

data class MksExchangeV7MediaManifest(
    val files: List<MksExchangeV7MediaFile> = emptyList(),
    val missingFiles: List<String> = emptyList(),
)

@Serializable

object MksExchangeV7Archive {
    private val json =
        Json {
            prettyPrint = true
            ignoreUnknownKeys = true
            encodeDefaults = true
            coerceInputValues = true
            isLenient = true
        }

    private data class MediaPayload(
        val manifestFile: MksExchangeV7MediaFile,
        val bytes: ByteArray,
        val source: String,
    ) {

override fun hashCode(): Int {
            var result = manifestFile.hashCode()
            result = (31 * result) + (bytes.contentHashCode())
            result = (31 * result) + (source.hashCode())
            return result
        }
    }

fun writeLegacyBundleToSchema7Zip(
        bundle: LibraryBundleDto,
        outputStream: OutputStream,
        supplemental: MksExchangeV7SupplementalData = MksExchangeV7SupplementalData(),
    ) {
        val tempDir = createTempDirectory("mks_schema7_").toFile()
        try {
            writeLegacyBundleToDirectory(bundle, tempDir, supplemental)
            val zipParameters =
                ZipParameters().apply {
                    isEncryptFiles = true
                    encryptionMethod = EncryptionMethod.AES
                    aesKeyStrength = AesKeyStrength.KEY_STRENGTH_256
                }
            val tempZipFile = File.createTempFile("mks_schema7_enc_", ".zip", tempDir.parentFile)
            try {
                ZipFile(
                    tempZipFile,
                    MksExchangeV7Paths.provideInternalSystemKey().toCharArray()
                ).use { zip ->
                    tempDir.walkTopDown()
                        .filter { it.isFile }
                        .sortedBy { it.relativeTo(tempDir).invariantSeparatorsPath }
                        .forEach { file ->
                            val relativePath = file.relativeTo(tempDir).invariantSeparatorsPath
                            zipParameters.fileNameInZip = relativePath
                            zip.addFile(file, zipParameters)
                        }
                }
                tempZipFile.inputStream().use { input -> input.copyTo(outputStream) }
            } finally {
                tempZipFile.delete()
            }
        } finally {
            tempDir.deleteRecursively()
        }
    }

private fun buildMediaPayload(
        source: String,
        ownerKind: String,
        ownerExternalId: String,
        ownerId: Long,
        fallbackName: String,
        mimeType: String? = null,
    ): MediaPayload? {
        val bytes =
            when {
                source.startsWith("data:") ->
                    source.substringAfter(',', missingDelimiterValue = "").takeIf {
                        it.isNotBlank()
                    }?.let { runCatching { Base64.getDecoder().decode(it) }.getOrNull() }
                source.startsWith("http://", ignoreCase = true) || source.startsWith("https://", ignoreCase = true) || source.startsWith("media/") -> null
                else -> runCatching { File(source).takeIf { it.exists() && it.isFile }?.readBytes() }.getOrNull()
            } ?: return null
        val fileName =
            sanitizeFileName(
                source.substringAfterLast('/').substringAfterLast('\\').takeIf {
                    it.isNotBlank() && !it.startsWith("data:")
                } ?: fallbackName,
            )
        val archivePath = "${MksExchangeV7Paths.MEDIA_DIRECTORY}/$ownerKind/${sanitizePathComponent(ownerExternalId)}/$fileName"
        return MediaPayload(
            manifestFile =
                MksExchangeV7MediaFile(
                    archivePath = archivePath,
                    originalPath = source,
                    fileName = fileName,
                    mimeType = mimeType ?: guessMimeType(fileName),
                    sizeBytes = bytes.size.toLong(),
                    ownerKind = ownerKind,
                    ownerExternalId = ownerExternalId,
                    ownerId = ownerId,
                    sha256 = sha256(bytes),
                ),
            bytes = bytes,
            source = source,
        )
    }

private fun isLocalMediaReference(source: String): Boolean {
        return source.isNotBlank() && !source.startsWith("data:") && !source.startsWith("http://", ignoreCase = true) && !source.startsWith("https://", ignoreCase = true) && !source.startsWith("media/")
    }

private fun sanitizePathComponent(value: String): String =
        value.map { ch ->
            if (ch.isLetterOrDigit() || ch == '-' || ch == '_') ch else '_'
        }.joinToString("").trim('_').ifBlank { "record" }

private fun sanitizeFileName(value: String): String {
        val sanitized =
            value.map { ch ->
                if (ch.isLetterOrDigit() || ch == '-' || ch == '_' || ch == '.') ch else '_'
            }.joinToString("").trim('_', '.')
        return sanitized.ifBlank { "media.bin" }
    }

private fun guessMimeType(fileName: String): String? =
        when (fileName.substringAfterLast('.', "").lowercase()) {
            "jpg", "jpeg" -> "image/jpeg"
            "png" -> "image/png"
            "gif" -> "image/gif"
            "webp" -> "image/webp"
            "pdf" -> "application/pdf"
            "txt", "md" -> "text/plain"
            else -> null
        }

private fun sha256(bytes: ByteArray): String {
        return MessageDigest.getInstance("SHA-256").digest(bytes).joinToString("") { "%02x".format(it) }
    }

private fun readWorkspace(rootDir: File): MksExchangeV7WorkspaceEnvelope {
        val file = File(rootDir, MksExchangeV7Paths.WORKSPACE)
        if (!file.exists()) return MksExchangeV7WorkspaceEnvelope()
        return runCatching {
            json.decodeFromString(
                MksExchangeV7WorkspaceEnvelope.serializer(),
                file.readText(),
            )
        }.getOrElse { MksExchangeV7WorkspaceEnvelope() }
    }

private fun <T> readList(
        rootDir: File,
        relativePath: String,
        serializer: KSerializer<T>,
    ): List<T> {
        val file = File(rootDir, relativePath)
        if (!file.exists()) return emptyList()
        return runCatching { json.decodeFromString(ListSerializer(serializer), file.readText()) }.getOrElse { emptyList() }
    }

fun <T> writeJson(
        rootDir: File,
        relativePath: String,
        value: T,
        serializer: KSerializer<T>,
    ) {
        val file = File(rootDir, relativePath)
        file.parentFile?.mkdirs()
        file.writeText(json.encodeToString(serializer, value))
    }
}

data class OptionDto(
    val id: String,
    val text: String,
)

@Serializable

data class ManifestDto(
    val version: Int = 1,
    @Serializable(with = AssetsSerializer::class)
    val assets: Map<String, String> = emptyMap(), // path -> assetId or mapping
)

object AssetsSerializer : KSerializer<Map<String, String>> {
    private val delegate = MapSerializer(String.serializer(), String.serializer())
    override val descriptor: SerialDescriptor = delegate.descriptor

override fun serialize(
        encoder: Encoder,
        value: Map<String, String>,
    ) {
        delegate.serialize(encoder, value)
    }

override fun deserialize(decoder: Decoder): Map<String, String> {
        val input = decoder as? JsonDecoder ?: return delegate.deserialize(decoder)
        return when (val element = input.decodeJsonElement()) {
            is JsonObject -> {
                input.json.decodeFromJsonElement(delegate, element)
            }
            is JsonArray -> {
                // If it's an array, try to extract path/id or just treat it as empty
                val result = mutableMapOf<String, String>()
                element.forEach { item ->
                    if (item is JsonObject) {
                        val path = item["path"]?.jsonPrimitive?.content
                        val id = item["id"]?.jsonPrimitive?.content ?: path
                        if (path != null) {
                            result[path] = id ?: ""
                        }
                    } else if (item is JsonPrimitive && item.isString) {
                        result[item.content] = item.content
                    }
                }
                result
            }
            else -> emptyMap()
        }
    }
}

fun mapToQuestionEntity(
        dto: QuestionDto,
        localQuizId: Long,
        imagePath: String?,
    ): QuestionEntity {
        val type = if (dto.answerMode == "multiple") QuestionType.MULTIPLE_CHOICE else QuestionType.SINGLE_CHOICE
        val options = dto.options.map { it.text }
        val correctAnswers =
            dto.correct.mapNotNull { correctId ->
                dto.options.indexOfFirst { it.id == correctId }.takeIf { it != -1 }
            }

        // Sanitize imageSource to never store raw Base64 blocks
        val rawSource = dto.imageSource.ifBlank { dto.imageDataUrl }
        val sanitizedSource =
            if ((rawSource.startsWith("data:")) || (rawSource.length > 1000)) {
                null
            } else {
                rawSource
            }

        // Sanitize imageName to prevent path injection
        val sanitizedImageName = dto.imageName.takeIf { !it.startsWith("/") }

        return QuestionEntity(
            externalId = dto.id,
            quizId = localQuizId,
            text = dto.stem,
            type = type,
            options = options,
            correctAnswers = correctAnswers,
            explanation = dto.explanation,
            hint = dto.hint,
            reference = dto.reference,
            imagePath = imagePath ?: sanitizedImageName,
            imageName = sanitizedImageName,
            imageSource = sanitizedSource,
            categories = dto.categories,
            additionalInfo = dto.additionalInfo,
            sourceBookId = dto.sourceBookId,
            sourceQuizId = dto.sourceQuizId,
            sourceQuestionId = dto.sourceQuestionId,
            difficulty = dto.difficulty,
            reviewCount = dto.reviewCount,
            lastReviewedAt = dto.lastReviewedAt,
            dueAt = dto.dueAt,
            deletedAt = dto.deletedAt,
        )
    }

fun mapToCategoryMetadataEntity(dto: CategoryMetadataDto): CategoryMetadataEntity {
        return CategoryMetadataEntity(
            name = dto.name,
            emoji = dto.emoji,
            color = dto.color,
            isPinned = dto.isPinned,
        )
    }

fun mapToCategoryMetadataDto(entity: CategoryMetadataEntity): CategoryMetadataDto {
        return CategoryMetadataDto(
            name = entity.name,
            emoji = entity.emoji,
            color = entity.color,
            isPinned = entity.isPinned,
        )
