class ImportLibraryManager(
    private val context: Context,
    private val database: MksDatabase,
    private val fileManager: FileManager,
) {
    private val bookDao = database.bookDao()
    private val quizDao = database.quizDao()
    private val questionDao = database.questionDao()
    private val sessionDao = database.sessionDao()
    private val categoryMetadataDao = database.categoryMetadataDao()
    private val questionCategoryDao = database.questionCategoryDao()
    private val assetReferenceDao = database.assetReferenceDao()
    private val workspaceDao = database.workspaceDao()

    private val formatDetector = ImportFormatDetector(context)
    private val jsonParser = JsonLibraryParser()
    private val zipParser = ZipLibraryParser(context, jsonParser)

    private val csvParser = CsvParser()
    private val headerMapper = SpreadsheetHeaderMapper()
    private val imageExtractor = GenericImageExtractor()
    private val textParser = TextQuestionParser(imageExtractor)
    private val jsonQuestionParser = JsonQuestionParser(imageExtractor)
    private val htmlParser = HtmlQuestionParser(jsonParser = jsonQuestionParser)
    private val xlsxCompiler = XlsxLibraryCompiler(context)

    private val validator = ImportValidator()
    private val normalizer = BundleNormalizer()
    private val mapper = LibraryMapper()

    private suspend fun getOrCreateDefaultWorkspaceId(): Long {
        workspaceDao.getWorkspaceByExternalId(WorkspaceDefaults.DEFAULT_EXTERNAL_ID)?.let { return it.id }
        workspaceDao.getDefaultWorkspace()?.let { workspace ->
            workspaceDao.updateWorkspace(
                workspace.copy(
                    externalId = WorkspaceDefaults.DEFAULT_EXTERNAL_ID,
                    name = WorkspaceDefaults.DEFAULT_NAME,
                    description = WorkspaceDefaults.DEFAULT_DESCRIPTION,
                    isDefault = true,
                    deletedAt = null,
                    updatedAt = System.currentTimeMillis(),
                ),
            )
            if (workspaceDao.getSettingsByWorkspaceId(workspace.id) == null) {
                workspaceDao.insertSettings(WorkspaceSettingsEntity(workspaceId = workspace.id))
            }
            return workspace.id
        }

        val workspaceId =
            workspaceDao.insertWorkspace(
                WorkspaceEntity(
                    externalId = WorkspaceDefaults.DEFAULT_EXTERNAL_ID,
                    name = WorkspaceDefaults.DEFAULT_NAME,
                    description = WorkspaceDefaults.DEFAULT_DESCRIPTION,
                    isDefault = true,
                ),
            )
        workspaceDao.insertSettings(WorkspaceSettingsEntity(workspaceId = workspaceId))
        return workspaceId
    }

fun cleanupStaleImportCache(maxAgeMillis: Long = 24L * 60L * 60L * 1000L) {
        val cutoff = System.currentTimeMillis() - maxAgeMillis
        context.cacheDir.listFiles()
            ?.filter { file -> file.name.startsWith("import_") && file.lastModified() < cutoff }
            ?.forEach { file -> runCatching { file.deleteRecursively() } }
    }

    private data class ResolvedImageResult(
        val path: String? = null,
        val warning: String? = null,
        val importedLocally: Boolean = false,
    )

private fun isTrackableLocalAsset(path: String?): Boolean {
        val value = path?.trim().orEmpty()
        if (value.isBlank()) return false
        return !value.startsWith("http://", ignoreCase = true) &&
            !value.startsWith("https://", ignoreCase = true) &&
            !value.startsWith("content://", ignoreCase = true) &&
            !value.startsWith("data:", ignoreCase = true) &&
            !value.startsWith("assets/", ignoreCase = true)
    }

    private suspend fun replaceOwnerAssetReferences(
        ownerType: String,
        ownerId: Long,
        paths: List<String?>,
    ) {
        val cleaned =
            paths
                .mapNotNull { it?.trim()?.takeIf { value -> isTrackableLocalAsset(value) } }
                .distinct()
        val previousPaths =
            assetReferenceDao.getReferencesForOwner(ownerType, ownerId)
                .map { it.path }
                .distinct()
        assetReferenceDao.replaceOwnerReferences(ownerType, ownerId, cleaned)
        previousPaths
            .filterNot { it in cleaned }
            .forEach { path ->
                if (assetReferenceDao.countReferencesForPath(path) == 0) {
                    fileManager.deleteImage(path)
                }
            }
    }

    private suspend fun syncQuestionCategories(
        questionId: Long,
        categories: List<String>,
    ) {
        questionCategoryDao.replaceCategories(questionId, categories)
    }

fun detectFormat(uri: Uri): ImportFormat {
        return formatDetector.detectFormat(uri)
    }

suspend fun getImportPreview(uri: Uri): ImportPreviewDto =
        withContext(Dispatchers.IO) {
            val format = formatDetector.detectFormat(uri)
            if (format == ImportFormat.UNKNOWN) throw Exception("Unsupported file format")

            var zipResult: ZipLibraryParser.ZipResult? = null
            try {
                val bundle =
                    when (format) {
                        ImportFormat.JSON -> {
                            val stream = context.contentResolver.openInputStream(uri) ?: throw Exception("Could not open stream")
                            stream.use { jsonParser.parse(it) }
                        }
                        ImportFormat.ZIP -> {
                            val stream = context.contentResolver.openInputStream(uri) ?: throw Exception("Could not open stream")
                            val parsedZip = stream.use { zipParser.parse(it) }
                            zipResult = parsedZip
                            parsedZip.bundle
                        }
                        ImportFormat.XLSX -> {
                            xlsxCompiler.compile(uri)
                        }
                        ImportFormat.CSV_TSV, ImportFormat.TEXT, ImportFormat.HTML -> {
                            val content = readImportText(uri, format)
                            val questions =
                                when (format) {
                                    ImportFormat.HTML -> htmlParser.parse(content)
                                    ImportFormat.TEXT -> textParser.parse(content)
                                    else -> parseSpreadsheetSimple(uri)
                                }
                            wrapQuestionsToBundle(questions, uri.lastPathSegment ?: "Imported File")
                        }
                        else -> throw Exception("Unexpected format: $format")
                    }

                val validation = validator.validate(bundle)
                val sanitizedBundle = validation.sanitizedBundle ?: bundle
                val normalized = normalizer.normalize(sanitizedBundle)

                val booksToCreate = mutableListOf<String>()
                val booksToUpdate = mutableListOf<String>()
                normalized.books.forEach { book ->
                    if (bookDao.getBookByExternalId(book.id) != null) {
                        booksToUpdate.add(book.title)
                    } else {
                        booksToCreate.add(book.title)
                    }
                }

                val quizzesToCreate = mutableListOf<String>()
                val quizzesToUpdate = mutableListOf<String>()
                normalized.quizzes.forEach { quiz ->
                    if (quizDao.getQuizByExternalId(quiz.id) != null) {
                        quizzesToUpdate.add(quiz.title)
                    } else {
                        quizzesToCreate.add(quiz.title)
                    }
                }

                val questionsToCreate = mutableListOf<String>()
                val questionsToUpdate = mutableListOf<String>()
                normalized.quizzes.forEach { quizDto ->
                    val existingQuiz = quizDao.getQuizByExternalId(quizDto.id)
                    if (existingQuiz == null) {
                        questionsToCreate.addAll(quizDto.questions.map { it.stem.take(50) })
                    } else {
                        quizDto.questions.forEach { questionDto ->
                            if (questionDao.getQuestionByExternalId(existingQuiz.id, questionDto.id) != null) {
                                questionsToUpdate.add(questionDto.stem.take(50))
                            } else {
                                questionsToCreate.add(questionDto.stem.take(50))
                            }
                        }
                    }
                }

                val searchDirs = mutableListOf<File>()
                zipResult?.libraryDir?.let { searchDirs.add(it) }
                zipResult?.rootDir?.let { if (it != zipResult.libraryDir) searchDirs.add(it) }

                val imageFiles =
                    searchDirs.flatMap { dir ->
                        dir.walkTopDown().filter {
                            it.isFile && it.extension.matches(Regex("png|jpe?g|webp|gif|svg|bmp", RegexOption.IGNORE_CASE))
                        }.toList()
                    }
                val totalImages = imageFiles.size
                val hasAssets = totalImages > 0
                val previewWarnings = validation.warnings.toMutableList()
                if (bundleContainsPlainHttpAssets(normalized)) {
                    previewWarnings.add(
                        ImportWarning(
                            "This import contains plain HTTP image URLs. They will not be downloaded unless you explicitly allow insecure image downloads in the review dialog.",
                            details = "Plain HTTP images are visible to the network and can be modified in transit.",
                        ),
                    )
                }

                ImportPreviewDto(
                    bundle = normalized,
                    booksToCreate = booksToCreate,
                    booksToUpdate = booksToUpdate,
                    quizzesToCreate = quizzesToCreate,
                    quizzesToUpdate = quizzesToUpdate,
                    questionsToCreate = questionsToCreate,
                    questionsToUpdate = questionsToUpdate,
                    totalQuestions = normalized.quizzes.sumOf { it.questions.size },
                    totalSessions = normalized.sessions?.size ?: 0,
                    totalCategories = normalized.categories.size,
                    totalImages = totalImages,
                    skippedRecordsCount = validation.skippedRecordsCount,
                    hasAssets = hasAssets,
                    warnings = previewWarnings,
                )
            } finally {
                zipResult?.rootDir?.deleteRecursively()
            }
        }

suspend fun importLibrary(
        uri: Uri,
        strategy: MergeStrategy = MergeStrategy.SKIP_EXISTING,
        targetBookId: Long? = null,
        targetQuizId: Long? = null,
        allowInsecureRemoteImages: Boolean = false,
        activeWorkspaceId: Long? = null,
        onProgress: (Float, String) -> Unit = { _, _ -> },
    ): MksResult<ImportResult> =
        withContext(Dispatchers.IO) {
            val startTime = System.currentTimeMillis()
            onProgress(0.05f, "Detecting format...")
            val format = formatDetector.detectFormat(uri)

            if (format == ImportFormat.UNKNOWN) {
                return@withContext MksResult.Error(message = "Unsupported file format")
            }

            var zipResult: ZipLibraryParser.ZipResult? = null
            try {
                val bundle =
                    when (format) {
                        ImportFormat.JSON -> {
                            onProgress(0.1f, "Parsing JSON...")
                            val stream =
                                context.contentResolver.openInputStream(uri)
                                    ?: throw Exception("Could not open stream")
                            stream.use { jsonParser.parse(it) }
                        }
                        ImportFormat.ZIP -> {
                            onProgress(0.1f, "Extracting ZIP...")
                            val stream =
                                context.contentResolver.openInputStream(uri)
                                    ?: throw Exception("Could not open stream")
                            val parsedZip = stream.use { zipParser.parse(it) }
                            zipResult = parsedZip
                            parsedZip.bundle
                        }
                        ImportFormat.XLSX -> {
                            onProgress(0.1f, "Compiling XLSX...")
                            xlsxCompiler.compile(uri)
                        }
                        ImportFormat.CSV_TSV, ImportFormat.TEXT, ImportFormat.HTML -> {
                            onProgress(0.1f, "Parsing file...")
                            val content = readImportText(uri, format)
                            val questions =
                                when (format) {
                                    ImportFormat.HTML -> htmlParser.parse(content)
                                    ImportFormat.TEXT -> textParser.parse(content)
                                    else -> parseSpreadsheetSimple(uri)
                                }
                            wrapQuestionsToBundle(questions, uri.lastPathSegment ?: "Imported File")
                        }
                        else -> throw Exception("Unexpected format: $format")
                    }

                val result =
                    executeImportPipeline(
                        bundle = bundle,
                        assetsDir = zipResult?.libraryDir,
                        format = format,
                        strategy = strategy,
                        targetBookId = targetBookId,
                        targetQuizId = targetQuizId,
                        startTime = startTime,
                        onProgress = onProgress,
                        allowInsecureRemoteImages = allowInsecureRemoteImages,
                        rootDir = zipResult?.rootDir,
                        manifest = zipResult?.manifest,
                        activeWorkspaceId = activeWorkspaceId,
                    )

                return@withContext MksResult.Success(result)
            } catch (e: Exception) {
                return@withContext MksResult.Error(
                    message = "Import failed: ${e.message}",
                    exception = e
                )
            } finally {
                zipResult?.rootDir?.deleteRecursively()
            }
        }

fun updateProgress(label: String) {
                currentStep++
                val progress = 0.3f + (currentStep.toFloat() / totalSteps.coerceAtLeast(1) * 0.65f)
                onProgress(progress, label)
            }

            // Categories
            normalizedBundle.categories.forEach { catDto ->
                try {
                    categoryMetadataDao.insertMetadata(mapper.mapToCategoryMetadataEntity(catDto))
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import category ${catDto.name}", e.message))
                }
                updateProgress("Importing category: ${catDto.name}")
            }

            // Books
            normalizedBundle.books.forEach { bookDto ->
                try {
                    val targetWorkspaceId =
                        activeWorkspaceId?.takeIf { it > 0 } ?: bookDto.workspaceExternalId
                            ?.let { workspaceDao.getWorkspaceByExternalId(it)?.id }
                            ?: defaultWorkspaceId
                    val existingBook = bookDao.getBookByExternalIdInWorkspace(bookDto.id, targetWorkspaceId)

                    if (existingBook != null && strategy == MergeStrategy.SKIP_EXISTING) {
                        bookIdMap[bookDto.id] = existingBook.id
                        updateProgress("Skipping existing book: ${bookDto.title}")
                        return@forEach
                    }

                    val coverImage = resolveImagePath(bookDto.coverImage, assetsDir, rootDir, manifest, allowInsecureRemoteImages)
                    coverImage.warning?.let { warning ->
                        warnings.add(ImportWarning("Book '${bookDto.title}' cover image import warning: $warning", affectedId = bookDto.id))
                    }
                    val coverPath = coverImage.path
                    if (coverImage.importedLocally) imagesCount++

                    val bookEntity = mapper.mapToBookEntity(bookDto, targetWorkspaceId, coverPath)
                    val bookId =
                        if (existingBook != null) {
                            bookDao.updateBook(
                                bookEntity.copy(
                                    id = existingBook.id,
                                    workspaceId = existingBook.workspaceId,
                                    createdAt = existingBook.createdAt,
                                    lastStudiedAt = existingBook.lastStudiedAt,
                                ),
                            )
                            updatedBooksCount++
                            existingBook.id
                        } else {
                            val newId = bookDao.insertBook(bookEntity)
                            booksCount++
                            newId
                        }
                    bookIdMap[bookDto.id] = bookId
                    replaceOwnerAssetReferences("book", bookId, listOf(coverPath))
                    affectedBookIds.add(bookId)
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import book ${bookDto.title}", e.message, bookDto.id))
                    skippedRecordsCount++
                }
                updateProgress("Importing book: ${bookDto.title}")
            }

            // Quizzes & Questions
            normalizedBundle.quizzes.forEach { quizDto ->
                try {
                    // Handle target IDs
                    var localBookId = targetQuiz?.bookId ?: targetBookId ?: bookIdMap[quizDto.bookId]

                    if (targetQuiz != null && targetBookId != null && targetBookId != targetQuiz.bookId) {
                        warnings.add(
                            ImportWarning(
                                "Ignoring targetBookId=$targetBookId because targetQuizId=$targetQuizId belongs to bookId=${targetQuiz.bookId}.",
                                affectedId = quizDto.id,
                            ),
                        )
                    }

                    if (localBookId == null && targetQuizId == null) {
                        // If it's a single quiz import without targetBookId, find first book or create default
                        val firstBookId =
                            bookIdMap.values.firstOrNull()
                                ?: bookDao.getBookByExternalIdInWorkspace("imported_default", defaultWorkspaceId)?.id
                        if (firstBookId != null) {
                            localBookId = firstBookId
                            warnings.add(
                                ImportWarning(
                                    "Quiz '${quizDto.title}' refers to unknown book ID '${quizDto.bookId}'. Linked to an available book.",
                                    affectedId = quizDto.id,
                                ),
                            )
                        } else {
                            // Create a default book if none exists
                            val defaultBook =
                                BookEntity(
                                    workspaceId = defaultWorkspaceId,
                                    title = "Imported Books",
                                    externalId = "imported_default",
                                    description = "Automatically created for imported quizzes",
                                )
                            localBookId = bookDao.insertBook(defaultBook)
                            bookIdMap["imported_default"] = localBookId
                            booksCount++
                        }
                    }

                    val existingQuiz = quizDao.getQuizByExternalId(quizDto.id)
                    var quizCoverPath: String? = null

                    val quizId =
                        targetQuizId ?: if (existingQuiz != null && strategy == MergeStrategy.SKIP_EXISTING) {
                            quizIdMap[quizDto.id] = existingQuiz.id
                            updateProgress("Skipping existing quiz: ${quizDto.title}")
                            return@forEach
                        } else if (existingQuiz != null) {
                            val resolvedBookId =
                                localBookId
                                    ?: throw IllegalStateException("Could not resolve a destination book for quiz '${quizDto.title}'")
                            val coverImage = resolveImagePath(quizDto.coverImage, assetsDir, rootDir, manifest, allowInsecureRemoteImages)
                            coverImage.warning?.let { warning ->
                                warnings.add(ImportWarning("Quiz '${quizDto.title}' cover image import warning: $warning", affectedId = quizDto.id))
                            }
                            val coverPath = coverImage.path
                            quizCoverPath = coverPath
                            if (coverImage.importedLocally) imagesCount++
                            val quizEntity = mapper.mapToQuizEntity(quizDto, resolvedBookId, coverPath)
                            quizDao.updateQuiz(
                                quizEntity.copy(
                                    id = existingQuiz.id,
                                    createdAt = existingQuiz.createdAt,
                                    lastStudiedAt = existingQuiz.lastStudiedAt,
                                ),
                            )
                            updatedQuizzesCount++
                            existingQuiz.id
                        } else {
                            val resolvedBookId =
                                localBookId
                                    ?: throw IllegalStateException("Could not resolve a destination book for quiz '${quizDto.title}'")
                            val coverImage = resolveImagePath(quizDto.coverImage, assetsDir, rootDir, manifest, allowInsecureRemoteImages)
                            coverImage.warning?.let { warning ->
                                warnings.add(ImportWarning("Quiz '${quizDto.title}' cover image import warning: $warning", affectedId = quizDto.id))
                            }
                            val coverPath = coverImage.path
                            quizCoverPath = coverPath
                            if (coverImage.importedLocally) imagesCount++
                            val quizEntity = mapper.mapToQuizEntity(quizDto, resolvedBookId, coverPath)
                            val newId = quizDao.insertQuiz(quizEntity)
                            quizzesCount++
                            newId
                        }
                    quizIdMap[quizDto.id] = quizId
                    if (quizCoverPath != null) {
                        replaceOwnerAssetReferences("quiz", quizId, listOf(quizCoverPath))
                    }
                    affectedQuizIds.add(quizId)
                    affectedBookIds.add(
                        localBookId ?: targetQuiz?.bookId
                            ?: throw IllegalStateException("Could not resolve a destination book for quiz '${quizDto.title}'"),
                    )

                    quizDto.questions.forEach { qDto ->
                        try {
                            val primaryImage = resolveImagePath(qDto.imageDataUrl, assetsDir, rootDir, manifest, allowInsecureRemoteImages)
                            val secondaryImage =
                                if (primaryImage.path == null) {
                                    resolveImagePath(qDto.imageSource, assetsDir, rootDir, manifest, allowInsecureRemoteImages)
                                } else {
                                    ResolvedImageResult()
                                }
                            val chosenImage = if (primaryImage.path != null) primaryImage else secondaryImage
                            val imagePath = chosenImage.path
                            if (primaryImage.importedLocally || secondaryImage.importedLocally) {
                                imagesCount++
                            }
                            chosenImage.warning?.let { warning ->
                                warnings.add(
                                    ImportWarning(
                                        "Question image in quiz '${quizDto.title}' import warning: $warning",
                                        affectedId = qDto.id,
                                    ),
                                )
                            }

                            val qEntity = mapper.mapToQuestionEntity(qDto, quizId, imagePath)

                            val existingQuestion = questionDao.getQuestionByExternalId(quizId, qEntity.externalId)

                            val localId =
                                if (existingQuestion != null) {
                                    questionDao.updateQuestion(
                                        qEntity.copy(
                                            id = existingQuestion.id,
                                            attempts = existingQuestion.attempts,
                                            correctCount = existingQuestion.correctCount,
                                            isDropped = existingQuestion.isDropped,
                                            droppedAt = existingQuestion.droppedAt,
                                            droppedReason = existingQuestion.droppedReason,
                                            isMarked = existingQuestion.isMarked,
                                            markedAt = existingQuestion.markedAt,
                                            markReason = existingQuestion.markReason,
                                            markReviewAt = existingQuestion.markReviewAt,
                                            notes = existingQuestion.notes ?: qEntity.notes,
                                            createdAt = existingQuestion.createdAt,
                                            lastStudiedAt = existingQuestion.lastStudiedAt,
                                            timeSpentMs = existingQuestion.timeSpentMs,
                                            lastAttemptResult = existingQuestion.lastAttemptResult,
                                            consecutiveCorrect = existingQuestion.consecutiveCorrect,
                                        ),
                                    )
                                    updatedQuestionsCount++
                                    existingQuestion.id
                                } else {
                                    val newId = questionDao.insertQuestion(qEntity)
                                    questionsCount++
                                    newId
                                }

                            questionIdMap[qDto.id] = localId
                            syncQuestionCategories(localId, qEntity.categories)
                            replaceOwnerAssetReferences("question", localId, listOf(qEntity.imagePath))
                        } catch (e: Exception) {
                            warnings.add(ImportWarning("Failed to import question in ${quizDto.title}", e.message, qDto.id))
                            skippedRecordsCount++
                        }
                    }
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import quiz ${quizDto.title}", e.message, quizDto.id))
                    skippedRecordsCount++
                }
                updateProgress("Importing quiz: ${quizDto.title}")
            }

            // Sessions
            normalizedBundle.sessions?.forEach { sessionDto ->
                try {
                    val localQuizId = quizIdMap[sessionDto.quizId]
                    if (localQuizId != null) {
                        sessionDao.insertSession(mapper.mapToSessionEntity(sessionDto, localQuizId, questionIdMap))
                        sessionsCount++
                    } else {
                        warnings.add(ImportWarning("Skipped session for unknown quiz ID ${sessionDto.quizId}"))
                        skippedRecordsCount++
                    }
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import session ${sessionDto.id}", e.message, sessionDto.id))
                    skippedRecordsCount++
                }
                updateProgress("Importing sessions...")
            }

            // Knowledge Bank - Flashcards
            val flashcardDeckIdMap = mutableMapOf<String, Long>()
            normalizedBundle.flashcardDecks.forEach { deckDto ->
                try {
                    val localBookId = bookIdMap[deckDto.bookId] ?: return@forEach
                    val cover = resolveImagePath(
                        deckDto.coverImage,
                        assetsDir,
                        rootDir,
                        manifest,
                        allowInsecureRemoteImages
                    )
                    val deckEntity =
                        mapper.mapToFlashcardDeckEntity(deckDto, localBookId, cover.path)
                    val deckId = database.flashcardDeckDao().insertFlashcardDeck(deckEntity)
                    flashcardDeckIdMap[deckDto.id] = deckId
                    if (cover.importedLocally) imagesCount++
                    replaceOwnerAssetReferences("flashcard_deck", deckId, listOf(cover.path))

                    deckDto.cards.forEach { cardDto ->
                        val img = resolveImagePath(
                            cardDto.imagePath,
                            assetsDir,
                            rootDir,
                            manifest,
                            allowInsecureRemoteImages
                        )
                        val cardEntity = mapper.mapToFlashcardEntity(cardDto, deckId, img.path)
                        database.flashcardDao().insertFlashcard(cardEntity)
                        flashcardsCount++
                        if (img.importedLocally) imagesCount++
                    }
                } catch (e: Exception) {
                    warnings.add(
                        ImportWarning(
                            "Failed to import flashcard deck ${deckDto.title}",
                            e.message
                        )
                    )
                }
                updateProgress("Importing flashcards: ${deckDto.title}")
            }

            // Knowledge Bank - Slideshows
            val slideshowIdMap = mutableMapOf<String, Long>()
            normalizedBundle.slideshowCourses.forEach { courseDto ->
                try {
                    val localBookId = bookIdMap[courseDto.bookId] ?: return@forEach
                    val cover = resolveImagePath(
                        courseDto.coverImage,
                        assetsDir,
                        rootDir,
                        manifest,
                        allowInsecureRemoteImages
                    )
                    val courseEntity =
                        mapper.mapToSlideshowCourseEntity(courseDto, localBookId, cover.path)
                    val courseId = database.slideshowCourseDao().insertCourse(courseEntity)
                    slideshowIdMap[courseDto.id] = courseId
                    if (cover.importedLocally) imagesCount++
                    replaceOwnerAssetReferences("slideshow", courseId, listOf(cover.path))

                    courseDto.slides.forEach { slideDto ->
                        val img = resolveImagePath(
                            slideDto.imagePath,
                            assetsDir,
                            rootDir,
                            manifest,
                            allowInsecureRemoteImages
                        )
                        val slideEntity =
                            mapper.mapToCourseSlideEntity(slideDto, courseId, img.path)
                        val slideId = database.courseSlideDao().insertSlide(slideEntity)
                        slidesCount++
                        if (img.importedLocally) imagesCount++
                        replaceOwnerAssetReferences("slide", slideId, listOf(img.path))
                    }
                } catch (e: Exception) {
                    warnings.add(
                        ImportWarning(
                            "Failed to import slideshow ${courseDto.title}",
                            e.message
                        )
                    )
                }
                updateProgress("Importing slideshow: ${courseDto.title}")
            }

            // Knowledge Bank - Notes
            val noteIdMap = mutableMapOf<String, Long>()
            normalizedBundle.noteBlueprints.forEach { noteDto ->
                try {
                    val localBookId = bookIdMap[noteDto.bookId] ?: return@forEach
                    val entity = mapper.mapToNoteBlueprintEntity(noteDto, localBookId)
                    val noteId = database.noteBlueprintDao().insertNote(entity)
                    noteIdMap[noteDto.id] = noteId
                    notesCount++
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import note ${noteDto.title}", e.message))
                }
                updateProgress("Importing note: ${noteDto.title}")
            }

            // Knowledge Bank - Prompts
            val promptDeckIdMap = mutableMapOf<String, Long>()
            normalizedBundle.promptDecks.forEach { deckDto ->
                try {
                    val localBookId = bookIdMap[deckDto.bookId] ?: return@forEach
                    val deckEntity = mapper.mapToPromptDeckEntity(deckDto, localBookId)
                    val deckId = database.promptDeckDao().insertDeck(deckEntity)
                    promptDeckIdMap[deckDto.id] = deckId

                    deckDto.cards.forEach { cardDto ->
                        val cardEntity = mapper.mapToPromptCardEntity(cardDto, deckId)
                        database.promptCardDao().insertCard(cardEntity)
                        promptsCount++
                    }
                } catch (e: Exception) {
                    warnings.add(
                        ImportWarning(
                            "Failed to import prompt deck ${deckDto.title}",
                            e.message
                        )
                    )
                }
                updateProgress("Importing prompt deck: ${deckDto.title}")
            }

            // Knowledge Bank - Study Sessions
            normalizedBundle.studySessions.forEach { sessionDto ->
                try {
                    val targetId = when (sessionDto.type) {
                        "FLASHCARD_DECK" -> flashcardDeckIdMap[sessionDto.contentId]
                        "SLIDESHOW" -> slideshowIdMap[sessionDto.contentId]
                        "NOTE" -> noteIdMap[sessionDto.contentId]
                        "PROMPT" -> promptDeckIdMap[sessionDto.contentId]
                        else -> null
                    } ?: return@forEach

                    val entity = KnowledgeStudySessionEntity(
                        targetType = sessionDto.type,
                        targetId = targetId,
                        isCompleted = sessionDto.isCompleted,
                        updatedAt = sessionDto.lastAccessedAt ?: System.currentTimeMillis(),
                        createdAt = System.currentTimeMillis(),
                        stateJson = "{}"
                    )
                    database.knowledgeStudySessionDao().insertSession(entity)
                } catch (_: Exception) {
                }
            }

            // Source Documents
            val sourceDocIdMap = mutableMapOf<Long, Long>()
            normalizedBundle.sourceDocuments.forEach { docDto ->
                try {
                    val localBookId = docDto.bookId?.let { bookIdMap[it] }
                    val resolvedDoc = resolveImagePath(
                        docDto.localPath,
                        assetsDir,
                        rootDir,
                        manifest,
                        allowInsecureRemoteImages
                    )
                    val entity =
                        mapper.mapToSourceDocumentEntity(docDto, localBookId, resolvedDoc.path)
                    val newId = database.sourceDocumentDao().insertSource(entity)
                    docDto.id?.let { sourceDocIdMap[it] = newId }
                    if (resolvedDoc.importedLocally) imagesCount++
                } catch (e: Exception) {
                    warnings.add(
                        ImportWarning(
                            "Failed to import source document ${docDto.title}",
                            e.message
                        )
                    )
                }
            }

            // Question Assets
            normalizedBundle.questionAssets.forEach { assetDto ->
                try {
                    val localBookId = assetDto.bookId?.let { bookIdMap[it] } ?: return@forEach
                    val localQuizId = assetDto.quizId?.let { quizIdMap[it] } ?: return@forEach
                    val localQuestionId =
                        assetDto.questionId?.let { questionIdMap[it] } ?: return@forEach
                    val sourceDocId = assetDto.sourceDocumentId?.let { sourceDocIdMap[it] }

                    val resolvedAsset = resolveImagePath(
                        assetDto.localPath,
                        assetsDir,
                        rootDir,
                        manifest,
                        allowInsecureRemoteImages
                    )
                    val entity = mapper.mapToQuestionAssetEntity(
                        assetDto,
                        localBookId,
                        localQuizId,
                        localQuestionId,
                        resolvedAsset.path,
                        sourceDocId
                    )
                    database.questionAssetDao().insertAsset(entity)
                    if (resolvedAsset.importedLocally) imagesCount++
                } catch (e: Exception) {
                    warnings.add(
                        ImportWarning(
                            "Failed to import question asset ${assetDto.title}",
                            e.message
                        )
                    )
                }
            }

            // Annotations
            normalizedBundle.annotations.forEach { annDto ->
                try {
                    val localBookId = annDto.bookId?.let { bookIdMap[it] } ?: return@forEach
                    val localOwnerId =
                        when (annDto.ownerType.uppercase()) {
                            "BOOK" -> localBookId
                            "QUIZ" -> annDto.ownerId?.let { quizIdMap[it] }
                            "QUESTION" -> annDto.ownerId?.let { questionIdMap[it] }
                            else -> null
                        } ?: return@forEach

                    val entity = mapper.mapToAnnotationEntity(
                        annDto,
                        defaultWorkspaceId,
                        localBookId,
                        localOwnerId
                    )
                    database.annotationDao().insertAnnotation(entity)
                } catch (e: Exception) {
                    warnings.add(ImportWarning("Failed to import annotation", e.message))
                }
            }

            onProgress(1.0f, "Import complete")

            ImportResult(
                success = true,
                detectedFormat = format,
                detectedSchemaVersion = bundle.schema,
                importedBooksCount = booksCount,
                updatedBooksCount = updatedBooksCount,
                importedQuizzesCount = quizzesCount,
                updatedQuizzesCount = updatedQuizzesCount,
                importedQuestionsCount = questionsCount,
                updatedQuestionsCount = updatedQuestionsCount,
                importedSessionsCount = sessionsCount,
                updatedSessionsCount = updatedSessionsCount,
                importedFlashcardsCount = flashcardsCount,
                importedSlidesCount = slidesCount,
                importedNotesCount = notesCount,
                importedPromptsCount = promptsCount,
                importedImagesCount = imagesCount,
                skippedRecordsCount = skippedRecordsCount,
                affectedBookIds = affectedBookIds.toList(),
                affectedQuizIds = affectedQuizIds.toList(),
                warnings = warnings,
                durationMillis = System.currentTimeMillis() - startTime,
                partiallyImported = skippedRecordsCount > 0,
            )
        }
    }

    private suspend fun resolveImagePath(
        assetRef: String?,
        assetsDir: File?,
        rootDir: File? = null,
        manifest: ManifestDto? = null,
        allowInsecureRemoteImages: Boolean = false,
    ): ResolvedImageResult {
        if (assetRef.isNullOrBlank()) return ResolvedImageResult()

        // If it's a data URL, save it directly via the new sanitization helper
        if (assetRef.startsWith("data:")) {
            val saved = fileManager.saveBase64AsImageDetailed(assetRef)
            return ResolvedImageResult(
                path = saved.getOrNull(),
                warning = saved.exceptionOrNull()?.message,
                importedLocally = saved.isSuccess,
            )
        }

        // Potential directories to search for assets
        val searchDirs = mutableListOf<File>()
        if (assetsDir != null) searchDirs.add(assetsDir)
        if (rootDir != null && rootDir != assetsDir) searchDirs.add(rootDir)

        if (searchDirs.isNotEmpty()) {
            // 1. Try the exact zip-relative path first.
            resolveRelativeAssetPath(searchDirs, assetRef)?.let { matchedFile ->
                matchedFile.inputStream().use { input ->
                    val saved = fileManager.saveImageDetailed(input, matchedFile.name)
                    return ResolvedImageResult(
                        path = saved.getOrNull(),
                        warning = saved.exceptionOrNull()?.message,
                        importedLocally = saved.isSuccess,
                    )
                }
            }

            // 2. Try manifest mappings for exported bundles and legacy manifests.
            if (manifest != null && manifest.assets.isNotEmpty()) {
                val manifestPath =
                    manifest.assets[assetRef]
                        ?: manifest.assets.entries.find { normalizeAssetRef(it.key) == normalizeAssetRef(assetRef) }?.value
                        ?: manifest.assets.entries.find { normalizeAssetRef(it.value) == normalizeAssetRef(assetRef) }?.key
                manifestPath?.let { path ->
                    resolveRelativeAssetPath(searchDirs, path)?.let { manifestFile ->
                        manifestFile.inputStream().use { input ->
                            val saved = fileManager.saveImageDetailed(input, manifestFile.name)
                            return ResolvedImageResult(
                                path = saved.getOrNull(),
                                warning = saved.exceptionOrNull()?.message,
                                importedLocally = saved.isSuccess,
                            )
                        }
                    }
                }
            }

            // 3. Fallback to a constrained recursive search for legacy bundles.
            val fileName = assetRef.substringAfterLast('/')
            val cleanRef = normalizeAssetRef(assetRef)

            val suffixMatches =
                searchDirs.flatMap { dir ->
                    dir.walkTopDown()

// [تكملة المقطع السابق بسبب طول الكود]
                        .filter { file -> file.isFile }
                        .filter { file ->
                            val relativePath = file.relativeTo(dir).invariantSeparatorsPath
                            relativePath == cleanRef || relativePath.endsWith("/$cleanRef")
                        }
                        .toList()
                }.distinctBy { it.canonicalPath }

            val matchedFile =
                when {
                    suffixMatches.size == 1 -> suffixMatches.first()
                    suffixMatches.isEmpty() -> {
                        val nameMatches =
                            searchDirs.flatMap { dir ->
                                dir.walkTopDown()
                                    .filter { file -> file.isFile && file.name == fileName }
                                    .toList()
                            }.distinctBy { it.canonicalPath }
                        nameMatches.singleOrNull()
                    }
                    else -> null
                }

            if (matchedFile != null) {
                matchedFile.inputStream().use { input ->
                    val saved = fileManager.saveImageDetailed(input, matchedFile.name)
                    return ResolvedImageResult(
                        path = saved.getOrNull(),
                        warning = saved.exceptionOrNull()?.message,
                        importedLocally = saved.isSuccess,
                    )
                }
            }
        }

        // If it's a remote URL, download it through the central policy gate.
        val remoteScheme = runCatching { assetRef.toUri().scheme?.lowercase() }.getOrNull()
        if (remoteScheme == "http" || remoteScheme == "https") {
            val localImage =
                fileManager.downloadAndSaveImageDetailed(
                    assetRef,
                    if (allowInsecureRemoteImages) RemoteAssetPolicy.UserAllowedPlainHttp else RemoteAssetPolicy.Default,
                )
            if (localImage is MksResult.Success) {
                return ResolvedImageResult(
                    path = localImage.data,
                    warning = null,
                    importedLocally = true
                )
            }
            if (remoteScheme == "http" && !allowInsecureRemoteImages) {
                return ResolvedImageResult(
                    warning = localImage.exceptionOrNull()?.message
                        ?: "Plain HTTP image URL was skipped until the user allows insecure image downloads.",
                    importedLocally = false,
                )
            }
            // HTTPS failures and user-approved HTTP failures are preserved as remote references.
            return ResolvedImageResult(
                path = assetRef,
                warning =
                    localImage.exceptionOrNull()?.message?.let { "Kept remote URL instead of importing locally: $it" }
                        ?: "Kept remote URL instead of importing locally.",
                importedLocally = false,
            )
        }

        // Final attempt as base64 or other string-based image if not already tried
        // SECURITY: FileManager.saveImage handles absolute path validation
        val saved = fileManager.saveImageDetailed(assetRef)
        if (saved is MksResult.Success) {
            return ResolvedImageResult(path = saved.data, importedLocally = true)
        }

        return if (assetRef.contains(",") || assetRef.length < 255) {
            ResolvedImageResult(
                warning = saved.exceptionOrNull()?.message ?: "Unsupported inline image data."
            )
        } else {
            ResolvedImageResult(
                path = assetRef,
                warning = saved.exceptionOrNull()?.message,
                importedLocally = false
            )
        }
    }

private fun resolveRelativeAssetPath(
        searchDirs: List<File>,
        assetRef: String,
    ): File? {
        val normalizedRef = normalizeAssetRef(assetRef)
        if (normalizedRef.isBlank() || normalizedRef.split('/').any { it == ".." }) return null

        return searchDirs
            .asSequence()
            .mapNotNull { dir ->
                val baseDir = runCatching { dir.canonicalFile }.getOrNull() ?: return@mapNotNull null
                val candidate = runCatching { File(baseDir, normalizedRef).canonicalFile }.getOrNull() ?: return@mapNotNull null
                val isInsideBase = candidate == baseDir || candidate.toPath().startsWith(baseDir.toPath())
                if (isInsideBase && candidate.exists() && candidate.isFile) candidate else null
            }
            .firstOrNull()
    }

private fun normalizeAssetRef(assetRef: String): String {
        return assetRef
            .replace('\\', '/')
            .removePrefix("./")
            .removePrefix("/")
    }

fun isPlainHttp(value: String?): Boolean = value?.startsWith("http://", ignoreCase = true) == true
        if (bundle.books.any { isPlainHttp(it.coverImage) }) return true
        return bundle.quizzes.any { quiz ->
            isPlainHttp(quiz.coverImage) ||
                quiz.questions.any { question ->
                    isPlainHttp(question.imageDataUrl) || isPlainHttp(question.imageSource) || isPlainHttp(question.imageName)
                }
        }
    }

private fun readImportText(
        uri: Uri,
        format: ImportFormat,
    ): String {
        val limit =
            when (format) {
                ImportFormat.HTML -> ImportLimits.MAX_HTML_IMPORT_BYTES
                ImportFormat.CSV_TSV -> ImportLimits.MAX_CSV_IMPORT_BYTES
                else -> ImportLimits.MAX_TEXT_IMPORT_BYTES
            }
        return context.contentResolver.openInputStream(uri)?.use { input -> input.readTextWithLimit(limit) }
            ?: throw Exception("Could not read file content")
    }

    companion object {

fun generateDeterministicId(
            stem: String,
            options: List<String>,
        ): String {
            val input = stem + options.sorted().joinToString("|")
            return try {
                val digest = MessageDigest.getInstance("SHA-256")
                val hash = digest.digest(input.toByteArray())
                hash.joinToString("") { "%02x".format(it) }.take(32)
            } catch (_: Exception) {
                UUID.nameUUIDFromBytes(input.toByteArray()).toString()
            }
        }
    }
}

fun normalize(bundle: LibraryBundleDto): LibraryBundleDto {
        return bundle.copy(
            quizzes =
                bundle.quizzes.map { quiz ->
                    quiz.copy(
                        questions = quiz.questions.map { normalizeQuestion(it) },
                    )
                },
        )
    }

private fun normalizeQuestion(question: QuestionDto): QuestionDto {
        val inferredAnswerMode =
            when {
                question.answerMode != null -> question.answerMode
                question.correct.size > 1 -> "multiple"
                else -> "single"
            }

        return question.copy(
            answerMode = inferredAnswerMode,
            stem = question.stem.trim(),
            explanation = question.explanation.trim(),
            hint = question.hint.trim(),
            reference = question.reference.trim(),
        )
    }
}

fun init() {
        if (isInitialized) return
        try {
            // Set StAX properties to use Aalto XML
            System.setProperty("javax.xml.stream.XMLInputFactory", "com.fasterxml.aalto.stax.InputFactoryImpl")
            System.setProperty("javax.xml.stream.XMLOutputFactory", "com.fasterxml.aalto.stax.OutputFactoryImpl")
            System.setProperty("javax.xml.stream.XMLEventFactory", "com.fasterxml.aalto.stax.EventFactoryImpl")

            // Set additional properties to ensure POI doesn't look for AWT
            System.setProperty("java.awt.headless", "true")
            System.setProperty("org.apache.poi.util.ignore_missing_fontmetrics", "true")

            isInitialized = true
        } catch (e: Exception) {
            MksLogger.e("PoiInitializer", "Failed to initialize POI environment", e)
        }
    }
}

class XlsxImageResolver {
    companion object {
        private const val MAX_ENTRY_SIZE = 20 * 1024 * 1024L // 20 MB
        private val DISPIMG_REGEX =
            Regex(
                """(?:_xlfn\.)?DISPIMG\(\s*(?:N\s*)?(?:\"|')?([^,\"'&)<>\s]+)(?:\"|')?""",
                RegexOption.IGNORE_CASE,
            )
    }

    private val dbf =
        DocumentBuilderFactory.newInstance().apply {
            isNamespaceAware = true
        }

fun extractDispImgId(formula: String): String? {
        val match = DISPIMG_REGEX.find(formula)
        return match?.groupValues?.getOrNull(1)?.trim()?.takeIf { it.isNotEmpty() }
    }

fun getCellImagePathMap(zipFile: ZipFile): Map<String, String> {
        val cellImagesXml = readEntry(zipFile, "xl/cellimages.xml") ?: return emptyMap()
        val relsXml = readEntry(zipFile, "xl/_rels/cellimages.xml.rels") ?: return emptyMap()

        val relMap = parseRelationships(relsXml, "xl/cellimages.xml")
        val result = mutableMapOf<String, String>()

        try {
            val doc = parseXml(cellImagesXml)
            val picNodes = doc.getElementsByTagNameNS("*", "pic")
            for (i in 0 until picNodes.length) {
                val pic = picNodes.item(i) as? Element ?: continue
                val cNvPr = pic.getElementsByTagNameNS("*", "cNvPr").item(0) as? Element
                val blip = pic.getElementsByTagNameNS("*", "blip").item(0) as? Element
                val imageId = cNvPr?.getAttribute("name").orEmpty().trim()
                val relId = extractRelationshipId(blip)
                val targetPath = relId?.let { relMap[it] }
                if (imageId.isNotEmpty() && !targetPath.isNullOrBlank()) {
                    result[imageId] = targetPath
                }
            }
        } catch (_: Exception) {
        }
        return result
    }

fun resolveSheetFormulaImages(
        zipFile: ZipFile,
        sheetName: String,
        cellImagePathMap: Map<String, String>,
    ): Map<String, String> {
        val sheetPath = getSheetPath(zipFile, sheetName) ?: return emptyMap()
        val sheetBytes = readEntry(zipFile, sheetPath) ?: return emptyMap()

        val result = mutableMapOf<String, String>()
        val pathCache = mutableMapOf<String, String>()

        try {
            val doc = parseXml(sheetBytes)
            val cellNodes = doc.getElementsByTagName("c")
            for (i in 0 until cellNodes.length) {
                val cell = cellNodes.item(i) as? Element ?: continue
                val addr = cell.getAttribute("r").trim()
                if (addr.isEmpty()) continue
                val formulaNode = cell.getElementsByTagName("f").item(0)
                val formulaText = formulaNode?.textContent.orEmpty()
                val imageId = extractDispImgId(formulaText) ?: continue
                val zipPath = cellImagePathMap[imageId] ?: continue
                val dataUrl = pathCache.getOrPut(zipPath) { readImageAsDataUrl(zipFile, zipPath).orEmpty() }
                if (dataUrl.isNotBlank()) {
                    result[addr] = dataUrl
                }
            }
        } catch (_: Exception) {
        }
        return result
    }

fun resolveSheetImages(
        zipFile: ZipFile,
        sheetName: String,
        cellImagePathMap: Map<String, String>,
    ): SheetImageResolution {
        val anchored = resolveAnchoredSheetImages(zipFile, sheetName)
        val formulaImages = resolveSheetFormulaImages(zipFile, sheetName, cellImagePathMap)
        val mergedAddressImages = anchored.addressImages.toMutableMap()
        formulaImages.forEach { (cell, image) ->
            if (image.isNotBlank()) {
                mergedAddressImages[cell] = image
            }
        }
        return SheetImageResolution(
            addressImages = mergedAddressImages,
            rowImages = anchored.rowImages,
        )
    }

private fun resolveAnchoredSheetImages(
        zipFile: ZipFile,
        sheetName: String,
    ): SheetImageResolution {
        val sheetPath = getSheetPath(zipFile, sheetName) ?: return SheetImageResolution()
        val sheetBytes = readEntry(zipFile, sheetPath) ?: return SheetImageResolution()
        val sheetRelsBytes = readEntry(zipFile, buildRelsPath(sheetPath)) ?: return SheetImageResolution()
        val drawingCache = mutableMapOf<String, String>()
        val addressImages = linkedMapOf<String, String>()
        val rowImages = linkedMapOf<Int, String>()

        try {
            val sheetDoc = parseXml(sheetBytes)
            val drawingRelIds = mutableListOf<String>()
            val drawingNodes = sheetDoc.getElementsByTagNameNS("*", "drawing")
            for (i in 0 until drawingNodes.length) {
                val drawing = drawingNodes.item(i) as? Element ?: continue
                extractRelationshipId(drawing)?.let { drawingRelIds.add(it) }
            }
            if (drawingRelIds.isEmpty()) return SheetImageResolution()
            val sheetRelMap = parseRelationships(sheetRelsBytes, sheetPath)
            drawingRelIds.forEach { relId ->
                val drawingPath = sheetRelMap[relId] ?: return@forEach
                mergeDrawingAnchors(zipFile, drawingPath, drawingCache, addressImages, rowImages)
            }
        } catch (_: Exception) {
        }

        return SheetImageResolution(addressImages = addressImages, rowImages = rowImages)
    }

private fun mergeDrawingAnchors(
        zipFile: ZipFile,
        drawingPath: String,
        pathCache: MutableMap<String, String>,
        addressImages: MutableMap<String, String>,
        rowImages: MutableMap<Int, String>,
    ) {
        val drawingBytes = readEntry(zipFile, drawingPath) ?: return
        val drawingRelsBytes = readEntry(zipFile, buildRelsPath(drawingPath)) ?: return
        val drawingRelMap = parseRelationships(drawingRelsBytes, drawingPath)

        try {
            val drawingDoc = parseXml(drawingBytes)
            consumeAnchorNodes(drawingDoc, "oneCellAnchor", drawingRelMap, zipFile, pathCache, addressImages, rowImages)
            consumeAnchorNodes(drawingDoc, "twoCellAnchor", drawingRelMap, zipFile, pathCache, addressImages, rowImages)
        } catch (_: Exception) {
        }
    }

private fun consumeAnchorNodes(
        drawingDoc: Document,
        localName: String,
        drawingRelMap: Map<String, String>,
        zipFile: ZipFile,
        pathCache: MutableMap<String, String>,
        addressImages: MutableMap<String, String>,
        rowImages: MutableMap<Int, String>,
    ) {
        val anchorNodes = drawingDoc.getElementsByTagNameNS("*", localName)
        for (i in 0 until anchorNodes.length) {
            val anchor = anchorNodes.item(i) as? Element ?: continue
            val from = anchor.getElementsByTagNameNS("*", "from").item(0) as? Element ?: continue
            val fromCol = childInt(from, "col") ?: continue
            val fromRowZero = childInt(from, "row") ?: continue

            var toCol = fromCol
            var toRowZero = fromRowZero
            val to = anchor.getElementsByTagNameNS("*", "to").item(0) as? Element
            if (to != null) {
                toCol = childInt(to, "col") ?: fromCol
                toRowZero = childInt(to, "row") ?: fromRowZero
            }

            val blip = anchor.getElementsByTagNameNS("*", "blip").item(0) as? Element ?: continue
            val relId = extractRelationshipId(blip) ?: continue
            val imagePath = drawingRelMap[relId] ?: continue
            val dataUrl = pathCache.getOrPut(imagePath) { readImageAsDataUrl(zipFile, imagePath).orEmpty() }
            if (dataUrl.isBlank()) continue

            val rowStart = min(fromRowZero, toRowZero) + 1
            val rowEnd = max(fromRowZero, toRowZero) + 1
            val colStart = min(fromCol, toCol)
            val colEnd = max(fromCol, toCol)

            for (row in rowStart..rowEnd) {
                rowImages.putIfAbsent(row, dataUrl)
                for (col in colStart..colEnd) {
                    addressImages.putIfAbsent(toCellRef(col, row), dataUrl)
                }
            }
        }
    }

private fun extractRelationshipId(element: Element?): String? {
        if (element == null) return null
        return element.getAttribute("r:embed").ifBlank {
            element.getAttributeNS(
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships",
                "embed",
            )
        }.ifBlank {
            element.getAttribute("r:id")
        }.ifBlank {
            element.getAttributeNS(
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships",
                "id",
            )
        }.trim().takeIf { it.isNotEmpty() }
    }

private fun childInt(
        parent: Element,
        localName: String,
    ): Int? {
        val value = parent.getElementsByTagNameNS("*", localName).item(0)?.textContent?.trim()
        return value?.toIntOrNull()
    }

private fun readImageAsDataUrl(
        zipFile: ZipFile,
        zipPath: String,
    ): String? {
        val bytes = readEntry(zipFile, zipPath) ?: return null
        val base64 = Base64.encodeToString(bytes, Base64.NO_WRAP)
        return "data:${getImageMimeType(zipPath)};base64,$base64"
    }

private fun readEntry(
        zipFile: ZipFile,
        name: String,
    ): ByteArray? {
        return try {
            zipFile.getEntry(name)?.let { entry ->
                if (entry.size > MAX_ENTRY_SIZE) {
                    return null
                }
                zipFile.getInputStream(entry).use { it.readBytes() }
            }
        } catch (_: Exception) {
            null
        }
    }

private fun parseXml(bytes: ByteArray): Document {
        return dbf.newDocumentBuilder().parse(bytes.inputStream())
    }

private fun parseRelationships(
        relsBytes: ByteArray,
        basePath: String,
    ): Map<String, String> {
        val map = mutableMapOf<String, String>()
        try {
            val doc = parseXml(relsBytes)
            val relNodes = doc.getElementsByTagName("Relationship")
            for (i in 0 until relNodes.length) {
                val rel = relNodes.item(i) as? Element ?: continue
                val id = rel.getAttribute("Id").trim()
                val target = rel.getAttribute("Target").trim()
                if (id.isNotEmpty() && target.isNotEmpty()) {
                    map[id] = resolveZipPath(basePath, target)
                }
            }
        } catch (_: Exception) {
        }
        return map
    }

private fun resolveZipPath(
        basePath: String,
        target: String,
    ): String {
        if (target.startsWith("/")) {
            return target.trimStart('/')
        }
        val baseDir = basePath.substringBeforeLast('/', "")
        val combined = if (baseDir.isEmpty()) target else "$baseDir/$target"
        val resolved = mutableListOf<String>()
        combined.split('/').forEach { part ->
            when (part) {
                "", "." -> Unit
                ".." -> if (resolved.isNotEmpty()) resolved.removeAt(resolved.lastIndex)
                else -> resolved.add(part)
            }
        }
        return resolved.joinToString("/")
    }

private fun buildRelsPath(path: String): String {
        val dir = path.substringBeforeLast('/', "")
        val fileName = path.substringAfterLast('/')
        return if (dir.isEmpty()) {
            "_rels/$fileName.rels"
        } else {
            "$dir/_rels/$fileName.rels"
        }
    }

private fun getSheetPath(
        zipFile: ZipFile,
        sheetName: String,
    ): String? {
        val workbookXml = readEntry(zipFile, "xl/workbook.xml") ?: return null
        val relsXml = readEntry(zipFile, "xl/_rels/workbook.xml.rels") ?: return null
        val relMap = parseRelationships(relsXml, "xl/workbook.xml")

        return try {
            val doc = parseXml(workbookXml)
            val sheetNodes = doc.getElementsByTagNameNS("*", "sheet")
            for (i in 0 until sheetNodes.length) {
                val sheet = sheetNodes.item(i) as? Element ?: continue
                if (sheet.getAttribute("name") == sheetName) {
                    val relId =
                        sheet.getAttributeNS(
                            "http://schemas.openxmlformats.org/officeDocument/2006/relationships",
                            "id",
                        ).ifEmpty { sheet.getAttribute("r:id") }.trim()
                    return relMap[relId]
                }
            }
            null
        } catch (_: Exception) {
            null
        }
    }

private fun toCellRef(
        zeroBasedCol: Int,
        oneBasedRow: Int,
    ): String {
        var col = zeroBasedCol + 1
        val builder = StringBuilder()
        while (col > 0) {
            val rem = (col - 1) % 26
            builder.insert(0, ('A'.code + rem).toChar())
            col = (col - 1) / 26
        }
        return builder.toString() + oneBasedRow
    }

private fun getImageMimeType(path: String): String {
        return when (path.substringAfterLast('.', "png").lowercase()) {
            "png" -> "image/png"
            "jpg", "jpeg" -> "image/jpeg"
            "gif" -> "image/gif"
            "webp" -> "image/webp"
            "svg" -> "image/svg+xml"
            "bmp" -> "image/bmp"
            else -> "image/png"
        }
    }
}

class XlsxLibraryCompiler(private val context: Context) {
    private val xlsxResolver = XlsxImageResolver()
    private val headerMapper = SpreadsheetHeaderMapper()
    private val imageExtractor = GenericImageExtractor()

private fun prepareTempFile(uri: Uri): java.io.File? {
        val extension =
            getFileName(uri)
                ?.substringAfterLast('.', "xlsx")
                ?.lowercase()
                ?.takeIf { it.isNotBlank() }
                ?: "xlsx"
        val file = java.io.File(context.cacheDir, "import_lib_${System.currentTimeMillis()}.$extension")
        return try {
            context.contentResolver.openInputStream(uri)?.use { input ->
                file.outputStream().use { output ->
                    input.copyToWithLimit(output, ImportLimits.MAX_XLSX_IMPORT_BYTES)
                }
            }
            file
        } catch (_: Exception) {
            null
        }
    }

private fun extractRowCells(
        row: Row?,
        columnCount: Int,
        formatter: DataFormatter,
    ): List<String> {
        if (row == null || columnCount <= 0) return emptyList()
        return (0 until columnCount).map { columnIndex ->
            row.getCell(columnIndex)?.let { cell ->
                formatCellSafely(cell, formatter).trim()
            }.orEmpty()
        }
    }

private fun formatCellSafely(
        cell: Cell,
        formatter: DataFormatter,
    ): String {
        return try {
            if (cell.cellType == CellType.FORMULA) {
                fallbackFormulaText(cell, formatter)
            } else {
                formatter.formatCellValue(cell)
            }
        } catch (_: Exception) {
            fallbackFormulaText(cell, formatter)
        }
    }

private fun fallbackFormulaText(
        cell: Cell,
        formatter: DataFormatter,
    ): String {
        if (cell.cellType != CellType.FORMULA) {
            return runCatching { formatter.formatCellValue(cell) }.getOrElse { cell.toString() }
        }

        return try {
            when (cell.cachedFormulaResultType) {
                CellType.STRING -> cell.richStringCellValue?.string.orEmpty()
                CellType.NUMERIC ->
                    formatter.formatRawCellContents(
                        cell.numericCellValue,
                        cell.cellStyle.dataFormat.toInt(),
                        cell.cellStyle.dataFormatString,
                    )
                CellType.BOOLEAN -> cell.booleanCellValue.toString()
                CellType.BLANK -> ""
                else -> "=" + cell.cellFormula.orEmpty()
            }
        } catch (_: Exception) {
            runCatching { "=" + cell.cellFormula.orEmpty() }.getOrElse { cell.toString() }
        }
    }

private fun detectStableColumnCount(
        sheet: org.apache.poi.ss.usermodel.Sheet,
        headerRowIdx: Int,
    ): Int {
        var maxColumns = 0
        val scanEnd = minOf(sheet.lastRowNum, headerRowIdx + 40)
        for (rowIndex in 0..scanEnd) {
            val row = sheet.getRow(rowIndex) ?: continue
            maxColumns = maxOf(maxColumns, row.lastCellNum.toInt().coerceAtLeast(0))
        }
        return maxColumns
    }

private fun getFileName(uri: Uri): String? {
        return try {
            context.contentResolver.query(uri, arrayOf(OpenableColumns.DISPLAY_NAME), null, null, null)?.use { cursor ->
                if (cursor.moveToFirst()) {
                    val index = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                    if (index != -1) cursor.getString(index) else null
                } else {
                    null
                }
            }
        } catch (_: Exception) {
            uri.lastPathSegment
        }
    }
}

package com.ahmedyejam.mks.data.importer.parser

import com.ahmedyejam.mks.data.importer.dto.LibraryBundleDto
import com.ahmedyejam.mks.data.importer.security.ImportLimits
import com.ahmedyejam.mks.util.readTextWithLimit
import kotlinx.serialization.json.*
import java.io.InputStream

open class JsonLibraryParser {
    private val json =
        Json {
            ignoreUnknownKeys = true
            isLenient = true
            coerceInputValues = true
            encodeDefaults = true
        }

    private object LibraryTransformingSerializer : JsonTransformingSerializer<LibraryBundleDto>(LibraryBundleDto.serializer()) {

override fun transformDeserialize(element: JsonElement): JsonElement {
            val root =
                when (element) {
                    is JsonArray -> {
                        // If it's an array, assume it's a list of quizzes or questions
                        val first = element.firstOrNull()
                        if (first is JsonObject && ("questions" in first || "items" in first || "stem" in first || "question" in first)) {
                            // Probably a list of quizzes or questions
                            if (first.containsKey("stem") || first.containsKey("question")) {
                                // List of questions, wrap in a quiz then in a bundle
                                buildJsonObject {
                                    put(
                                        "quizzes",
                                        buildJsonArray {
                                            add(
                                                buildJsonObject {
                                                    put("title", "Imported Questions")
                                                    put("questions", element)
                                                },
                                            )
                                        },
                                    )
                                }
                            } else {
                                // List of quizzes, wrap in a bundle
                                buildJsonObject {
                                    put("quizzes", element)
                                }
                            }
                        } else {
                            // Unknown array, just wrap it as quizzes and hope for the best
                            buildJsonObject {
                                put("quizzes", element)
                            }
                        }
                    }
                    is JsonObject -> element
                    else -> return element
                }.toMutableMap()

            // Normalize top-level quizzes/quizes
            if ("quizes" in root && "quizzes" !in root) {
                root["quizes"]?.let { root["quizzes"] = it }
            }
            if ("bookList" in root && "books" !in root) {
                root["bookList"]?.let { root["books"] = it }
            }

            // Normalize books
            val books = root["books"]
            if (books is JsonArray) {
                root["books"] =
                    JsonArray(
                        books.map { book ->
                            if (book !is JsonObject) return@map book
                            val bMap = book.toMutableMap()
                            bMap["name"]?.let { if ("title" !in bMap) bMap["title"] = it }
                            JsonObject(bMap)
                        },
                    )
            }

            // If we have quizzes but no books, create a default book
            if ("quizzes" in root && ("books" !in root || (root["books"] as? JsonArray)?.isEmpty() == true)) {
                val bookId = java.util.UUID.randomUUID().toString()
                root["books"] =
                    buildJsonArray {
                        add(
                            buildJsonObject {
                                put("id", bookId)
                                put("title", "Default Book")
                            },
                        )
                    }
                // Ensure quizzes refer to this book and have unique IDs
                val quizzes = root["quizzes"]
                if (quizzes is JsonArray) {
                    root["quizzes"] =
                        JsonArray(
                            quizzes.map { quiz ->
                                if (quiz !is JsonObject) return@map quiz
                                val qMap = quiz.toMutableMap()
                                if ("id" !in qMap) qMap["id"] = JsonPrimitive(java.util.UUID.randomUUID().toString())
                                if ("bookId" !in qMap) qMap["bookId"] = JsonPrimitive(bookId)
                                JsonObject(qMap)
                            },
                        )
                }
            }

            // Normalize quizzes content
            val quizzes = root["quizzes"]
            if (quizzes is JsonArray) {
                root["quizzes"] =
                    JsonArray(
                        quizzes.map { quiz ->
                            if (quiz !is JsonObject) return@map quiz
                            val qMap = quiz.toMutableMap()

                            qMap["name"]?.let { if ("title" !in qMap) qMap["title"] = it }

                            // quizzes items -> questions
                            if ("items" in qMap && "questions" !in qMap) {
                                qMap["items"]?.let { qMap["questions"] = it }
                            }
                            if ("questionList" in qMap && "questions" !in qMap) {
                                qMap["questionList"]?.let { qMap["questions"] = it }
                            }

                            val questions = qMap["questions"]
                            if (questions is JsonArray) {
                                qMap["questions"] =
                                    JsonArray(
                                        questions.map { question ->
                                            if (question !is JsonObject) return@map question
                                            val questMap = question.toMutableMap()

                                            // stem aliases
                                            if ("stem" !in questMap) {
                                                questMap["question"]?.let { questMap["stem"] = it }
                                                    ?: questMap["text"]?.let { questMap["stem"] = it }
                                            }

                                            // options aliases: can be List<String> or List<JsonObject>
                                            var options = questMap["options"] ?: questMap["answers"] ?: questMap["choices"] ?: questMap["optionList"]
                                            if (options is JsonArray) {
                                                val firstOpt = options.firstOrNull()
                                                if (firstOpt is JsonPrimitive && firstOpt.isString) {
                                                    // List of strings, convert to OptionDto list
                                                    options =
                                                        JsonArray(
                                                            options.mapIndexed { idx, opt ->
                                                                buildJsonObject {
                                                                    put("id", "opt_$idx")
                                                                    put("text", opt)
                                                                }
                                                            },
                                                        )
                                                } else if (firstOpt is JsonObject) {
                                                    // Handle cases where options are objects but might use "value" or "content" instead of "text"
                                                    options =
                                                        JsonArray(
                                                            options.mapIndexed { idx, opt ->
                                                                val oMap = (opt as JsonObject).toMutableMap()
                                                                if ("id" !in oMap) oMap["id"] = JsonPrimitive("opt_$idx")
                                                                if ("text" !in oMap) {
                                                                    val textVal = oMap["text"] ?: oMap["value"] ?: oMap["content"] ?: oMap["answer"] ?: JsonPrimitive("")
                                                                    oMap["text"] = textVal
                                                                }
                                                                JsonObject(oMap)
                                                            },
                                                        )
                                                }
                                                questMap["options"] = options
                                            }

                                            // correct aliases: can be List<Int> (indices) or List<String> (IDs)
                                            var correct = questMap["correct"] ?: questMap["answer"] ?: questMap["correctAnswers"] ?: questMap["solution"] ?: questMap["correct_index"]
                                            if (correct is JsonPrimitive) {
                                                correct = JsonArray(listOf(correct))
                                            }

                                            if (correct is JsonArray && options is JsonArray) {
                                                questMap["correct"] =
                                                    JsonArray(
                                                        correct.map { c ->
                                                            if (c is JsonPrimitive && !c.isString) {
                                                                // Index-based, convert to ID
                                                                val idx = c.content.toIntOrNull() ?: -1
                                                                if (idx != -1) JsonPrimitive("opt_$idx") else c
                                                            } else if (c is JsonPrimitive && c.isString) {
                                                                // If it's a string, it might be the actual text of the answer or an ID
                                                                // If it matches an opt_X pattern or an ID in options, keep it.
                                                                // Otherwise, try to find the option with matching text.
                                                                val cStr = c.content
                                                                val matchingOpt =
                                                                    options.filterIsInstance<JsonObject>().find {
                                                                        it["id"]?.jsonPrimitive?.content == cStr || it["text"]?.jsonPrimitive?.content == cStr
                                                                    }
                                                                matchingOpt?.get("id") ?: c
                                                            } else {
                                                                c
                                                            }
                                                        },
                                                    )
                                            }

                                            // explanation, hint, reference aliases
                                            if ("explanation" !in questMap) {
                                                questMap["explanation"] = questMap["rational"] ?: questMap["feedback"] ?: questMap["comment"] ?: JsonPrimitive("")
                                            }
                                            if ("imageDataUrl" !in questMap) {
                                                questMap["imageDataUrl"] = questMap["image"] ?: questMap["imageUrl"] ?: questMap["photo"] ?: questMap["img"] ?: JsonPrimitive("")
                                            }

                                            JsonObject(questMap)
                                        },
                                    )
                            }
                            JsonObject(qMap)
                        },
                    )
            }

            return JsonObject(root)
        }
    }

    open fun parse(jsonString: String): LibraryBundleDto {
        return json.decodeFromString(LibraryTransformingSerializer, jsonString)
    }

fun parse(inputStream: InputStream): LibraryBundleDto {
        val jsonString = inputStream.readTextWithLimit(ImportLimits.MAX_TEXT_IMPORT_BYTES)
        return parse(jsonString)
    }
}

fun parse(
        text: String,
        deckId: Long,
        startIndex: Int = 0,
        mode: TextParseMode = TextParseMode.ALTERNATING_PARAGRAPHS,
    ): List<FlashcardEntity> {
        val result = mutableListOf<FlashcardEntity>()

        val paragraphs = text.split(Regex("\\n\\s*\\n")).map { it.trim() }.filter { it.isNotEmpty() }
        var order = startIndex

        if (mode == TextParseMode.ALTERNATING_PARAGRAPHS) {
            var i = 0
            while (i < paragraphs.size) {
                val frontParagraph = paragraphs[i]
                var backParagraph = ""
                if (i + 1 < paragraphs.size) {
                    backParagraph = paragraphs[i + 1]
                    i += 2
                } else {
                    break
                }

                val frontClean = frontParagraph.replace(Regex("^(Front|Q|Question):\\s*", RegexOption.IGNORE_CASE), "").trim()
                val backClean = backParagraph.replace(Regex("^(Back|A|Answer):\\s*", RegexOption.IGNORE_CASE), "").trim()

                result.add(
                    FlashcardEntity(
                        externalId = UUID.randomUUID().toString(),
                        deckId = deckId,
                        frontText = frontClean,
                        backText = backClean,
                        orderIndex = order++,
                    ),
                )
            }
        } else {
            // Explicit Labels Mode
            val frontRegex = Regex("(?m)^\\s*(?:Front|Q|Question):\\s*", RegexOption.IGNORE_CASE)
            val frontMatches = frontRegex.findAll(text).toList()

            if (frontMatches.isEmpty()) {
                // Fallback: if no labels at all, just treat the whole text as one card
                val parts = text.split(Regex("(?m)^\\s*(?:Back|A|Answer):\\s*", RegexOption.IGNORE_CASE), limit = 2)
                if (parts.size == 2) {
                    result.add(
                        FlashcardEntity(
                            externalId = UUID.randomUUID().toString(),
                            deckId = deckId,
                            frontText = parts[0].trim(),
                            backText = parts[1].trim(),
                            orderIndex = order++,
                        ),
                    )
                } else {
                    result.add(
                        FlashcardEntity(
                            externalId = UUID.randomUUID().toString(),
                            deckId = deckId,
                            frontText = text.trim(),
                            backText = "",
                            orderIndex = order++,
                        ),
                    )
                }
            } else {
                for (i in frontMatches.indices) {
                    val match = frontMatches[i]
                    val startIndex = match.range.last + 1
                    val endIndex = if (i + 1 < frontMatches.size) frontMatches[i + 1].range.first else text.length

                    val block = text.substring(startIndex, endIndex).trim()
                    if (block.isEmpty()) continue

                    val parts = block.split(Regex("(?m)^\\s*(?:Back|A|Answer):\\s*", RegexOption.IGNORE_CASE), limit = 2)

                    if (parts.size == 2) {
                        result.add(
                            FlashcardEntity(
                                externalId = UUID.randomUUID().toString(),
                                deckId = deckId,
                                frontText = parts[0].trim(),
                                backText = parts[1].trim(),
                                orderIndex = order++,
                            ),
                        )
                    } else {
                        result.add(
                            FlashcardEntity(
                                externalId = UUID.randomUUID().toString(),
                                deckId = deckId,
                                frontText = block.trim(),
                                backText = "",
                                orderIndex = order++,
                            ),
                        )
                    }
                }
            }
        }
        return result
    }
}

suspend fun parse(
        context: Context,
        uri: Uri,
        courseId: Long,
        startIndex: Int = 0,
    ): List<CourseSlideEntity> {
        return withContext(Dispatchers.IO) {
            val result = mutableListOf<CourseSlideEntity>()
            context.contentResolver.openInputStream(uri)?.use { inputStream ->
                val ppt = XMLSlideShow(inputStream)
                var order = startIndex
                val now = System.currentTimeMillis()

                for (slide in ppt.slides) {
                    val title = slide.title ?: ""

                    // Extract text from text shapes, excluding the title shape
                    val bodyParts = mutableListOf<String>()
                    for (shape in slide.shapes) {
                        if (shape is org.apache.poi.xslf.usermodel.XSLFTextShape) {
                            // POI has placeholder checking
                            if (shape.textType != org.apache.poi.sl.usermodel.Placeholder.TITLE &&
                                shape.textType != org.apache.poi.sl.usermodel.Placeholder.CENTERED_TITLE
                            ) {
                                val text = shape.text?.trim()
                                if (!text.isNullOrEmpty()) {
                                    bodyParts.add(text)
                                }
                            }
                        }
                    }
                    val body = bodyParts.joinToString("\n\n").trim()

                    // Extract notes
                    val notesSlide = slide.notes
                    val notesParts = mutableListOf<String>()
                    if (notesSlide != null) {
                        for (shape in notesSlide.shapes) {
                            if (shape is org.apache.poi.xslf.usermodel.XSLFTextShape) {
                                // Exclude header/footer placeholders typically on notes
                                if (shape.textType == org.apache.poi.sl.usermodel.Placeholder.BODY) {
                                    val text = shape.text?.trim()
                                    if (!text.isNullOrEmpty()) {
                                        notesParts.add(text)
                                    }
                                }
                            }
                        }
                    }
                    val notes = notesParts.joinToString("\n\n").trim().takeIf { it.isNotEmpty() }

                    // We add a slide even if it's empty to preserve structure
                    result.add(
                        CourseSlideEntity(
                            externalId = UUID.randomUUID().toString(),
                            courseId = courseId,
                            title = title,
                            body = body,
                            speakerNotes = notes,
                            orderIndex = order++,
                            createdAt = now,
                            updatedAt = now,
                        ),
                    )
                }
            }
            result
        }
    }
}

fun parse(
        text: String,
        collectionId: Long,
        mode: TextArticleParseMode = TextArticleParseMode.BASIC,
        defaultMode: String = "SIMPLE_NOTE",
    ): List<NoteBlueprintEntity> {
        val result = mutableListOf<NoteBlueprintEntity>()

        if (mode == TextArticleParseMode.BASIC) {
            // Split by double newline to treat blocks as separate articles
            val articlesText = text.split(Regex("(?m)^---$")).map { it.trim() }.filter { it.isNotEmpty() }

            for (articleText in articlesText) {
                val paragraphs = articleText.split(Regex("\\n\\s*\\n")).map { it.trim() }.filter { it.isNotEmpty() }

                if (paragraphs.isEmpty()) continue

                val title = paragraphs[0]
                val summary = if (paragraphs.size > 1) paragraphs[1] else null
                val body = if (paragraphs.size > 2) paragraphs.drop(2).joinToString("\n\n") else ""

                result.add(
                    NoteBlueprintEntity(
                        externalId = UUID.randomUUID().toString(),
                        collectionId = collectionId,
                        title = title,
                        summary = summary,
                        body = body,
                        blueprintMode = defaultMode,
                    ),
                )
            }
        } else {
            // Explicit Labels Mode
            // Articles are separated by "---"
            val articlesText = text.split(Regex("(?m)^---$")).map { it.trim() }.filter { it.isNotEmpty() }

            for (articleText in articlesText) {
                val titleMatch =
                    Regex(
                        "^(?:Title):\\s*(.*?)(?:\\n(?:Summary|Body|Bullet|Tag):|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(articleText)
                val summaryMatch =
                    Regex(
                        "\\n(?:Summary):\\s*(.*?)(?:\\n(?:Title|Body|Bullet|Tag):|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(articleText)
                val bodyMatch =
                    Regex(
                        "\\n(?:Body):\\s*(.*?)(?:\\n(?:Title|Summary|Bullet|Tag):|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(articleText)

                val bulletMatches = Regex("\\n(?:Bullet):\\s*(.*?)(?:\\n|$)", setOf(RegexOption.IGNORE_CASE)).findAll(articleText)
                val bullets = bulletMatches.map { it.groupValues[1].trim() }.toList()

                val tagMatches = Regex("\\n(?:Tag):\\s*(.*?)(?:\\n|$)", setOf(RegexOption.IGNORE_CASE)).findAll(articleText)
                val tags = tagMatches.map { it.groupValues[1].trim() }.toList()

                if (titleMatch != null) {
                    result.add(
                        NoteBlueprintEntity(
                            externalId = UUID.randomUUID().toString(),
                            collectionId = collectionId,
                            title = titleMatch.groupValues.getOrNull(1)?.trim() ?: "Untitled",
                            summary = summaryMatch?.groupValues?.getOrNull(1)?.trim(),
                            body = bodyMatch?.groupValues?.getOrNull(1)?.trim() ?: "",
                            bulletPoints = bullets,
                            tags = tags,
                            blueprintMode = defaultMode,
                        ),
                    )
                } else {
                    // Fallback
                    result.add(
                        NoteBlueprintEntity(
                            externalId = UUID.randomUUID().toString(),
                            collectionId = collectionId,
                            title = articleText.take(50).trim() + "...",
                            body = articleText.trim(),
                            blueprintMode = defaultMode,
                        ),
                    )
                }
            }
        }
        return result
    }
}

fun parse(
        content: String,
        delimiter: Char? = null,
    ): List<List<String>> {
        if (content.isBlank()) return emptyList()

        val sep = delimiter ?: inferDelimiter(content)
        val result = mutableListOf<List<String>>()
        val currentLine = mutableListOf<String>()
        val currentValue = StringBuilder()

        var inQuotes = false
        var justClosedQuote = false
        var i = 0

        while (i < content.length) {
            val char = content[i]

            when {
                char == '"' -> {
                    if (inQuotes && i + 1 < content.length && content[i + 1] == '"') {
                        // Escaped quote
                        currentValue.append('"')
                        i++
                    } else if (inQuotes) {
                        // Close a quoted field. We only honor quotes as structural
                        // when they appear at field boundaries.
                        inQuotes = false
                        justClosedQuote = true
                    } else if (isAtQuotedFieldStart(currentValue)) {
                        // Discard leading whitespace before an opening quote.
                        currentValue.setLength(0)
                        inQuotes = true
                        justClosedQuote = false
                    } else {
                        // Treat misplaced quotes as literal content.
                        currentValue.append(char)
                        justClosedQuote = false
                    }
                }
                char == sep && !inQuotes -> {
                    currentLine.add(currentValue.toString().trim())
                    currentValue.setLength(0)
                    justClosedQuote = false
                }
                (char == '\n' || char == '\r') && !inQuotes -> {
                    if (char == '\r' && i + 1 < content.length && content[i + 1] == '\n') {
                        i++
                    }
                    currentLine.add(currentValue.toString().trim())
                    if (currentLine.any { it.isNotEmpty() }) {
                        result.add(ArrayList(currentLine))
                    }
                    currentLine.clear()
                    currentValue.setLength(0)
                    justClosedQuote = false
                }
                else -> {
                    if (justClosedQuote) {
                        if (char.isWhitespace()) {
                            // Ignore trailing whitespace between a closing quote and a delimiter/newline.
                        } else {
                            // The quote was misplaced after all, so preserve it as data.
                            currentValue.append('"')
                            currentValue.append(char)
                        }
                        justClosedQuote = false
                    } else {
                        currentValue.append(char)
                    }
                }
            }
            i++
        }

        // Handle last value and line if not ended with newline
        if (currentValue.isNotEmpty() || currentLine.isNotEmpty()) {
            currentLine.add(currentValue.toString().trim())
            if (currentLine.any { it.isNotEmpty() }) {
                result.add(ArrayList(currentLine))
            }
        }

        return result
    }

private fun inferDelimiter(content: String): Char {
        val testDelimiters = listOf(',', '\t', ';')
        val lines = content.lineSequence().filter { it.isNotBlank() }.toList()

        if (lines.isEmpty()) return ','

        return testDelimiters
            .map { delimiter -> buildDelimiterScore(delimiter, lines.map { line -> countFields(line, delimiter) }) }
            .maxWithOrNull(
                compareBy<DelimiterScore> { it.supportingRows }
                    .thenBy { it.modeFrequency }
                    .thenBy { it.modeFieldCount }
                    .thenByDescending { it.varianceScore },
            )?.delimiter ?: ','
    }

private fun countFields(
        line: String,
        delimiter: Char,
    ): Int {
        var count = 1
        var inQuotes = false
        var justClosedQuote = false
        val currentField = StringBuilder()
        var i = 0
        while (i < line.length) {
            val c = line[i]
            if (c == '"') {
                if (inQuotes && i + 1 < line.length && line[i + 1] == '"') {
                    i++
                } else if (inQuotes) {
                    inQuotes = false
                    justClosedQuote = true
                } else if (isAtQuotedFieldStart(currentField)) {
                    inQuotes = true
                    currentField.setLength(0)
                } else {
                    // Misplaced quotes are treated as literal content.
                    currentField.append(c)
                }
            } else if (c == delimiter && !inQuotes) {
                count++
                currentField.setLength(0)
                justClosedQuote = false
            } else if (justClosedQuote) {
                if (c.isWhitespace()) {
                    // Ignore trailing whitespace before the delimiter/newline.
                } else {
                    currentField.append('"')
                    currentField.append(c)
                }
                justClosedQuote = false
            } else {
                currentField.append(c)
            }
            i++
        }
        return count
    }

private fun isAtQuotedFieldStart(currentValue: CharSequence): Boolean {
        return currentValue.isEmpty() || currentValue.all { it.isWhitespace() }
    }

private fun buildDelimiterScore(
        delimiter: Char,
        counts: List<Int>,
    ): DelimiterScore {
        val supportingCounts = counts.filter { it > 1 }
        if (supportingCounts.isEmpty()) {
            return DelimiterScore(
                delimiter = delimiter,
                supportingRows = 0,
                modeFrequency = 0,
                modeFieldCount = 0,
                varianceScore = Double.NEGATIVE_INFINITY,
            )
        }

        val grouped = supportingCounts.groupingBy { it }.eachCount()
        val modeFieldCount =
            grouped.maxWithOrNull(
                compareBy<Map.Entry<Int, Int>> { it.value }.thenBy { it.key },
            )?.key ?: 0
        val modeFrequency = grouped[modeFieldCount] ?: 0
        val avg = supportingCounts.average()
        val variance = supportingCounts.map { (it - avg) * (it - avg) }.sum() / supportingCounts.size

        return DelimiterScore(
            delimiter = delimiter,
            supportingRows = supportingCounts.size,
            modeFrequency = modeFrequency,
            modeFieldCount = modeFieldCount,
            varianceScore = -variance,
        )
    }

    private data class DelimiterScore(
        val delimiter: Char,
        val supportingRows: Int,
        val modeFrequency: Int,
        val modeFieldCount: Int,
        val varianceScore: Double,
    )
}

fun detectMode(
        fileName: String?,
        content: String?,
    ): ImportMode {
        val ext = fileName?.substringAfterLast('.')?.lowercase() ?: ""

        if (ext in listOf("xlsx", "xls", "csv", "tsv")) {
            return ImportMode.SPREADSHEET
        }

        if (ext == "json") return ImportMode.JSON
        if (ext in listOf("html", "htm")) return ImportMode.HTML

        val trimmed = content?.trim() ?: ""
        if (trimmed.startsWith("[") || (trimmed.startsWith("{") && trimmed.contains("\"kind\""))) {
            return ImportMode.JSON
        }

        if (trimmed.contains("<html", ignoreCase = true) ||
            trimmed.contains("<script", ignoreCase = true) ||
            trimmed.contains("<img", ignoreCase = true)
        ) {
            return ImportMode.HTML
        }

        // Guess spreadsheet if it looks like CSV/TSV and has keywords
        if (isTabular(trimmed)) {
            return ImportMode.SPREADSHEET
        }

        return ImportMode.TEXT
    }

private fun isTabular(content: String): Boolean {
        val lines = content.lines().take(5)
        if (lines.isEmpty()) return false

        val commonSeparators = listOf('\t', ',', ';')
        for (sep in commonSeparators) {
            val counts = lines.map { it.count { char -> char == sep } }
            if (counts.all { it > 0 } && counts.distinct().size <= 2) {
                // Check for keywords in the first row
                val header = lines.first().lowercase()
                val keywords = listOf("question", "answer", "correct", "stem", "السؤال", "الإجابة")
                if (keywords.any { header.contains(it) }) return true
            }
        }
        return false
    }
}

fun extractFromText(text: String?): ResolvedImage? {
        val raw = text?.trim() ?: return null
        if (raw.isEmpty()) return null

        // 1. Data URL
        val dataUrlMatch =
            Regex("""(data:image/[a-zA-Z0-9.+-]+;base64,[A-Za-z0-9+/=\s]+)""", RegexOption.IGNORE_CASE)
                .find(raw)
        if (dataUrlMatch != null) {
            return ResolvedImage(imageDataUrl = dataUrlMatch.groupValues[1].replace(Regex("""\s+"""), ""), via = "direct-data-url")
        }

        // 2. HTTP/HTTPS URL
        val urlMatch =
            Regex(
                """(https?://[^\s"'<>]+\.(?:png|jpe?g|gif|webp|svg|bmp|tiff?|avif|ico|pdf|png|jpg|jpeg)(?:[?#][^\s"'<>]*)|https?://[^\s"'<>]+)""",
                RegexOption.IGNORE_CASE,
            )
                .find(raw)
        if (urlMatch != null) {
            return ResolvedImage(imageSource = urlMatch.groupValues[1], via = "direct-url")
        }

        // 3. HTML img tag
        val imgMatch =
            Regex("""<img[^>]+src=["']([^"']+)["']""", RegexOption.IGNORE_CASE)
                .find(raw)
        if (imgMatch != null) {
            val src = imgMatch.groupValues[1]
            return if (src.startsWith(
                    "data:",
                )
            ) {
                ResolvedImage(imageDataUrl = src, via = "html-img")
            } else {
                ResolvedImage(imageSource = src, via = "html-img")
            }
        }

        // 4. Markdown syntax
        val mdMatch =
            Regex("""!\[[^\]]*\]\(([^)]+)\)""")
                .find(raw)
        if (mdMatch != null) {
            val src = mdMatch.groupValues[1]
            return if (src.startsWith(
                    "data:",
                )
            ) {
                ResolvedImage(imageDataUrl = src, via = "markdown-img")
            } else {
                ResolvedImage(imageSource = src, via = "markdown-img")
            }
        }

        return null
    }

fun extractFromFields(text: String?): ResolvedImage? {
        val raw = text ?: return null
        val lines = raw.lines()
        val prefixes = listOf("image:", "image url:", "img:", "picture:", "media:", "image source:", "صورة:", "رابط الصورة:")

        for (line in lines) {
            val trimmed = line.trim()
            for (prefix in prefixes) {
                if (trimmed.startsWith(prefix, ignoreCase = true)) {
                    val value = trimmed.substring(prefix.length).trim()
                    return extractFromText(value) ?: ResolvedImage(imageSource = value, via = "field-match")
                }
            }
        }
        return null
    }
}

fun parse(
        text: String,
        courseId: Long,
        startIndex: Int = 0,
        mode: TextParseMode = TextParseMode.ALTERNATING_PARAGRAPHS,
    ): List<CourseSlideEntity> {
        val result = mutableListOf<CourseSlideEntity>()

        val paragraphs = text.split(Regex("\\n\\s*\\n")).map { it.trim() }.filter { it.isNotEmpty() }
        var order = startIndex

        val now = System.currentTimeMillis()

        if (mode == TextParseMode.ALTERNATING_PARAGRAPHS) {
            var i = 0
            while (i < paragraphs.size) {
                val titleParagraph = paragraphs[i]
                var bodyParagraph = ""
                if (i + 1 < paragraphs.size) {
                    bodyParagraph = paragraphs[i + 1]
                    i += 2
                } else {
                    break
                }

                val titleClean = titleParagraph.replace(Regex("^(Title|Front|Q|Question):\\s*", RegexOption.IGNORE_CASE), "").trim()
                val bodyClean = bodyParagraph.replace(Regex("^(Body|Back|A|Answer):\\s*", RegexOption.IGNORE_CASE), "").trim()

                result.add(
                    CourseSlideEntity(
                        externalId = UUID.randomUUID().toString(),
                        courseId = courseId,
                        title = titleClean,
                        body = bodyClean,
                        orderIndex = order++,
                        createdAt = now,
                        updatedAt = now,
                    ),
                )
            }
        } else if (mode == TextParseMode.EXPLICIT_LABELS) {
            // Explicit Labels Mode
            for (paragraph in paragraphs) {
                val titleMatch =
                    Regex(
                        "^(?:Title|Front|Q|Question):\\s*(.*?)(?:\\n(?:Body|Back|A|Answer):|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(paragraph)
                val bodyMatch =
                    Regex(
                        "\\n(?:Body|Back|A|Answer):\\s*(.*)$",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(paragraph)

                if (titleMatch != null && bodyMatch != null) {
                    result.add(
                        CourseSlideEntity(
                            externalId = UUID.randomUUID().toString(),
                            courseId = courseId,
                            title = titleMatch.groupValues.getOrNull(1)?.trim() ?: "",
                            body = bodyMatch.groupValues.getOrNull(1)?.trim() ?: "",
                            orderIndex = order++,
                            createdAt = now,
                            updatedAt = now,
                        ),
                    )
                } else {
                    // Fallback
                    result.add(
                        CourseSlideEntity(
                            externalId = UUID.randomUUID().toString(),
                            courseId = courseId,
                            title = paragraph.trim(),
                            body = "",
                            orderIndex = order++,
                            createdAt = now,
                            updatedAt = now,
                        ),
                    )
                }
            }
        } else if (mode == TextParseMode.HEADER_BODY_NOTES) {
            val slideBlocks = text.split(Regex("(?m)^---$|^#\\s+")).map { it.trim() }.filter { it.isNotEmpty() }
            for (block in slideBlocks) {
                val lines = block.lines()
                var title = ""
                var body = ""
                var notes: String? = null

                val headerMatch =
                    Regex(
                        "^(?:Header|Title|Front|Q|Question):\\s*(.*?)(?:\\n(?:Body|Back|A|Answer|Notes):|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(block)
                val bodyMatch =
                    Regex(
                        "\\n(?:Body|Back|A|Answer):\\s*(.*?)(?:\\nNotes:|$)",
                        setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL),
                    ).find(block)
                val notesMatch = Regex("\\nNotes:\\s*(.*)$", setOf(RegexOption.IGNORE_CASE, RegexOption.DOT_MATCHES_ALL)).find(block)

                if (headerMatch != null || bodyMatch != null || notesMatch != null) {
                    title = headerMatch?.groupValues?.getOrNull(1)?.trim() ?: ""
                    body = bodyMatch?.groupValues?.getOrNull(1)?.trim() ?: ""
                    notes = notesMatch?.groupValues?.getOrNull(1)?.trim()
                } else {
                    title = lines.firstOrNull()?.removePrefix("#")?.trim() ?: ""
                    val remainingLines = lines.drop(1)
                    val bodyLines = mutableListOf<String>()
                    val notesLines = mutableListOf<String>()
                    for (line in remainingLines) {
                        if (line.trim().startsWith(">")) {
                            notesLines.add(line.trim().removePrefix(">").trim())
                        } else {
                            bodyLines.add(line)
                        }
                    }
                    body = bodyLines.joinToString("\n").trim()
                    notes = if (notesLines.isNotEmpty()) notesLines.joinToString("\n").trim() else null
                }

                result.add(
                    CourseSlideEntity(
                        externalId = UUID.randomUUID().toString(),
                        courseId = courseId,
                        title = title,
                        body = body,
                        speakerNotes = notes,
                        orderIndex = order++,
                        createdAt = now,
                        updatedAt = now,
                    ),
                )
            }
        }
        return result
    }
}

class SpreadsheetQuestionParser(
    private val mapping: Map<String, Int>,
    private val optionCols: List<Int>,
    private val sheetAddressImages: Map<String, String>,
    private val sheetRowImages: Map<Int, String>,
    private val imageExtractor: GenericImageExtractor,
) {
    companion object {
        private val CATEGORY_DELIMITER = Regex("""[,،;؛/|]+""")
        private val MARKED_REGEX = Regex("""[*✓✔☑]""")
        private val DISPIMG_REGEX =
            Regex(
                """(?:_xlfn\.)?DISPIMG\([^)]*\)""",
                RegexOption.IGNORE_CASE,
            )
        private val WHITESPACE_REGEX = Regex("""\s+""")
        private val NORMALIZED_KEY_REGEX = Regex("[^A-Z0-9,;|\\s]")
        private val PART_DELIMITER_REGEX = Regex("[,;|\\s]+")
    }

fun parseRow(
        row: List<String>,
        rowNumberOneBased: Int,
    ): ParsedQuestion? {
        val stem = cleanCellText(get(row, "question"))
        val externalId = cleanCellText(get(row, "id")).ifBlank { null }
        val answerRaw = cleanCellText(get(row, "answer"))

        val options =
            optionCols.mapIndexedNotNull { index, colIdx ->
                val cell = cleanCellText(row.getOrNull(colIdx))
                if (cell.isBlank()) {
                    null
                } else {
                    ParsedOption(
                        id = generateOptionId(index),
                        text = cell,
                        marked = isMarked(cell),
                    )
                }
            }

        val resolvedCorrectAnswers = resolveCorrectAnswers(answerRaw, options)
        val questionColIdx = mapping["question"] ?: -1
        val imageColIdx = mapping["image"] ?: -1
        val resolvedImage = resolveImage(row, rowNumberOneBased, questionColIdx, imageColIdx, optionCols)

        val categories =
            cleanCellText(get(row, "categories"))
                .split(CATEGORY_DELIMITER)
                .map { it.trim() }
                .filter { it.isNotEmpty() }
                .distinct()
                .ifEmpty { listOf("none") }

        val type = if (resolvedCorrectAnswers.size > 1) QuestionType.MULTIPLE_CHOICE else QuestionType.SINGLE_CHOICE

        if (stem.isBlank() && options.isEmpty() && resolvedImage.imageDataUrl.isNullOrBlank() && resolvedImage.imageSource.isNullOrBlank()) {
            return null
        }

        val issues = mutableListOf<String>()
        if (options.isEmpty()) issues.add("No options found")
        if (resolvedCorrectAnswers.isEmpty() && options.isNotEmpty()) issues.add("No correct answer identified")

        return ParsedQuestion(
            stem = stem,
            externalId = externalId,
            options = options,
            correctAnswers = resolvedCorrectAnswers,
            explanation = cleanCellText(get(row, "explanation")).ifBlank { null },
            hint = cleanCellText(get(row, "hint")).ifBlank { null },
            reference = cleanCellText(get(row, "reference")).ifBlank { null },
            additionalInfo = cleanCellText(get(row, "additional")).ifBlank { null },
            categories = categories,
            imageDataUrl = resolvedImage.imageDataUrl,
            imageSource = resolvedImage.imageSource,
            derivedFlags = listOfNotNull(resolvedImage.via?.let { "Image resolved via $it" }),
            sourceLine = rowNumberOneBased,
            type = type,
            issues = issues,
            answerMode = if (type == QuestionType.MULTIPLE_CHOICE) "multiple" else "single",
            isIncluded = true,
        )
    }

private fun generateOptionId(index: Int): String {
        return "opt_$index"
    }

private fun resolveImage(
        row: List<String>,
        rowNumber: Int,
        qIdx: Int,
        imgIdx: Int,
        optIdxs: List<Int>,
    ): ResolvedImage {
        if (imgIdx != -1) {
            resolveFromCell(row.getOrNull(imgIdx), cellRef(imgIdx, rowNumber), rowNumber)?.let { return it }
        }
        if (qIdx != -1) {
            resolveFromCell(row.getOrNull(qIdx), cellRef(qIdx, rowNumber), rowNumber)?.let { return it }
        }
        for (idx in optIdxs) {
            resolveFromCell(row.getOrNull(idx), cellRef(idx, rowNumber), rowNumber)?.let { return it }
        }
        val rowFallback = sheetRowImages[rowNumber]
        return if (!rowFallback.isNullOrBlank()) {
            ResolvedImage(imageDataUrl = rowFallback, via = "row-fallback")
        } else {
            ResolvedImage()
        }
    }

private fun resolveFromCell(
        value: String?,
        ref: String,
        rowNum: Int,
    ): ResolvedImage? {
        imageExtractor.extractFromText(value)?.let { return it }
        sheetAddressImages[ref]?.takeIf { it.isNotBlank() }?.let {
            return ResolvedImage(imageDataUrl = it, via = "exact-cell")
        }
        return sheetRowImages[rowNum]?.takeIf { it.isNotBlank() }?.let {
            ResolvedImage(imageDataUrl = it, via = "row-fallback")
        }
    }

private fun get(
        row: List<String>,
        field: String,
    ): String? {
        val idx = mapping[field] ?: return null
        return row.getOrNull(idx)
    }

private fun cellRef(
        colIdx: Int,
        rowNum: Int,
    ): String {
        var n = colIdx + 1
        var letters = ""
        while (n > 0) {
            val rem = (n - 1) % 26
            letters = (65 + rem).toChar() + letters
            n = (n - 1) / 26
        }
        return letters + rowNum
    }

private fun resolveCorrectAnswers(
        answerRaw: String,
        options: List<ParsedOption>,
    ): List<String> {
        val indices = linkedSetOf<String>()
        val normalizedKey = answerRaw.uppercase().replace(NORMALIZED_KEY_REGEX, " ")
        val parts = normalizedKey.split(PART_DELIMITER_REGEX).filter { it.isNotEmpty() }

        parts.forEach { part ->
            // Check for A-Z
            if (part.length == 1 && part[0] in 'A'..'Z') {
                val index = part[0] - 'A'
                if (index in options.indices) indices.add(options[index].id)
            }
            // Check for multi-char string of letters like "ABC"
            else if (part.all { it in 'A'..'Z' } && part.length > 1 && part.length <= options.size) {
                part.forEach { char ->
                    val index = char - 'A'
                    if (index in options.indices) indices.add(options[index].id)
                }
            }
            // Check for numeric 1-26
            else {
                val numericIndex = part.toIntOrNull()?.minus(1)
                if (numericIndex != null && numericIndex in options.indices) {
                    indices.add(options[numericIndex].id)
                } else {
                    // Direct text match
                    val directIndex =
                        options.indexOfFirst { option ->
                            option.text.trim().equals(part.trim(), ignoreCase = true)
                        }
                    if (directIndex != -1) indices.add(options[directIndex].id)
                }
            }
        }

        // Direct text match fallback
        if (indices.isEmpty() && answerRaw.isNotBlank()) {
            val directIndex =
                options.indexOfFirst { option ->
                    option.text.trim().equals(answerRaw.trim(), ignoreCase = true)
                }
            if (directIndex != -1) indices.add(options[directIndex].id)
        }

        // Only include marked options if no explicit answers were found
        if (indices.isEmpty()) {
            options.forEach { option ->
                if (option.marked) indices.add(option.id)
            }
        }

        return indices.toList().sorted()
    }
}

class HtmlQuestionParser(
    private val jsonParser: JsonQuestionParser,
) {

fun parse(text: String): List<ParsedQuestion> {
        val patterns =
            listOf(
                Regex("""id=["']quiz-data["'][^>]*>([\s\S]*?)<\/script>""", RegexOption.IGNORE_CASE),
                Regex("""window\.__QUIZ__\s*=\s*(\[[\s\S]*?\]|\{[\s\S]*?\});?""", RegexOption.IGNORE_CASE),
                Regex("""window\.QUIZ_DATA\s*=\s*(\[[\s\S]*?\]|\{[\s\S]*?\});?""", RegexOption.IGNORE_CASE),
                Regex("""const\s+allData\s*=\s*(\[[\s\S]*?\]);""", RegexOption.IGNORE_CASE),
            )

        for (pattern in patterns) {
            val match = pattern.find(text)
            if (match != null && match.groupValues.size > 1) {
                try {
                    return jsonParser.parse(match.groupValues[1])
                } catch (e: Exception) {
                    // Continue to next pattern
                }
            }
        }

        throw Exception("No embedded quiz JSON found in the HTML.")
    }
}

fun calculateRowScore(headerRow: List<String>): Int {
        if (headerRow.isEmpty()) return -100

        var score = 0
        val mapped = mapHeaders(headerRow)

        for ((field, idx) in mapped) {
            val weight = fieldWeights[field] ?: 0
            val cellValue = headerRow.getOrNull(idx) ?: ""

            // Penalty for long text in header cells (headers are usually < 6 words)
            if (cellValue.split(Regex("\\s+")).size > 6) {
                score -= 100
            } else {
                score += weight
            }
        }

        val options = guessOptionColumns(headerRow, mapped)
        score += (options.size * 20).coerceAtMost(120)

        // Penalty for empty rows
        if (headerRow.all { it.isBlank() }) score -= 200

        // Penalty for mostly numeric rows (likely data, not headers)
        val numericCount = headerRow.count { it.isNotBlank() && it.all { c -> (c.isDigit() || c == '.') } }
        if (numericCount > headerRow.size / 2) score -= 40

        return score
    }

fun mapHeaders(headerRow: List<String>): Map<String, Int> {
        val result = mutableMapOf<String, Int>()
        val usedCols = mutableSetOf<Int>()

        // Sort fields by weight so we map Question/Answer first
        val sortedFields = aliases.keys.sortedByDescending { fieldWeights[it] ?: 0 }

        for (field in sortedFields) {
            val aliasList = aliases[field] ?: continue

            // 1. Try Exact match first
            var foundIdx =
                headerRow.indexOfFirst { cell ->
                    if (headerRow.indexOf(cell) in usedCols) return@indexOfFirst false
                    val normalizedCell = normalize(cell)
                    aliasList.any { alias -> normalizedCell == normalize(alias) }
                }

            // 2. Try Word match for longer aliases
            if (foundIdx == -1) {
                foundIdx =
                    headerRow.indexOfFirst { cell ->
                        if (headerRow.indexOf(cell) in usedCols) return@indexOfFirst false
                        val normalizedCell = normalize(cell)
                        aliasList.any { alias ->
                            val normAlias = normalize(alias)
                            if (normAlias.length < 3) return@any false
                            // Use unicode-aware word boundaries or manual checks
                            val pattern = "(^|[^\\p{L}\\p{N}])${Regex.escape(normAlias)}($|[^\\p{L}\\p{N}])"
                            Regex(pattern, RegexOption.IGNORE_CASE).containsMatchIn(normalizedCell)
                        }
                    }
            }

            // 3. Try fallback substring for very specific aliases
            if (foundIdx == -1) {
                foundIdx =
                    headerRow.indexOfFirst { cell ->
                        if (headerRow.indexOf(cell) in usedCols) return@indexOfFirst false
                        val normalizedCell = normalize(cell)
                        aliasList.any { alias ->
                            val normAlias = normalize(alias)
                            if (normAlias.length < 5) return@any false
                            normalizedCell.contains(normAlias)
                        }
                    }
            }

            if (foundIdx != -1) {
                result[field] = foundIdx
                usedCols.add(foundIdx)
            }
        }
        return result
    }

fun guessOptionColumns(
        headerRow: List<String>,
        mapped: Map<String, Int>,
    ): List<Int> {
        val options = mutableListOf<Int>()
        val mappedCols = mapped.values.toSet()

        headerRow.forEachIndexed { index, cell ->
            if (index in mappedCols) return@forEachIndexed
            val norm = normalize(cell)
            if (norm.isBlank()) return@forEachIndexed

            // 1. Matches predefined aliases (A, B, C..., Arabic...)
            val isAliasMatch = optionAliases.any { list -> list.any { alias -> norm == normalize(alias) } }

            // 2. Matches "Option 1", "Opt 1", "1", etc.
            val isNumericOption =
                Regex("""^(option|opt|choice|answer option|mcq|ans|q|خيار|الخيار)\s*\d+$""", RegexOption.IGNORE_CASE).containsMatchIn(norm) ||
                    Regex("""^\d+$""").matches(norm)

            // 3. Matches "Option A", "Opt A", etc.
            val isAlphaOption =
                Regex(
                    """^(option|opt|choice|answer option|mcq|ans|q|خيار|الخيار)\s*[a-z]$""",
                    RegexOption.IGNORE_CASE,
                ).containsMatchIn(norm)

            if (isAliasMatch || isNumericOption || isAlphaOption) {
                options.add(index)
            }
        }

        if (options.isEmpty()) {
            val qIdx = mapped["question"] ?: -1
            val aIdx = mapped["answer"] ?: headerRow.size
            if (qIdx != -1) {
                val start = minOf(qIdx, aIdx)
                val end = maxOf(qIdx, aIdx)
                for (i in (start + 1) until end) {
                    if (i !in mappedCols) options.add(i)
                }
            }
        }

        return options.take(120) // Safety limit
    }

class ZipLibraryParser(
    private val context: Context,
    private val jsonParser: JsonLibraryParser,
) {
    companion object {
        private const val MAX_ENTRIES = ImportLimits.MAX_ZIP_ENTRIES
        private const val MAX_SINGLE_FILE_SIZE = ImportLimits.MAX_ZIP_SINGLE_UNCOMPRESSED_BYTES
        private const val MAX_TOTAL_SIZE = ImportLimits.MAX_ZIP_TOTAL_UNCOMPRESSED_BYTES
        private const val MAX_COMPRESSED_SIZE = ImportLimits.MAX_ZIP_COMPRESSED_BYTES
    }

    private val json = Json { ignoreUnknownKeys = true }

fun parse(inputStream: InputStream): ZipResult {
        val tempDir = File(context.cacheDir, "import_${System.currentTimeMillis()}")
        tempDir.mkdirs()

        val tempZipFile = File(context.cacheDir, "import_temp_${System.currentTimeMillis()}.zip")

        try {
            // Save inputStream to a temporary file because Zip4j ZipFile works with Files.
            tempZipFile.outputStream().use { output ->
                inputStream.copyToWithLimit(output, MAX_COMPRESSED_SIZE)
            }

            ZipFile(tempZipFile).use { zipFile ->
                if (zipFile.isEncrypted) {
                    zipFile.setPassword(MksExchangeV7Paths.provideInternalSystemKey().toCharArray())

                    // Pre-extraction validation and individual file extraction.
                    var totalBytes = 0L
                    var totalEntries = 0
                    val canonicalTempDir = tempDir.canonicalPath

                    zipFile.fileHeaders.forEach { header ->
                        totalEntries++
                        if (totalEntries > MAX_ENTRIES) {
                            throw IllegalStateException("Too many entries in ZIP archive")
                        }

                        if (header.uncompressedSize > MAX_SINGLE_FILE_SIZE) {
                            throw IllegalStateException("Zip entry '${header.fileName}' exceeds maximum size")
                        }

                        totalBytes += header.uncompressedSize
                        if (totalBytes > MAX_TOTAL_SIZE) {
                            throw IllegalStateException("Total uncompressed size of ZIP archive exceeds maximum")
                        }

                        if (header.fileName.contains("..") || header.fileName.startsWith("/")) {
                            throw SecurityException("Illegal zip entry name detected: ${header.fileName}")
                        }

                        val destinationFile = File(tempDir, header.fileName)
                        val canonicalDestPath = destinationFile.canonicalPath
                        if (!canonicalDestPath.startsWith(canonicalTempDir + File.separator)) {
                            throw SecurityException("Illegal zip entry path detected: ${header.fileName}")
                        }

                        zipFile.extractFile(header, tempDir.absolutePath)
                    }
                } else {
                    extractPlainZip(tempZipFile, tempDir)
                }
            }

            val manifestJsonFile = tempDir.walkTopDown().find { it.name == "manifest.json" }
            val manifestText = manifestJsonFile?.readTextWithLimit(ImportLimits.MAX_TEXT_IMPORT_BYTES)
            val isSchema7Exchange =
                manifestText?.let { text ->
                    runCatching {
                        val root = json.parseToJsonElement(text) as? JsonObject
                        (
                            root?.get("format")?.jsonPrimitive?.content == "mks.exchange" &&
                                root["schemaVersion"]?.jsonPrimitive?.content?.toIntOrNull() == 7
                        )
                    }.getOrDefault(false)
                } ?: false

            if (isSchema7Exchange) {
                val bundle = MksExchangeV7Archive.readLegacyBundleFromDirectory(tempDir)
                val manifest =
                    manifestText.let {
                        json.decodeFromString(ManifestDto.serializer(), it)
                    }
                return ZipResult(bundle, manifest, tempDir, tempDir)
            }

            var libraryJsonFile =
                tempDir.walkTopDown()
                    .find { it.name == "library.json" || it.name == "bundle.json" || it.name == "data.json" }

            if (libraryJsonFile == null) {
                // Look for any non-manifest JSON file if the canonical names are absent.
                libraryJsonFile =
                    tempDir.walkTopDown()
                        .find { it.extension.lowercase() == "json" && it.name != "manifest.json" }
            }

            if (libraryJsonFile == null) throw IllegalStateException("No JSON library file found in ZIP")

            val bundle = libraryJsonFile.inputStream().use { jsonParser.parse(it) }
            val manifest =
                manifestText?.let {
                    json.decodeFromString(ManifestDto.serializer(), it)
                }

            return ZipResult(bundle, manifest, libraryJsonFile.parentFile ?: tempDir, tempDir)
        } catch (e: Exception) {
            tempDir.deleteRecursively()
            throw e
        } finally {
            tempZipFile.delete()
        }
    }

private fun extractPlainZip(
        zipFile: File,
        targetDir: File,
    ) {
        var totalBytes = 0L
        var totalEntries = 0
        val canonicalTempDir = targetDir.canonicalFile.toPath()
        ZipInputStream(zipFile.inputStream()).use { zip ->
            while (true) {
                val entry = zip.nextEntry ?: break
                if (entry.isDirectory) {
                    zip.closeEntry()
                    continue
                }
                totalEntries++
                if (totalEntries > MAX_ENTRIES) throw IllegalStateException("Too many entries in ZIP archive")
                val entryName = entry.name.replace('\\', '/')
                if (entryName.contains("..") || entryName.startsWith("/")) {
                    throw SecurityException(
                        "Illegal zip entry name detected: $entryName",
                    )
                }
                if (entry.size > MAX_SINGLE_FILE_SIZE) throw IllegalStateException("Zip entry '$entryName' exceeds maximum size")
                val destinationFile = File(targetDir, entryName)
                val destinationPath = destinationFile.canonicalFile.toPath()
                if (!destinationPath.startsWith(canonicalTempDir)) throw SecurityException("Illegal zip entry path detected: $entryName")
                destinationFile.parentFile?.mkdirs()
                destinationFile.outputStream().use { output ->
                    val copied = zip.copyToWithLimit(output, MAX_SINGLE_FILE_SIZE)
                    totalBytes += copied
                    if (totalBytes > MAX_TOTAL_SIZE) throw IllegalStateException("Total uncompressed size of ZIP archive exceeds maximum")
                }
                zip.closeEntry()
            }
        }
    }
}

class JsonQuestionParser(
    private val imageExtractor: GenericImageExtractor,
) {
    private val moshi = Moshi.Builder().build()

fun parse(text: String): List<ParsedQuestion> {
        val trimmed = text.trim()
        val adapter = moshi.adapter(Any::class.java)
        val parsed = adapter.fromJson(trimmed) ?: return emptyList()

        return when (parsed) {
            is List<*> -> parseList(parsed)
            is Map<*, *> ->
                @Suppress("UNCHECKED_CAST")
                parseMap(parsed as Map<String, Any>)
            else -> emptyList()
        }
    }

private fun parseList(list: List<*>): List<ParsedQuestion> {
        val result = mutableListOf<ParsedQuestion>()
        list.forEachIndexed { index, item ->
            if (item is Map<*, *>) {
                @Suppress("UNCHECKED_CAST")
                result.add(parseSingle(item as Map<String, Any>, index + 1))
            }
        }
        return result
    }

private fun parseMap(map: Map<String, Any>): List<ParsedQuestion> {
        val questions = map["questions"] ?: map["quizData"]
        if (questions is List<*>) {
            return parseList(questions)
        }
        // Fallback for single question object
        if (map.containsKey("question") || map.containsKey("stem") || map.containsKey("q")) {
            return listOf(parseSingle(map, 1))
        }
        return emptyList()
    }

private fun parseSingle(
        map: Map<String, Any>,
        line: Int,
    ): ParsedQuestion {
        val stem = (map["stem"] ?: map["question"] ?: map["q"] ?: map["text"] ?: "").toString()
        val optionsRaw = map["options"]

        val options = mutableListOf<ParsedOption>()
        if (optionsRaw is List<*>) {
            optionsRaw.forEachIndexed { i, opt ->
                val optText = if (opt is Map<*, *>) opt["text"] ?: opt["label"] ?: opt["t"] else opt
                val isCorrect = if (opt is Map<*, *>) opt["correct"] == true else false
                options.add(
                    ParsedOption(
                        id = "opt_$i",
                        text = optText.toString().trim(),
                        marked = isCorrect,
                    ),
                )
            }
        } else {
            // Fallback to A, B, C... fields
            for (i in 0 until 8) {
                val letter = (65 + i).toChar().toString()
                val valLower = map[letter.lowercase()]
                val valUpper = map[letter]
                val text = (valLower ?: valUpper)?.toString() ?: ""
                if (text.isNotBlank()) {
                    options.add(ParsedOption(id = "opt_$i", text = text.trim()))
                }
            }
        }

        val answerRaw = (map["answer"] ?: map["correctAnswer"] ?: map["correct"] ?: "").toString()
        val correctIds = resolveCorrect(answerRaw, options)

        val imageSource = (map["imageDataUrl"] ?: map["image"] ?: map["imageUrl"] ?: map["photo"] ?: map["img"] ?: "").toString()
        val resolvedImage = if (imageSource.isNotBlank()) imageExtractor.extractFromText(imageSource) else null

        val stemImage = imageExtractor.extractFromText(stem)

        return ParsedQuestion(
            stem = stem,
            options = options,
            correctAnswers = correctIds,
            explanation = (map["explanation"] ?: map["e"] ?: "").toString(),
            hint = (map["hint"] ?: map["hintText"] ?: "").toString(),
            reference = (map["reference"] ?: map["ref"] ?: "").toString(),
            additionalInfo = (map["additionalInfo"] ?: map["additional"] ?: map["info"] ?: "").toString(),
            categories = parseCategories(map["categories"] ?: map["category"]),
            imageDataUrl = (resolvedImage ?: stemImage)?.imageDataUrl,
            imageSource = (resolvedImage ?: stemImage)?.imageSource ?: if (!imageSource.startsWith("data:")) imageSource else "",
            sourceLine = line,
            type = if (correctIds.size > 1) QuestionType.MULTIPLE_CHOICE else QuestionType.SINGLE_CHOICE,
        )
    }

private fun resolveCorrect(
        answerRaw: String,
        options: List<ParsedOption>,
    ): List<String> {
        val result = mutableSetOf<String>()
        val trimmedAnswer = answerRaw.trim()

        if (options.isEmpty()) return emptyList()

        // 1. Exact textual match against option text
        options.forEach { opt ->
            if (opt.text.equals(trimmedAnswer, ignoreCase = true)) {
                result.add(opt.id)
            }
        }

        // 2. Exact match against option letter (A, B, C...)
        if (result.isEmpty()) {
            val upperTrimmed = trimmedAnswer.uppercase()
            options.forEach { opt ->
                val letter = opt.id.removePrefix("opt_")
                if (upperTrimmed == letter) {
                    result.add(opt.id)
                }
            }
        }

        // 3. Multi-answer match (e.g. "A, B" or "A;B")
        if (result.isEmpty()) {
            val parts =
                trimmedAnswer.uppercase()
                    .split(Regex("[,;\\s]+"))
                    .map { it.trim() }
                    .filter { it.isNotEmpty() }

            parts.forEach { part ->
                options.forEach { opt ->
                    val letter = opt.id.removePrefix("opt_")
                    if (part == letter || opt.text.equals(part, ignoreCase = true)) {
                        result.add(opt.id)
                    }
                }
            }
        }

        // 4. Fallback to marked options in JSON
        if (result.isEmpty()) {
            options.forEach { opt ->
                if (opt.marked) result.add(opt.id)
            }
        }

        // 5. Smart fallback for letters contained in answer text (Word boundaries)
        if (result.isEmpty() && answerRaw.isNotBlank()) {
            val upperAnswer = answerRaw.uppercase()
            options.forEach { opt ->
                val letter = opt.id.removePrefix("opt_")
                if (letter.length == 1) {
                    // Match ONLY if letter is isolated (fixes Issue 6)
                    val regex = Regex("\\b$letter\\b")
                    if (upperAnswer.contains(regex)) {
                        result.add(opt.id)
                    }
                } else {
                    if (upperAnswer.contains(letter)) {
                        result.add(opt.id)
                    }
                }
            }
        }

        return result.toList().sorted()
    }

private fun parseCategories(value: Any?): List<String> {
        return when (value) {
            is List<*> -> value.map { it.toString() }
            is String -> value.split(",").map { it.trim() }.filter { it.isNotEmpty() }
            else -> emptyList()
        }
    }
}

class TextQuestionParser(
    private val imageExtractor: GenericImageExtractor,
) {

fun parse(
        text: String,
        answersText: String? = null,
    ): List<ParsedQuestion> {
        val lines = text.lines()
        val answerMap = parseAnswerBlock(answersText)

        val result = mutableListOf<ParsedQuestion>()
        var current: RawQuestion? = null
        var qNum = 0

        lines.forEachIndexed { index, line ->
            val s = line.trim()
            if (s.isEmpty()) return@forEachIndexed

            if (isQuestionStart(s)) {
                current?.let { result.add(finalize(it, answerMap)) }
                qNum++
                current =
                    RawQuestion(
                        stem = stripQuestionMarker(s),
                        sourceLine = index + 1,
                        qNum = qNum,
                    )
            } else {
                current?.let { q ->
                    val opt = parseOption(s)
                    if (opt != null) {
                        q.options.add(opt)
                    } else {
                        val field = parseField(s)
                        if (field != null) {
                            q.fields[field.first] = field.second
                        } else if (q.options.isEmpty()) {
                            q.stem += "\n" + s
                        } else {
                            q.options.last().let { last ->
                                // Append to last option text
                                // This is a bit simplified
                            }
                        }
                    }
                }
            }
        }
        current?.let { result.add(finalize(it, answerMap)) }
        return result
    }

private fun isQuestionStart(line: String): Boolean {
        return Regex("""^(?:q(?:uestion)?\s*)?\d+[\)\.\-:\s]+""", RegexOption.IGNORE_CASE).containsMatchIn(line) ||
            Regex("""^س(?:ؤال)?\s*\d+[\)\.\-:\s]*""").containsMatchIn(line)
    }

private fun stripQuestionMarker(line: String): String {
        return line.replace(Regex("""^(?:q(?:uestion)?\s*)?\d+[\)\.\-:\s]+""", RegexOption.IGNORE_CASE), "")
            .replace(Regex("""^س(?:ؤال)?\s*\d+[\)\.\-:\s]*"""), "")
            .trim()
    }

private fun parseOption(line: String): ParsedOption? {
        val match = Regex("""^[*✓✔☑\-\s]*([A-Z])[\)\.\-:\s]+(.+)$""", RegexOption.IGNORE_CASE).find(line)
        if (match != null) {
            return ParsedOption(
                id = "opt_${match.groupValues[1].uppercase()}",
                text = match.groupValues[2].trim(),
                marked = line.contains(Regex("""[*✓✔☑]""")),
            )
        }
        return null
    }

private fun parseField(line: String): Pair<String, String>? {
        val prefixes =
            mapOf(
                "answer" to listOf("answer:", "ans:", "correct:", "الإجابة:", "الجواب:"),
                "explanation" to listOf("explanation:", "rationale:", "exp:", "الشرح:", "تفسير:"),
                "hint" to listOf("hint:", "tip:", "تلميح:"),
                "reference" to listOf("reference:", "ref:", "مرجع:"),
                "categories" to listOf("categories:", "category:", "tags:", "تصنيف:"),
            )
        for ((field, list) in prefixes) {
            for (p in list) {
                if (line.trim().startsWith(p, ignoreCase = true)) {
                    return field to line.trim().substring(p.length).trim()
                }
            }
        }
        return null
    }

private fun parseAnswerBlock(text: String?): Map<Int, String> {
        if (text == null) return emptyMap()
        val map = mutableMapOf<Int, String>()
        text.lines().forEach { line ->
            val match = Regex("""(\d+)\s*[:\-=\)\.]\s*(.+)""").find(line)
            if (match != null) {
                match.groupValues[1].toIntOrNull()?.let { map[it] = match.groupValues[2].trim() }
            }
        }
        return map
    }

private fun resolveCorrect(
        answerRaw: String,
        options: List<ParsedOption>,
    ): List<String> {
        val result = mutableSetOf<String>()
        val trimmedAnswer = answerRaw.trim()

        if (options.isEmpty()) return emptyList()

        // 1. Try exact textual match against options (Case insensitive)
        options.forEach { opt ->
            if (opt.text.trim().equals(trimmedAnswer, ignoreCase = true)) {
                result.add(opt.id)
            }
        }

        // 2. If no exact match, try matching by letter if trimmedAnswer is just a letter
        if (result.isEmpty()) {
            val upperTrimmed = trimmedAnswer.uppercase()
            options.forEach { opt ->
                val letter = opt.id.removePrefix("opt_")
                if (upperTrimmed == letter) {
                    result.add(opt.id)
                }
            }
        }

        // 3. If still no match, parse by delimiter (comma, semicolon, space)
        if (result.isEmpty()) {
            val upperTrimmed = trimmedAnswer.uppercase()
            val parts =
                upperTrimmed
                    .split(Regex("[,;\\s]+"))
                    .map { it.trim() }
                    .filter { it.isNotEmpty() }

            parts.forEach { part ->
                options.forEach { opt ->
                    val letter = opt.id.removePrefix("opt_")
                    if (part == letter || opt.text.trim().equals(part, ignoreCase = true)) {
                        result.add(opt.id)
                    }
                }
            }
        }

        // 4. Fallback to marked options (if no explicit answers found)
        if (result.isEmpty()) {
            options.forEach { opt ->
                if (opt.marked) result.add(opt.id)
            }
        }

        // 5. Global fallback (isolated letters only - to fix Issue 6)
        if (result.isEmpty() && answerRaw.isNotBlank()) {
            val upperAnswer = answerRaw.uppercase()
            options.forEach { opt ->
                val letter = opt.id.removePrefix("opt_")
                if (letter.length == 1) {
                    val regex = Regex("\\b$letter\\b")
                    if (upperAnswer.contains(regex)) {
                        result.add(opt.id)
                    }
                } else if (upperAnswer.contains(letter)) {
                    result.add(opt.id)
                }
            }
        }

        return result.toList().sorted()
    }

    private data class RawQuestion(
        var stem: String,
        val options: MutableList<ParsedOption> = mutableListOf(),
        val fields: MutableMap<String, String> = mutableMapOf(),
        val sourceLine: Int,
        val qNum: Int,
    )
}

fun detectFormat(uri: Uri): ImportFormat {
        val fileName = getFileName(uri)
        val extension =
            fileName?.substringAfterLast('.', "")?.lowercase()
                ?: uri.path?.substringAfterLast('.', "")?.lowercase()

        // Check extension first as it's the most reliable for XLSX/ZIP
        val formatFromExt =
            when (extension) {
                "json" -> ImportFormat.JSON
                "zip" -> ImportFormat.ZIP
                "xlsx", "xlsm", "xltx", "xltm" -> ImportFormat.XLSX
                "xls" -> ImportFormat.XLSX // Map legacy XLS to XLSX for mode detection
                "csv", "tsv" -> ImportFormat.CSV_TSV
                "txt" -> ImportFormat.TEXT
                "html", "htm" -> ImportFormat.HTML
                else -> null
            }

        if (formatFromExt != null) return formatFromExt

        // Content detection if extension is missing or unclear
        return try {
            context.contentResolver.openInputStream(uri)?.use { inputStream ->
                detectFromStream(inputStream)
            } ?: ImportFormat.UNKNOWN
        } catch (e: Exception) {
            ImportFormat.UNKNOWN
        }
    }

private fun getFileName(uri: Uri): String? {
        if (uri.scheme == "content") {
            try {
                context.contentResolver.query(uri, arrayOf(OpenableColumns.DISPLAY_NAME), null, null, null)?.use { cursor ->
                    if (cursor.moveToFirst()) {
                        val index = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                        if (index != -1) return cursor.getString(index)
                    }
                }
            } catch (e: Exception) {
            }
        }
        return uri.lastPathSegment
    }

private fun detectFromStream(inputStream: InputStream): ImportFormat {
        // Use a buffered stream to peek at the content
        val bis = java.io.BufferedInputStream(inputStream)
        bis.mark(2048)
        val header = ByteArray(2048)
        val bytesRead = bis.read(header)
        // We don't necessarily need to reset if we are done with the stream here,
        // but it's good practice if it was passed in. However, we are in a 'use' block above.

        if (bytesRead < 4) return ImportFormat.UNKNOWN

        // Check for ZIP/XLSX magic number (PK..)
        if (header[0] == 0x50.toByte() && header[1] == 0x4B.toByte() &&
            header[2] == 0x03.toByte() && header[3] == 0x04.toByte()
        ) {
            val headerStr = String(header, 0, bytesRead, Charset.forName("US-ASCII"))
            if (headerStr.contains("xl/") || headerStr.contains("[Content_Types].xml")) {
                return ImportFormat.XLSX
            }
            return ImportFormat.ZIP
        }

        // Check for Zip4j encrypted ZIP (PK\x07\x08)
        if (header[0] == 0x50.toByte() && header[1] == 0x4B.toByte() &&
            header[2] == 0x07.toByte() && header[3] == 0x08.toByte()
        ) {
            return ImportFormat.ZIP
        }

        // Check for XLS (Legacy Excel) magic number: D0 CF 11 E0 A1 B1 1A E1
        if (header[0] == 0xD0.toByte() && header[1] == 0xCF.toByte() &&
            header[2] == 0x11.toByte() && header[3] == 0xE0.toByte()
        ) {
            return ImportFormat.XLSX // Treat as XLSX for mode selection
        }

        // Check for JSON start ({ or [)
        val firstChar = header.firstOrNull { it > 32 }?.toInt()?.toChar()
        if (firstChar == '{' || firstChar == '[') {
            return ImportFormat.JSON
        }

        // Check for HTML
        val headerString = String(header, 0, bytesRead).lowercase()
        if (headerString.contains("<!doc") || headerString.contains("<html") || headerString.contains("<body")) {
            return ImportFormat.HTML
        }

        // Check for CSV/TSV like structure (simple heuristic)
        if (isLikelyTabular(headerString)) {
            return ImportFormat.CSV_TSV
        }

        return ImportFormat.TEXT
    }

private fun isLikelyTabular(content: String): Boolean {
        val lines = content.lines().take(5).filter { it.isNotBlank() }
        if (lines.isEmpty()) return false

        val commonSeparators = listOf('\t', ',', ';')
        for (sep in commonSeparators) {
            val counts = lines.map { it.count { char -> char == sep } }
            if (counts.all { it > 0 } && counts.distinct().size <= 2) {
                return true
            }
        }
        return false
    }
}

data class ParseIssue(
    val message: String,
    val severity: IssueSeverity = IssueSeverity.WARNING,
)

enum class IssueSeverity {
    INFO,
    WARNING,
    ERROR,
}

data class ValidationResult(
    val isValid: Boolean,
    val warnings: List<ImportWarning> = emptyList(),
    val criticalError: String? = null,
    val sanitizedBundle: LibraryBundleDto? = null,
    val skippedRecords: List<SkippedImportRecord> = emptyList(),
) {
    val skippedRecordsCount: Int get() = skippedRecords.size
}

fun validate(
        bundle: LibraryBundleDto,
        allowUnboundQuizzes: Boolean = false,
    ): ValidationResult {
        val warnings = mutableListOf<ImportWarning>()
        val skipped = mutableListOf<SkippedImportRecord>()

        if (bundle.schema !in listOf(4, 5, 6, 7)) {
            warnings.add(ImportWarning("Schema version ${bundle.schema} is not officially supported, but import will proceed."))
        }

        val validKinds = listOf("book-bundle", "library-bundle", "quiz-bundle", "full-library")
        if (bundle.kind !in validKinds) {
            warnings.add(ImportWarning("Unexpected bundle kind: ${bundle.kind}"))
        }

        val bookIds = bundle.books.map { it.id }.toSet()
        if (bookIds.size < bundle.books.size) {
            warnings.add(ImportWarning("Duplicate book IDs found in bundle"))
        }

        val quizIds = bundle.quizzes.map { it.id }.toSet()
        if (quizIds.size < bundle.quizzes.size) {
            warnings.add(ImportWarning("Duplicate quiz IDs found in bundle"))
        }

        val sanitizedQuizzes =
            bundle.quizzes.map { quiz ->
                if (!allowUnboundQuizzes && quiz.bookId !in bookIds) {
                    warnings.add(ImportWarning("Quiz '${quiz.title}' refers to unknown book ID '${quiz.bookId}'", affectedId = quiz.id))
                }

                val seenQuestionIds = mutableSetOf<String>()
                val validQuestions =
                    quiz.questions.mapIndexedNotNull { index, question ->
                        val problems = questionProblems(question, seenQuestionIds)
                        if (problems.isEmpty()) {
                            seenQuestionIds.add(question.id)
                            question
                        } else {
                            val location = question.sourceLine?.takeIf { it > 0 }
                            val displayLine = location?.let { "line/row $it" } ?: "line/row unknown"
                            val reason = problems.joinToString("; ")
                            skipped.add(SkippedImportRecord(question.id, quiz.id, location, reason))
                            warnings.add(
                                ImportWarning(
                                    message = "Skipped question '${question.id.ifBlank { "#${index + 1}" }}' in quiz '${quiz.title}' at $displayLine: $reason",
                                    details = "quizId=${quiz.id}; questionId=${question.id}; line=${location ?: "unknown"}",
                                    affectedId = question.id,
                                ),
                            )
                            null
                        }
                    }
                quiz.copy(questions = validQuestions)
            }

        val sanitizedBundle = bundle.copy(quizzes = sanitizedQuizzes)
        return ValidationResult(
            isValid = true,
            warnings = warnings,
            sanitizedBundle = sanitizedBundle,
            skippedRecords = skipped,
        )
    }

private fun questionProblems(
        question: QuestionDto,
        seenQuestionIds: Set<String>,
    ): List<String> {
        val problems = mutableListOf<String>()
        if (question.id.isBlank()) problems.add("blank question ID")
        if (question.id.isNotBlank() && question.id in seenQuestionIds) problems.add("duplicate question ID in same quiz")
        if (question.stem.isBlank()) problems.add("blank question stem")
        if (question.options.isEmpty()) problems.add("no answer options")

        val optionIds = question.options.map { it.id }
        val distinctOptionIds = optionIds.toSet()
        if (distinctOptionIds.size < optionIds.size) problems.add("duplicate option IDs")
        question.options.forEachIndexed { optionIndex, option ->
            if (option.id.isBlank()) problems.add("blank option ID at option ${optionIndex + 1}")
            if (option.text.isBlank()) problems.add("blank option text at option ${optionIndex + 1}")
        }

        if (question.correct.isEmpty()) problems.add("no correct answer IDs")
        question.correct.forEach { correctId ->
            if (correctId !in distinctOptionIds) {
                problems.add("unknown correct option ID '$correctId'")
            }
        }

        val answerMode = question.answerMode?.lowercase()
        if (answerMode != null && answerMode !in listOf("single", "multiple")) {
            problems.add("unsupported answer mode '${question.answerMode}'")
        }
        if (answerMode == "single" && question.correct.size > 1) {
            problems.add("single-answer question has multiple correct answers")
        }
        return problems.distinct()
    }
}

