class FocusManager @Inject constructor(
    @ApplicationContext private val context: Context,
) {
    private val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
    private var previousFilter: Int = NotificationManager.INTERRUPTION_FILTER_ALL

fun hasNotificationPolicyAccess(): Boolean {
        return notificationManager.isNotificationPolicyAccessGranted
    }

fun requestNotificationPolicyAccess() {
        val intent = Intent(Settings.ACTION_NOTIFICATION_POLICY_ACCESS_SETTINGS)
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        context.startActivity(intent)
    }

fun enableFocusMode(): Boolean {
        if (!hasNotificationPolicyAccess()) return false

        try {
            previousFilter = notificationManager.currentInterruptionFilter
            notificationManager.setInterruptionFilter(NotificationManager.INTERRUPTION_FILTER_NONE)
            return true
        } catch (e: Exception) {
            MksLogger.w("FocusManager", "Unable to enable focus mode", e)
            return false
        }
    }

fun disableFocusMode() {
        if (!hasNotificationPolicyAccess()) return

        try {
            notificationManager.setInterruptionFilter(previousFilter)
        } catch (e: Exception) {
            MksLogger.w("FocusManager", "Unable to restore focus mode interruption filter", e)
            // Fallback to all if restore fails
            notificationManager.setInterruptionFilter(NotificationManager.INTERRUPTION_FILTER_ALL)
        }
    }
}

suspend fun search(query: String): List<GlobalSearchResult> =
        withContext(Dispatchers.IO) {
            val cleaned = query.trim()
            if (cleaned.length < 2) return@withContext emptyList()
            dao.search("%$cleaned%")
                .map { it.toResult() }
                .sortedWith(compareByDescending<GlobalSearchResult> { it.updatedAt ?: 0L }.thenBy { it.type.name })
        }
}

fun GlobalSearchResultRow.toResult(): GlobalSearchResult {
    val resolvedType = runCatching { GlobalSearchResultType.valueOf(type) }.getOrDefault(GlobalSearchResultType.QUESTION)
    val route =
        when (resolvedType) {
            GlobalSearchResultType.BOOK -> MksRoutes.LIBRARY
            GlobalSearchResultType.QUIZ -> quizId?.let { MksRoutes.sessions(it) }
            GlobalSearchResultType.QUESTION,
            GlobalSearchResultType.ANSWER,
            GlobalSearchResultType.EXPLANATION,
            GlobalSearchResultType.HINT,
            GlobalSearchResultType.NOTE,
            -> quizId?.let { MksRoutes.quizQuestions(it) }
            GlobalSearchResultType.ASSET -> quizId?.let { MksRoutes.quizQuestions(it) }
            GlobalSearchResultType.SOURCE -> bookId?.let { MksRoutes.bookDashboard(it) }
            GlobalSearchResultType.FLASHCARD -> parentId?.let { MksRoutes.flashcards(it, id.toLongOrNull()) }
            GlobalSearchResultType.BLUEPRINT -> id.toLongOrNull()?.let { MksRoutes.blueprint(it) }
            GlobalSearchResultType.SLIDE -> parentId?.let { MksRoutes.slideshow(it, id.toLongOrNull()) }
            GlobalSearchResultType.PROMPT_DECK -> id.toLongOrNull()?.let { MksRoutes.promptDeck(it) }
            GlobalSearchResultType.PROMPT_CARD -> parentId?.let { MksRoutes.promptDeck(it, cardId = id.toLongOrNull()) }
            GlobalSearchResultType.PROMPT_RUN -> parentId?.let { MksRoutes.promptDeck(it, runId = id.toLongOrNull()) }
            GlobalSearchResultType.MISTAKE -> id.toLongOrNull()?.let { MksRoutes.reviewDashboard(it) }
            GlobalSearchResultType.ANNOTATION -> bookId?.let { MksRoutes.bookDashboard(it) }
            GlobalSearchResultType.CATEGORY, GlobalSearchResultType.TAG -> title.takeIf { it.isNotBlank() }?.let { MksRoutes.category(it) }
        }
    return GlobalSearchResult(id, resolvedType, title, subtitle, snippet, bookId, quizId, questionId, route, updatedAt)
}

class FileManager(private val context: Context) {
    private val remoteAssetFetcher by lazy { RemoteAssetFetcher() }

    companion object {
        private const val MAX_IMAGE_INPUT_BYTES = 12 * 1024 * 1024
        private const val MAX_IMAGE_DIMENSION = 2048
        private const val MAX_IMAGE_PIXELS = 12_000_000L
        private const val IMAGE_QUALITY = 82
        private const val MAX_ASSET_INPUT_BYTES = 50 * 1024 * 1024
    }

    private data class NormalizedImageResult(
        val bytes: ByteArray? = null,
        val error: String? = null,
    )

fun saveBase64AsImage(base64String: String): String? {
        return saveBase64AsImageDetailed(base64String).getOrNull()
    }

fun saveBase64AsImageDetailed(base64String: String): MksResult<String> {
        if (base64String.isBlank()) return MksResult.Error(message = "Image data is empty.")

        return try {
            val pureBase64 =
                if (base64String.contains(",")) {
                    base64String.substring(base64String.indexOf(",") + 1)
                } else {
                    base64String
                }

            val estimatedBytes = ((pureBase64.length.toLong() * 3L) / 4L)
            if (estimatedBytes > MAX_IMAGE_INPUT_BYTES) {
                return MksResult.Error(message = "Image exceeds ${MAX_IMAGE_INPUT_BYTES / (1024 * 1024)} MB input limit.")
            }

            val imageBytes = Base64.decode(pureBase64, Base64.DEFAULT)
            saveImageDetailed(imageBytes)
        } catch (e: Exception) {
            MksResult.Error(message = e.message ?: "Invalid Base64 image data.", exception = e)
        }
    }

fun saveImage(base64String: String?): String? {
        return saveImageDetailed(base64String).getOrNull()
    }

fun copyAssetUriToInternalStorage(
        uriString: String,
        originalName: String? = null,
    ): MksResult<AssetFileSaveResult> {
        if (uriString.isBlank()) return MksResult.Error(message = "Asset URI is empty.")
        return try {
            val uri = Uri.parse(uriString)
            val scheme = uri.scheme?.lowercase()
            if (scheme != "content" && scheme != "file") {
                return MksResult.Error(message = "Only content:// or file:// local asset URIs can be copied.")
            }

            val mimeType = context.contentResolver.getType(uri)
            val safeName =
                sanitizeAssetFileName(
                    originalName?.takeIf { it.isNotBlank() }
                        ?: uri.lastPathSegment
                        ?: "asset",
                )
            val extension =
                safeName.substringAfterLast('.', missingDelimiterValue = "bin")
                    .takeIf { it.isNotBlank() }
                    ?: "bin"
            val fileName = "asset_${UUID.randomUUID()}.$extension"
            val target = File(getQuestionAssetsDir(), fileName).canonicalFile

            context.contentResolver.openInputStream(uri)?.use { input ->
                val bytes =
                    readBytesWithLimit(input, MAX_ASSET_INPUT_BYTES)
                        ?: return MksResult.Error(message = "Asset exceeds ${MAX_ASSET_INPUT_BYTES / (1024 * 1024)} MB input limit.")
                FileOutputStream(target).use { output -> output.write(bytes) }
                return MksResult.Success(
                    AssetFileSaveResult(
                    path = target.absolutePath,
                    mimeType = mimeType,
                    fileName = safeName,
                    fileSizeBytes = bytes.size.toLong(),
                    )
                )
            }
            MksResult.Error(message = "Unable to open asset URI.")
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Asset copy operation failed", e)
            MksResult.Error(message = e.message ?: "Failed to copy asset.", exception = e)
        }
    }

fun deleteAssetFile(path: String?) {
        if (path.isNullOrBlank()) return
        if (!isPathInsideAssetsDir(path)) return
        try {
            val file = File(path).canonicalFile
            if (file.exists()) file.delete()
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Asset delete operation failed", e)
        }
    }

private fun getQuestionAssetsDir(): File {
        val dir = File(context.filesDir, "question_assets")
        if (!dir.exists()) dir.mkdirs()
        return dir
    }

private fun isPathInsideAssetsDir(path: String): Boolean {
        return try {
            val file = File(path).canonicalFile
            val assetsDir = getQuestionAssetsDir().canonicalFile
            file == assetsDir || file.toPath().startsWith(assetsDir.toPath())
        } catch (e: Exception) {
            false
        }
    }

private fun sanitizeAssetFileName(value: String): String {
        return value.substringAfterLast('/').substringAfterLast('\\')
            .replace(Regex("[^A-Za-z0-9._-]"), "_")
            .ifBlank { "asset" }
            .take(96)
    }

fun saveImageDetailed(base64String: String?): MksResult<String> {
        if (base64String.isNullOrBlank()) return MksResult.Error(message = "Image reference is empty.")

        // Check if it's already a local path or a relative path
        if (base64String.startsWith("/") || base64String.startsWith("assets/")) {
            // SECURITY: Reject absolute paths to prevent path injection
            if (base64String.startsWith("/")) {
                // If it's already inside our internal images directory, it's fine
                if (isPathInsideImagesDir(base64String)) {
                    return MksResult.Success(base64String)
                }
                return MksResult.Error(message = "Absolute image paths outside the app images directory are not allowed.")
            }
            return MksResult.Error(message = "Relative asset references are not accepted here.")
        }

        return saveBase64AsImageDetailed(base64String)
    }

fun saveImage(
        bytes: ByteArray,
        extension: String = "webp",
    ): String? {
        return saveImageDetailed(bytes, extension).getOrNull()
    }

fun saveImageDetailed(
        bytes: ByteArray,
        extension: String = "webp",
    ): MksResult<String> {
        return try {
            val normalized = normalizeImageBytes(bytes)
            val finalBytes =
                normalized.bytes
                    ?: return MksResult.Error(
                        message = normalized.error ?: "Image normalization failed."
                    )
            val path =
                writeNormalizedImage(finalBytes)
                    ?: return MksResult.Error(message = "Failed to persist normalized image.")
            MksResult.Success(path)
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Image operation failed", e)
            MksResult.Error(message = e.message ?: "Failed to save image.", exception = e)
        }
    }

suspend fun downloadAndSaveImage(
        url: String,
        policy: RemoteAssetPolicy = RemoteAssetPolicy.Default,
    ): String? {
        return downloadAndSaveImageDetailed(url, policy).getOrNull()
    }

suspend fun downloadAndSaveImageDetailed(
        url: String,
        policy: RemoteAssetPolicy = RemoteAssetPolicy.Default,
    ): MksResult<String> {
        if (!isHttpOrHttpsUrl(url)) return MksResult.Error(message = "Only HTTP(S) image URLs are supported.")

        val fetched = remoteAssetFetcher.fetch(url, policy.copy(maxBytes = MAX_IMAGE_INPUT_BYTES.toLong()))
        val bytes =
            fetched.bytes ?: return MksResult.Error(
                message = fetched.error ?: fetched.warning ?: "Remote image was not downloaded.",
            )
        val saved = saveImageDetailed(bytes)
        return if (saved is MksResult.Success && fetched.warning != null) {
            // In case of success with warning, we still return Success but could log the warning
            MksLogger.w("FileManager", "Image downloaded with warning: ${fetched.warning}")
            saved
        } else {
            saved
        }
    }

fun saveImage(
        inputStream: InputStream,
        originalName: String? = null,
    ): String? {
        return saveImageDetailed(inputStream, originalName).getOrNull()
    }

fun saveImageDetailed(
        inputStream: InputStream,
        originalName: String? = null,
    ): MksResult<String> {
        return try {
            val bytes =
                readBytesWithLimit(inputStream, MAX_IMAGE_INPUT_BYTES)
                    ?: return MksResult.Error(message = "Image exceeds ${MAX_IMAGE_INPUT_BYTES / (1024 * 1024)} MB input limit.")
            saveImageDetailed(bytes)
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Image operation failed", e)
            MksResult.Error(message = e.message ?: "Failed to read image stream.", exception = e)
        }
    }

fun saveImage(uri: Uri): String? {
        return try {
            context.contentResolver.openInputStream(uri)?.use { input ->
                saveImage(input, uri.lastPathSegment)
            }
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Image operation failed", e)
            null
        }
    }

private fun getImagesDir(): File {
        val dir = File(context.filesDir, "images")
        if (!dir.exists()) dir.mkdirs()
        return dir
    }

private fun isPathInsideImagesDir(path: String): Boolean {
        return try {
            val file = File(path).canonicalFile
            val imagesDir = getImagesDir().canonicalFile
            file == imagesDir || file.toPath().startsWith(imagesDir.toPath())
        } catch (e: Exception) {
            false
        }
    }

private fun isHttpOrHttpsUrl(value: String): Boolean {
        val scheme = runCatching { Uri.parse(value).scheme?.lowercase() }.getOrNull()
        return scheme == "http" || scheme == "https"
    }

fun getFile(path: String?): File? {
        if (path.isNullOrBlank()) return null
        // Security check: only allow files from internal images directory
        if (!isPathInsideImagesDir(path)) return null

        val file = File(path)
        return if (file.exists()) file else null
    }

fun getBase64Image(path: String?): String {
        if (path.isNullOrBlank()) return ""
        if (!isPathInsideImagesDir(path)) return ""

        return try {
            val file = File(path)
            if (!file.exists()) return ""

            val bytes = file.readBytes()
            val mimeType =
                when (file.extension.lowercase()) {
                    "png" -> "image/png"
                    "jpg", "jpeg" -> "image/jpeg"
                    "webp" -> "image/webp"
                    else -> "image/webp"
                }

            "data:$mimeType;base64," + Base64.encodeToString(bytes, Base64.NO_WRAP)
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Image operation failed", e)
            ""
        }
    }

fun deleteImage(path: String?) {
        if (path.isNullOrBlank()) return
        // SECURITY: Only allow deleting files within our images directory
        if (!isPathInsideImagesDir(path)) return

        try {
            val file = File(path).canonicalFile
            if (file.exists()) file.delete()
        } catch (e: Exception) {
            MksLogger.w("FileManager", "Image operation failed", e)
        }
    }

private fun normalizeImageBytes(bytes: ByteArray): NormalizedImageResult {
        if (bytes.isEmpty()) return NormalizedImageResult(error = "Image data is empty.")
        if (bytes.size > MAX_IMAGE_INPUT_BYTES) {
            return NormalizedImageResult(error = "Image exceeds ${MAX_IMAGE_INPUT_BYTES / (1024 * 1024)} MB input limit.")
        }

        val bounds =
            BitmapFactory.Options().apply {
                inJustDecodeBounds = true
            }
        BitmapFactory.decodeByteArray(bytes, 0, bytes.size, bounds)
        val sourceWidth = bounds.outWidth
        val sourceHeight = bounds.outHeight
        if (sourceWidth <= 0 || sourceHeight <= 0) {
            return NormalizedImageResult(error = "Unsupported or invalid image format.")
        }

        val sourcePixels = sourceWidth.toLong() * sourceHeight.toLong()
        if (sourcePixels <= 0L) {
            return NormalizedImageResult(error = "Invalid image dimensions.")
        }

        val decodeOptions =
            BitmapFactory.Options().apply {
                inPreferredConfig = Bitmap.Config.ARGB_8888
                inSampleSize = calculateInSampleSize(sourceWidth, sourceHeight, sourcePixels)
            }

        val decoded =
            BitmapFactory.decodeByteArray(bytes, 0, bytes.size, decodeOptions)
                ?: return NormalizedImageResult(error = "Failed to decode image.")
        val scaled = scaleBitmapIfNeeded(decoded)
        if (scaled !== decoded) {
            decoded.recycle()
        }

        return try {
            ByteArrayOutputStream().use { output ->
                val format =
                    if (scaled.hasAlpha()) {
                        Bitmap.CompressFormat.WEBP_LOSSLESS
                    } else {
                        Bitmap.CompressFormat.WEBP_LOSSY
                    }
                if (!scaled.compress(format, IMAGE_QUALITY, output)) {
                    return NormalizedImageResult(error = "Failed to compress normalized image.")
                }
                NormalizedImageResult(bytes = output.toByteArray())
            }
        } finally {
            scaled.recycle()
        }
    }

private fun writeNormalizedImage(bytes: ByteArray): String? {
        val fileName = "img_${UUID.randomUUID()}.webp"
        val file = File(getImagesDir(), fileName).canonicalFile
        FileOutputStream(file).use { output ->
            output.write(bytes)
        }
        return file.absolutePath
    }

private fun readBytesWithLimit(
        inputStream: InputStream,
        maxBytes: Int,
    ): ByteArray? {
        val buffer = ByteArray(DEFAULT_BUFFER_SIZE)
        var totalRead = 0
        val output = ByteArrayOutputStream()
        while (true) {
            val read = inputStream.read(buffer)
            if (read == -1) break
            totalRead += read
            if (totalRead > maxBytes) {
                return null
            }
            output.write(buffer, 0, read)
        }
        return output.toByteArray()
    }

private fun calculateInSampleSize(
        width: Int,
        height: Int,
        totalPixels: Long,
    ): Int {
        var sampleSize = 1
        while (
            width / sampleSize > MAX_IMAGE_DIMENSION ||
            height / sampleSize > MAX_IMAGE_DIMENSION ||
            totalPixels / (sampleSize.toLong() * sampleSize.toLong()) > MAX_IMAGE_PIXELS
        ) {
            sampleSize *= 2
        }
        return sampleSize.coerceAtLeast(1)
    }

private fun scaleBitmapIfNeeded(bitmap: Bitmap): Bitmap {
        val width = bitmap.width
        val height = bitmap.height
        val largestDimension = maxOf(width, height)
        if (largestDimension <= MAX_IMAGE_DIMENSION) {
            return bitmap
        }

        val scale = MAX_IMAGE_DIMENSION.toFloat() / largestDimension.toFloat()
        val targetWidth = (width * scale).toInt().coerceAtLeast(1)
        val targetHeight = (height * scale).toInt().coerceAtLeast(1)
        return Bitmap.createScaledBitmap(bitmap, targetWidth, targetHeight, true)
    }
}

class ReviewRepository @Inject constructor(
    private val flashcardDao: FlashcardDao,
    private val noteBlueprintDao: NoteBlueprintDao,
    private val mistakeLogDao: MistakeLogDao,
    private val questionDao: QuestionDao,
    private val courseSlideDao: CourseSlideDao,
) {

suspend fun markReviewed(item: ReviewQueueItem) =
        withContext(Dispatchers.IO) {
            val itemId = item.id.toLongOrNull() ?: return@withContext
            val now = System.currentTimeMillis()
            when (item.type) {
                ReviewQueueType.FLASHCARD -> flashcardDao.markReviewed(itemId, now, now + 3L * 24L * 60L * 60L * 1000L)
                ReviewQueueType.BLUEPRINT -> noteBlueprintDao.markReviewed(itemId, now)
                ReviewQueueType.MISTAKE -> mistakeLogDao.markFixed(itemId, now)
                ReviewQueueType.MARKED_QUESTION -> questionDao.clearQuestionMark(itemId, now)
                ReviewQueueType.WEAK_QUESTION -> questionDao.markQuestionReviewed(itemId, now)
                else -> Unit
            }
        }

suspend fun snooze(
        item: ReviewQueueItem,
        millis: Long,
    ) = withContext(Dispatchers.IO) {
        val itemId = item.id.toLongOrNull() ?: return@withContext
        val now = System.currentTimeMillis()
        val due = now + millis
        when (item.type) {
            ReviewQueueType.FLASHCARD -> flashcardDao.snooze(itemId, due, now)
            ReviewQueueType.MISTAKE -> mistakeLogDao.snooze(itemId, due, now)
            ReviewQueueType.BLUEPRINT -> noteBlueprintDao.snoozeBlueprint(itemId, due)
            ReviewQueueType.WEAK_QUESTION -> questionDao.markQuestionReviewed(itemId, now)
            ReviewQueueType.MARKED_QUESTION -> questionDao.snoozeMarkedQuestion(itemId, due, now)
            else -> Unit
        }
    }
}

class CategoryMergePreviewService @Inject constructor(
    private val questionCategoryDao: QuestionCategoryDao,
) {

suspend fun previewMerge(
        source: String,
        target: String,
    ): ChangeSimulationResult {
        val questionsFromSource = questionCategoryDao.getQuestionsByCategory(source)
        val questionsInTarget = questionCategoryDao.getQuestionsByCategory(target).map { it.id }.toSet()

        val toUpdate = questionsFromSource.filter { it.id !in questionsInTarget }
        val toSkip = questionsFromSource.filter { it.id in questionsInTarget }

        return ChangeSimulationResult(
            title = "Merge Category: $source -> $target",
            summary = "This will update ${toUpdate.size} questions and remove the '$source' category metadata.",
            affectedQuestions = toUpdate.size,
            updatedItems = toUpdate.map { SimulatedItem(it.id.toString(), "Question", it.text.take(80)) },
            skippedItems =
                toSkip.map {
                    SimulatedItem(
                        it.id.toString(),
                        "Question",
                        it.text.take(80),
                        reason = "Already has target category",
                    )
                },
        )
    }
}

class DeletePreviewService @Inject constructor(
    private val bookDao: BookDao,
    private val quizDao: QuizDao,
    private val questionDao: QuestionDao,
) {

suspend fun previewQuizDeletion(quizId: Long): ChangeSimulationResult {
        val quiz = quizDao.getQuizById(quizId) ?: return emptyResult("Delete Quiz")
        val questionCount = questionDao.getQuestionsByQuizId(quizId).first().size

        return ChangeSimulationResult(
            title = "Delete Quiz: ${quiz.title}",
            summary = "This will delete the quiz and $questionCount questions.",
            affectedQuizzes = 1,
            affectedQuestions = questionCount,
            deletedItems = listOf(SimulatedItem(quizId.toString(), "Quiz", quiz.title)),
        )
    }

class ClearMarksPreviewService @Inject constructor(
    private val questionDao: QuestionDao,
) {

suspend fun previewClearMarksForQuiz(quizId: Long): ChangeSimulationResult {
        val questions = questionDao.getMarkedQuestionsByQuiz(quizId)
        return ChangeSimulationResult(
            title = "Clear Marked Questions",
            summary = "This will clear marks from ${questions.size} questions in this quiz.",
            affectedQuestions = questions.size,
            updatedItems = questions.map { SimulatedItem(it.id.toString(), "Question", it.text.take(80), reason = it.markReason) },
        )
    }
}

class GlobalErrorHandler @Inject constructor() {
    private val _errorFlow = MutableSharedFlow<MksResult.Error>(extraBufferCapacity = 1)
    val errorFlow = _errorFlow.asSharedFlow()

fun handleError(error: MksResult.Error) {
        MksLogger.e("GlobalErrorHandler", "Error received: ${error.message}", error.exception)
        _errorFlow.tryEmit(error)
    }

fun handleError(message: String, exception: Throwable? = null, code: String? = null) {
        handleError(MksResult.Error(message, exception, code))
    }

fun handleError(exception: Throwable) {
        handleError(exception.message ?: "An unexpected error occurred", exception)
    }
}

class AssetReferenceAuditService @Inject constructor(
    private val assetReferenceDao: AssetReferenceDao,
    private val bookDao: BookDao,
    private val quizDao: QuizDao,
    private val questionDao: QuestionDao,
    private val flashcardDao: FlashcardDao,
    private val courseSlideDao: CourseSlideDao,
    private val sourceDocumentDao: SourceDocumentDao,
    private val questionAssetDao: QuestionAssetDao,
) {

suspend fun audit(): AssetReferenceRepairResult {
        val references = assetReferenceDao.getAllReferences()
        var missingFiles = 0
        var orphanedReferences = 0

        references.forEach { ref: AssetReferenceEntity ->
            if (!File(ref.path).exists()) {
                missingFiles++
            }
            // Check if owner still exists
            val ownerExists =
                when (ref.ownerType) {
                    "book" -> bookDao.getBookById(ref.ownerId) != null
                    "quiz" -> quizDao.getQuizById(ref.ownerId) != null
                    "question" -> questionDao.getQuestionById(ref.ownerId) != null
                    "flashcard_deck" -> true // Assuming deck ID is correct for now
                    "flashcard" -> flashcardDao.getFlashcardById(ref.ownerId) != null
                    "slideshow_course" -> true
                    "course_slide" -> true
                    "source_document" -> sourceDocumentDao.getSourceById(ref.ownerId) != null
                    "question_asset" -> questionAssetDao.getAssetById(ref.ownerId) != null
                    else -> false
                }
            if (!ownerExists) {
                orphanedReferences++
            }
        }

        return AssetReferenceRepairResult(
            checkedPaths = references.size,
            missingFiles = missingFiles,
            orphanedReferences = orphanedReferences,
            deletedReferences = 0,
            deletedFiles = 0,
        )
    }
}

fun validate(session: SessionEntity): SessionValidationResult {
        if (session.questionIds.isEmpty()) {
            return SessionValidationResult(
                isValid = false,
                canBeRepaired = true,
                message = "Session question sequence has not been initialized.",
            )
        }

        if (session.currentQuestionIndex !in session.questionIds.indices) {
            return SessionValidationResult(
                isValid = false,
                canBeRepaired = true,
                message = "Current question index is out of bounds.",
            )
        }

        // Additional checks for timer and other settings can go here

        return SessionValidationResult(isValid = true)
    }
}

fun validate(question: QuestionEntity): QuestionValidationResult {
        val errors = mutableListOf<String>()
        val warnings = mutableListOf<String>()

        if (question.text.isBlank()) {
            errors.add("Question stem cannot be blank.")
        }

        if (question.type == QuestionType.SINGLE_CHOICE || question.type == QuestionType.MULTIPLE_CHOICE) {
            if (question.options.size < 2) {
                errors.add("Multiple choice questions must have at least 2 options.")
            }
            if (question.options.any { it.isBlank() }) {
                errors.add("Question options cannot be blank.")
            }
        }

        if (question.correctAnswers.isEmpty()) {
            errors.add("At least one correct answer must be selected.")
        }

        if (question.correctAnswers.any { it !in question.options.indices }) {
            errors.add("One or more correct answer indices are out of range.")
        }

        if (question.type == QuestionType.SINGLE_CHOICE && question.correctAnswers.size > 1) {
            errors.add("Single choice questions can only have one correct answer.")
        }

        if (question.explanation.isNullOrBlank()) {
            warnings.add("Adding an explanation is recommended for better learning.")
        }

        return QuestionValidationResult(
            isValid = errors.isEmpty(),
            errors = errors,
            warnings = warnings,
        )
    }
}

