fun extractFromText_dataUrl_extractsCorrectly() {
        val dataUrl = "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAUA"
        val result = extractor.extractFromText(dataUrl)
        assertNotNull(result)
