        assertEquals(ImportMode.HTML, detector.detectMode("file.txt", """<img src="test.png">"""))
    }

    @Test

fun detectMode_tabularTsv_returnsSpreadsheet() {
        val tsvContent = "question\tanswer\texplanation\n" +
                "What is 1+1?\t2\tBasic math\n" +
                "What is 2+2?\t4\tAddition\n" +
                "What is 3+3?\t6\tAddition\n" +
                "What is 4+4?\t8\tAddition\n" +
                "What is 5+5?\t10\tAddition"
        assertEquals(ImportMode.SPREADSHEET, detector.detectMode("file.txt", tsvContent))
    }

    // ── Fallback ──

    @Test

fun detectMode_plainText_returnsText() {
        assertEquals(ImportMode.TEXT, detector.detectMode("file.txt", "Just some plain text"))
    }

    @Test

fun detectMode_nullContent_usesExtension() {
        assertEquals(ImportMode.JSON, detector.detectMode("data.json", null))
    }

    @Test

fun detectMode_nullBoth_returnsText() {
        assertEquals(ImportMode.TEXT, detector.detectMode(null, null))
    }

    @Test

fun detectMode_emptyContent_returnsText() {
        assertEquals(ImportMode.TEXT, detector.detectMode(null, ""))
    }

    // ── Extension priority over content ──

    @Test

fun detectMode_xlsxExtension_overridesJsonContent() {
        // Extension should take priority for spreadsheet formats
        assertEquals(
            ImportMode.SPREADSHEET,
            detector.detectMode("data.xlsx", "[{\"question\": \"test\"}]")
        )
    }

    @Test

fun detectMode_caseInsensitiveExtension() {
        // Extensions are lowercased, so .XLSX should also work
        assertEquals(ImportMode.SPREADSHEET, detector.detectMode("data.XLSX", null))
    }
}

fun json_answerParsing_avoidsFalsePositives() {
        val parser = JsonQuestionParser(GenericImageExtractor())

        // Answer "Paris" should match option A (opt_A) textually
        val json =
            """
            {
                "question": "What is the capital of France?",
                "options": ["Paris", "London"],
                "answer": "Paris"
            }
            """.trimIndent()

        val results = parser.parse(json)
        assertEquals(1, results.size)
        val q = results[0]

        assertEquals("opt_A", q.correctAnswers[0])

        // Test with "A" which is a substring of "Paris"
        val json2 =
            """
            {
                "question": "Q",
                "options": ["Paris", "Berlin"],
                "answer": "A"
            }
            """.trimIndent()
        val results2 = parser.parse(json2)
        assertEquals("opt_A", results2[0].correctAnswers[0])

        // Test with an answer that is NOT an option letter and NOT an option text
        val json3 =
            """
            {
                "question": "Q",
                "options": ["Option X", "Option Y"],
                "answer": "Z"
            }
            """.trimIndent()
        val results3 = parser.parse(json3)
        assertTrue("Answer 'Z' should not match any options", results3[0].correctAnswers.isEmpty())
    }

    @Test

class TextSlideParserTest {
    private lateinit var parser: TextSlideParser

    @Before

fun setup() {
        parser = TextSlideParser()
    }

    // ── ALTERNATING_PARAGRAPHS mode ──

    @Test

fun alternating_oddParagraphs_skipsOrphan() {
        val text = """
            Title

            Body

            Orphan
        """.trimIndent()

        val slides = parser.parse(text, courseId = 1L, mode = TextParseMode.ALTERNATING_PARAGRAPHS)
        assertEquals(1, slides.size)
    }

    @Test

fun alternating_emptyInput_returnsEmpty() {
        val slides = parser.parse("", courseId = 1L, mode = TextParseMode.ALTERNATING_PARAGRAPHS)
        assertTrue(slides.isEmpty())
    }

    @Test

fun alternating_correctCourseId() {
        val text = """
            Title

            Body
        """.trimIndent()

        val slides = parser.parse(text, courseId = 99L, mode = TextParseMode.ALTERNATING_PARAGRAPHS)
        assertEquals(99L, slides[0].courseId)
    }

    @Test

fun alternating_hasTimestamps() {
        val text = """
            Title

            Body
        """.trimIndent()

        val before = System.currentTimeMillis()
        val slides = parser.parse(text, courseId = 1L, mode = TextParseMode.ALTERNATING_PARAGRAPHS)
        val after = System.currentTimeMillis()

        assertTrue(slides[0].createdAt in before..after)
        assertTrue(slides[0].updatedAt in before..after)
    }

    // ── EXPLICIT_LABELS mode ──

    @Test

fun explicitLabels_fallbackNoLabels() {
        val text = "Just a paragraph without labels"

        val slides = parser.parse(text, courseId = 1L, mode = TextParseMode.EXPLICIT_LABELS)
        assertEquals(1, slides.size)
        assertEquals("Just a paragraph without labels", slides[0].title)
        assertEquals("", slides[0].body)
    }

    // ── HEADER_BODY_NOTES mode ──

    @Test

fun headerBodyNotes_emptyInput_returnsEmpty() {
        val slides = parser.parse("", courseId = 1L, mode = TextParseMode.HEADER_BODY_NOTES)
        assertTrue(slides.isEmpty())
    }

