        fileManager: FileManager,
    ): ImportLibraryManager {
        return ImportLibraryManager(context, database, fileManager)
    }

    @Provides
    @Singleton
    @ApplicationScope

fun provideApplicationScope(): CoroutineScope {
        return CoroutineScope(Dispatchers.Default)
    }
}

