                onBack = {
                    // Prefer returning to the sessions screen for this quiz if present in backstack
                    val poppedToSessions = navController.popBackStack("sessions/$quizId", inclusive = false)
                    if (!poppedToSessions) {
                        val popped = navController.popBackStack()
                        if (!popped) {
                            navController.navigate("library") {
                                popUpTo("library") { inclusive = true }
                                launchSingleTop = true
                            }
                        }
                    }
                },
            ) { category ->
                navController.navigate("category/${Uri.encode(category)}")
            }
        }

        composable(
            route = "sessions/{quizId}",
            arguments = listOf(navArgument("quizId") { type = NavType.LongType }),
        ) { backStackEntry ->
            val quizId = backStackEntry.requirePositiveLongArg("quizId")
            if (quizId == null) {
                InvalidRouteScreen { navController.popBackStack() }
                return@composable
            }
            val sessionViewModel: SessionViewModel = hiltViewModel()
            val questionsViewModel: QuizQuestionsViewModel = hiltViewModel()

            LaunchedEffect(quizId) {
                questionsViewModel.loadQuiz(quizId)
            }

            val questionsState by questionsViewModel.uiState.collectAsState()

            QuizDetailTabsScreen(
                quizId = quizId,
                quizTitle = questionsState.quiz?.title,
                sessionViewModel = sessionViewModel,
                questionsViewModel = questionsViewModel,
                dataStoreManager = dataStoreManager,
                onSessionSelected = { sessionId, isCompleted ->
                    if (isCompleted) {
                        navController.navigate("summary/$sessionId")
                    } else {
                        navController.navigate("quiz/$quizId?sessionId=$sessionId")
                    }
                },
                onBack = {
                    navController.navigate("library") {
                        popUpTo("library") { inclusive = false }
                        launchSingleTop = true
                        restoreState = true
                    }
                }
            )
        }

        composable(
            route = "scanner/{quizId}",
            arguments = listOf(navArgument("quizId") { type = NavType.LongType }),
        ) { backStackEntry ->
            val quizId = backStackEntry.requirePositiveLongArg("quizId")
            if (quizId == null) {
                InvalidRouteScreen { navController.popBackStack() }
                return@composable
            }
            val scannerViewModel: ScannerViewModel = hiltViewModel()

            ScannerScreen(
                quizId = quizId,
                viewModel = scannerViewModel,
            ) { navController.popBackStack() }
        }

        composable(
            route = "adaptive/{type}/{id}",
            arguments = listOf(
                navArgument("type") { type = NavType.StringType },
                navArgument("id") { type = NavType.StringType },
            ),
        ) { backStackEntry ->
            val type = backStackEntry.requireNonBlankStringArg("type")
            val id = backStackEntry.requireNonBlankStringArg("id")
            if ((type == null) || (id == null)) {
                InvalidRouteScreen { navController.popBackStack() }
                return@composable
            }
            val quizViewModel: QuizViewModel = hiltViewModel()

            LaunchedEffect(type, id) {
                quizViewModel.startAdaptiveTraining(type, id)
            }

            QuizPlayerScreen(
                viewModel = quizViewModel,
                onQuizFinished = { sId, _, _ ->
                    if (sId != -1L) {
                        navController.navigate("summary/$sId") {
                            popUpTo("library") { inclusive = false }
                        }
                    } else {
                        navController.navigate("library") {
                            popUpTo("library") { inclusive = true }
                        }
                    }
                },
                onAskAiClick = { questionId ->
                    quizViewModel.getAskAiPromptDeckId { promptId ->
                        navController.navigate("prompt_deck/$promptId?questionId=$questionId")
                    }
                },
                onBack = {
                    val popped = navController.popBackStack()
                    if (!popped) {
                        navController.navigate("library") {
                            popUpTo("library") { inclusive = true }
                            launchSingleTop = true
                        }
                    }
                },
            )
        }

        composable(
            route = "summary/{sessionId}",
            arguments = listOf(navArgument("sessionId") { type = NavType.LongType }),
        ) { backStackEntry ->
            val sessionId = backStackEntry.requirePositiveLongArg("sessionId")
            if (sessionId == null) {
                InvalidRouteScreen { navController.popBackStack() }
                return@composable
            }
            val summaryViewModel: SummaryViewModel = hiltViewModel()

            SummaryScreen(
                viewModel = summaryViewModel,
                sessionId = sessionId,
                onHomeClick = {
                    navController.navigate("library") {
                        popUpTo("library") { inclusive = true }
                    }
                },
                onRetryClick = { navController.popBackStack() },
            )
        }
    }
}

fun SettingsScreen(
    viewModel: SettingsViewModel = androidx.hilt.navigation.compose.hiltViewModel(),
    onBack: () -> Unit,
    onGlobalSearch: () -> Unit = {},
    onReviewDashboard: () -> Unit = {},
    onDataTools: () -> Unit = {}
) {
    val dataStoreManager = viewModel.dataStoreManager
    val focusManager = viewModel.focusManager
    val scope = rememberCoroutineScope()
    val context = LocalContext.current
    val tokens = LocalMksDesignTokens.current
    val snackbarHostState = remember { SnackbarHostState() }

    val skipUnanswered by dataStoreManager.unansweredSkipEnabled.collectAsState(initial = true)
    val doubleTapToSubmit by dataStoreManager.doubleTapToSubmit.collectAsState(initial = false)
    val showCovers by dataStoreManager.showCovers.collectAsState(initial = true)
    val autoAdvanceDelay by dataStoreManager.autoAdvanceDelay.collectAsState(initial = 2000)
    val currentLanguage by dataStoreManager.language.collectAsState(initial = "en")
    val showWelcomeOnStartup by dataStoreManager.showWelcomeOnStartup.collectAsState(initial = true)

    var showResetDialog by rememberSaveable { mutableStateOf(false) }
    var showClearCategoriesDialog by rememberSaveable { mutableStateOf(false) }

    BackHandler(onBack = onBack)

    val exportLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.CreateDocument("application/zip")
    ) { uri ->
        uri?.let { exportUri ->
            scope.launch {
                withContext(Dispatchers.IO) {
                    context.contentResolver.openOutputStream(exportUri)?.use { stream ->
                        viewModel.exportAllData(stream)
                    }
                }
            }
        }
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.settings_title)) },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(
                            Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = stringResource(R.string.cancel)
                        )
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .padding(padding)
                .fillMaxSize()
                .padding(16.dp)
                .verticalScroll(rememberScrollState()),
            verticalArrangement = Arrangement.spacedBy(24.dp)
        ) {
            SettingsGroup(title = stringResource(R.string.library_backup_group)) {
                Button(
                    onClick = {
                        val timestamp = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.getDefault()).format(java.util.Date())
                        exportLauncher.launch("mks_full_library_$timestamp.zip")
                    },
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.chipRadius)
                ) {
                    Icon(Icons.Default.FileUpload, contentDescription = null)
                    Spacer(Modifier.width(8.dp))
                    Text(stringResource(R.string.export_full_library))
                }
                OutlinedButton(
                    onClick = onDataTools,
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.chipRadius)
                ) {
                    Text("Advanced import/export preview")
                }
                OutlinedButton(
                    onClick = onGlobalSearch,
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.chipRadius)
                ) {
                    Text("Global search")
                }
                OutlinedButton(
                    onClick = onReviewDashboard,
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.chipRadius)
                ) {
                    Text("Review dashboard")
                }
            }

            val themeOptions = listOf(
                ThemeOption("DAWN", R.string.theme_dawn, R.string.theme_dawn_desc),
                ThemeOption("FOREST", R.string.theme_forest, R.string.theme_forest_desc),
                ThemeOption("MIDNIGHT", R.string.theme_midnight, R.string.theme_midnight_desc),
                ThemeOption("LAVENDER", R.string.theme_lavender, R.string.theme_lavender_desc),
                ThemeOption("PLAIN_LIGHT", R.string.theme_plain_light, R.string.theme_plain_light_desc),
                ThemeOption("PLAIN_DARK", R.string.theme_plain_dark, R.string.theme_plain_dark_desc),
                ThemeOption("SYSTEM", R.string.theme_plain_system, R.string.theme_plain_system_desc)
            )
            val currentThemeMode by dataStoreManager.themeMode.collectAsState(initial = "DAWN")
            val savedFontScale by dataStoreManager.fontScale.collectAsState(initial = 1.0f)
            val savedUiDensity by dataStoreManager.uiDensity.collectAsState(initial = 1.0f)

            var fontScale by remember(savedFontScale) { mutableStateOf(savedFontScale) }
            var uiDensity by remember(savedUiDensity) { mutableStateOf(savedUiDensity) }

            SettingsGroup(
                title = stringResource(R.string.appearance_group),
                actions = {
                    TextButton(onClick = {
                        scope.launch {
                            dataStoreManager.setThemeMode("DAWN")
                            dataStoreManager.setFontScale(1.0f)
                            dataStoreManager.setUiDensity(1.0f)
                        }
                    }) {
                        Icon(Icons.Default.Refresh, null, modifier = Modifier.size(18.dp))
                        Spacer(Modifier.width(4.dp))
                        Text(stringResource(R.string.reset))
                    }
                }
            ) {
                Text(stringResource(R.string.theme_label), style = MaterialTheme.typography.labelLarge)

                var themeExpanded by remember { mutableStateOf(false) }
                val currentThemeOption = themeOptions.find { it.key == currentThemeMode } ?: themeOptions.last()

                ExposedDropdownMenuBox(
                    expanded = themeExpanded,
                    onExpandedChange = { themeExpanded = it },
                    modifier = Modifier.fillMaxWidth()
                ) {
                    OutlinedTextField(
                        value = stringResource(currentThemeOption.labelRes),
                        onValueChange = {},
                        readOnly = true,
                        label = { Text(stringResource(R.string.theme_label)) },
                        trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = themeExpanded) },
                        colors = ExposedDropdownMenuDefaults.outlinedTextFieldColors(),
                        modifier = Modifier
                            .menuAnchor(MenuAnchorType.PrimaryNotEditable)
                            .fillMaxWidth()
                    )
                    ExposedDropdownMenu(
                        expanded = themeExpanded,
                        onDismissRequest = { themeExpanded = false }
                    ) {
                        themeOptions.forEach { option ->
                            DropdownMenuItem(
                                text = {
                                    Column {
                                        Text(stringResource(option.labelRes))
                                        Text(
                                            text = stringResource(option.descriptionRes),
                                            style = MaterialTheme.typography.labelSmall,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }
                                },
                                onClick = {
                                    scope.launch { dataStoreManager.setThemeMode(option.key) }
                                    themeExpanded = false
                                },
                                contentPadding = ExposedDropdownMenuDefaults.ItemContentPadding
                            )
                        }
                    }
                }

                HorizontalDivider(modifier = Modifier.padding(vertical = 4.dp))

                Column(modifier = Modifier.fillMaxWidth()) {
                    Text(stringResource(R.string.font_scale_format, fontScale), style = MaterialTheme.typography.labelLarge)
                    Slider(
                        value = fontScale,
                        onValueChange = { fontScale = it },
                        onValueChangeFinished = { scope.launch { dataStoreManager.setFontScale(fontScale) } },
                        valueRange = 0.5f..2.0f,
                        steps = 14
                    )
                }

                Column(modifier = Modifier.fillMaxWidth()) {
                    Text(stringResource(R.string.ui_density_format, uiDensity), style = MaterialTheme.typography.labelLarge)
                    Slider(
                        value = uiDensity,
                        onValueChange = { uiDensity = it },
                        onValueChangeFinished = { scope.launch { dataStoreManager.setUiDensity(uiDensity) } },
                        valueRange = 0.5f..1.5f,
                        steps = 10
                    )
                }

                SettingsToggle(
                    title = stringResource(R.string.show_cover_images),
                    description = stringResource(R.string.show_cover_images_desc),
                    checked = showCovers,
                    onCheckedChange = { scope.launch { dataStoreManager.setShowCovers(it) } }
                )

                HorizontalDivider(modifier = Modifier.padding(vertical = 4.dp))

                Text(stringResource(R.string.language_label), style = MaterialTheme.typography.labelLarge)
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    FilterChip(
                        selected = currentLanguage == "en",
                        onClick = { scope.launch { dataStoreManager.setLanguage("en") } },
                        label = { Text(stringResource(R.string.language_en)) }
                    )
                    FilterChip(
                        selected = currentLanguage == "ar",
                        onClick = { scope.launch { dataStoreManager.setLanguage("ar") } },
                        label = { Text(stringResource(R.string.language_ar)) }
                    )
                }
            }

            SettingsGroup(title = stringResource(R.string.global_config_group)) {
                Text(
                    stringResource(R.string.global_config_desc),
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )

                SettingsToggle(
                    title = stringResource(R.string.show_welcome_screen),
                    description = stringResource(R.string.show_welcome_screen_desc),
                    checked = showWelcomeOnStartup,
                    onCheckedChange = { scope.launch { dataStoreManager.setShowWelcomeOnStartup(it) } }
                )

                val focusModeEnabled by dataStoreManager.focusModeEnabled.collectAsState(initial = false)
                var hasFocusPermission by remember { mutableStateOf(focusManager.hasNotificationPolicyAccess()) }

                SettingsToggle(
                    title = stringResource(R.string.focus_mode_label),
                    description = stringResource(R.string.focus_mode_desc),
                    checked = focusModeEnabled,
                    onCheckedChange = { enabled ->
                        if (enabled && !focusManager.hasNotificationPolicyAccess()) {
                            focusManager.requestNotificationPolicyAccess()
                            hasFocusPermission = focusManager.hasNotificationPolicyAccess()
                        } else {
                            scope.launch { dataStoreManager.setFocusModeEnabled(enabled) }
                        }
                    }
                )

                if (focusModeEnabled && !hasFocusPermission) {
                    TextButton(
                        onClick = {
                            focusManager.requestNotificationPolicyAccess()
                            hasFocusPermission = focusManager.hasNotificationPolicyAccess()
                        },
                        modifier = Modifier.padding(start = 8.dp)
                    ) {
                        Icon(Icons.Default.Settings, null, modifier = Modifier.size(18.dp))
                        Spacer(Modifier.width(8.dp))
                        Text(stringResource(R.string.grant_permission), style = MaterialTheme.typography.labelMedium)
                    }
                }

                SettingsToggle(
                    title = stringResource(R.string.skip_answered_label),
                    description = stringResource(R.string.skip_answered_desc),
                    checked = skipUnanswered,
                    onCheckedChange = { scope.launch { dataStoreManager.setUnansweredSkipEnabled(it) } }
                )

                SettingsToggle(
                    title = stringResource(R.string.double_tap_submit_label),
                    description = stringResource(R.string.double_tap_submit_desc),
                    checked = doubleTapToSubmit,
                    onCheckedChange = { scope.launch { dataStoreManager.setDoubleTapToSubmit(it) } }
                )

                Column(modifier = Modifier.fillMaxWidth()) {
                    Text(stringResource(R.string.rapid_advance_delay_format, autoAdvanceDelay), style = MaterialTheme.typography.labelLarge)
                    Slider(
                        value = autoAdvanceDelay.toFloat(),
                        onValueChange = { scope.launch { dataStoreManager.setAutoAdvanceDelay(it.toInt()) } },
                        valueRange = 500f..5000f,
                        steps = 8
                    )
                }
            }

            val ollamaBaseUrl by dataStoreManager.ollamaBaseUrl.collectAsState(initial = "http://10.0.2.2:11434")
            val ollamaModelName by dataStoreManager.ollamaModelName.collectAsState(initial = "llama3")
            val ollamaApiKey by dataStoreManager.ollamaApiKey.collectAsState(initial = "")
            var editOllamaBaseUrl by remember(ollamaBaseUrl) { mutableStateOf(ollamaBaseUrl) }
            var editOllamaModelName by remember(ollamaModelName) { mutableStateOf(ollamaModelName) }
            var editOllamaApiKey by remember(ollamaApiKey) { mutableStateOf(ollamaApiKey) }
            var isTestingOllama by remember { mutableStateOf(false) }

            SettingsGroup(title = "AI Integrations") {
                Text(
                    "Configure local LLM settings for the AI Prompt Deck. Ollama is recommended. For Android Emulators, use http://10.0.2.2:11434. A remote server can be reached via its http(s) URL; add an API key if it is protected by a reverse proxy.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )

                OutlinedTextField(
                    value = editOllamaBaseUrl,
                    onValueChange = { editOllamaBaseUrl = it },
                    label = { Text("Ollama Base URL") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true
                )
                OutlinedTextField(
                    value = editOllamaModelName,
                    onValueChange = { editOllamaModelName = it },
                    label = { Text("Ollama Model Name (e.g. llama3)") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true
                )
                OutlinedTextField(
                    value = editOllamaApiKey,
                    onValueChange = { editOllamaApiKey = it },
                    label = { Text("API Key (optional, for secured servers)") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true
                )
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp, Alignment.End)
                ) {
                    OutlinedButton(
                        enabled = !isTestingOllama,
                        onClick = {
                            scope.launch {
                                isTestingOllama = true
                                val result = viewModel.ollamaRepository.testConnection(
                                    baseUrl = editOllamaBaseUrl,
                                    modelName = editOllamaModelName,
                                    apiKey = editOllamaApiKey.takeIf { it.isNotBlank() }
                                )
                                isTestingOllama = false
                                snackbarHostState.showSnackbar(result.message)
                            }
                        }
                    ) {
                        Text(if (isTestingOllama) "Testing..." else "Test Connection")
                    }
                    Button(
                        onClick = {
                            scope.launch {
                                dataStoreManager.setOllamaBaseUrl(editOllamaBaseUrl)
                                dataStoreManager.setOllamaModelName(editOllamaModelName)
                                dataStoreManager.setOllamaApiKey(editOllamaApiKey)
                                snackbarHostState.showSnackbar("AI settings saved")
                            }
                        }
                    ) {
                        Text("Save Settings")
                    }
                }
            }

            SettingsGroup(title = stringResource(R.string.danger_zone_group), titleColor = MaterialTheme.colorScheme.error) {
                OutlinedButton(
                    onClick = { showClearCategoriesDialog = true },
                    modifier = Modifier.fillMaxWidth(),
                    colors = ButtonDefaults.outlinedButtonColors(
                        contentColor = MaterialTheme.colorScheme.error
                    )
                ) {
                    Icon(Icons.Default.DeleteForever, contentDescription = null)
                    Spacer(Modifier.width(8.dp))
                    Column(horizontalAlignment = Alignment.Start) {
                        Text(stringResource(R.string.clear_categories))
                    }
                }

                Button(
                    onClick = { showResetDialog = true },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer,
                        contentColor = MaterialTheme.colorScheme.onErrorContainer
                    ),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Icon(Icons.Default.DeleteForever, contentDescription = null)
                    Spacer(Modifier.width(8.dp))
                    Text(stringResource(R.string.reset_database))
                }
            }
        }
    }

    if (showClearCategoriesDialog) {
        AlertDialog(
            onDismissRequest = { showClearCategoriesDialog = false },
            title = { Text(stringResource(R.string.clear_categories_title)) },
            text = { Text(stringResource(R.string.clear_categories_msg)) },
            confirmButton = {
                TextButton(
                    onClick = {
                        showClearCategoriesDialog = false
                        viewModel.clearCategories()
                        scope.launch {
                            snackbarHostState.showSnackbar(context.getString(R.string.clear_categories_success))
                        }
                    }
                ) {
                    Text(stringResource(R.string.clear_categories), color = MaterialTheme.colorScheme.error)
                }
            },
            dismissButton = {
                TextButton(onClick = { showClearCategoriesDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showResetDialog) {
        AlertDialog(
            onDismissRequest = { showResetDialog = false },
            title = { Text(stringResource(R.string.reset_database_title)) },
            text = { Text(stringResource(R.string.reset_database_msg)) },
            confirmButton = {
                TextButton(
                    onClick = {
                        viewModel.resetDatabase()
                        showResetDialog = false
                    }
                ) {
                    Text(stringResource(R.string.reset), color = MaterialTheme.colorScheme.error)
                }
            },
            dismissButton = {
                TextButton(onClick = { showResetDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }
}

private data class ThemeOption(
    val key: String,
    val labelRes: Int,
    val descriptionRes: Int
)

fun SettingsGroup(
    title: String,
    titleColor: Color = MaterialTheme.colorScheme.primary,
    actions: @Composable (RowScope.() -> Unit)? = null,
    content: @Composable ColumnScope.() -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    Column(modifier = Modifier.fillMaxWidth()) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 8.dp, start = 4.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Text(
                text = title,
                style = MaterialTheme.typography.titleMedium,
                color = titleColor
            )
            actions?.invoke(this)
        }
        Card(
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(tokens.cardRadius),
            elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation),
            colors = CardDefaults.cardColors(
                containerColor = MaterialTheme.colorScheme.surfaceContainerLow
            )
        ) {
            Column(
                modifier = Modifier
                    .padding(16.dp)
                    .fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                content()
            }
        }
    }
}

fun SettingsToggle(
    title: String,
    description: String,
    checked: Boolean,
    onCheckedChange: (Boolean) -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Text(title, style = MaterialTheme.typography.bodyLarge)
            Text(description, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
        }
        Switch(checked = checked, onCheckedChange = onCheckedChange)
    }
}

class SettingsViewModel @Inject constructor(
    private val exportManager: ExportManager,
    private val workspaceRepository: WorkspaceRepository,
    private val quizRepository: QuizRepository,
    private val assetRepository: AssetRepository,
    val ollamaRepository: OllamaRepository,
    val dataStoreManager: DataStoreManager,
    val focusManager: FocusManager
) : ViewModel() {

    private val _isExporting = MutableStateFlow(false)
    val isExporting = _isExporting.asStateFlow()

    private val _exportMessage = MutableStateFlow<String?>(null)
    val exportMessage = _exportMessage.asStateFlow()

    private val _isResetting = MutableStateFlow(false)
    val isResetting = _isResetting.asStateFlow()

fun clearExportMessage() {
        _exportMessage.value = null
    }

fun exportAllData(stream: OutputStream) {
        viewModelScope.launch(Dispatchers.IO) {
            _isExporting.value = true
            _exportMessage.value = "Exporting data... please wait."
            try {
                val result = exportManager.exportAllToZip(stream)
                _exportMessage.value = if (result.success) {
                    "Export completed successfully."
                } else {
                    "Export failed: ${result.errorMessage}"
                }
            } catch (e: Exception) {
                _exportMessage.value = "Error during export: ${e.message}"
            } finally {
                _isExporting.value = false
                stream.close()
            }
        }
    }

fun resetDatabase() {
        viewModelScope.launch(Dispatchers.IO) {
            _isResetting.value = true
            try {
                workspaceRepository.resetDatabase()
            } catch (e: Exception) {
                e.printStackTrace()
            } finally {
                _isResetting.value = false
            }
        }
    }

fun clearCategories() {
        viewModelScope.launch(Dispatchers.IO) {
            quizRepository.clearAllCategories()
        }
    }

fun rebuildDerivedIndexes() {
        viewModelScope.launch(Dispatchers.IO) {
            assetRepository.rebuildDerivedIndexes()
        }
    }
}

class ImportViewModel @Inject constructor(
    private val quizRepository: QuizRepository
) : ViewModel() {

    private val _importState = MutableStateFlow<ImportState>(ImportState.Idle)
    val importState: StateFlow<ImportState> = _importState

fun detectFormat(uri: Uri): ImportFormat {
        return quizRepository.detectFormat(uri)
    }

fun getImportPreview(uri: Uri, targetBookId: Long? = null, targetQuizId: Long? = null) {
        viewModelScope.launch {
            _importState.value = ImportState.Loading(0.1f, "Preparing preview...")
            try {
                val preview = quizRepository.getImportPreview(uri)
                    ?: throw Exception("Could not load preview")
                _importState.value = ImportState.Review(preview, uri, targetBookId, targetQuizId)
            } catch (e: Exception) {
                _importState.value = ImportState.Error(e.message ?: "Failed to load preview")
            }
        }
    }

fun importLibrary(
        uri: Uri,
        strategy: MergeStrategy = MergeStrategy.SKIP_EXISTING,
        targetBookId: Long? = null,
        targetQuizId: Long? = null,
        allowInsecureRemoteImages: Boolean = false,
        activeWorkspaceId: Long? = null
    ) {
        viewModelScope.launch {
            _importState.value = ImportState.Loading(0f, "Starting import...")
            try {
                val result = quizRepository.importFromUri(
                    uri = uri,
                    strategy = strategy,
                    targetBookId = targetBookId,
                    targetQuizId = targetQuizId,
                    allowInsecureRemoteImages = allowInsecureRemoteImages,
                    activeWorkspaceId = activeWorkspaceId
                ) { progress, message ->
                    _importState.value = ImportState.Loading(progress, message)
                }

                when (result) {
                    is MksResult.Success -> {
                        _importState.value = ImportState.Success(result.data)
                    }

                    is MksResult.Error -> {
                        _importState.value = ImportState.Error(result.message)
                    }

                    null -> {
                        _importState.value = ImportState.Error("Import manager not available")
                    }
                }
            } catch (e: Exception) {
                _importState.value = ImportState.Error(e.message ?: "Critical import failure")
            }
        }
    }

fun resetState() {
        _importState.value = ImportState.Idle
    }

data class Error(val message: String) : ImportState()
    }
}

class CategoryQuestionsViewModel @Inject constructor(
    private val knowledgeRepository: KnowledgeRepository,
    private val assetRepository: AssetRepository,
    private val quizRepository: QuizRepository,
    private val studyRepository: StudyRepository
) : ViewModel() {

    private val _categoryName = MutableStateFlow("")
    private val _searchQuery = MutableStateFlow("")
    private val _visibility = MutableStateFlow(VisibilityState())
    private val _isLoading = MutableStateFlow(value = false)
    private val _selectedQuestionIds = MutableStateFlow<Set<Long>>(emptySet())
    private val _questionIdsWithAssets = assetRepository.getQuestionIdsWithAssetsFlow()
        .map { it.toSet() }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptySet())

    val allQuizzes: StateFlow<List<QuizEntity>> = quizRepository.getAllQuizzesFlow()
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    private val _allQuestions = _categoryName
        .filter { it.isNotBlank() }
        .onEach { _isLoading.value = true }
        .flatMapLatest { category ->
            quizRepository.getQuestionsByCategoryFlow(category)
        }
        .onEach { _isLoading.value = false }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    val uiState: StateFlow<CategoryQuestionsUiState> = combine(
        _categoryName,
        _allQuestions,
        _searchQuery,
        _visibility,
        _isLoading,
        _selectedQuestionIds,
        _questionIdsWithAssets
    ) { args: Array<Any> ->
        val category = args[0] as String
        @Suppress("UNCHECKED_CAST")
        val questions = args[1] as List<QuestionEntity>
        val query = args[2] as String
        val visibility = args[3] as VisibilityState
        val loading = args[4] as Boolean
        @Suppress("UNCHECKED_CAST")
        val selectedIds = args[5] as Set<Long>
        @Suppress("UNCHECKED_CAST")
        val assetIds = args[6] as Set<Long>

        CategoryQuestionsUiState(
            categoryName = category,
            allQuestions = questions,
            filteredQuestions = applyFilter(questions, query, visibility.showOnlyMarked, visibility.showOnlyWithAssets, assetIds),
            searchQuery = query,
            visibility = visibility,
            isLoading = loading,
            selectedQuestionIds = selectedIds,
            questionIdsWithAssets = assetIds
        )
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), CategoryQuestionsUiState())

fun loadCategory(category: String) {
        _categoryName.value = category
    }

fun setSearchQuery(query: String) {
        _searchQuery.value = query
    }

fun toggleSelection(questionId: Long) {
        _selectedQuestionIds.update { current ->
            if (current.contains(questionId)) current - questionId else current + questionId
        }
    }

fun clearSelection() {
        _selectedQuestionIds.value = emptySet()
    }

fun deleteSelectedQuestions() {
        val idsToDelete = _selectedQuestionIds.value.toList()
        if (idsToDelete.isEmpty()) return

        viewModelScope.launch {
            _isLoading.value = true
            // Fetch fresh questions by IDs to ensure we have correct image paths and quiz IDs for cleanup
            val questionsToDelete = quizRepository.getQuestionsByIds(idsToDelete)
            val affectedQuizIds = questionsToDelete.asSequence()
                .map { it.quizId }
                .distinct()
                .toList()
            questionsToDelete.forEach { question ->
                quizRepository.deleteQuestion(question)
            }
            affectedQuizIds.forEach { quizRepository.refreshQuizStats(it) }
            clearSelection()
            _isLoading.value = false
        }
    }

fun moveSelectedQuestionsToQuiz(targetQuizId: Long) {
        val idsToMove = _selectedQuestionIds.value
        if (idsToMove.isEmpty()) return

        viewModelScope.launch {
            val questionsToMove = _allQuestions.value.filter { it.id in idsToMove }
            val affectedQuizIds = questionsToMove.asSequence()
                .map { it.quizId }
                .distinct()
                .toList()
            questionsToMove.forEach { question ->
                assetRepository.updateQuestion(question.copy(quizId = targetQuizId, updatedAt = System.currentTimeMillis()))
            }
            affectedQuizIds.forEach { quizRepository.refreshQuizStats(it) }
            quizRepository.refreshQuizStats(targetQuizId)
            clearSelection()
        }
    }

fun copySelectedQuestionsToQuiz(targetQuizId: Long) {
        val idsToCopy = _selectedQuestionIds.value
        if (idsToCopy.isEmpty()) return

        viewModelScope.launch {
            val questionsToCopy = _allQuestions.value.filter { it.id in idsToCopy }
            val newQuestions = questionsToCopy.map { question ->
                question.copy(
                    id = 0,
                    quizId = targetQuizId,
                    externalId = java.util.UUID.randomUUID().toString(),
                    createdAt = System.currentTimeMillis(),
                    updatedAt = System.currentTimeMillis()
                )
            }
            knowledgeRepository.insertQuestions(newQuestions)
            quizRepository.refreshQuizStats(targetQuizId)
            clearSelection()
        }
    }

fun exportSelectedQuestionsToNewQuiz(title: String) {
        val idsToExport = _selectedQuestionIds.value
        if (idsToExport.isEmpty() || title.isBlank()) return

        viewModelScope.launch {
            val questionsToExport = _allQuestions.value.filter { it.id in idsToExport }
            val sourceQuizId = questionsToExport.firstOrNull()?.quizId ?: return@launch
            val sourceQuiz = allQuizzes.value.firstOrNull { it.id == sourceQuizId } ?: quizRepository.getQuizById(sourceQuizId)
            val sourceBookId = sourceQuiz?.bookId ?: return@launch
            val newQuizId = knowledgeRepository.insertQuiz(
                QuizEntity(
                    bookId = sourceBookId,
                    externalId = java.util.UUID.randomUUID().toString(),
                    title = title.trim(),
                    description = "Exported from category: ${_categoryName.value}"
                )
            )
            val newQuestions = questionsToExport.map { question ->
                question.copy(
                    id = 0,
                    quizId = newQuizId,
                    externalId = java.util.UUID.randomUUID().toString(),
                    createdAt = System.currentTimeMillis(),
                    updatedAt = System.currentTimeMillis()
                )
            }
            knowledgeRepository.insertQuestions(newQuestions)
            quizRepository.refreshQuizStats(newQuizId)
            clearSelection()
        }
    }

fun markSelectedQuestions(marked: Boolean) {
        val idsToMark = _selectedQuestionIds.value
        if (idsToMark.isEmpty()) return

        viewModelScope.launch {
            val questionsToMark = _allQuestions.value.filter { it.id in idsToMark }
            questionsToMark.forEach { question ->
                assetRepository.updateQuestion(question.copy(isMarked = marked, updatedAt = System.currentTimeMillis()))
            }
            clearSelection()
        }
    }

fun updateQuestion(question: QuestionEntity) {
        viewModelScope.launch {
            assetRepository.updateQuestion(question.copy(updatedAt = System.currentTimeMillis()))
            quizRepository.refreshQuizStats(question.quizId)
        }
    }

fun toggleAllSelection() {
        val currentSelected = _selectedQuestionIds.value
        val allVisibleIds = uiState.value.filteredQuestions.map { it.id }.toSet()

        if (currentSelected.containsAll(allVisibleIds)) {
            _selectedQuestionIds.value = emptySet()
        } else {
            _selectedQuestionIds.value = allVisibleIds
        }
    }

private fun applyFilter(questions: List<QuestionEntity>, query: String, onlyMarked: Boolean, onlyWithAssets: Boolean, questionIdsWithAssets: Set<Long>): List<QuestionEntity> {
        var filtered = questions
        if (onlyMarked) {
            filtered = filtered.filter { it.isMarked }
        }
        if (onlyWithAssets) {
            filtered = filtered.filter { it.id in questionIdsWithAssets }
        }
        if (query.isBlank()) return filtered

        return filtered.filter { q ->
            q.text.contains(query, ignoreCase = true) ||
            q.options.any { it.contains(query, ignoreCase = true) } ||
            (q.explanation?.contains(query, ignoreCase = true) ?: false) ||
            (q.additionalInfo?.contains(query, ignoreCase = true) ?: false)
        }
    }

fun toggleVisibility(update: VisibilityState.() -> VisibilityState) {
        _visibility.update { it.update() }
    }

fun toggleMarked(question: QuestionEntity) {
        viewModelScope.launch {
            assetRepository.updateQuestion(question.copy(isMarked = !question.isMarked))
        }
    }

fun addQuestionAnnotation(bookId: Long, questionId: Long, selectedText: String?, noteBody: String, colorLabel: String = AnnotationColorLabel.YELLOW) {
        viewModelScope.launch {
            assetRepository.createAnnotationForOwner(
                bookId = bookId,
                ownerType = AnnotationOwnerType.QUESTION,
                ownerId = questionId,
                selectedText = selectedText,
                noteBody = noteBody,
                colorLabel = colorLabel
            )
        }
    }

fun updateAnnotation(annotation: AnnotationEntity) {
        viewModelScope.launch { studyRepository.updateAnnotation(annotation) }
    }

fun deleteAnnotation(annotation: AnnotationEntity) {
        viewModelScope.launch { assetRepository.softDeleteAnnotation(annotation.id) }
    }

fun addQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.insertQuestionAsset(asset) }
    }

fun createSourceAndAddQuestionAsset(asset: QuestionAssetEntity, source: SourceDocumentEntity) {
        viewModelScope.launch {
            val preparedSource = source.copy(
                sourceType = source.sourceType.ifBlank { SourceDocumentTypes.OTHERS },
                bookId = source.bookId ?: asset.bookId
            )
            assetRepository.createSourceDocumentAndQuestionAsset(preparedSource, asset.copy(assetType = QuestionAssetType.SOURCE_REFERENCE))
        }
    }

fun createBlueprintFromQuestion(bookId: Long, questionId: Long) {
        viewModelScope.launch { knowledgeRepository.createBlueprintFromQuestion(bookId, questionId, BlueprintMode.CONCEPT_TEMPLATE) }
    }

fun updateQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.updateQuestionAsset(asset) }
    }

fun deleteQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.deleteQuestionAsset(asset) }
    }

fun createFlashcardsFromSelected(title: String, clearMarksAfter: Boolean) {
        val selected = _selectedQuestionIds.value.toList()
        if (selected.isEmpty() || title.isBlank()) return
        viewModelScope.launch {
            val questions = quizRepository.getQuestionsByIds(selected)
            val sourceQuiz = questions.firstOrNull()?.let { quizRepository.getQuizById(it.quizId) } ?: return@launch
            knowledgeRepository.createFlashcardDeckFromQuestions(sourceQuiz.bookId, title, "Generated from selected questions", selected, clearMarksAfter)
            clearSelection()
        }
    }
}

fun CategoryChip(
    category: CategoryWithMetadata,
    isSelected: Boolean = false,
    onCategorySelected: (CategoryWithMetadata) -> Unit,
    onCategoryLongClick: (CategoryWithMetadata) -> Unit
) {
    val haptic = LocalHapticFeedback.current
    val isDark = isSystemInDarkTheme()
    val hasEmoji = category.emoji != null || (category.name.trim().firstOrNull()?.let { it.code > 127 } ?: false)
    val customColor = category.color?.let { Color(it) }

    val containerColor = when {
        isSelected -> MaterialTheme.colorScheme.primary
        category.isPinned -> MaterialTheme.colorScheme.primaryContainer
        customColor != null -> if (isDark) customColor.copy(alpha = 0.3f) else customColor.copy(alpha = 0.15f)
        else -> MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
    }

    val contentColor = when {
        isSelected -> MaterialTheme.colorScheme.onPrimary
        category.isPinned -> MaterialTheme.colorScheme.onPrimaryContainer
        customColor != null -> if (isDark) {
            customColor
        } else customColor
        else -> MaterialTheme.colorScheme.onSurfaceVariant
    }

    Surface(
        shape = RoundedCornerShape(12.dp),
        color = containerColor,
        contentColor = contentColor,
        border = when {
            isSelected -> BorderStroke(2.dp, MaterialTheme.colorScheme.primaryContainer)
            category.isPinned -> BorderStroke(1.dp, MaterialTheme.colorScheme.primary)
            customColor != null -> BorderStroke(1.dp, customColor.copy(alpha = 0.5f))
            else -> null
        },
        modifier = Modifier.combinedClickable(
            onClick = { onCategorySelected(category) },
            onLongClick = {
                haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                onCategoryLongClick(category)
            }
        )
    ) {
        Row(
            modifier = Modifier.padding(horizontal = 12.dp, vertical = 8.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            val emoji = category.emoji
            if (emoji != null) {
                Text(emoji)
            } else if (!hasEmoji) {
                Icon(
                    Icons.AutoMirrored.Rounded.FactCheck,
                    contentDescription = null,
                    modifier = Modifier.size(16.dp),
                    tint = contentColor
                )
            }

            Text(
                text = category.name,
                style = MaterialTheme.typography.labelLarge,
                color = contentColor,
                modifier = Modifier.weight(1f),
                maxLines = 1,
                overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis
            )

            if (category.questionCount > 0) {
                Surface(
                    color = contentColor.copy(alpha = 0.1f),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Text(
                        text = category.questionCount.toString(),
                        style = MaterialTheme.typography.labelSmall,
                        modifier = Modifier.padding(horizontal = 6.dp, vertical = 2.dp),
                        color = contentColor,
                        maxLines = 1
                    )
                }
            }

            if (category.isPinned) {
                Icon(
                    Icons.Rounded.PushPin,
                    contentDescription = "Pinned",
                    modifier = Modifier.size(14.dp),
                    tint = contentColor
                )
            }
        }
    }
}

fun CategoryBrowserDialog(
    categories: List<CategoryWithMetadata>,
    onDismiss: () -> Unit,
    onCategorySelected: (CategoryWithMetadata) -> Unit,
    onCategoryLongClick: (CategoryWithMetadata) -> Unit = {}
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.categories_header)) },
        text = {
            LazyVerticalGrid(
                columns = GridCells.Adaptive(minSize = 100.dp),
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(max = 400.dp),
                contentPadding = PaddingValues(4.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(categories, key = { it.name }) { category ->
                    CategoryChip(
                        category = category,
                        onCategorySelected = onCategorySelected,
                        onCategoryLongClick = onCategoryLongClick
                    )
                }
            }
        },
        confirmButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

fun CategoryEditDialog(
    category: CategoryWithMetadata,
    allCategories: List<CategoryWithMetadata>,
    books: List<BookEntity>,
    onDismiss: () -> Unit,
    onDelete: () -> Unit,
    onRename: (String) -> Unit,
    onMerge: (String) -> Unit,
    onGetMergePreview: suspend (String) -> Int,
    onCreateQuiz: (String, Long) -> Unit,
    onTogglePin: () -> Unit,
    onUpdateEmoji: (String?) -> Unit,
    onUpdateColor: (Int?) -> Unit,
    onViewQuestions: () -> Unit
) {
    var showDeleteConfirm by rememberSaveable { mutableStateOf(false) }
    var showRenameDialog by rememberSaveable { mutableStateOf(false) }
    var showMergeDialog by rememberSaveable { mutableStateOf(false) }
    var showCreateQuizDialog by rememberSaveable { mutableStateOf(false) }
    var showEmojiPicker by rememberSaveable { mutableStateOf(false) }
    var showColorPicker by rememberSaveable { mutableStateOf(false) }
    var showInfo by rememberSaveable { mutableStateOf(false) }

    if (showDeleteConfirm) {
        AlertDialog(
            onDismissRequest = { showDeleteConfirm = false },
            title = { Text(stringResource(R.string.delete_category_title)) },
            text = { Text(stringResource(R.string.delete_category_msg, category.name)) },
            confirmButton = {
                TextButton(onClick = onDelete, colors = ButtonDefaults.textButtonColors(contentColor = MaterialTheme.colorScheme.error)) {
                    Text(stringResource(R.string.delete))
                }
            },
            dismissButton = {
                TextButton(onClick = { showDeleteConfirm = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showRenameDialog) {
        var newName by rememberSaveable { mutableStateOf(category.name) }
        AlertDialog(
            onDismissRequest = { showRenameDialog = false },
            title = { Text(stringResource(R.string.rename_category_title)) },
            text = {
                OutlinedTextField(
                    value = newName,
                    onValueChange = { newName = it },
                    label = { Text(stringResource(R.string.new_name_label)) },
                    modifier = Modifier.fillMaxWidth()
                )
            },
            confirmButton = {
                TextButton(onClick = { 
                    if (allCategories.any { it.name == newName } && newName != category.name) {
                        showRenameDialog = false
                        showMergeDialog = true
                    } else {
                        onRename(newName)
                        showRenameDialog = false
                    }
                }) {
                    Text(stringResource(R.string.rename))
                }
            },
            dismissButton = {
                TextButton(onClick = { showRenameDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showMergeDialog) {
        var targetCategory by rememberSaveable(allCategories) { 
            mutableStateOf(allCategories.firstOrNull { it.name != category.name }?.name ?: "") 
        }
        var mergeCount by remember { mutableIntStateOf(0) }

        LaunchedEffect(targetCategory) {
            if (targetCategory.isNotBlank()) {
                mergeCount = onGetMergePreview(targetCategory)
            }
        }

        AlertDialog(
            onDismissRequest = { showMergeDialog = false },
            title = { Text(stringResource(R.string.merge_category_title)) },
            text = {
                Column {
                    Text(stringResource(R.string.merge_into_prefix, category.name))
                    Spacer(modifier = Modifier.height(8.dp))
                    allCategories.filter { it.name != category.name }.forEach { cat ->
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.fillMaxWidth().clickable { targetCategory = cat.name }.padding(8.dp)
                        ) {
                            RadioButton(selected = targetCategory == cat.name, onClick = { targetCategory = cat.name })
                            Text(cat.name)
                        }
                    }
                    if (targetCategory.isNotBlank()) {
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            stringResource(R.string.merge_count_msg, mergeCount, targetCategory),
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.primary
                        )
                    }
                }
            },
            confirmButton = {
                TextButton(onClick = { 
                    onMerge(targetCategory)
                    showMergeDialog = false
                }, enabled = targetCategory.isNotBlank()) {
                    Text(stringResource(R.string.merge))
                }
            },
            dismissButton = {
                TextButton(onClick = { showMergeDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showCreateQuizDialog) {
        val defaultTitle = stringResource(R.string.category_quiz_prefix, category.name)
        var quizTitle by rememberSaveable { mutableStateOf(defaultTitle) }
        var selectedBookId by rememberSaveable { mutableLongStateOf(books.firstOrNull()?.id ?: -1L) }

        AlertDialog(
            onDismissRequest = { showCreateQuizDialog = false },
            title = { Text(stringResource(R.string.create_quiz_from_category)) },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedTextField(
                        value = quizTitle,
                        onValueChange = { quizTitle = it },
                        label = { Text(stringResource(R.string.quiz_title_label)) },
                        modifier = Modifier.fillMaxWidth()
                    )
                    Text(stringResource(R.string.select_book_label), style = MaterialTheme.typography.labelMedium)
                    books.forEach { book ->
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.fillMaxWidth().clickable { selectedBookId = book.id }.padding(vertical = 4.dp)
                        ) {
                            RadioButton(selected = selectedBookId == book.id, onClick = { selectedBookId = book.id })
                            Text(book.title)
                        }
                    }
                }
            },
            confirmButton = {
                TextButton(onClick = { 
                    onCreateQuiz(quizTitle, selectedBookId)
                    showCreateQuizDialog = false
                }, enabled = selectedBookId != -1L) {
                    Text(stringResource(R.string.create))
                }
            },
            dismissButton = {
                TextButton(onClick = { showCreateQuizDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showEmojiPicker) {
        val emojis = listOf("🎯", "📚", "💡", "🧪", "🌍", "💻", "🎨", "⚽", "🎵", "📝", "🧠", "⚖️", "⚙️", "🔋", "💊")
        AlertDialog(
            onDismissRequest = { showEmojiPicker = false },
            title = { Text(stringResource(R.string.select_emoji_title)) },
            text = {
                Column {
                    FlowRow(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        emojis.forEach { emoji ->
                            TextButton(
                                onClick = {
                                    onUpdateEmoji(emoji)
                                    showEmojiPicker = false
                                },
                                modifier = Modifier.size(48.dp)
                            ) {
                                Text(emoji, style = MaterialTheme.typography.headlineSmall)
                            }
                        }
                        TextButton(
                            onClick = {
                                onUpdateEmoji(null)
                                showEmojiPicker = false
                            },
                            modifier = Modifier.size(48.dp)
                        ) {
                            Icon(Icons.Rounded.Clear, contentDescription = stringResource(R.string.clear_label))
                        }
                    }
                }
            },
            confirmButton = {},
            dismissButton = {
                TextButton(onClick = { showEmojiPicker = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showColorPicker) {
        val colors = listOf(
            MaterialTheme.colorScheme.primary,
            MaterialTheme.colorScheme.secondary,
            MaterialTheme.colorScheme.tertiary,
            androidx.compose.ui.graphics.Color(0xFFEF5350), // Red
            androidx.compose.ui.graphics.Color(0xFFEC407A), // Pink
            androidx.compose.ui.graphics.Color(0xFFAB47BC), // Purple
            androidx.compose.ui.graphics.Color(0xFF5C6BC0), // Indigo
            androidx.compose.ui.graphics.Color(0xFF42A5F5), // Blue
            androidx.compose.ui.graphics.Color(0xFF26A69A), // Teal
            androidx.compose.ui.graphics.Color(0xFF66BB6A), // Green
            androidx.compose.ui.graphics.Color(0xFFFFEE58), // Yellow
            androidx.compose.ui.graphics.Color(0xFFFFA726), // Orange
            androidx.compose.ui.graphics.Color(0xFF8D6E63), // Brown
            androidx.compose.ui.graphics.Color(0xFF78909C), // Blue Grey
        )
        AlertDialog(
            onDismissRequest = { showColorPicker = false },
            title = { Text(stringResource(R.string.select_color_title)) },
            text = {
                Column {
                    FlowRow(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        colors.forEach { color ->
                            Surface(
                                onClick = {
                                    onUpdateColor(color.toArgb())
                                    showColorPicker = false
                                },
                                shape = RoundedCornerShape(12.dp),
                                color = color,
                                modifier = Modifier.size(48.dp),
                                border = if (category.color == color.toArgb()) {
                                    androidx.compose.foundation.BorderStroke(2.dp, MaterialTheme.colorScheme.onSurface)
                                } else null
                            ) {}
                        }
                        Surface(
                            onClick = {
                                onUpdateColor(null)
                                showColorPicker = false
                            },
                            shape = RoundedCornerShape(12.dp),
                            color = MaterialTheme.colorScheme.surfaceVariant,
                            modifier = Modifier.size(48.dp),
                            border = if (category.color == null) {
                                androidx.compose.foundation.BorderStroke(2.dp, MaterialTheme.colorScheme.onSurface)
                            } else null
                        ) {
                            Box(contentAlignment = Alignment.Center) {
                                Icon(Icons.Rounded.Clear, contentDescription = stringResource(R.string.clear_label))
                            }
                        }
                    }
                }
            },
            confirmButton = {},
            dismissButton = {
                TextButton(onClick = { showColorPicker = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    ModalBottomSheet(onDismissRequest = onDismiss) {
        Column(modifier = Modifier.padding(16.dp).padding(bottom = 32.dp)) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier.padding(bottom = 16.dp)
            ) {
                Surface(
                    onClick = { showEmojiPicker = true },
                    shape = RoundedCornerShape(12.dp),
                    color = category.color?.let { androidx.compose.ui.graphics.Color(it) } ?: MaterialTheme.colorScheme.surfaceVariant,
                    modifier = Modifier.size(56.dp)
                ) {
                    Box(contentAlignment = Alignment.Center) {
                        Text(
                            text = category.emoji ?: "📂",
                            style = MaterialTheme.typography.headlineMedium
                        )
                    }
                }
                Spacer(modifier = Modifier.width(16.dp))
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = category.name,
                        style = MaterialTheme.typography.titleLarge
                    )
                    Text(
                        text = stringResource(R.string.questions_count, category.questionCount),
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                IconButton(
                    onClick = { showColorPicker = true },
                    colors = IconButtonDefaults.iconButtonColors(
                        containerColor = MaterialTheme.colorScheme.surfaceVariant,
                        contentColor = category.color?.let { androidx.compose.ui.graphics.Color(it) } ?: MaterialTheme.colorScheme.onSurfaceVariant
                    )
                ) {
                    Icon(
                        Icons.Rounded.Palette,
                        contentDescription = stringResource(R.string.color_label)
                    )
                }
                IconButton(
                    onClick = onTogglePin,
                    colors = IconButtonDefaults.iconButtonColors(
                        containerColor = if (category.isPinned) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant,
                        contentColor = if (category.isPinned) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                ) {
                    Icon(
                        Icons.Rounded.PushPin,
                        contentDescription = stringResource(R.string.pin_label)
                    )
                }
            }

            HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))

            ListItem(
                headlineContent = { Text(stringResource(R.string.show_info_stats)) },
                leadingContent = { Icon(Icons.Rounded.Info, contentDescription = null) },
                trailingContent = {
                    Switch(checked = showInfo, onCheckedChange = { showInfo = it })
                },
                modifier = Modifier.clickable { showInfo = !showInfo }
            )

            AnimatedVisibility(visible = showInfo) {
                EntityInfoSection(
                    title = stringResource(R.string.metadata_stats_title),
                    info = listOf(
                        stringResource(R.string.name_label) to category.name,
                        stringResource(R.string.total_questions_label) to category.questionCount.toString(),
                        stringResource(R.string.answered_label) to "${category.answeredCount} (${if (category.questionCount > 0) (category.answeredCount.toFloat() / category.questionCount * 100).toInt() else 0}%)",
                        stringResource(R.string.accuracy_label) to "${(category.accuracyPercentage * 100).toInt()}%",
                        stringResource(R.string.pinned_label) to if (category.isPinned) stringResource(R.string.yes_label) else stringResource(R.string.no_label),
                        stringResource(R.string.emoji_label) to (category.emoji ?: stringResource(R.string.default_label))
                    ),
                    modifier = Modifier.padding(8.dp)
                )
            }

            HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))

            ListItem(
                headlineContent = { Text(stringResource(R.string.browse_questions)) },
                leadingContent = { Icon(Icons.AutoMirrored.Rounded.List, contentDescription = null) },
                modifier = Modifier.clickable { 
                    onViewQuestions()
                    onDismiss()
                }
            )
            ListItem(
                headlineContent = { Text(stringResource(if (category.isPinned) R.string.unpin_from_top else R.string.pin_to_top)) },
                leadingContent = { 
                    Icon(
                        Icons.Rounded.PushPin, 
                        contentDescription = null,
                        tint = if (category.isPinned) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
                    ) 
                },
                modifier = Modifier.clickable { 
                    onTogglePin()
                    onDismiss()
                }
            )
            ListItem(
                headlineContent = { Text(stringResource(R.string.rename)) },
                leadingContent = { Icon(Icons.Rounded.Edit, contentDescription = null) },
                modifier = Modifier.clickable { 
                    showRenameDialog = true
                }
            )
            ListItem(
                headlineContent = { Text(stringResource(R.string.merge_into_category)) },
                leadingContent = { Icon(Icons.Rounded.Merge, contentDescription = null) },
                modifier = Modifier.clickable { 
                    showMergeDialog = true
                }
            )
            ListItem(
                headlineContent = { Text(stringResource(R.string.make_separate_quiz)) },
                leadingContent = { Icon(Icons.AutoMirrored.Rounded.FactCheck, contentDescription = null) },
                modifier = Modifier.clickable { 
                    showCreateQuizDialog = true
                }
            )
            ListItem(
                headlineContent = { Text(stringResource(R.string.delete)) },
                leadingContent = { Icon(Icons.Rounded.Delete, contentDescription = null, tint = MaterialTheme.colorScheme.error) },
                modifier = Modifier.clickable { 
                    showDeleteConfirm = true
                }
            )
        }
    }
}

fun QuestionAssetsDialog(
    question: QuestionEntity,
    bookId: Long,
    assets: List<QuestionAssetEntity>,
    annotations: List<AnnotationEntity> = emptyList(),
    sourceDocuments: List<SourceDocumentEntity> = emptyList(),
    linkedBlueprints: List<NoteBlueprintEntity> = emptyList(),
    onDismiss: () -> Unit,
    onAddAsset: (QuestionAssetEntity) -> Unit,
    onUpdateAsset: (QuestionAssetEntity) -> Unit,
    onDeleteAsset: (QuestionAssetEntity) -> Unit,
    onAddAnnotation: (selectedText: String?, noteBody: String, colorLabel: String) -> Unit = { _, _, _ -> },
    onUpdateAnnotation: (AnnotationEntity) -> Unit = {},
    onDeleteAnnotation: (AnnotationEntity) -> Unit = {},
    onCreateSourceAndAddAsset: (QuestionAssetEntity, SourceDocumentEntity) -> Unit = { asset, _ -> onAddAsset(asset) },
    onCreateBlueprintFromQuestion: () -> Unit = {}
) {
    var editingAsset by remember { mutableStateOf<QuestionAssetEntity?>(null) }
    var editingAnnotation by remember { mutableStateOf<AnnotationEntity?>(null) }
    var showAddForm by rememberSaveable { mutableStateOf(false) }
    var showAnnotationForm by rememberSaveable { mutableStateOf(false) }

    if (showAnnotationForm || editingAnnotation != null) {
        AnnotationFormDialog(
            existing = editingAnnotation,
            onDismiss = {
                editingAnnotation = null
                showAnnotationForm = false
            },
            onSave = { selectedText, noteBody, colorLabel ->
                val existing = editingAnnotation
                if (existing == null) {
                    onAddAnnotation(selectedText, noteBody, colorLabel)
                } else {
                    onUpdateAnnotation(
                        existing.copy(
                            selectedText = selectedText?.takeIf { it.isNotBlank() },
                            noteBody = noteBody.takeIf { it.isNotBlank() },
                            colorLabel = colorLabel,
                            updatedAt = System.currentTimeMillis()
                        )
                    )
                }
                editingAnnotation = null
                showAnnotationForm = false
            }
        )
    }

    if (showAddForm || editingAsset != null) {
        QuestionAssetFormDialog(
            question = question,
            bookId = bookId,
            existing = editingAsset,
            sourceDocuments = sourceDocuments,
            onDismiss = {
                editingAsset = null
                showAddForm = false
            },
            onSave = { asset ->
                if (asset.id == 0L) onAddAsset(asset) else onUpdateAsset(asset)
                editingAsset = null
                showAddForm = false
            },
            onCreateSourceAndSave = { asset, source ->
                onCreateSourceAndAddAsset(asset, source)
                editingAsset = null
                showAddForm = false
            }
        )
    }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Question attachments & sources") },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Text(
                    text = question.text,
                    maxLines = 3,
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
                if (assets.isEmpty()) {
                    Card(colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)) {
                        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("No attachments yet", fontWeight = FontWeight.SemiBold)
                            Text("Add an image, PDF, text note, web link, or source citation to make this question a richer study workspace.")
                        }
                    }
                } else {
                    assets.forEach { asset ->
                        QuestionAssetCard(
                            asset = asset,
                            sourceDocuments = sourceDocuments,
                            onEdit = { editingAsset = asset },
                            onDelete = { onDeleteAsset(asset) }
                        )
                    }
                }

                Spacer(Modifier.height(6.dp))
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Text("Annotations", style = MaterialTheme.typography.titleSmall, fontWeight = FontWeight.Bold, modifier = Modifier.weight(1f))
                    TextButton(onClick = { showAnnotationForm = true }) { Text("Add note") }
                }
                if (annotations.isEmpty()) {
                    Text("No annotations yet. Add a highlight or margin note for this question.")
                } else {
                    annotations.forEach { annotation ->
                        AnnotationCard(
                            annotation = annotation,
                            onEdit = { editingAnnotation = annotation },
                            onDelete = { onDeleteAnnotation(annotation) }
                        )
                    }
                }

                Spacer(Modifier.height(6.dp))
                Text("Linked blueprints", style = MaterialTheme.typography.titleSmall, fontWeight = FontWeight.Bold)
                if (linkedBlueprints.isEmpty()) {
                    Text("No linked blueprint yet. Create one from this question when you want a structured reusable note.")
                } else {
                    linkedBlueprints.forEach { blueprint ->
                        val tokens = LocalMksDesignTokens.current
                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            shape = RoundedCornerShape(tokens.cardRadius),
                            elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
                        ) {
                            Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(Icons.Default.Description, contentDescription = null)
                                    Spacer(Modifier.width(8.dp))
                                    Text(blueprint.title, fontWeight = FontWeight.SemiBold)
                                }
                                Text(blueprint.blueprintMode, style = MaterialTheme.typography.labelSmall)
                                blueprint.summary?.takeIf { it.isNotBlank() }?.let { Text(it, maxLines = 3) }
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                TextButton(onClick = onCreateBlueprintFromQuestion) { Text("Make blueprint") }
                Button(onClick = { showAddForm = true }) {
                    Icon(Icons.Default.Add, contentDescription = null)
                    Spacer(Modifier.width(8.dp))
                    Text("Add")
                }
            }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Close") } }
    )
}

private fun AnnotationCard(
    annotation: AnnotationEntity,
    onEdit: () -> Unit,
    onDelete: () -> Unit,
    showActions: Boolean = true
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.secondaryContainer)
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(Icons.AutoMirrored.Filled.StickyNote2, contentDescription = null)
                Spacer(Modifier.width(8.dp))
                Column(Modifier.weight(1f)) {
                    Text(annotation.colorLabel.lowercase().replaceFirstChar { it.titlecase() }, fontWeight = FontWeight.SemiBold)
                    Text(annotation.ownerType.lowercase().replaceFirstChar { it.titlecase() }, style = MaterialTheme.typography.labelSmall)
                }
                if (showActions) {
                    IconButton(onClick = onEdit) { Icon(Icons.Default.Edit, contentDescription = "Edit annotation") }
                    IconButton(onClick = onDelete) { Icon(Icons.Default.Delete, contentDescription = "Delete annotation") }
                }
            }
            annotation.selectedText?.takeIf { it.isNotBlank() }?.let { Text("Highlight: $it", maxLines = 3) }
            annotation.noteBody?.takeIf { it.isNotBlank() }?.let { Text(it, maxLines = 5) }
        }
    }
}

private fun AnnotationFormDialog(
    existing: AnnotationEntity?,
    onDismiss: () -> Unit,
    onSave: (selectedText: String?, noteBody: String, colorLabel: String) -> Unit
) {
    var selectedText by rememberSaveable(existing?.id) { mutableStateOf(existing?.selectedText.orEmpty()) }
    var noteBody by rememberSaveable(existing?.id) { mutableStateOf(existing?.noteBody.orEmpty()) }
    var colorLabel by rememberSaveable(existing?.id) { mutableStateOf(existing?.colorLabel ?: AnnotationColorLabel.YELLOW) }
    val colorOptions = listOf(
        AnnotationColorLabel.YELLOW,
        AnnotationColorLabel.GREEN,
        AnnotationColorLabel.BLUE,
        AnnotationColorLabel.PINK,
        AnnotationColorLabel.ORANGE,
        AnnotationColorLabel.RED
    )

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (existing == null) "Add annotation" else "Edit annotation") },
        text = {
            Column(
                modifier = Modifier.fillMaxWidth().verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                OutlinedTextField(
                    value = selectedText,
                    onValueChange = { selectedText = it },
                    label = { Text("Highlighted text") },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 2
                )
                OutlinedTextField(
                    value = noteBody,
                    onValueChange = { noteBody = it },
                    label = { Text("Margin note") },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 3
                )
                Text("Color", style = MaterialTheme.typography.labelMedium)
                Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                    colorOptions.forEach { option ->
                        FilterChip(
                            selected = colorLabel == option,
                            onClick = { colorLabel = option },
                            label = { Text(option.lowercase().replaceFirstChar { it.titlecase() }) }
                        )
                    }
                }
            }
        },
        confirmButton = {
            Button(
                enabled = selectedText.isNotBlank() || noteBody.isNotBlank(),
                onClick = { onSave(selectedText.trim().takeIf { it.isNotBlank() }, noteBody.trim(), colorLabel) }
            ) { Text("Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

private fun QuestionAssetCard(
    asset: QuestionAssetEntity,
    sourceDocuments: List<SourceDocumentEntity>,
    onEdit: () -> Unit,
    onDelete: () -> Unit,
    showActions: Boolean = true
) {
    val tokens = LocalMksDesignTokens.current
    val source = asset.sourceDocumentId?.let { id -> sourceDocuments.firstOrNull { it.id == id } }
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(
                    imageVector = if (asset.assetType == QuestionAssetType.SOURCE_REFERENCE) Icons.Default.Book else Icons.Default.AttachFile,
                    contentDescription = null
                )
                Spacer(Modifier.width(8.dp))
                Column(Modifier.weight(1f)) {
                    Text(asset.title, fontWeight = FontWeight.SemiBold)
                    Text(asset.assetType.replace('_', ' '), style = MaterialTheme.typography.labelSmall)
                }
                if (asset.isPinned) {
                    Icon(Icons.Default.PushPin, contentDescription = "Pinned", tint = MaterialTheme.colorScheme.primary)
                }
                if (showActions) {
                    IconButton(onClick = onEdit) {
                        Icon(Icons.Default.Edit, contentDescription = "Edit asset")
                    }
                    IconButton(onClick = onDelete) {
                        Icon(Icons.Default.Delete, contentDescription = "Delete asset")
                    }
                }
            }
            source?.let {
                AssistChip(onClick = {}, label = { Text(it.title) }, leadingIcon = { Icon(Icons.Default.Book, contentDescription = null) })
            }
            asset.sourcePage?.takeIf { it.isNotBlank() }?.let { Text("Page/location: $it") }
            asset.sourceQuote?.takeIf { it.isNotBlank() }?.let { Text("Quote: $it", maxLines = 4) }
            asset.description?.takeIf { it.isNotBlank() }?.let { Text(it) }
            asset.externalUrl?.takeIf { it.isNotBlank() }?.let { Text(it, color = MaterialTheme.colorScheme.primary) }
            asset.localPath?.takeIf { it.isNotBlank() }?.let { Text("Local: $it", style = MaterialTheme.typography.labelSmall) }
            asset.textContent?.takeIf { it.isNotBlank() }?.let { Text(it, maxLines = 4) }
        }
    }
}

private fun QuestionAssetFormDialog(
    question: QuestionEntity,
    bookId: Long,
    existing: QuestionAssetEntity?,
    sourceDocuments: List<SourceDocumentEntity>,
    onDismiss: () -> Unit,
    onSave: (QuestionAssetEntity) -> Unit,
    onCreateSourceAndSave: (QuestionAssetEntity, SourceDocumentEntity) -> Unit
) {
    val availableTypes = remember { QuestionAssetType.firstPassTypes + QuestionAssetType.SOURCE_REFERENCE }
    var assetType by rememberSaveable(existing?.id) { mutableStateOf(existing?.assetType ?: QuestionAssetType.IMAGE) }
    var title by rememberSaveable(existing?.id) { mutableStateOf(existing?.title ?: "") }
    var description by rememberSaveable(existing?.id) { mutableStateOf(existing?.description ?: "") }
    var localPath by rememberSaveable(existing?.id) { mutableStateOf(existing?.localPath ?: "") }
    var externalUrl by rememberSaveable(existing?.id) { mutableStateOf(existing?.externalUrl ?: "") }
    var textContent by rememberSaveable(existing?.id) { mutableStateOf(existing?.textContent ?: "") }
    var selectedSourceIdText by rememberSaveable(existing?.id) { mutableStateOf(existing?.sourceDocumentId?.toString().orEmpty()) }
    var sourcePage by rememberSaveable(existing?.id) { mutableStateOf(existing?.sourcePage ?: "") }
    var sourceQuote by rememberSaveable(existing?.id) { mutableStateOf(existing?.sourceQuote ?: "") }
    var newSourceTitle by rememberSaveable(existing?.id) { mutableStateOf("") }
    var newSourceType by rememberSaveable(existing?.id) { mutableStateOf(SourceDocumentTypes.BOOK) }
    var newSourceDetails by rememberSaveable(existing?.id) { mutableStateOf("") }
    var isPinned by rememberSaveable(existing?.id) { mutableStateOf(existing?.isPinned ?: false) }
    var isPrimary by rememberSaveable(existing?.id) { mutableStateOf(existing?.isPrimary ?: false) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (existing == null) "Add attachment/source" else "Edit attachment/source") },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Text("Type", style = MaterialTheme.typography.labelMedium)
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    availableTypes.forEach { type ->
                        FilterChip(
                            selected = assetType == type,
                            onClick = { assetType = type },
                            label = { Text(type.replace('_', ' ')) }
                        )
                    }
                }
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = description,
                    onValueChange = { description = it },
                    label = { Text("Description") },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 2
                )
                when (assetType) {
                    QuestionAssetType.WEB_LINK -> {
                        OutlinedTextField(
                            value = externalUrl,
                            onValueChange = { externalUrl = it },
                            label = { Text("Web link URL") },
                            modifier = Modifier.fillMaxWidth()
                        )
                    }
                    QuestionAssetType.TEXT_NOTE -> {
                        OutlinedTextField(
                            value = textContent,
                            onValueChange = { textContent = it },
                            label = { Text("Text note") },
                            modifier = Modifier.fillMaxWidth(),
                            minLines = 4
                        )
                    }
                    QuestionAssetType.SOURCE_REFERENCE -> {
                        Text("Pick existing source", style = MaterialTheme.typography.labelMedium)
                        if (sourceDocuments.isEmpty()) {
                            Text("No book sources yet. Create a simple source below.")
                        } else {
                            sourceDocuments.forEach { source ->
                                FilterChip(
                                    selected = selectedSourceIdText == source.id.toString(),
                                    onClick = { selectedSourceIdText = source.id.toString() },
                                    label = { Text(source.title) },
                                    leadingIcon = { Icon(Icons.Default.Book, contentDescription = null) }
                                )
                            }
                            TextButton(onClick = { selectedSourceIdText = "" }) { Text("Create new source instead") }
                        }
                        OutlinedTextField(
                            value = sourcePage,
                            onValueChange = { sourcePage = it },
                            label = { Text("Page / section / timestamp") },
                            modifier = Modifier.fillMaxWidth()
                        )
                        OutlinedTextField(
                            value = sourceQuote,
                            onValueChange = { sourceQuote = it },
                            label = { Text("Quote / citation note") },
                            modifier = Modifier.fillMaxWidth(),
                            minLines = 3
                        )
                        if (selectedSourceIdText.isBlank() && existing == null) {
                            Text("New source", style = MaterialTheme.typography.labelMedium, fontWeight = FontWeight.Bold)
                            OutlinedTextField(
                                value = newSourceTitle,
                                onValueChange = { newSourceTitle = it },
                                label = { Text("Source title") },
                                modifier = Modifier.fillMaxWidth()
                            )
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                SourceDocumentTypes.all.forEach { type ->
                                    FilterChip(
                                        selected = newSourceType == type,
                                        onClick = { newSourceType = type },
                                        label = { Text(type.lowercase().replaceFirstChar { it.titlecase() }) }
                                    )
                                }
                            }
                            OutlinedTextField(
                                value = newSourceDetails,
                                onValueChange = { newSourceDetails = it },
                                label = { Text("Source details") },
                                modifier = Modifier.fillMaxWidth(),
                                minLines = 2
                            )
                        }
                    }
                    else -> {
                        OutlinedTextField(
                            value = localPath,
                            onValueChange = { localPath = it },
                            label = { Text("Local path / content URI") },
                            modifier = Modifier.fillMaxWidth()
                        )
                    }
                }
                Row(verticalAlignment = Alignment.CenterVertically) {
                    FilterChip(selected = isPinned, onClick = { isPinned = !isPinned }, label = { Text("Pinned") })
                    Spacer(Modifier.width(8.dp))
                    FilterChip(selected = isPrimary, onClick = { isPrimary = !isPrimary }, label = { Text("Primary") })
                }
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    val effectiveTitle = title.ifBlank {
                        when (assetType) {
                            QuestionAssetType.SOURCE_REFERENCE -> newSourceTitle.ifBlank { "Source reference" }
                            else -> assetType.replace('_', ' ')
                        }
                    }
                    val baseAsset = QuestionAssetEntity(
                        id = existing?.id ?: 0L,
                        bookId = bookId,
                        quizId = question.quizId,
                        questionId = question.id,
                        assetType = assetType,
                        title = effectiveTitle,
                        description = description.takeIf { it.isNotBlank() },
                        localPath = localPath.takeIf { it.isNotBlank() },
                        externalUrl = externalUrl.takeIf { it.isNotBlank() },
                        textContent = textContent.takeIf { it.isNotBlank() },
                        sourceDocumentId = selectedSourceIdText.toLongOrNull(),
                        sourcePage = sourcePage.takeIf { it.isNotBlank() },
                        sourceQuote = sourceQuote.takeIf { it.isNotBlank() },
                        sortOrder = existing?.sortOrder ?: 0,
                        isPinned = isPinned,
                        isPrimary = isPrimary,
                        createdAt = existing?.createdAt ?: System.currentTimeMillis(),
                        updatedAt = System.currentTimeMillis()
                    )
                    if (assetType == QuestionAssetType.SOURCE_REFERENCE && selectedSourceIdText.isBlank() && newSourceTitle.isNotBlank() && existing == null) {
                        onCreateSourceAndSave(
                            baseAsset,
                            SourceDocumentEntity(
                                bookId = bookId,
                                title = newSourceTitle.trim(),
                                sourceType = newSourceType,
                                description = newSourceDetails.takeIf { it.isNotBlank() }
                            )
                        )
                    } else {
                        onSave(baseAsset)
                    }
                },
                enabled = title.isNotBlank() || assetType == QuestionAssetType.SOURCE_REFERENCE || assetType == QuestionAssetType.TEXT_NOTE
            ) { Text("Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

fun QuestionAssetsReadOnlyDialog(
    question: QuestionEntity,
    assets: List<QuestionAssetEntity>,
    sourceDocuments: List<SourceDocumentEntity> = emptyList(),
    onDismiss: () -> Unit
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Assets & sources (${assets.size})") },
        text = {
            Column(
                modifier = Modifier.fillMaxWidth().verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Text(question.text, maxLines = 3, color = MaterialTheme.colorScheme.onSurfaceVariant)
                if (assets.isEmpty()) {
                    Text("No attachments or source citations for this question yet.")
                } else {
                    assets.forEach { asset ->
                        QuestionAssetCard(
                            asset = asset,
                            sourceDocuments = sourceDocuments,
                            onEdit = {},
                            onDelete = {},
                            showActions = false
                        )
                    }
                }
            }
        },
        confirmButton = { TextButton(onClick = onDismiss) { Text("Close") } }
    )
}

fun CategoryQuestionsScreen(
    viewModel: CategoryQuestionsViewModel,
    onBack: () -> Unit,
    onStartQuiz: (String) -> Unit = {},
) {
    val uiState by viewModel.uiState.collectAsState()
    val allQuizzes by viewModel.allQuizzes.collectAsState()
    val showFiltersState = rememberSaveable { mutableStateOf(value = false) }
    var showFilters by showFiltersState
    val isSearchingState = rememberSaveable { mutableStateOf(value = false) }
    var isSearching by isSearchingState
    val showMoveDialogState = remember { mutableStateOf(value = false) }
    var showMoveDialog by showMoveDialogState
    val showCopyDialogState = remember { mutableStateOf(value = false) }
    var showCopyDialog by showCopyDialogState
    val showExportDialogState = remember { mutableStateOf(value = false) }
    var showExportDialog by showExportDialogState
    val showDeleteConfirmState = remember { mutableStateOf(value = false) }
    var showDeleteConfirm by showDeleteConfirmState
    val showEditDialogState = remember { mutableStateOf<QuestionEntity?>(null) }
    var showEditDialog by showEditDialogState
    val showAssetsDialogState = remember { mutableStateOf<QuestionEntity?>(null) }
    var showAssetsDialog by showAssetsDialogState
    val showFlashcardDialogState = remember { mutableStateOf(value = false) }
    var showFlashcardDialog by showFlashcardDialogState

    val scrollState = rememberLazyListState()
    val scrollBehavior = TopAppBarDefaults.exitUntilCollapsedScrollBehavior()
    val isSelectionMode = uiState.selectedQuestionIds.isNotEmpty()
    val fullscreenImageUrlState = remember { mutableStateOf<String?>(null) }
    var fullscreenImageUrl by fullscreenImageUrlState

    if (showMoveDialog) {
        MoveQuestionsDialog(
            title = "Move to Quiz",
            confirmText = "Move",
            onDismiss = { showMoveDialogState.value = false },
            onMove = { targetQuizId ->
                viewModel.moveSelectedQuestionsToQuiz(targetQuizId)
                showMoveDialogState.value = false
            },
            viewModel = viewModel,
        )
    }

    if (showCopyDialog) {
        MoveQuestionsDialog(
            title = "Copy to Quiz",
            confirmText = "Copy",
            onDismiss = { showCopyDialogState.value = false },
            onMove = { targetQuizId ->
                viewModel.copySelectedQuestionsToQuiz(targetQuizId)
                showCopyDialogState.value = false
            },
            viewModel = viewModel,
        )
    }

    if (showExportDialog) {
        var newQuizTitle by remember { mutableStateOf("") }
        AlertDialog(
            onDismissRequest = { showExportDialogState.value = false },
            title = { Text("Export to New Quiz") },
            text = {
                OutlinedTextField(
                    value = newQuizTitle,
                    onValueChange = { newQuizTitle = it },
                    label = { Text("Quiz title") },
                    modifier = Modifier.fillMaxWidth(),
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.exportSelectedQuestionsToNewQuiz(newQuizTitle)
                        showExportDialogState.value = false
                    },
                    enabled = newQuizTitle.isNotBlank(),
                ) { Text("Create") }
            },
            dismissButton = { TextButton(onClick = { showExportDialogState.value = false }) { Text("Cancel") } },
        )
    }

    if (showFlashcardDialog) {
        CreateFlashcardsFromSelectedDialog(
            selectedCount = uiState.selectedQuestionIds.size,
            onDismiss = { showFlashcardDialogState.value = false },
        ) { title, clearMarks ->
            viewModel.createFlashcardsFromSelected(title, clearMarks)
            showFlashcardDialogState.value = false
        }
    }

    if (showDeleteConfirm) {
        AlertDialog(
            onDismissRequest = { showDeleteConfirmState.value = false },
            title = { Text("Delete selected questions?") },
            text = { Text("This will permanently delete ${uiState.selectedQuestionIds.size} selected question(s).") },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.deleteSelectedQuestions()
                        showDeleteConfirmState.value = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error),
                ) { Text("Delete") }
            },
            dismissButton = { TextButton(onClick = { showDeleteConfirmState.value = false }) { Text("Cancel") } },
        )
    }

    showEditDialog?.let { question ->
        EditQuestionDialog(
            question = question,
            onDismiss = { showEditDialogState.value = null },
        ) {
            viewModel.updateQuestion(it)
            showEditDialogState.value = null
        }
    }

    showAssetsDialog?.let { question ->
        val assets by viewModel.assetsForQuestion(question.id).collectAsState(initial = emptyList())
        val bookId = allQuizzes.firstOrNull { it.id == question.quizId }?.bookId ?: 0L
        val sources by viewModel.sourceDocumentsForBook(bookId).collectAsState(initial = emptyList())
        val linkedBlueprints by viewModel.linkedBlueprintsForQuestion(bookId, question.id).collectAsState(initial = emptyList())
        val annotations by viewModel.annotationsForQuestion(question.id).collectAsState(initial = emptyList())
        QuestionAssetsDialog(
            question = question,
            bookId = bookId,
            assets = assets,
            annotations = annotations,
            sourceDocuments = sources,
            linkedBlueprints = linkedBlueprints,
            onDismiss = { showAssetsDialogState.value = null },
            onAddAsset = { viewModel.addQuestionAsset(it) },
            onUpdateAsset = { viewModel.updateQuestionAsset(it) },
            onDeleteAsset = { viewModel.deleteQuestionAsset(it) },
            onAddAnnotation = { selectedText, noteBody, colorLabel -> viewModel.addQuestionAnnotation(bookId, question.id, selectedText, noteBody, colorLabel) },
            onUpdateAnnotation = { viewModel.updateAnnotation(it) },
            onDeleteAnnotation = { viewModel.deleteAnnotation(it) },
            onCreateSourceAndAddAsset = { asset, source -> viewModel.createSourceAndAddQuestionAsset(asset, source) },
            onCreateBlueprintFromQuestion = { viewModel.createBlueprintFromQuestion(bookId, question.id) },
        )
    }

    Scaffold(
        modifier = Modifier.nestedScroll(scrollBehavior.nestedScrollConnection),
        topBar = {
            if (isSelectionMode) {
                SelectionTopAppBar(
                    selectedCount = uiState.selectedQuestionIds.size,
                    onClearSelection = { viewModel.clearSelection() },
                    onDelete = { showDeleteConfirmState.value = true },
                    onMove = { showMoveDialogState.value = true },
                    onSelectAll = { viewModel.toggleAllSelection() },
                    onCopy = { showCopyDialogState.value = true },
                    onExport = { showExportDialogState.value = true },
                    onCreateFlashcards = { showFlashcardDialogState.value = true },
                    onMarkSelected = { viewModel.markSelectedQuestions(marked = true) },
                    onUnmarkSelected = { viewModel.markSelectedQuestions(marked = false) },
                    showMarkActions = true,
                    scrollBehavior = scrollBehavior,
                )
            } else {
                DefaultTopAppBar(
                    categoryName = uiState.categoryName,
                    filteredCount = uiState.filteredQuestions.size,
                    totalCount = uiState.allQuestions.size,
                    isSearching = isSearching,
                    searchQuery = uiState.searchQuery,
                    onSearchQueryChange = { viewModel.setSearchQuery(it) },
                    onToggleSearch = { isSearchingState.value = !isSearching },
                    onToggleFilters = { showFiltersState.value = !showFilters },
                    onBack = onBack,
                    scrollBehavior = scrollBehavior,
                )
            }
        },
        floatingActionButton = {
            if (uiState.filteredQuestions.isNotEmpty()) {
                ExtendedFloatingActionButton(
                    onClick = { onStartQuiz(uiState.categoryName) },
                    icon = { Icon(Icons.Default.PlayArrow, contentDescription = null) },
                    text = { Text("Start Quiz") },
                    containerColor = MaterialTheme.colorScheme.primaryContainer,
                    contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                )
            }
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .padding(padding)
                .fillMaxSize()
        ) {
            if (showFilters) {
                FilterControls(
                    visibility = uiState.visibility,
                    onToggle = { viewModel.toggleVisibility(it) }
                )
            }

            if (uiState.isLoading) {
                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            } else if (uiState.filteredQuestions.isEmpty()) {
                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    Text(if (uiState.searchQuery.isBlank()) "No questions found for this category." else "No questions match your search.")
                }
            } else {
                LazyColumn(
                    state = scrollState,
                    modifier = Modifier.fillMaxSize(),
                    contentPadding = PaddingValues(16.dp, 16.dp, 16.dp, 80.dp),
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    items(uiState.filteredQuestions, key = { it.id }) { question ->
                        QuestionCard(
                            question = question,
                            visibility = uiState.visibility,
                            isSelected = uiState.selectedQuestionIds.contains(question.id),
                            isSelectionMode = uiState.selectedQuestionIds.isNotEmpty(),
                            onToggleSelection = { viewModel.toggleSelection(question.id) },
                            onToggleMarked = { viewModel.toggleMarked(question) },
                            onImageClick = { fullscreenImageUrlState.value = it },
                            onEditClick = { showEditDialogState.value = question },
                            hasAssets = question.id in uiState.questionIdsWithAssets,
                            onAssetsClick = { showAssetsDialogState.value = question },
                        )
                    }
                }
            }
        }
    }

    fullscreenImageUrl?.let { data ->
        com.ahmedyejam.mks.ui.quiz.ZoomableImageDialog(
            imageData = data,
        ) { fullscreenImageUrlState.value = null }
    }
}

@OptIn(ExperimentalLayoutApi::class)

fun FilterControls(
    visibility: VisibilityState,
    onToggle: (VisibilityState.() -> VisibilityState) -> Unit
) {
    Surface(
        modifier = Modifier.fillMaxWidth(),
        color = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
    ) {
        FlowRow(
            modifier = Modifier.padding(8.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            FilterChip(
                selected = visibility.showStem,
                onClick = { onToggle { copy(showStem = !showStem) } },
                label = { Text("Stem") }
            )
            FilterChip(
                selected = visibility.showOptions,
                onClick = { onToggle { copy(showOptions = !showOptions) } },
                label = { Text("Options") }
            )
            FilterChip(
                selected = visibility.showCorrectAnswer,
                onClick = { onToggle { copy(showCorrectAnswer = !showCorrectAnswer) } },
                label = { Text("Correct Answer") }
            )
            FilterChip(
                selected = visibility.showExplanation,
                onClick = { onToggle { copy(showExplanation = !showExplanation) } },
                label = { Text("Explanation") }
            )
            FilterChip(
                selected = visibility.showHint,
                onClick = { onToggle { copy(showHint = !showHint) } },
                label = { Text("Hint") }
            )
            FilterChip(
                selected = visibility.showReference,
                onClick = { onToggle { copy(showReference = !showReference) } },
                label = { Text("Reference") }
            )
            FilterChip(
                selected = visibility.showAdditionalInfo,
                onClick = { onToggle { copy(showAdditionalInfo = !showAdditionalInfo) } },
                label = { Text("Info") }
            )
            FilterChip(
                selected = visibility.showOnlyMarked,
                onClick = { onToggle { copy(showOnlyMarked = !showOnlyMarked) } },
                label = { Text("Marked Only") },
                leadingIcon = { Icon(Icons.Default.Bookmark, contentDescription = null, modifier = Modifier.size(16.dp)) }
            )
            FilterChip(
                selected = visibility.showOnlyWithAssets,
                onClick = { onToggle { copy(showOnlyWithAssets = !showOnlyWithAssets) } },
                label = { Text("Has attachments") },
                leadingIcon = { Icon(Icons.Default.AttachFile, contentDescription = null, modifier = Modifier.size(16.dp)) }
            )
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)

fun SelectionTopAppBar(
    selectedCount: Int,
    onClearSelection: () -> Unit,
    onDelete: () -> Unit,
    onMove: () -> Unit,
    onSelectAll: () -> Unit,
    onCopy: (() -> Unit)? = null,
    onExport: (() -> Unit)? = null,
    onCreateFlashcards: (() -> Unit)? = null,
    onMarkSelected: (() -> Unit)? = null,
    onUnmarkSelected: (() -> Unit)? = null,
    showMarkActions: Boolean = false,
    scrollBehavior: TopAppBarScrollBehavior? = null
) {
    TopAppBar(
        title = { Text(stringResource(R.string.selected_count_title, selectedCount)) },
        scrollBehavior = scrollBehavior,
        navigationIcon = {
            IconButton(onClick = onClearSelection) {
                Icon(Icons.Default.Close, contentDescription = "Clear Selection")
            }
        },
        actions = {
            IconButton(onClick = onSelectAll) {
                Icon(Icons.Default.SelectAll, contentDescription = "Select All")
            }
            if (showMarkActions && (onMarkSelected != null) && (onUnmarkSelected != null)) {
                IconButton(onClick = onMarkSelected) {
                    Icon(Icons.Default.Bookmark, contentDescription = "Mark selected")
                }
                IconButton(onClick = onUnmarkSelected) {
                    Icon(Icons.Default.BookmarkBorder, contentDescription = "Unmark selected")
                }
            }
            IconButton(onClick = onMove) {
                Icon(Icons.AutoMirrored.Filled.DriveFileMove, contentDescription = "Move")
            }
            onCopy?.let {
                IconButton(onClick = it) {
                    Icon(Icons.Default.ContentCopy, contentDescription = "Copy")
                }
            }
            onExport?.let {
                IconButton(onClick = it) {
                    Icon(Icons.Default.FileUpload, contentDescription = "Export")
                }
            }
            onCreateFlashcards?.let {
            IconButton(onClick = it) {
                Icon(Icons.Default.Style, contentDescription = "Create flashcards")
            }
        }
            IconButton(onClick = onDelete) {
                Icon(Icons.Default.Delete, contentDescription = "Delete")
            }
        },
        colors = TopAppBarDefaults.topAppBarColors(
            containerColor = MaterialTheme.colorScheme.primaryContainer,
            titleContentColor = MaterialTheme.colorScheme.onPrimaryContainer,
            navigationIconContentColor = MaterialTheme.colorScheme.onPrimaryContainer,
            actionIconContentColor = MaterialTheme.colorScheme.onPrimaryContainer,
        ),
    )
}

@OptIn(ExperimentalMaterial3Api::class)

fun DefaultTopAppBar(
    categoryName: String,
    filteredCount: Int,
    totalCount: Int,
    isSearching: Boolean,
    searchQuery: String,
    onSearchQueryChange: (String) -> Unit,
    onToggleSearch: () -> Unit,
    onToggleFilters: () -> Unit,
    onBack: () -> Unit,
    scrollBehavior: TopAppBarScrollBehavior? = null
) {
    MediumTopAppBar(
        scrollBehavior = scrollBehavior,
        title = {
            if (isSearching) {
                TextField(
                    value = searchQuery,
                    onValueChange = onSearchQueryChange,
                    placeholder = { Text("Search questions...") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true,
                    colors = TextFieldDefaults.colors(
                        focusedContainerColor = Color.Transparent,
                        unfocusedContainerColor = Color.Transparent,
                        focusedIndicatorColor = Color.Transparent,
                        unfocusedIndicatorColor = Color.Transparent
                    )
                )
            } else {
                Column {
                    Text(
                        categoryName, 
                        style = MaterialTheme.typography.titleMedium,
                        maxLines = 1,
                        overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis
                    )
                    if (totalCount > 0) {
                        Text(
                            "$filteredCount / $totalCount Questions",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }
        },
        navigationIcon = {
            IconButton(
                onClick = {
                    if (isSearching) {
                        onToggleSearch()
                        onSearchQueryChange("")
                    } else {
                        onBack()
                    }
                },
            ) {
                Icon(
                    if (isSearching) Icons.Default.Close else Icons.AutoMirrored.Filled.ArrowBack,
                    contentDescription = "Back"
                )
            }
        },
        actions = {
            IconButton(onClick = onToggleSearch) {
                Icon(if (isSearching) Icons.Default.SearchOff else Icons.Default.Search, contentDescription = "Search")
            }
            IconButton(onClick = onToggleFilters) {
                Icon(Icons.Default.FilterList, contentDescription = "Toggle Filters")
            }
        },
        colors = TopAppBarDefaults.mediumTopAppBarColors(
            containerColor = MaterialTheme.colorScheme.background,
            scrolledContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.8f)
        )
    )
}

@OptIn(ExperimentalFoundationApi::class)

fun QuestionCard(
    question: QuestionEntity,
    visibility: VisibilityState,
    isSelected: Boolean,
    isSelectionMode: Boolean = false,
    onToggleSelection: () -> Unit,
    onToggleMarked: () -> Unit,
    onImageClick: (String) -> Unit,
    onEditClick: () -> Unit = {},
    hasAssets: Boolean = false,
    onAssetsClick: () -> Unit = {},
    onToggleDropped: (() -> Unit)? = null
) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .combinedClickable(
                onClick = { if (isSelectionMode) onToggleSelection() else onEditClick() },
                onLongClick = onToggleSelection
            ),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation),
        colors = CardDefaults.cardColors(
            containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.3f) 
                             else MaterialTheme.colorScheme.surface
        )
    ) {
        Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    if (isSelected) {
                        Icon(
                            Icons.Default.CheckCircle,
                            contentDescription = "Selected",
                            tint = MaterialTheme.colorScheme.primary,
                            modifier = Modifier
                                .size(20.dp)
                                .padding(end = 8.dp)
                        )
                    }
                    if (question.isDropped) {
                        Spacer(modifier = Modifier.width(8.dp))
                        Surface(
                            color = MaterialTheme.colorScheme.errorContainer,
                            shape = RoundedCornerShape(4.dp)
                        ) {
                            Text(
                                "DROPPED",
                                modifier = Modifier.padding(horizontal = 4.dp, vertical = 2.dp),
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onErrorContainer
                            )
                        }
                    }
                }
                Row {
                    IconButton(onClick = onAssetsClick, modifier = Modifier.size(24.dp)) {
                        Icon(
                            imageVector = Icons.Default.AttachFile,
                            contentDescription = "Attachments",
                            tint = if (hasAssets) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(8.dp))
                    IconButton(onClick = onEditClick, modifier = Modifier.size(24.dp)) {
                        Icon(
                            imageVector = Icons.Default.Edit,
                            contentDescription = "Edit",
                            tint = MaterialTheme.colorScheme.outline,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(8.dp))
                    IconButton(onClick = onToggleMarked, modifier = Modifier.size(24.dp)) {
                        Icon(
                            imageVector = if (question.isMarked) Icons.Default.Bookmark else Icons.Default.BookmarkBorder,
                            contentDescription = "Mark",
                            tint = if (question.isMarked) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline,
                            modifier = Modifier.size(20.dp)
                        )
                    }
                    onToggleDropped?.let { toggleDrop ->
                        Spacer(modifier = Modifier.width(8.dp))
                        IconButton(onClick = toggleDrop, modifier = Modifier.size(24.dp)) {
                            Icon(
                                imageVector = Icons.Default.Block,
                                contentDescription = "Drop",
                                tint = if (question.isDropped) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.outline,
                                modifier = Modifier.size(18.dp)
                            )
                        }
                    }
                }
            }

            if (visibility.showStem && question.text.isNotBlank()) {
                Text(
                    text = question.text,
                    style = MaterialTheme.typography.bodyLarge,
                    fontWeight = FontWeight.Medium
                )
            }

            val displayImage = question.imagePath ?: question.imageSource
            if (!displayImage.isNullOrBlank()) {
                AsyncImage(
                    model = ImageRequest.Builder(LocalContext.current)
                    .data(displayImage)
                    .crossfade(enable = true)
                    .build(),
                    contentDescription = "Question Image",
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(8.dp))
                        .border(
                            1.dp,
                            MaterialTheme.colorScheme.outlineVariant,
                            RoundedCornerShape(8.dp)
                        )
                        .clickable { onImageClick(displayImage) },
                    contentScale = ContentScale.FillWidth
                )
            }

            if (visibility.showOptions && question.options.isNotEmpty()) {
                Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                    question.options.forEachIndexed { index, option ->
                        val isCorrect = visibility.showCorrectAnswer && question.correctAnswers.contains(index)
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(
                                    if (isCorrect) MaterialTheme.colorScheme.primaryContainer else Color.Transparent,
                                    RoundedCornerShape(4.dp)
                                )
                                .padding(4.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(
                                text = "${'A' + index}.",
                                style = MaterialTheme.typography.bodyMedium,
                                fontWeight = if (isCorrect) FontWeight.Bold else FontWeight.Normal,
                                color = if (isCorrect) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurface
                            )
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = option,
                                style = MaterialTheme.typography.bodyMedium,
                                color = if (isCorrect) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurface
                            )
                        }
                    }
                }
            } else if (visibility.showCorrectAnswer && question.correctAnswers.isNotEmpty() && !visibility.showOptions) {
                Text(
                    text = "Correct Answer: ${question.correctAnswers.joinToString { index -> ( 'A' + index).toString() }}",
                    style = MaterialTheme.typography.bodyMedium,
                    fontWeight = FontWeight.Bold,
                    color = MaterialTheme.colorScheme.primary
                )
            }

            if (visibility.showHint && !question.hint.isNullOrBlank()) {
                InfoSection(title = "Hint", content = question.hint!!, color = MaterialTheme.colorScheme.secondary)
            }

            if (visibility.showExplanation && !question.explanation.isNullOrBlank()) {
                InfoSection(title = "Explanation", content = question.explanation!!, color = MaterialTheme.colorScheme.tertiary)
            }

            if (visibility.showReference && !question.reference.isNullOrBlank()) {
                InfoSection(title = "Reference", content = question.reference!!, color = MaterialTheme.colorScheme.outline)
            }

            if (visibility.showAdditionalInfo && !question.additionalInfo.isNullOrBlank()) {
                InfoSection(title = "Additional Info", content = question.additionalInfo!!, color = MaterialTheme.colorScheme.outline)
            }
        }
    }
}

fun InfoSection(title: String, content: String, color: Color) {
    Column {
        Text(
            text = title,
            style = MaterialTheme.typography.labelSmall,
            color = color,
            fontWeight = FontWeight.Bold
        )
        Text(
            text = content,
            style = MaterialTheme.typography.bodySmall,
            lineHeight = 16.sp
        )
    }
}

fun MoveQuestionsDialog(
    title: String = "Move to Quiz",
    confirmText: String = "Move",
    onDismiss: () -> Unit,
    onMove: (Long) -> Unit,
    viewModel: CategoryQuestionsViewModel
) {
    val quizzes by viewModel.allQuizzes.collectAsState()
    var selectedQuizId by remember { mutableStateOf<Long?>(null) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(title) },
        text = {
            if (quizzes.isEmpty()) {
                Text("No quizzes available to move to.")
            } else {
                LazyColumn(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 400.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    items(quizzes, key = { it.id }) { quiz ->
                        Surface(
                            onClick = { selectedQuizId = quiz.id },
                            shape = RoundedCornerShape(8.dp),
                            color = if (selectedQuizId == quiz.id) MaterialTheme.colorScheme.primaryContainer else Color.Transparent,
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant)
                        ) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                RadioButton(
                                    selected = selectedQuizId == quiz.id,
                                    onClick = { selectedQuizId = quiz.id }
                                )
                                Spacer(modifier = Modifier.width(8.dp))
                                Column {
                                    Text(quiz.title, style = MaterialTheme.typography.bodyLarge)
                                    quiz.description.let { desc ->
                                        if (desc.isNotBlank()) {
                                            Text(
                                                desc,
                                                style = MaterialTheme.typography.bodySmall,
                                                maxLines = 1
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(
                onClick = { selectedQuizId?.let { onMove(it) } },
                enabled = selectedQuizId != null
            ) {
                Text(confirmText)
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        }
    )
}

