fun WorkspaceManagerDialog(
    viewModel: LibraryViewModel,
    activeWorkspaceId: Long,
    onDismiss: () -> Unit
) {
    val activeWorkspaces by viewModel.workspaces.collectAsState(initial = emptyList<WorkspaceEntity>())
    val deletedWorkspaces by viewModel.deletedWorkspaces.collectAsState(initial = emptyList<WorkspaceEntity>())

    var showCreateDialog by remember { mutableStateOf(false) }
    var editingWorkspace by remember { mutableStateOf<WorkspaceEntity?>(null) }
    var deletingWorkspace by remember { mutableStateOf<WorkspaceEntity?>(null) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Manage Workspaces") },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(max = 450.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // Active workspaces
                Text("Active Workspaces", style = MaterialTheme.typography.titleMedium)
                LazyColumn(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f, fill = false),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    items(activeWorkspaces, key = { it.id }) { workspace ->
                        val isActive = workspace.id == activeWorkspaceId
                        val containerColor = if (isActive) {
                            MaterialTheme.colorScheme.primaryContainer
                        } else {
                            MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                        }

                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(8.dp))
                                .background(containerColor)
                                .clickable {
                                    if (!isActive) {
                                        viewModel.selectWorkspace(workspace.id)
                                        onDismiss()
                                    }
                                }
                                .padding(horizontal = 12.dp, vertical = 8.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column(modifier = Modifier.weight(1f)) {
                                Text(
                                    text = workspace.name,
                                    style = MaterialTheme.typography.bodyLarge,
                                    color = if (isActive) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurface
                                )
                                if (!workspace.description.isNullOrBlank()) {
                                    Text(
                                        text = workspace.description!!,
                                        style = MaterialTheme.typography.bodySmall,
                                        color = if (isActive) MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.7f) else MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                            Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                IconButton(onClick = { editingWorkspace = workspace }) {
                                    Icon(
                                        Icons.Default.Edit,
                                        contentDescription = "Edit workspace",
                                        tint = if (isActive) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.primary
                                    )
                                }
                                if (!workspace.isDefault) {
                                    IconButton(onClick = { deletingWorkspace = workspace }) {
                                        Icon(
                                            Icons.Default.Delete,
                                            contentDescription = "Delete workspace",
                                            tint = if (isActive) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.error
                                        )
                                    }
                                }
                            }
                        }
                    }
                }

                // Deleted Workspaces section
                if (deletedWorkspaces.isNotEmpty()) {
                    Text("Deleted Workspaces (Trash)", style = MaterialTheme.typography.titleMedium)
                    LazyColumn(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(1f, fill = false),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(deletedWorkspaces, key = { it.id }) { workspace ->
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.2f))
                                    .padding(horizontal = 12.dp, vertical = 8.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = workspace.name,
                                        style = MaterialTheme.typography.bodyMedium,
                                        color = MaterialTheme.colorScheme.onSurface
                                    )
                                }
                                Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    IconButton(onClick = { viewModel.restoreWorkspace(workspace.id) }) {
                                        Icon(
                                            Icons.Default.Restore,
                                            contentDescription = "Restore workspace",
                                            tint = MaterialTheme.colorScheme.primary
                                        )
                                    }
                                    IconButton(onClick = { viewModel.permanentlyDeleteWorkspace(workspace) }) {
                                        Icon(
                                            Icons.Default.Delete,
                                            contentDescription = "Permanently delete workspace",
                                            tint = MaterialTheme.colorScheme.error
                                        )
                                    }
                                }
                            }
                        }
                    }
                }

                Button(
                    onClick = { showCreateDialog = true },
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Text("Create Workspace")
                }
            }
        },
        confirmButton = {
            TextButton(onClick = onDismiss) {
                Text("Close")
            }
        }
    )

    // Nested Workspace Creation Dialog
    if (showCreateDialog) {
        var newName by remember { mutableStateOf("") }
        var newDesc by remember { mutableStateOf("") }

        AlertDialog(
            onDismissRequest = { showCreateDialog = false },
            title = { Text("New Workspace") },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedTextField(
                        value = newName,
                        onValueChange = { newName = it },
                        label = { Text("Workspace Name") },
                        modifier = Modifier.fillMaxWidth()
                    )
                    OutlinedTextField(
                        value = newDesc,
                        onValueChange = { newDesc = it },
                        label = { Text("Description (Optional)") },
                        modifier = Modifier.fillMaxWidth()
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        if (newName.isNotBlank()) {
                            viewModel.insertWorkspace(newName, newDesc.takeIf { it.isNotBlank() })
                            showCreateDialog = false
                        }
                    },
                    enabled = newName.isNotBlank()
                ) {
                    Text("Create")
                }
            },
            dismissButton = {
                TextButton(onClick = { showCreateDialog = false }) {
                    Text("Cancel")
                }
            }
        )
    }

    // Nested Workspace Edit Dialog
    editingWorkspace?.let { workspace ->
        var editName by remember { mutableStateOf(workspace.name) }
        var editDesc by remember { mutableStateOf(workspace.description ?: "") }

        AlertDialog(
            onDismissRequest = { editingWorkspace = null },
            title = { Text("Edit Workspace") },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedTextField(
                        value = editName,
                        onValueChange = { editName = it },
                        label = { Text("Workspace Name") },
                        modifier = Modifier.fillMaxWidth()
                    )
                    OutlinedTextField(
                        value = editDesc,
                        onValueChange = { editDesc = it },
                        label = { Text("Description (Optional)") },
                        modifier = Modifier.fillMaxWidth()
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        if (editName.isNotBlank()) {
                            viewModel.updateWorkspace(
                                workspace.copy(
                                    name = editName.trim(),
                                    description = editDesc.trim().takeIf { it.isNotBlank() }
                                )
                            )
                            editingWorkspace = null
                        }
                    },
                    enabled = editName.isNotBlank()
                ) {
                    Text("Save")
                }
            },
            dismissButton = {
                TextButton(onClick = { editingWorkspace = null }) {
                    Text("Cancel")
                }
            }
        )
    }

    // Nested Workspace Delete Confirmation Dialog
    deletingWorkspace?.let { workspace ->
        AlertDialog(
            onDismissRequest = { deletingWorkspace = null },
            title = { Text("Delete Workspace?") },
            text = {
                Text("Are you sure you want to delete workspace \"${workspace.name}\"? All books and content inside this workspace will be soft-deleted and moved to the Trash Bin.")
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.deleteWorkspace(workspace)
                        deletingWorkspace = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error)
                ) {
                    Text("Delete")
                }
            },
            dismissButton = {
                TextButton(onClick = { deletingWorkspace = null }) {
                    Text("Cancel")
                }
            }
        )
    }
}

fun requirePositiveLongArg(backStackEntry: NavBackStackEntry, key: String): Long? {
        val value = backStackEntry.arguments?.getLong(key) ?: 0L
        return if (value > 0) value else null
    }

fun requireNonBlankStringArg(backStackEntry: NavBackStackEntry, key: String): String? {
        val value = backStackEntry.arguments?.getString(key)
        return if (!value.isNullOrBlank()) value else null
    }
}

fun quiz(quizId: Long, sessionId: Long? = null): String {
        return if (sessionId != null) {
            "quiz/$quizId?sessionId=$sessionId"
        } else {
            "quiz/$quizId"
        }
    }

fun category(category: String): String {
        val encoded = URLEncoder.encode(category, "UTF-8").replace("+", "%20")
        return "category/$encoded"
    }

fun adaptive(type: String, id: String): String {
        val encodedId = URLEncoder.encode(id, "UTF-8").replace("+", "%20")
        return "adaptive/$type/$encodedId"
    }
}

class CompilerViewModel @Inject constructor(
    @ApplicationContext context: Context,
    private val knowledgeRepository: KnowledgeRepository,
    private val quizRepository: QuizRepository,
    private val dataStoreManager: com.ahmedyejam.mks.data.preferences.DataStoreManager
) : ViewModel() {

    private val applicationContext = context.applicationContext
    private val _uiState = MutableStateFlow(CompilerUiState())
    val uiState = _uiState.asStateFlow()

    private val importFormatDetector = ImportFormatDetector(applicationContext)
    private val csvParser = com.ahmedyejam.mks.data.importer.parser.CsvParser()
    private val imageExtractor = GenericImageExtractor()
    private val xlsxResolver = XlsxImageResolver()
    private val jsonParser = JsonQuestionParser(imageExtractor)
    private val htmlParser = HtmlQuestionParser(jsonParser)
    private val textParser = TextQuestionParser(imageExtractor)
    private val headerMapper = SpreadsheetHeaderMapper()

    private var cellImagePathMap: Map<String, String> = emptyMap()
    private var currentUri: Uri? = null
    private var tempFile: java.io.File? = null
    private var currentFormat: ImportFormat = ImportFormat.UNKNOWN
    private var activeWorkspaceIdOverride: Long? = null

    // Cache for raw spreadsheet/CSV data
    private var cachedRows: List<List<String>>? = null
    private var cachedSheetImages: SheetImageResolution? = null

    // Persistent objects for performance
    private var currentWorkbook: org.apache.poi.ss.usermodel.Workbook? = null
    private var currentZipFile: ZipFile? = null

override fun onCleared() {
        super.onCleared()
        closeCurrentResources()
        tempFile?.delete()
    }

private fun closeCurrentResources() {
        try {
            currentWorkbook?.close()
            currentZipFile?.close()
        } catch (_: Exception) {}
        currentWorkbook = null
        currentZipFile = null
    }

private fun prepareTempFile(uri: Uri, format: ImportFormat): java.io.File? {
        tempFile?.delete()
        val extension = getFileName(uri)
            ?.substringAfterLast('.', "xlsx")
            ?.lowercase()
            ?.takeIf { it.isNotBlank() }
            ?: "xlsx"
        val file = java.io.File(applicationContext.cacheDir, "import_${System.currentTimeMillis()}.$extension")
        val maxBytes = when (format) {
            ImportFormat.CSV_TSV -> ImportLimits.MAX_CSV_IMPORT_BYTES
            else -> ImportLimits.MAX_XLSX_IMPORT_BYTES
        }
        return try {
            applicationContext.contentResolver.openInputStream(uri)?.use { input ->
                file.outputStream().use { output ->
                    input.copyToWithLimit(output, maxBytes)
                }
            }
            tempFile = file
            file
        } catch (_: Exception) {
            null
        }
    }

fun onFileSelected(
        uri: Uri,
        targetQuizId: Long? = null,
        targetDeckId: Long? = null,
        activeWorkspaceId: Long? = null
    ) {
        currentUri = uri
        activeWorkspaceIdOverride = activeWorkspaceId
        closeCurrentResources()
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null, questions = emptyList(), targetQuizId = targetQuizId, targetDeckId = targetDeckId) }
            try {
                val format = withContext(Dispatchers.IO) {
                    importFormatDetector.detectFormat(uri)
                }
                currentFormat = format

                val detectedMode = when (format) {
                    ImportFormat.XLSX, ImportFormat.CSV_TSV -> ImportMode.SPREADSHEET
                    ImportFormat.JSON -> ImportMode.JSON
                    ImportFormat.HTML -> ImportMode.HTML
                    else -> ImportMode.TEXT
                }

                _uiState.update { it.copy(detectedMode = detectedMode) }

                if (detectedMode == ImportMode.SPREADSHEET) {
                    loadSpreadsheet(uri, format)
                } else {
                    val content = withContext(Dispatchers.IO) {
                        val limit = when (format) {
                            ImportFormat.HTML -> ImportLimits.MAX_HTML_IMPORT_BYTES
                            else -> ImportLimits.MAX_TEXT_IMPORT_BYTES
                        }
                        applicationContext.contentResolver.openInputStream(uri)?.use { it.readTextWithLimit(limit) } ?: ""
                    }
                    parseContent(content, detectedMode)
                }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }

    private suspend fun loadSpreadsheet(uri: Uri, format: ImportFormat) = withContext(Dispatchers.IO) {
        try {
            closeCurrentResources()
            val file = prepareTempFile(uri, format) ?: throw IllegalStateException("Could not create temporary file")

            cellImagePathMap = if (format == ImportFormat.XLSX) {
                try {
                    val zipFile = ZipFile(file)
                    currentZipFile = zipFile
                    xlsxResolver.getCellImagePathMap(zipFile)
                } catch (_: Exception) {
                    emptyMap()
                }
            } else {
                emptyMap()
            }

            if (format == ImportFormat.CSV_TSV) {
                val sheetName = "CSV/TSV Content"
                _uiState.update {
                    it.copy(
                        sheetNames = listOf(sheetName),
                        selectedSheet = sheetName,
                        isLoading = false
                    )
                }
                onSheetSelected(sheetName)
            } else {
                val workbook = withContext(Dispatchers.IO) {
                    WorkbookFactory.create(file)
                }
                if (workbook.numberOfSheets > ImportLimits.MAX_XLSX_SHEETS) {
                    throw IllegalStateException("XLSX has too many sheets (max ${ImportLimits.MAX_XLSX_SHEETS}).")
                }
                currentWorkbook = workbook

                val sheets = (0 until workbook.numberOfSheets).map { workbook.getSheetAt(it).sheetName }
                val firstSheet = sheets.firstOrNull() ?: return@withContext

                _uiState.update {
                    it.copy(
                        sheetNames = sheets,
                        selectedSheet = firstSheet,
                        isLoading = false
                    )
                }

                onSheetSelected(firstSheet)
            }
        } catch (e: Exception) {
            closeCurrentResources()
            _uiState.update { it.copy(error = e.message, isLoading = false) }
        }
    }

fun onSheetSelected(sheetName: String?) {
        val file = tempFile ?: return
        if (sheetName == null) return

        // Reset cache for new sheet
        cachedRows = null
        cachedSheetImages = null

        _uiState.update { it.copy(isLoading = true, selectedSheet = sheetName) }
        viewModelScope.launch(Dispatchers.IO) {
            try {
                if (currentFormat == ImportFormat.CSV_TSV) {
                    val rows = parseCsvFile(file)
                    cachedRows = rows

                    var bestRowIdx = 0
                    var maxScore = -100
                    val scanLimit = minOf(rows.size - 1, 10)

                    for (i in 0..scanLimit) {
                        val cells = rows[i]
                        val score = headerMapper.calculateRowScore(cells)
                        if (score > maxScore) {
                            maxScore = score
                            bestRowIdx = i
                        }
                        if (score >= 200) break
                    }

                    processSpreadsheetRows(rows, rows.getOrNull(bestRowIdx), bestRowIdx)
                } else {
                    val workbook = currentWorkbook ?: WorkbookFactory.create(file).also { currentWorkbook = it }
                    val sheet = workbook.getSheet(sheetName) ?: return@launch
                    if ((sheet.lastRowNum + 1) > ImportLimits.MAX_XLSX_ROWS_PER_SHEET) {
                        throw IllegalStateException("Sheet '$sheetName' exceeds ${ImportLimits.MAX_XLSX_ROWS_PER_SHEET} row limit.")
                    }
                    val formatter = DataFormatter()

                    var bestRowIdx = 0
                    var maxScore = -100
                    val scanLimit = minOf(sheet.lastRowNum, 10)

                    val columnCount = detectStableColumnCount(sheet).coerceAtMost(ImportLimits.MAX_XLSX_COLUMNS)
                    if ((sheet.lastRowNum + 1).toLong() * columnCount.toLong() > ImportLimits.MAX_XLSX_CELLS_PER_SHEET) {
                        throw IllegalStateException("Sheet '$sheetName' exceeds ${ImportLimits.MAX_XLSX_CELLS_PER_SHEET} cell limit.")
                    }

                    // Pre-load rows for header detection and caching
                    val allRows = mutableListOf<List<String>>()
                    for (i in 0..sheet.lastRowNum) {
                        val row = sheet.getRow(i)
                        val cells = row?.let { extractRowCells(it, columnCount, formatter) } ?: emptyList()
                        allRows.add(cells)

                        if ((i <= scanLimit) && cells.isNotEmpty()) {
                            val score = headerMapper.calculateRowScore(cells)
                            if (score > maxScore) {
                                maxScore = score
                                bestRowIdx = i
                            }
                            // Early exit if high confidence header is found (Question + Answer + Options)
                            if (score >= 200) {
                                // Continue loading remaining rows without re-calculating score
                                for (j in (i + 1)..sheet.lastRowNum) {
                                    val nextRow = sheet.getRow(j)
                                    allRows.add(nextRow?.let { extractRowCells(it, columnCount, formatter) } ?: emptyList())
                                }
                                break
                            }
                        }
                    }
                    cachedRows = allRows

                    // Resolve images once for the whole sheet
                    val zipFile = currentZipFile ?: ZipFile(file).also { currentZipFile = it }
                    cachedSheetImages = xlsxResolver.resolveSheetImages(zipFile, sheetName, cellImagePathMap)

                    val headerRowIdx = bestRowIdx
                    val headerRow = allRows.getOrNull(headerRowIdx) ?: emptyList()
                    processSpreadsheetRows(null, headerRow, headerRowIdx)
                }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }

private fun processSpreadsheetRows(
        csvRows: List<List<String>>?,
        headerRow: List<String>? = null,
        headerIdx: Int = 0
    ) {
        val finalHeaderRow = headerRow ?: csvRows?.getOrNull(headerIdx) ?: emptyList()
        val mapping = headerMapper.mapHeaders(finalHeaderRow)
        val options = headerMapper.guessOptionColumns(finalHeaderRow, mapping)

        _uiState.update {
            it.copy(
                headerRow = headerIdx,
                mapping = mapping,
                optionColumns = options,
                availableColumns = finalHeaderRow
            )
        }

        viewModelScope.launch(Dispatchers.Default) {
            performCachedParse(mapping, options, headerIdx)
        }
    }

    private suspend fun performCachedParse(
        mapping: Map<String, Int>,
        optionCols: List<Int>,
        headerIdx: Int
    ) = withContext(Dispatchers.Default) {
        val rows = cachedRows ?: return@withContext
        val images = cachedSheetImages

        try {
            val parser = SpreadsheetQuestionParser(
                mapping = mapping,
                optionCols = optionCols,
                sheetAddressImages = images?.addressImages ?: emptyMap(),
                sheetRowImages = images?.rowImages ?: emptyMap(),
                imageExtractor = imageExtractor
            )

            val questions = mutableListOf<ParsedQuestion>()
            var skippedEmptyStem = 0
            var errors = 0

            for (i in (headerIdx + 1) until rows.size) {
                try {
                    val cells = rows[i]
                    val parsedQuestion = parser.parseRow(cells, i + 1)
                    if (parsedQuestion == null) {
                        skippedEmptyStem++
                    } else {
                        questions.add(parsedQuestion)
                    }
                } catch (e: Exception) {
                    errors++
                }
            }

            val stats = ParseStats(
                totalRowsProcessed = rows.size - headerIdx - 1,
                successfullyParsed = questions.size,
                skippedEmptyStem = skippedEmptyStem,
                errors = errors,
                questionsWithImages = questions.count { it.imageDataUrl != null || it.imageSource != null },
                questionsWithIssues = questions.count { it.issues.isNotEmpty() }
            )

            _uiState.update { it.copy(questions = questions, stats = stats, isLoading = false) }
        } catch (e: Exception) {
            _uiState.update { it.copy(error = e.message, isLoading = false) }
        }
    }

fun updateMapping(mapping: Map<String, Int>, optionCols: List<Int>) {
        val headerIdx = _uiState.value.headerRow

        _uiState.update {
            it.copy(
                mapping = mapping,
                optionColumns = optionCols,
                isLoading = true
            )
        }

        viewModelScope.launch(Dispatchers.Default) {
            performCachedParse(mapping, optionCols, headerIdx)
        }
    }

fun updateHeaderRow(index: Int) {
        val rows = cachedRows ?: return
        val headerRow = rows.getOrNull(index) ?: emptyList()

        _uiState.update { it.copy(headerRow = index, isLoading = true) }
        processSpreadsheetRows(rows, headerRow, index)
    }

fun toggleQuestionInclusion(index: Int) {
        _uiState.update { state ->
            val currentQuestions = state.questions.toMutableList()
            if (index in currentQuestions.indices) {
                val q = currentQuestions[index]
                currentQuestions[index] = q.copy(isIncluded = !q.isIncluded)
                state.copy(questions = currentQuestions)
            } else state
        }
    }

fun toggleQuestionsRange(from: Int, to: Int, include: Boolean) {
        _uiState.update { state ->
            val currentQuestions = state.questions.toMutableList()
            val start = (from - 1).coerceIn(currentQuestions.indices)
            val end = (to - 1).coerceIn(currentQuestions.indices)
            val range = if (start <= end) start..end else end..start

            for (i in range) {
                currentQuestions[i] = currentQuestions[i].copy(isIncluded = include)
            }
            state.copy(questions = currentQuestions)
        }
    }

fun updateQuestionCorrectAnswer(index: Int, answerId: String) {
        _uiState.update { state ->
            val currentQuestions = state.questions.toMutableList()
            if (index in currentQuestions.indices) {
                val q = currentQuestions[index]
                val newAnswers = if (q.correctAnswers.contains(answerId)) {
                    q.correctAnswers.filter { it != answerId }
                } else {
                    q.correctAnswers + answerId
                }
                currentQuestions[index] = q.copy(correctAnswers = newAnswers.sorted())
                state.copy(questions = currentQuestions)
            } else {
                state
            }
        }
    }

fun saveParsedQuestions(
        title: String,
        bookId: Long?,
        targetQuizId: Long? = null,
        targetDeckId: Long? = null,
        newBookTitle: String? = null
    ) {
        val questions = _uiState.value.questions.filter { it.isIncluded }
        if (questions.isEmpty()) return

        viewModelScope.launch(Dispatchers.IO) {
            _uiState.update { it.copy(isLoading = true) }
            try {
                val currentWorkspaceId =
                    activeWorkspaceIdOverride ?: dataStoreManager.currentWorkspaceId.firstOrNull()
                val currentTargetDeckId = targetDeckId ?: _uiState.value.targetDeckId
                if (currentTargetDeckId != null) {
                    val flashcards = questions.mapIndexed { index, q ->
                        val optionsText = if (q.options.isNotEmpty()) {
                            q.options.joinToString("\n") { opt -> "${opt.id.removePrefix("opt_")}: ${opt.text}" }
                        } else ""
                        val answersText = if (q.correctAnswers.isNotEmpty()) {
                            q.options.filter { q.correctAnswers.contains(it.id) }.joinToString(", ") { it.text }
                                .takeIf { it.isNotBlank() } ?: q.correctAnswers.joinToString(", ") { it.removePrefix("opt_") }
                        } else ""
                        FlashcardEntity(
                            externalId = java.util.UUID.randomUUID().toString(),
                            deckId = currentTargetDeckId,
                            frontText = buildString {
                                append(q.stem)
                                if (optionsText.isNotBlank()) append("\n\n$optionsText")
                            },
                            backText = buildString {
                                append(answersText)
                                if (!q.explanation.isNullOrBlank()) append("\n\n${q.explanation}")
                                if (!q.reference.isNullOrBlank()) append("\n\nReference: ${q.reference}")
                            },
                            hint = q.hint,
                            tags = q.categories,
                            orderIndex = index
                        )
                    }
                    val currentOrder = knowledgeRepository.getFlashcardsByDeckId(currentTargetDeckId).firstOrNull()?.size ?: 0
                    val finalFlashcards = flashcards.mapIndexed { i, f -> f.copy(orderIndex = currentOrder + i) }
                    knowledgeRepository.insertFlashcards(finalFlashcards)
                } else {
                    quizRepository.importCompiledQuestions(
                        title = title,
                        targetBookId = bookId,
                        targetQuizId = targetQuizId,
                        newBookTitle = newBookTitle,
                        questions = questions,
                        activeWorkspaceId = currentWorkspaceId
                    )
                }
                activeWorkspaceIdOverride = null
                _uiState.update { it.copy(isLoading = false, questions = emptyList()) }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }

private fun parseCsvFile(file: java.io.File): List<List<String>> {
        val content = file.readTextWithLimit(ImportLimits.MAX_CSV_IMPORT_BYTES)
        return csvParser.parse(content)
    }

    private suspend fun parseContent(content: String, mode: ImportMode) = withContext(Dispatchers.Default) {
        val questions = when (mode) {
            ImportMode.JSON -> jsonParser.parse(content)
            ImportMode.HTML -> htmlParser.parse(content)
            else -> textParser.parse(content)
        }
        _uiState.update { it.copy(questions = questions, isLoading = false) }
    }

private fun extractRowCells(
        row: Row?,
        columnCount: Int,
        formatter: DataFormatter,
    ): List<String> {
        if (row == null || columnCount <= 0) return emptyList()
        return (0 until columnCount).map { columnIndex ->
            row.getCell(columnIndex)?.let { cell ->
                formatCellSafely(cell, formatter).trim()
            }.orEmpty()
        }
    }

private fun formatCellSafely(
        cell: Cell,
        formatter: DataFormatter,
    ): String {
        return try {
            if (cell.cellType == CellType.FORMULA) fallbackFormulaText(cell, formatter)
            else formatter.formatCellValue(cell)
        } catch (_: Exception) {
            fallbackFormulaText(cell, formatter)
        }
    }

private fun fallbackFormulaText(cell: Cell, formatter: DataFormatter): String {
        if (cell.cellType != CellType.FORMULA) {
            return runCatching { formatter.formatCellValue(cell) }.getOrElse { cell.toString() }
        }

        return try {
            when (cell.cachedFormulaResultType) {
                CellType.STRING -> cell.richStringCellValue?.string.orEmpty()
                CellType.NUMERIC -> formatter.formatRawCellContents(
                    cell.numericCellValue,
                    cell.cellStyle.dataFormat.toInt(),
                    cell.cellStyle.dataFormatString
                )
                CellType.BOOLEAN -> cell.booleanCellValue.toString()
                CellType.BLANK -> ""
                else -> "=" + cell.cellFormula.orEmpty()
            }
        } catch (_: Exception) {
            runCatching { "=" + cell.cellFormula.orEmpty() }.getOrElse { cell.toString() }
        }
    }

private fun detectStableColumnCount(sheet: org.apache.poi.ss.usermodel.Sheet): Int {
        var maxColumns = 0
        val scanEnd = minOf(sheet.lastRowNum, 40)
        for (rowIndex in 0..scanEnd) {
            val row = sheet.getRow(rowIndex) ?: continue
            maxColumns = maxOf(maxColumns, row.lastCellNum.toInt().coerceAtLeast(0))
        }
        return maxColumns
    }

private fun getFileName(uri: Uri): String? {
        return try {
            applicationContext.contentResolver.query(uri, arrayOf(OpenableColumns.DISPLAY_NAME), null, null, null)?.use { cursor ->
                if (cursor.moveToFirst()) {
                    val index = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                    if (index != -1) cursor.getString(index) else null
                } else {
                    null
                }
            }
        } catch (_: Exception) {
            uri.lastPathSegment
        }
    }
}

fun QuizQuestionsScreen(
    viewModel: QuizQuestionsViewModel,
    focusedQuestionId: Long? = null,
    isEmbedded: Boolean = false,
    onBack: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsState()
    var showFilters by rememberSaveable { mutableStateOf(false) }
    var isSearching by rememberSaveable { mutableStateOf(false) }
    var showMoveDialog by remember { mutableStateOf(false) }
    var showCopyDialog by remember { mutableStateOf(false) }
    var showExportDialog by remember { mutableStateOf(false) }
    var showEditDialog by remember { mutableStateOf<QuestionEntity?>(null) }
    var showAssetsDialog by remember { mutableStateOf<QuestionEntity?>(null) }
    var showAddDialog by remember { mutableStateOf(false) }
    var showDeleteConfirm by remember { mutableStateOf(false) }
    var showFlashcardDialog by remember { mutableStateOf(false) }

    val scrollBehavior = TopAppBarDefaults.exitUntilCollapsedScrollBehavior()
    val scrollState = rememberLazyListState()
    val isSelectionMode = uiState.selectedQuestionIds.isNotEmpty()

    LaunchedEffect(focusedQuestionId, uiState.filteredQuestions) {
        if (focusedQuestionId != null && uiState.filteredQuestions.isNotEmpty()) {
            val index = uiState.filteredQuestions.indexOfFirst { it.id == focusedQuestionId }
            if (index != -1) {
                scrollState.animateScrollToItem(index + 1)
            }
        }
    }
    var fullscreenImageUrl by remember { mutableStateOf<String?>(null) }

    if (showMoveDialog) {
        QuizActionDialog(
            title = stringResource(R.string.move_to_quiz_title),
            onDismiss = { showMoveDialog = false },
            onConfirm = { targetQuizId ->
                viewModel.moveSelectedQuestionsToQuiz(targetQuizId)
                showMoveDialog = false
            },
            viewModel = viewModel
        )
    }

    if (showCopyDialog) {
        QuizActionDialog(
            title = stringResource(R.string.copy_to_quiz),
            onDismiss = { showCopyDialog = false },
            onConfirm = { targetQuizId ->
                viewModel.copySelectedQuestionsToQuiz(targetQuizId)
                showCopyDialog = false
            },
            viewModel = viewModel
        )
    }

    if (showExportDialog) {
        var newQuizTitle by remember { mutableStateOf("") }
        AlertDialog(
            onDismissRequest = { showExportDialog = false },
            title = { Text(stringResource(R.string.export_to_new_quiz)) },
            text = {
                OutlinedTextField(
                    value = newQuizTitle,
                    onValueChange = { newQuizTitle = it },
                    label = { Text(stringResource(R.string.quiz_title_label)) },
                    modifier = Modifier.fillMaxWidth()
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.exportSelectedQuestionsToNewQuiz(newQuizTitle)
                        showExportDialog = false
                    },
                    enabled = newQuizTitle.isNotBlank()
                ) {
                    Text(stringResource(R.string.create))
                }
            },
            dismissButton = {
                TextButton(onClick = { showExportDialog = false }) {
                    Text(stringResource(R.string.cancel))
                }
            }
        )
    }

    if (showFlashcardDialog) {
        CreateFlashcardsFromSelectedDialog(
            selectedCount = uiState.selectedQuestionIds.size,
            onDismiss = { showFlashcardDialog = false },
            onConfirm = { title, clearMarks ->
                viewModel.createFlashcardsFromSelected(title, clearMarks)
                showFlashcardDialog = false
            }
        )
    }

    if (showAddDialog) {
        EditQuestionDialog(
            question = QuestionEntity(
                quizId = uiState.quiz?.id ?: 0L,
                externalId = java.util.UUID.randomUUID().toString(),
                text = "",
                options = listOf("", "", "", ""),
                correctAnswers = listOf(0),
                type = com.ahmedyejam.mks.data.local.entity.QuestionType.SINGLE_CHOICE
            ),
            onDismiss = { showAddDialog = false },
            onConfirm = {
                viewModel.addQuestion(it)
                showAddDialog = false
            }
        )
    }

    showEditDialog?.let { question ->
        EditQuestionDialog(
            question = question,
            onDismiss = { showEditDialog = null },
            onConfirm = {
                viewModel.updateQuestion(it)
                showEditDialog = null
            }
        )
    }

    showAssetsDialog?.let { question ->
        val assets by viewModel.assetsForQuestion(question.id).collectAsState(initial = emptyList())
        val bookId = uiState.quiz?.bookId ?: 0L
        val sources by viewModel.sourceDocumentsForBook(bookId).collectAsState(initial = emptyList())
        val linkedBlueprints by viewModel.linkedBlueprintsForQuestion(bookId, question.id).collectAsState(initial = emptyList())
        val annotations by viewModel.annotationsForQuestion(question.id).collectAsState(initial = emptyList())
        QuestionAssetsDialog(
            question = question,
            bookId = bookId,
            assets = assets,
            annotations = annotations,
            sourceDocuments = sources,
            linkedBlueprints = linkedBlueprints,
            onDismiss = { showAssetsDialog = null },
            onAddAsset = { viewModel.addQuestionAsset(it) },
            onUpdateAsset = { viewModel.updateQuestionAsset(it) },
            onDeleteAsset = { viewModel.deleteQuestionAsset(it) },
            onAddAnnotation = { selectedText, noteBody, colorLabel -> viewModel.addQuestionAnnotation(bookId, question.id, selectedText, noteBody, colorLabel) },
            onUpdateAnnotation = { viewModel.updateAnnotation(it) },
            onDeleteAnnotation = { viewModel.deleteAnnotation(it) },
            onCreateSourceAndAddAsset = { asset, source -> viewModel.createSourceAndAddQuestionAsset(asset, source) },
            onCreateBlueprintFromQuestion = { viewModel.createBlueprintFromQuestion(bookId, question.id) }
        )
    }

    if (showDeleteConfirm) {
        AlertDialog(
            onDismissRequest = { showDeleteConfirm = false },
            title = { Text("Delete selected questions?") },
            text = { Text("This will permanently delete ${uiState.selectedQuestionIds.size} selected question(s).") },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.deleteSelectedQuestions()
                        showDeleteConfirm = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error)
                ) { Text("Delete") }
            },
            dismissButton = { TextButton(onClick = { showDeleteConfirm = false }) { Text("Cancel") } }
        )
    }

    if (isEmbedded) {
        Scaffold(
            topBar = {
                if (isSelectionMode) {
                    SelectionTopAppBar(
                        selectedCount = uiState.selectedQuestionIds.size,
                        onClearSelection = { viewModel.clearSelection() },
                        onDelete = { showDeleteConfirm = true },
                        onMove = { showMoveDialog = true },
                        onSelectAll = { viewModel.toggleAllSelection() },
                        onCopy = { showCopyDialog = true },
                        onExport = { showExportDialog = true },
                        onCreateFlashcards = { showFlashcardDialog = true },
                        onMarkSelected = { viewModel.markSelectedQuestions(true) },
                        onUnmarkSelected = { viewModel.markSelectedQuestions(false) },
                        showMarkActions = true,
                        scrollBehavior = null
                    )
                }
            },
            floatingActionButton = {
                FloatingActionButton(
                    onClick = { showAddDialog = true },
                    containerColor = MaterialTheme.colorScheme.primaryContainer,
                    contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                ) {
                    Icon(Icons.Default.Add, contentDescription = stringResource(R.string.new_question))
                }
            }
        ) { padding ->
            Column(
                Modifier
                    .fillMaxSize()
                    .padding(padding)
            ) {
                if (showFilters) {
                    FilterControls(
                        visibility = uiState.visibility,
                        onToggle = { viewModel.toggleVisibility(it) }
                    )
                }
                QuizQuestionsList(
                    uiState = uiState,
                    scrollState = scrollState,
                    onToggleSelection = { viewModel.toggleSelection(it) },
                    onToggleMarked = { viewModel.toggleMarked(it) },
                    onImageClick = { fullscreenImageUrl = it },
                    onEditClick = { showEditDialog = it },
                    onAssetsClick = { showAssetsDialog = it },
                    onToggleDropped = { viewModel.toggleDropped(it) }
                )
            }
        }
    } else {
        Scaffold(
            modifier = Modifier.nestedScroll(scrollBehavior.nestedScrollConnection),
            topBar = {
                if (isSelectionMode) {
                    SelectionTopAppBar(
                        selectedCount = uiState.selectedQuestionIds.size,
                        onClearSelection = { viewModel.clearSelection() },
                        onDelete = { showDeleteConfirm = true },
                        onMove = { showMoveDialog = true },
                        onSelectAll = { viewModel.toggleAllSelection() },
                        onCopy = { showCopyDialog = true },
                        onExport = { showExportDialog = true },
                        onCreateFlashcards = { showFlashcardDialog = true },
                        onMarkSelected = { viewModel.markSelectedQuestions(true) },
                        onUnmarkSelected = { viewModel.markSelectedQuestions(false) },
                        showMarkActions = true,
                        scrollBehavior = scrollBehavior
                    )
                } else {
                    DefaultTopAppBar(
                        categoryName = uiState.quiz?.title ?: stringResource(R.string.quizzes_title),
                        filteredCount = uiState.filteredQuestions.size,
                        totalCount = uiState.allQuestions.size,
                        isSearching = isSearching,
                        searchQuery = uiState.searchQuery,
                        onSearchQueryChange = { viewModel.setSearchQuery(it) },
                        onToggleSearch = { isSearching = !isSearching },
                        onToggleFilters = { showFilters = !showFilters },
                        onBack = onBack,
                        scrollBehavior = scrollBehavior
                    )
                }
            },
            floatingActionButton = {
                FloatingActionButton(
                    onClick = { showAddDialog = true },
                    containerColor = MaterialTheme.colorScheme.primaryContainer,
                    contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                ) {
                    Icon(Icons.Default.Add, contentDescription = stringResource(R.string.new_question))
                }
            }
        ) { padding ->
            Column(
                modifier = Modifier
                    .padding(padding)
                    .fillMaxSize()
            ) {
                if (showFilters) {
                    FilterControls(
                        visibility = uiState.visibility,
                        onToggle = { viewModel.toggleVisibility(it) }
                    )
                }
                QuizQuestionsList(
                    uiState = uiState,
                    scrollState = scrollState,
                    onToggleSelection = { viewModel.toggleSelection(it) },
                    onToggleMarked = { viewModel.toggleMarked(it) },
                    onImageClick = { fullscreenImageUrl = it },
                    onEditClick = { showEditDialog = it },
                    onAssetsClick = { showAssetsDialog = it },
                    onToggleDropped = { viewModel.toggleDropped(it) }
                )
            }
        }
    }

    fullscreenImageUrl?.let { data ->
        ZoomableImageDialog(
            imageData = data,
            onDismiss = { fullscreenImageUrl = null }
        )
    }
}

private fun QuizQuestionsList(
    uiState: QuizQuestionsUiState,
    scrollState: androidx.compose.foundation.lazy.LazyListState,
    onToggleSelection: (Long) -> Unit,
    onToggleMarked: (QuestionEntity) -> Unit,
    onImageClick: (String) -> Unit,
    onEditClick: (QuestionEntity) -> Unit,
    onAssetsClick: (QuestionEntity) -> Unit,
    onToggleDropped: (QuestionEntity) -> Unit
) {
    if (uiState.isLoading) {
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            CircularProgressIndicator()
        }
    } else if (uiState.filteredQuestions.isEmpty()) {
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            Text(if (uiState.searchQuery.isBlank()) stringResource(R.string.no_questions_found) else stringResource(R.string.no_questions_match_filter))
        }
    } else {
        LazyColumn(
            state = scrollState,
            modifier = Modifier.fillMaxSize(),
            contentPadding = PaddingValues(16.dp, 16.dp, 16.dp, 80.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            uiState.quizSummary?.let { summary ->
                item { QuizKnowledgeSummaryCard(summary) }
            }
            items(uiState.filteredQuestions, key = { it.id }) { question ->
                QuestionCard(
                    question = question,
                    visibility = uiState.visibility,
                    isSelected = uiState.selectedQuestionIds.contains(question.id),
                    isSelectionMode = uiState.selectedQuestionIds.isNotEmpty(),
                    onToggleSelection = { onToggleSelection(question.id) },
                    onToggleMarked = { onToggleMarked(question) },
                    onImageClick = { onImageClick(it) },
                    onEditClick = { onEditClick(question) },
                    hasAssets = question.id in uiState.questionIdsWithAssets,
                    onAssetsClick = { onAssetsClick(question) },
                    onToggleDropped = { onToggleDropped(question) }
                )
            }
        }
    }
}

private fun QuizKnowledgeSummaryCard(summary: QuizKnowledgeSummary) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            Text("Quiz summary", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold)
            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                QuizSummaryChip("Questions", summary.totalQuestions, Modifier.weight(1f))
                QuizSummaryChip("Marked", summary.markedQuestions, Modifier.weight(1f))
                QuizSummaryChip("Missed", summary.missedQuestions, Modifier.weight(1f))
            }
            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                QuizSummaryChip("Notes", summary.questionsWithNotes, Modifier.weight(1f))
                QuizSummaryChip("Assets", summary.questionsWithAssets, Modifier.weight(1f))
                QuizSummaryChip("Sources", summary.questionsWithSources, Modifier.weight(1f))
            }
        }
    }
}

private fun QuizSummaryChip(label: String, value: Int, modifier: Modifier = Modifier) {
    Surface(
        modifier = modifier,
        shape = RoundedCornerShape(12.dp),
        color = MaterialTheme.colorScheme.surfaceVariant
    ) {
        Column(modifier = Modifier.padding(10.dp), horizontalAlignment = Alignment.CenterHorizontally) {
            Text(value.toString(), style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold)
            Text(label, style = MaterialTheme.typography.labelSmall)
        }
    }
}

fun QuizActionDialog(
    title: String,
    onDismiss: () -> Unit,
    onConfirm: (Long) -> Unit,
    viewModel: QuizQuestionsViewModel
) {
    val quizzes by viewModel.allQuizzes.collectAsState()
    var selectedQuizId by remember { mutableStateOf<Long?>(null) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(title) },
        text = {
            if (quizzes.isEmpty()) {
                Text(stringResource(R.string.no_quizzes_available))
            } else {
                LazyColumn(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 400.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    items(quizzes, key = { it.id }) { quiz ->
                        Surface(
                            onClick = { selectedQuizId = quiz.id },
                            shape = RoundedCornerShape(8.dp),
                            color = if (selectedQuizId == quiz.id) MaterialTheme.colorScheme.primaryContainer else Color.Transparent,
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant)
                        ) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                RadioButton(
                                    selected = selectedQuizId == quiz.id,
                                    onClick = { selectedQuizId = quiz.id }
                                )
                                Spacer(modifier = Modifier.width(8.dp))
                                Column {
                                    Text(quiz.title, style = MaterialTheme.typography.bodyLarge)
                                    quiz.description?.let { desc ->
                                        if (desc.isNotBlank()) {
                                            Text(
                                                desc,
                                                style = MaterialTheme.typography.bodySmall,
                                                maxLines = 1
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(
                onClick = { selectedQuizId?.let { onConfirm(it) } },
                enabled = selectedQuizId != null
            ) {
                Text(stringResource(R.string.move))
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text(stringResource(R.string.cancel)) }
        }
    )
}

fun QuizDetailTabsScreen(
    quizId: Long,
    quizTitle: String?,
    sessionViewModel: SessionViewModel,
    questionsViewModel: QuizQuestionsViewModel,
    dataStoreManager: DataStoreManager,
    onSessionSelected: (Long, Boolean) -> Unit,
    onBack: () -> Unit
) {
    val scope = rememberCoroutineScope()
    val tabs = remember { QuizTab.entries.toTypedArray() }
    val pagerState = rememberPagerState(initialPage = 0) { tabs.size }

    Scaffold(
        topBar = {
            Column(
                modifier = Modifier.background(MaterialTheme.colorScheme.surface)
            ) {
                TopAppBar(
                    title = { Text(quizTitle ?: "Quiz Details") },
                    navigationIcon = {
                        IconButton(onClick = onBack) {
                            Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back")
                        }
                    }
                )
                TabRow(
                    selectedTabIndex = pagerState.currentPage,
                    containerColor = MaterialTheme.colorScheme.surface,
                    contentColor = MaterialTheme.colorScheme.primary,
                    indicator = { tabPositions ->
                        if (pagerState.currentPage < tabPositions.size) {
                            TabRowDefaults.SecondaryIndicator(
                                Modifier.tabIndicatorOffset(tabPositions[pagerState.currentPage]),
                                color = MaterialTheme.colorScheme.primary
                            )
                        }
                    }
                ) {
                    tabs.forEachIndexed { index, tab ->
                        Tab(
                            selected = pagerState.currentPage == index,
                            onClick = { scope.launch { pagerState.animateScrollToPage(index) } },
                            text = { Text(tab.title) },
                            icon = { Icon(tab.icon, null, Modifier.size(20.dp)) }
                        )
                    }
                }
            }
        }
    ) { padding ->
        HorizontalPager(
            state = pagerState,
            modifier = Modifier
                .fillMaxSize()
                .padding(padding),
            beyondViewportPageCount = 1
        ) { page ->
            when (tabs[page]) {
                QuizTab.SESSIONS -> {
                    SessionManagementScreen(
                        quizId = quizId,
                        viewModel = sessionViewModel,
                        dataStoreManager = dataStoreManager,
                        isEmbedded = true,
                        onSessionSelected = onSessionSelected,
                        onNavigateBack = onBack
                    )
                }
                QuizTab.BROWSE -> {
                    QuizQuestionsScreen(
                        viewModel = questionsViewModel,
                        isEmbedded = true,
                        onBack = onBack
                    )
                }
            }
        }
    }
}

fun QuizPlayerScreen(
    viewModel: QuizViewModel,
    onQuizFinished: (Long, Int, Int) -> Unit,
    onAskAiClick: (Long) -> Unit = {},
    onBack: () -> Unit,
    onViewCategoryQuestions: (String) -> Unit = {},
) {
    val state by viewModel.uiState.collectAsStateWithLifecycle()

    val currentQuestion by remember(state.currentIndex, state.questions) {
        derivedStateOf {
            state.questions.getOrNull(state.currentIndex)
        }
    }

    val totalQuestions = state.questions.size

    val fullscreenImageUrlState = remember { mutableStateOf<Any?>(null) }
    var fullscreenImageUrl by fullscreenImageUrlState
    val showDropQuestionDialogState = rememberSaveable { mutableStateOf(value = false) }
    var showDropQuestionDialog by showDropQuestionDialogState
    val showQuestionAssetsState = rememberSaveable { mutableStateOf(value = false) }
    var showQuestionAssets by showQuestionAssetsState
    var selectedCategoryForEdit by rememberSaveable(state.allCategoriesWithMetadata) { mutableStateOf<CategoryWithMetadata?>(null) }


    if (showDropQuestionDialog) {
        AlertDialog(
            onDismissRequest = { showDropQuestionDialogState.value = false },
            title = { Text(stringResource(R.string.drop_question_title)) },
            text = { Text(stringResource(R.string.drop_question_msg)) },
            confirmButton = {
                TextButton(
                    onClick = {
                        viewModel.dropQuestion()
                        showDropQuestionDialogState.value = false
                    },
                ) {
                    Text(stringResource(R.string.drop), color = MaterialTheme.colorScheme.error)
                }
            },
            dismissButton = {
                TextButton(onClick = { showDropQuestionDialogState.value = false }) {
                    Text(stringResource(R.string.cancel))
                }
            },
        )
    }

    val currentQuestionAssets by viewModel
        .assetsForQuestion(currentQuestion?.id ?: -1L)
        .collectAsStateWithLifecycle(initialValue = emptyList())
    val currentBookSources by viewModel
        .sourceDocumentsForCurrentQuiz()
        .collectAsStateWithLifecycle(initialValue = emptyList())

    if (showQuestionAssets) {
        currentQuestion?.let { question ->
            QuestionAssetsReadOnlyDialog(
                question = question,
                assets = currentQuestionAssets,
                sourceDocuments = currentBookSources,
            ) { showQuestionAssetsState.value = false }
        }
    }

    LaunchedEffect(state.isCompleted) {
        if (state.isCompleted) {
            onQuizFinished(state.sessionId ?: -1L, state.score, state.initialQuestionCount)
        }
    }

    if (state.isLoading) {
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            CircularProgressIndicator()
        }
        return
    }

    BoxWithConstraints(modifier = Modifier.fillMaxSize()) {
        val fullHeight = this.maxHeight.value * LocalDensity.current.density
        val density = LocalDensity.current
        var sheetContentHeight by remember { mutableFloatStateOf(0f) }

        val navBarHeight = WindowInsets.navigationBars.asPaddingValues().calculateBottomPadding()
        val collapsedHeight = with(density) { (56.dp + navBarHeight).toPx() }
        val partialHeight = with(density) { (100.dp + navBarHeight).toPx() }
        val expandedOffset = with(density) { 64.dp.toPx() }

        val anchors = remember(fullHeight, sheetContentHeight) {
            DraggableAnchors {
                QuizSheetValue.Collapsed at (fullHeight - collapsedHeight)
                QuizSheetValue.PartiallyExpanded at (fullHeight - partialHeight)

                val targetExpanded = if (sheetContentHeight > 0) {
                    (fullHeight - sheetContentHeight).coerceAtLeast(expandedOffset)
                } else {
                    expandedOffset
                }
                QuizSheetValue.Expanded at targetExpanded
            }
        }

        val draggableState = remember(anchors) {
            AnchoredDraggableState(
                initialValue = QuizSheetValue.PartiallyExpanded,
                anchors = anchors,
                positionalThreshold = { distance: Float -> distance * 0.5f },
                velocityThreshold = { with(density) { 100.dp.toPx() } },
                snapAnimationSpec = spring(),
                decayAnimationSpec = exponentialDecay(),
            )
        }

        Scaffold(
            modifier = Modifier.fillMaxSize(),
            contentWindowInsets = WindowInsets(0, 0, 0, 0),
            topBar = {
                QuizTopBar(
                    currentIndex = state.currentIndex,
                    totalQuestions = totalQuestions,
                    initialQuestionCount = state.initialQuestionCount,
                    isMarked = currentQuestion?.isMarked ?: false,
                    focusModeEnabled = state.focusModeEnabled,
                    sessionLabel = state.sessionLabel,
                    timerStateFlow = viewModel.timerState,
                    quizTimerSeconds = state.quizTimerSeconds,
                    questionTimerSeconds = state.questionTimerSeconds,
                    isAnswered = state.isAnswered,
                    score = state.score,
                    currentStreak = state.currentStreak,
                    onAskAiClick = { currentQuestion?.id?.let(onAskAiClick) },
                    onBack = onBack,
                )
            }
        ) { padding ->
            val currentOffset = draggableState.offset
            val isOffsetNan = currentOffset.isNaN()
            val bottomPadding = if (isOffsetNan) 100.dp else with(density) { (fullHeight - currentOffset).toDp() }

            Box(
                modifier = Modifier
                    .padding(padding)
                    .padding(bottom = bottomPadding.coerceAtLeast(0.dp))
                    .fillMaxSize(),
            ) {
                if (totalQuestions == 0) {
                    EmptyQuestionsPlaceholder(error = state.error)
                } else {
                    currentQuestion?.let { question ->
                        QuestionContent(
                            state = state,
                            currentQuestion = question,
                            viewModel = viewModel,
                            onEditCategory = { selectedCategoryForEdit = it },
                            onImageClick = { fullscreenImageUrl = it },
                            assetCount = currentQuestionAssets.size,
                        ) { showQuestionAssetsState.value = true }
                    } ?: Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                        CircularProgressIndicator()
                    }
                }
            }
        }

        // Custom Bottom Sheet
        Surface(
            modifier = Modifier
                .offset {
                    val yOffset = draggableState.offset
                    IntOffset(
                        x = 0,
                        y = if (yOffset.isNaN()) (fullHeight - partialHeight).roundToInt() else yOffset.roundToInt()
                    )
                }
                .anchoredDraggable(draggableState, Orientation.Vertical)
                .wrapContentHeight(align = Alignment.Top)
                .heightIn(max = with(density) { (fullHeight - expandedOffset).toDp() }),
            shape = RoundedCornerShape(topStart = 28.dp, topEnd = 28.dp),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.85f),
            tonalElevation = 0.dp,
            shadowElevation = 2.dp
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .navigationBarsPadding()
                    .onGloballyPositioned { coords ->
                        sheetContentHeight = coords.size.height.toFloat()
                    }
            ) {
                // Drag Handle
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Box(
                        modifier = Modifier
                            .size(width = 32.dp, height = 4.dp)
                            .background(
                                color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                                shape = RoundedCornerShape(2.dp)
                            )
                    )
                }

                QuizSheetContent(
                    state = state,
                    viewModel = viewModel,
                    onDropQuestion = { showDropQuestionDialogState.value = true },
                    onAskAiClick = onAskAiClick
                )
            }
        }
    }

    fullscreenImageUrl?.let { data ->
        ZoomableImageDialog(
            imageData = data,
        ) { fullscreenImageUrlState.value = null }
    }

    selectedCategoryForEdit?.let { category ->
        key(category.name) {
            CategoryEditDialog(
                category = category,
                allCategories = state.allCategoriesWithMetadata,
                books = emptyList(),
                onDismiss = { selectedCategoryForEdit = null },
                onDelete = {
                    viewModel.deleteCategory(category.name)
                    selectedCategoryForEdit = null
                },
                onRename = { newName ->
                    viewModel.renameCategory(category.name, newName)
                    selectedCategoryForEdit = null
                },
                onMerge = { target ->
                    viewModel.mergeCategory(category.name, target)
                    selectedCategoryForEdit = null
                },
                onGetMergePreview = { target ->
                    viewModel.getMergePreview(category.name, target)
                },
                onCreateQuiz = { _, _ -> },
                onTogglePin = { viewModel.onToggleCategoryPin(category.name) },
                onUpdateEmoji = { emoji -> viewModel.onUpdateCategoryEmoji(category.name, emoji) },
                onUpdateColor = { color -> viewModel.onUpdateCategoryColor(category.name, color) },
                onViewQuestions = { onViewCategoryQuestions(category.name) }
            )
        }
    }
}

fun EmptyQuestionsPlaceholder(error: String? = null) {
    Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
            modifier = Modifier.padding(32.dp)
        ) {
            Icon(
                imageVector = if (error != null) Icons.Rounded.ErrorOutline else Icons.Rounded.Inbox,
                contentDescription = null,
                modifier = Modifier.size(64.dp),
                tint = if (error != null) MaterialTheme.colorScheme.error.copy(alpha = 0.5f) else MaterialTheme.colorScheme.outline.copy(alpha = 0.5f)
            )
            Spacer(modifier = Modifier.height(16.dp))
            Text(
                text = error ?: stringResource(R.string.no_questions_found),
                style = MaterialTheme.typography.titleMedium,
                color = if (error != null) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.onSurfaceVariant,
                textAlign = androidx.compose.ui.text.style.TextAlign.Center
            )
        }
    }
}

fun QuestionContent(
    state: QuizState,
    currentQuestion: com.ahmedyejam.mks.data.local.entity.QuestionEntity,
    viewModel: QuizViewModel,
    onEditCategory: (CategoryWithMetadata) -> Unit,
    onImageClick: (Any) -> Unit,
    assetCount: Int = 0,
    onAssetsClick: () -> Unit = {}
) {
    val haptic = LocalHapticFeedback.current
    val isRtl = LocalLayoutDirection.current == LayoutDirection.Rtl
    val themeMode by viewModel.themeMode.collectAsStateWithLifecycle()
    var newCategoryName by rememberSaveable { mutableStateOf("")    }
    var totalDrag by remember { mutableFloatStateOf(0f) }
    val swipeThreshold = with(LocalDensity.current) { 50.dp.toPx() }

    val tokens = LocalMksDesignTokens.current
    AnimatedContent(
        targetState = state.currentIndex,
        transitionSpec = {
            if (tokens.isPlain) {
                fadeIn(animationSpec = snap()) togetherWith fadeOut(animationSpec = snap())
            } else {
                val direction = if (targetState > initialState) 1 else -1
                (slideInHorizontally { width ->
                    if (isRtl) -direction * width else direction * width
                } + fadeIn()).togetherWith(
                    slideOutHorizontally { width ->
                        if (isRtl) direction * width else -direction * width
                    } + fadeOut()
                ).using(
                    SizeTransform(clip = false)
                )
            }
        },
        label = "QuestionTransition",
        modifier = Modifier
            .fillMaxSize()
            .pointerInput(isRtl) {
                detectHorizontalDragGestures(
                    onDragEnd = {
                        if (isRtl) {
                            if (totalDrag > swipeThreshold) {
                                viewModel.nextQuestion()
                            } else if (totalDrag < -swipeThreshold) {
                                viewModel.previousQuestion()
                            }
                        } else {
                            if (totalDrag > swipeThreshold) {
                                viewModel.previousQuestion()
                            } else if (totalDrag < -swipeThreshold) {
                                viewModel.nextQuestion()
                            }
                        }
                        totalDrag = 0f
                    },
                    onHorizontalDrag = { change, dragAmount ->
                        change.consume()
                        totalDrag += dragAmount
                    }
                )
            }
    ) { targetIndex ->
        val animQuestion = state.questions.getOrNull(targetIndex) ?: currentQuestion
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(horizontal = 16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp),
            contentPadding = PaddingValues(top = 16.dp, bottom = 140.dp)
        ) {
            item {
                Column {
                    Text(
                        text = animQuestion.text,
                        style = MaterialTheme.typography.headlineSmall,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.padding(bottom = 8.dp)
                    )

                    val finalImage = resolveQuestionImage(
                        imagePath = animQuestion.imagePath,
                        imageSource = animQuestion.imageSource,
                        themeMode = themeMode,
                        isRtl = isRtl
                    )

                    if (assetCount > 0) {
                        OutlinedButton(onClick = onAssetsClick, modifier = Modifier.fillMaxWidth()) {
                            Icon(Icons.Rounded.AttachFile, contentDescription = null)
                            Spacer(modifier = Modifier.width(8.dp))
                            Text("Assets ($assetCount)")
                        }
                    }

                    if ((finalImage != null) && ((finalImage !is String) || finalImage.isNotBlank())) {
            AsyncImage(
                model = ImageRequest.Builder(LocalContext.current)
                    .data(finalImage)
                    .crossfade(enable = true)
                    .build(),
                            contentDescription = stringResource(R.string.question_image_desc),
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(vertical = 8.dp)
                                .clip(RoundedCornerShape(8.dp))
                                .border(
                                    1.dp,
                                    MaterialTheme.colorScheme.outlineVariant,
                                    RoundedCornerShape(8.dp)
                                )
                                .clickable { onImageClick(finalImage) },
                            contentScale = ContentScale.FillWidth
                        )
                    }
                }
            }

            itemsIndexed(
                state.shuffledOptions,
                key = { _, option -> option },
            ) { index, option ->
                if ((!state.isOneByOne) || (index < state.visibleOptionsCount) || state.isAnswered) {
                    val originalIndex = state.optionMapping[index]
                    val isDropped = state.droppedOptions.contains(originalIndex)

                    OptionItem(
                        text = option,
                        isSelected = state.selectedOptions.contains(originalIndex),
                        isAnswered = state.isAnswered,
                        isCorrect = animQuestion.correctAnswers.contains(originalIndex),
                        isDropped = isDropped,
                        isSingleChoice = animQuestion.type == QuestionType.SINGLE_CHOICE,
                        eliminationModeEnabled = state.eliminationModeEnabled,
                        onClick = {
                            if (!tokens.isPlain) haptic.performHapticFeedback(HapticFeedbackType.TextHandleMove)
                            viewModel.onOptionSelected(index)
                        },
                        onDoubleClick = {
                            if (!tokens.isPlain) haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                            viewModel.onOptionDoubleClicked(index)
                        },
                        onDrop = { viewModel.dropOption(index) }
                    )
                }
            }

            if (state.isAnswered) {
                item {
                    QuestionExplanation(
                        isCorrect = state.isCorrect,
                        explanation = animQuestion.explanation,
                    )
                }
            }

            if (state.showCategorization && state.isAnswered) {
                item {
                    QuestionCategories(
                        allCategories = state.allCategoriesWithMetadata,
                        questionCategories = animQuestion.categories,
                        onToggleCategory = { viewModel.toggleQuestionCategory(it) },
                        onEditCategory = onEditCategory,
                        newCategoryName = newCategoryName,
                        onNewCategoryNameChange = { newCategoryName = it }
                    )
                }
            }

            if (state.isAnswered) {
                item {
                    QuestionNotes(
                        permanentNote = animQuestion.notes ?: "",
                        onPermanentNoteChange = { viewModel.updateQuestionNote(it) }
                    )
                }
            }

            if (state.hintsEnabled && animQuestion.hint != null) {
                item {
                    QuestionHint(
                        showHint = state.showHint,
                        hintText = animQuestion.hint!!,
                        onToggleHint = { viewModel.toggleHint() }
                    )
                }
            }

            item {
                Spacer(modifier = Modifier.height(16.dp))
            }
        }
    }
}

fun QuestionExplanation(isCorrect: Boolean, explanation: String?) {
    val successContainer = if (isSystemInDarkTheme()) Color(0xFF1B5E20) else Color(0xFFE8F5E9)
    val onSuccessContainer = if (isSystemInDarkTheme()) Color(0xFFA5D6A7) else Color(0xFF1B5E20)

    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier
            .padding(top = 16.dp)
            .fillMaxWidth(),
        shape = RoundedCornerShape(tokens.cardRadius),
        colors = CardDefaults.cardColors(
            containerColor = if (isCorrect)
                successContainer else MaterialTheme.colorScheme.errorContainer,
            contentColor = if (isCorrect)
                onSuccessContainer else MaterialTheme.colorScheme.onErrorContainer
        ),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(
                    imageVector = if (isCorrect) Icons.Rounded.CheckCircle else Icons.Rounded.Cancel,
                    contentDescription = null,
                    tint = if (isCorrect) onSuccessContainer else MaterialTheme.colorScheme.error
                )
                Spacer(modifier = Modifier.width(8.dp))
                Text(
                    text = if (isCorrect) "Excellent!" else "Not quite right",
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.ExtraBold,
                    color = if (isCorrect) onSuccessContainer else MaterialTheme.colorScheme.onErrorContainer
                )
            }

            if (!explanation.isNullOrBlank()) {
                Spacer(modifier = Modifier.height(8.dp))
                HorizontalDivider(
                    color = if (isCorrect)
                        onSuccessContainer.copy(alpha = 0.2f)
                    else MaterialTheme.colorScheme.error.copy(alpha = 0.2f)
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = "Explanation:",
                    style = MaterialTheme.typography.labelLarge,
                    fontWeight = FontWeight.Bold,
                    color = if (isCorrect) onSuccessContainer else MaterialTheme.colorScheme.error
                )
                Text(
                    text = explanation,
                    style = MaterialTheme.typography.bodyMedium,
                    color = if (isCorrect) onSuccessContainer else MaterialTheme.colorScheme.onErrorContainer
                )
            }
        }
    }
}

@OptIn(ExperimentalLayoutApi::class)

fun QuestionCategories(
    allCategories: List<CategoryWithMetadata>,
    questionCategories: List<String>,
    onToggleCategory: (String) -> Unit,
    onEditCategory: (CategoryWithMetadata) -> Unit,
    newCategoryName: String,
    onNewCategoryNameChange: (String) -> Unit
) {
    Column(modifier = Modifier.padding(top = 16.dp)) {
        Text(stringResource(R.string.import_review_categories), style = MaterialTheme.typography.titleSmall)
        FlowRow(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 8.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            allCategories.forEach { category ->
                CategoryChip(
                    category = category,
                    isSelected = questionCategories.contains(category.name),
                    onCategorySelected = { onToggleCategory(it.name) },
                    onCategoryLongClick = { onEditCategory(it) }
                )
            }
        }
        OutlinedTextField(
            value = newCategoryName,
            onValueChange = onNewCategoryNameChange,
            label = { Text(stringResource(R.string.add_new_category_label)) },
            modifier = Modifier.fillMaxWidth(),
            trailingIcon = {
                IconButton(
                    onClick = {
                        if (newCategoryName.isNotBlank()) {
                            onToggleCategory(newCategoryName)
                            onNewCategoryNameChange("")
                        }
                    },
                ) {
                    Icon(Icons.Rounded.Add, contentDescription = stringResource(R.string.add_new_category_label))
                }
            }
        )
    }
}

fun QuestionNotes(
    permanentNote: String,
    onPermanentNoteChange: (String) -> Unit
) {
    Column(modifier = Modifier.padding(top = 12.dp)) {
        Text("Notes", style = MaterialTheme.typography.titleSmall, color = MaterialTheme.colorScheme.secondary)

        OutlinedTextField(
            value = permanentNote,
            onValueChange = onPermanentNoteChange,
            label = { Text(stringResource(R.string.permanent_note_label)) },
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 8.dp),
            minLines = 2,
            placeholder = { Text(stringResource(R.string.permanent_note_placeholder)) }
        )
    }
}

fun QuestionHint(
    showHint: Boolean,
    hintText: String,
    onToggleHint: () -> Unit
) {
    TextButton(
        onClick = onToggleHint,
        contentPadding = PaddingValues(0.dp)
    ) {
        Icon(Icons.Rounded.Lightbulb, contentDescription = null, modifier = Modifier.size(18.dp))
        Spacer(modifier = Modifier.width(4.dp))
        Text(if (showHint) "Hide Hint" else stringResource(R.string.hint_label))
    }

    AnimatedVisibility(visible = showHint) {
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 8.dp),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.tertiaryContainer)
        ) {
            Text(
                text = hintText,
                modifier = Modifier.padding(12.dp),
                style = MaterialTheme.typography.bodyMedium
            )
        }
    }
}

/**
 * Top app bar for the quiz player.
 */
@OptIn(ExperimentalMaterial3Api::class)

fun QuizTopBar(
    currentIndex: Int,
    totalQuestions: Int,
    initialQuestionCount: Int,
    isMarked: Boolean,
    focusModeEnabled: Boolean,
    sessionLabel: String?,
    timerStateFlow: StateFlow<TimerState>,
    quizTimerSeconds: Int,
    questionTimerSeconds: Int,
    isAnswered: Boolean,
    score: Int,
    currentStreak: Int,
    onAskAiClick: () -> Unit = {},
    onBack: () -> Unit
) {
    val timerState by timerStateFlow.collectAsStateWithLifecycle()

    Column {
        com.ahmedyejam.mks.ui.components.StudyTopAppBar(
            title = stringResource(
                R.string.question_counter,
                if (totalQuestions == 0) 0 else currentIndex + 1,
                totalQuestions
            ),
            subtitle = sessionLabel,
            onNavigateBack = onBack,
            actions = {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    if (isMarked) {
                        Icon(
                            Icons.Rounded.Bookmark,
                            contentDescription = stringResource(R.string.mark_toggle),
                            modifier = Modifier
                                .size(18.dp)
                                .padding(end = 4.dp),
                            tint = MaterialTheme.colorScheme.primary
                        )
                    }
                    IconButton(onClick = onAskAiClick) {
                        Icon(
                            Icons.Rounded.Lightbulb,
                            contentDescription = "Ask AI",
                            tint = MaterialTheme.colorScheme.primary
                        )
                    }
                    if (focusModeEnabled) {
                        Icon(
                            Icons.Rounded.NotificationsOff,
                            contentDescription = stringResource(R.string.focus_toggle),
                            modifier = Modifier
                                .size(18.dp)
                                .padding(end = 8.dp),
                            tint = MaterialTheme.colorScheme.secondary
                        )
                    }

                    Column(
                        horizontalAlignment = Alignment.End,
                        modifier = Modifier.padding(end = 8.dp)
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(Icons.Rounded.Timer, contentDescription = null, modifier = Modifier.size(14.dp))
                            Text(
                                text = formatTime(timerState.timeLeft),
                                modifier = Modifier.padding(start = 4.dp),
                                style = MaterialTheme.typography.labelSmall
                            )
                        }
                        if (quizTimerSeconds > 0) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(Icons.Rounded.HourglassBottom, contentDescription = "Quiz Timer", modifier = Modifier.size(14.dp), tint = MaterialTheme.colorScheme.primary)
                                Text(
                                    text = formatTime(timerState.quizTimeLeft),
                                    modifier = Modifier.padding(start = 4.dp),
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.primary,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                        if (questionTimerSeconds > 0 && !isAnswered) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(Icons.Rounded.Update, contentDescription = "Question Timer", modifier = Modifier.size(14.dp), tint = MaterialTheme.colorScheme.secondary)
                                Text(
                                    text = formatTime(timerState.questionTimeLeft),
                                    modifier = Modifier.padding(start = 4.dp),
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.secondary,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(Icons.Rounded.Star, contentDescription = "Score", modifier = Modifier.size(14.dp), tint = MaterialTheme.colorScheme.primary)
                            Text(
                                text = "$score/$initialQuestionCount",
                                modifier = Modifier.padding(start = 4.dp),
                                style = MaterialTheme.typography.labelSmall,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.primary
                            )
                        }
                        if (currentStreak > 0) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(Icons.Rounded.Whatshot, contentDescription = "Streak", modifier = Modifier.size(14.dp), tint = Color(0xFFFF9800))
                                Text(
                                    text = currentStreak.toString(),
                                    modifier = Modifier.padding(start = 4.dp),
                                    style = MaterialTheme.typography.labelSmall,
                                    fontWeight = FontWeight.ExtraBold,
                                    color = Color(0xFFFF9800)
                                )
                            }
                        }
                    }
                }
            }
        )
        if (initialQuestionCount > 0) {
            LinearProgressIndicator(
                progress = { ((currentIndex + 1).toFloat() / initialQuestionCount).coerceAtMost(1f) },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(6.dp)
                    .padding(horizontal = 4.dp)
                    .clip(CircleShape),
                color = MaterialTheme.colorScheme.primary,
                trackColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.5f)
            )
        }
    }
}

@OptIn(ExperimentalLayoutApi::class)

fun QuizSheetContent(
    state: QuizState,
    viewModel: QuizViewModel,
    onDropQuestion: () -> Unit,
    onAskAiClick: (Long) -> Unit
) {
    val haptic = LocalHapticFeedback.current
    val currentQuestion = remember(state.questions, state.currentIndex) {
        if (state.questions.isNotEmpty() && state.currentIndex in state.questions.indices) {
            state.questions[state.currentIndex]
        } else null
    }

    Column(modifier = Modifier.fillMaxWidth()) {
        // Fixed Header part (Visible in peek)
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp)
                .padding(top = 12.dp, bottom = 8.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                // Performance Stats in Peek
                Column(
                    modifier = Modifier.weight(0.3f),
                    horizontalAlignment = Alignment.Start
                ) {
                    val answered = state.questionResultsByIndex.size
                    val accuracy = if (answered > 0) (state.score * 100 / answered) else 0
                    Text(
                        text = stringResource(R.string.accuracy_peek, accuracy),
                        style = MaterialTheme.typography.labelMedium,
                        fontWeight = FontWeight.Bold,
                        color = if (accuracy >= 80) Color(0xFF4CAF50) else if (accuracy >= 50) Color(0xFFFF9800) else MaterialTheme.colorScheme.error
                    )
                    Text(
                        text = stringResource(R.string.streak_peek, state.currentStreak),
                        style = MaterialTheme.typography.labelSmall,
                        color = Color(0xFFFF9800)
                    )
                }

                Button(
                    modifier = Modifier
                        .weight(0.7f)
                        .height(48.dp),
                    onClick = {
                        haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                        viewModel.submitAnswer()
                    },
                    enabled = (state.isAnswered ||
                            state.selectedOptions.isNotEmpty() ||
                            (state.isOneByOne && state.visibleOptionsCount < state.shuffledOptions.size) ||
                            state.skipUnansweredGlobal) && state.questions.isNotEmpty(),
                    shape = RoundedCornerShape(16.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (state.isAnswered) MaterialTheme.colorScheme.secondary else MaterialTheme.colorScheme.primary
                    )
                ) {
                    Text(
                        text = if (state.isAnswered) stringResource(R.string.next) else if (state.isOneByOne && state.visibleOptionsCount < state.shuffledOptions.size) stringResource(R.string.reveal) else stringResource(R.string.submit),
                        style = MaterialTheme.typography.titleMedium
                    )
                }
            }
        }

        // Expandable Body part
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .verticalScroll(rememberScrollState())
                .padding(horizontal = 16.dp)
                .padding(bottom = 32.dp)
        ) {
            Spacer(modifier = Modifier.height(8.dp))

            // Toggles Row
            FlowRow(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                val toggleModifier = Modifier
                    .weight(1f)
                    .widthIn(min = 100.dp)
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.Category,
                    label = stringResource(R.string.categories_toggle),
                    checked = state.showCategorization,
                    onCheckedChange = { viewModel.toggleCategorization() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.Lightbulb,
                    label = "Explain",
                    checked = false,
                    onCheckedChange = {
                        val qId = currentQuestion?.id ?: return@ControlToggle
                        onAskAiClick(qId)
                    }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.Filter1,
                    label = stringResource(R.string.one_by_one_toggle),
                    checked = state.isOneByOne,
                    onCheckedChange = { viewModel.toggleOneByOne() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.Bolt,
                    label = stringResource(R.string.rapid_toggle),
                    checked = state.isRapidMode,
                    onCheckedChange = { viewModel.toggleRapidMode() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.Block,
                    label = stringResource(R.string.eliminate_toggle),
                    checked = state.eliminationModeEnabled,
                    onCheckedChange = { viewModel.toggleEliminationMode() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.DeleteForever,
                    label = stringResource(R.string.drop_q_toggle),
                    checked = false,
                    onCheckedChange = { onDropQuestion() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = if (state.focusModeEnabled) Icons.Rounded.NotificationsOff else Icons.Rounded.Notifications,
                    label = stringResource(R.string.focus_toggle),
                    checked = state.focusModeEnabled,
                    onCheckedChange = { viewModel.toggleFocusMode() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = if (state.questions.isNotEmpty() && state.questions[state.currentIndex].isMarked) Icons.Rounded.Bookmark else Icons.Rounded.BookmarkBorder,
                    label = stringResource(R.string.mark_toggle),
                    checked = state.questions.isNotEmpty() && state.questions[state.currentIndex].isMarked,
                    onCheckedChange = { viewModel.toggleMarked() }
                )
                ControlToggle(
                    modifier = toggleModifier,
                    icon = Icons.Rounded.DoneAll,
                    label = stringResource(R.string.finish_quiz),
                    checked = false,
                    onCheckedChange = { viewModel.finishSession() }
                )
            }

            HorizontalDivider()

            // Navigation Controls
            LazyRow(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 4.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                items(NavigationFilter.entries, key = { it.name }) { filter ->
                    FilterChip(
                        selected = state.navigationFilter == filter,
                        onClick = { viewModel.setNavigationFilter(filter) },
                        label = { Text(filter.name, style = MaterialTheme.typography.labelSmall) }
                    )
                }
            }

            currentQuestion?.let { question ->
                if (question.isDropped) {
                    AssistChip(
                        onClick = { viewModel.restoreCurrentDroppedQuestion() },
                        label = { Text("Restore dropped question") },
                        leadingIcon = { Icon(Icons.Rounded.Restore, contentDescription = null) },
                        modifier = Modifier.padding(top = 8.dp)
                    )
                }
            }

            val filteredIndices = remember(state.questions, state.questionResultsByIndex, state.navigationFilter) {
                state.questions.indices.filter { index ->
                    val result = state.questionResultsByIndex[index]
                    when (state.navigationFilter) {
                        NavigationFilter.ALL -> true
                        NavigationFilter.ANSWERED -> result != null
                        NavigationFilter.UNANSWERED -> result == null
                        NavigationFilter.MISSED -> result == false
                        NavigationFilter.MARKED -> state.questions[index].isMarked
                        NavigationFilter.DROPPED -> state.questions[index].isDropped
                    }
                }
            }

            if (filteredIndices.isNotEmpty()) {
                LazyRow(
                    modifier = Modifier
                        .fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    items(filteredIndices, key = { it }) { index ->
                        val status = viewModel.getQuestionStatus(index)
                        val isMarked = state.questions[index].isMarked

                        val color = when (status) {
                            QuestionStatus.CURRENT -> MaterialTheme.colorScheme.primary
                            QuestionStatus.CORRECT -> Color(0xFF4CAF50)
                            QuestionStatus.INCORRECT -> Color(0xFFF44336)
                            QuestionStatus.UNANSWERED -> MaterialTheme.colorScheme.outline
                        }

                        Box(
                            modifier = Modifier
                                .size(32.dp)
                                .clip(RoundedCornerShape(8.dp))
                                .background(color.copy(alpha = if (status == QuestionStatus.CURRENT) 1f else 0.6f))
                                .border(
                                    width = if (status == QuestionStatus.CURRENT) 2.dp else 0.dp,
                                    color = MaterialTheme.colorScheme.onPrimary,
                                    shape = RoundedCornerShape(8.dp)
                                )
                                .clickable { viewModel.jumpToQuestion(index) },
                            contentAlignment = Alignment.Center
                        ) {
                            if (isMarked) {
                                Icon(
                                    Icons.Rounded.Bookmark,
                                    contentDescription = null,
                                    modifier = Modifier
                                        .size(12.dp)
                                        .align(Alignment.TopEnd)
                                        .padding(2.dp),
                                    tint = Color.White
                                )
                            }
                            Text(
                                text = (index + 1).toString(),
                                style = MaterialTheme.typography.labelMedium,
                                color = Color.White
                            )
                        }
                    }
                }
            }
            Spacer(modifier = Modifier.height(32.dp))
        }
    }
}

/**
 * A toggle control button used in the quiz scaffold.
 *
 * @param icon The icon to display.
 * @param label The text label for the control.
 * @param checked Whether the toggle is currently active.
 * @param onCheckedChange Callback triggered when the toggle is clicked.
 * @param modifier The modifier to be applied to the layout.
 */

fun OptionItem(
    text: String,
    isSelected: Boolean,
    isAnswered: Boolean,
    isCorrect: Boolean,
    isDropped: Boolean,
    isSingleChoice: Boolean,
    eliminationModeEnabled: Boolean,
    onClick: () -> Unit,
    onDoubleClick: () -> Unit,
    onDrop: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    val haptic = LocalHapticFeedback.current

    val successColor = tokens.success
    val successContainer = successColor.copy(alpha = 0.12f)

    val backgroundColor by animateColorAsState(
        targetValue = when {
            isAnswered && isCorrect -> successContainer
            isAnswered && isSelected -> MaterialTheme.colorScheme.errorContainer
            isSelected -> MaterialTheme.colorScheme.secondaryContainer
            else -> MaterialTheme.colorScheme.surface
        },
        animationSpec = tokens.animationSpec(),
        label = "optionBackground"
    )

    val contentColor = when {
        isAnswered && isCorrect -> successColor
        isAnswered && isSelected -> MaterialTheme.colorScheme.onErrorContainer
        isSelected -> MaterialTheme.colorScheme.onSecondaryContainer
        else -> MaterialTheme.colorScheme.onSurface
    }

    val borderColor by animateColorAsState(
        targetValue = when {
            isAnswered && isCorrect -> successColor
            isAnswered && isSelected && !isCorrect -> MaterialTheme.colorScheme.error
            isSelected -> MaterialTheme.colorScheme.secondary
            else -> MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f)
        },
        animationSpec = tokens.animationSpec(),
        label = "optionBorder"
    )

    val scale by animateFloatAsState(
        targetValue = if (isSelected && !isAnswered) 1.01f else 1f,
        animationSpec = tokens.animationSpec(),
        label = "optionScale"
    )

    Surface(
        modifier = Modifier
            .fillMaxWidth()
            .alpha(if (isDropped) 0.5f else 1f)
            .graphicsLayer(scaleX = scale, scaleY = scale)
            .combinedClickable(
                enabled = !isAnswered && !isDropped,
                onClick = onClick,
                onDoubleClick = onDoubleClick,
                onLongClick = {
                    haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                    onDrop()
                }
            ),
        shape = RoundedCornerShape(tokens.cardRadius),
        color = backgroundColor,
        contentColor = contentColor,
        border = BorderStroke(if (isSelected || isAnswered) 2.dp else 1.dp, borderColor)
    ) {
        Row(
            modifier = Modifier.padding(16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Surface(
                modifier = Modifier.size(24.dp),
                shape = if (isSingleChoice) CircleShape else RoundedCornerShape(6.dp),
                color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline.copy(alpha = 0.2f),
                border = BorderStroke(1.dp, if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline)
            ) {
                Box(contentAlignment = Alignment.Center) {
                    if (isSelected) {
                        Icon(Icons.Rounded.Check, contentDescription = null, modifier = Modifier.size(16.dp), tint = MaterialTheme.colorScheme.onPrimary)
                    }
                }
            }

            Spacer(modifier = Modifier.width(16.dp))

            Text(
                text = text,
                modifier = Modifier.weight(1f),
                style = MaterialTheme.typography.bodyLarge.copy(
                    textDecoration = if (isDropped) TextDecoration.LineThrough else TextDecoration.None
                ),
                fontWeight = if (isSelected) FontWeight.SemiBold else FontWeight.Normal
            )

            if (eliminationModeEnabled && !isAnswered && !isDropped) {
                IconButton(
                    onClick = {
                        haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                        onDrop()
                    },
                    modifier = Modifier.size(32.dp)
                ) {
                    Icon(
                        imageVector = Icons.Rounded.Clear,
                        contentDescription = stringResource(R.string.eliminate_label),
                        modifier = Modifier.size(18.dp),
                        tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f)
                    )
                }
            }

            if (isAnswered) {
                if (isCorrect) {
                    Icon(Icons.Rounded.CheckCircle, contentDescription = null, tint = successColor)
                } else if (isSelected) {
                    Icon(Icons.Rounded.Cancel, contentDescription = null, tint = MaterialTheme.colorScheme.error)
                }
            }
            Spacer(modifier = Modifier.height(16.dp))
        }
    }
}

/**
 * Formats a duration in seconds into a MM:SS string.
 *
 * @param seconds The total number of seconds.
 * @return A formatted time string.
 */

fun formatTime(seconds: Int): String {
    val mins = seconds / 60
    val secs = seconds % 60
    return "%02d:%02d".format(mins, secs)
}

/**
 * Resolves the image to display for a question, handling special placeholders like "contact_banner".
 */

fun resolveQuestionImage(
    imagePath: String?,
    imageSource: String?,
    themeMode: String,
    isRtl: Boolean
): Any? {
    val displayImage = imagePath ?: imageSource
    if (displayImage != "contact_banner") return displayImage

    val normalizedTheme = normalizeMksThemeMode(themeMode)
    val isSystemDark = isSystemInDarkTheme()
    val isActuallyDark = when (normalizedTheme) {
        "MIDNIGHT", "PLAIN_DARK" -> true
        "SYSTEM" -> isSystemDark
        else -> false
    }

    return when {
        normalizedTheme == "FOREST" -> if (isRtl) R.drawable.contact_banner_ar_light_forest_path else R.drawable.contact_banner_en_light_forest_path
        normalizedTheme == "LAVENDER" || normalizedTheme == "PLAIN_LIGHT" -> if (isRtl) R.drawable.contact_banner_ar_light_lavender_valley else R.drawable.contact_banner_en_light_lavender_valley
        isActuallyDark -> if (isRtl) R.drawable.contact_banner_ar_dark_moonlit_valley else R.drawable.contact_banner_en_dark_moonlit_valley
        else -> if (isRtl) R.drawable.contact_banner_ar_light_sunrise_valley else R.drawable.contact_banner_en_light_sunrise_valley
    }
}

fun CompilerDialog(
    viewModel: CompilerViewModel,
    books: List<BookEntity>,
    quizzes: List<QuizEntity> = emptyList(),
    onDismiss: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsState()
    var showMappingEditor by remember { mutableStateOf(false) }
    var showRangeDialog by remember { mutableStateOf(false) }
    var importTitle by remember { mutableStateOf("") }
    var importBookTitle by remember { mutableStateOf("") }
    var selectedBookId by remember { mutableStateOf<Long?>(null) }
    var showSaveDialog by remember { mutableStateOf(false) }

    var selectedQuestionIndexForAnswer by remember { mutableStateOf<Int?>(null) }

    Dialog(
        onDismissRequest = onDismiss,
        properties = DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier.fillMaxSize(),
            color = MaterialTheme.colorScheme.background
        ) {
            Column(modifier = Modifier.fillMaxSize()) {
                TopAppBar(
                    title = { Text(stringResource(R.string.advanced_compiler_title)) },
                    navigationIcon = {
                        IconButton(onClick = onDismiss) {
                            Icon(Icons.Default.Close, contentDescription = stringResource(R.string.cancel))
                        }
                    },
                    actions = {
                        if (uiState.questions.isNotEmpty()) {
                            IconButton(onClick = { showRangeDialog = true }) {
                                Icon(Icons.Default.SelectAll, contentDescription = stringResource(R.string.range_selection))
                            }
                            Button(onClick = { showSaveDialog = true }) {
                                Text(stringResource(R.string.save_with_count, uiState.questions.count { it.isIncluded }))
                            }
                        }
                    }
                )

                if (uiState.isLoading) {
                    LinearProgressIndicator(modifier = Modifier.fillMaxWidth())
                }

                uiState.error?.let { error ->
                    Text(
                        text = error,
                        color = MaterialTheme.colorScheme.error,
                        modifier = Modifier.padding(16.dp)
                    )
                }

                if (uiState.sheetNames.isNotEmpty()) {
                    ScrollableTabRow(
                        selectedTabIndex = uiState.sheetNames.indexOf(uiState.selectedSheet ?: ""),
                        edgePadding = 16.dp
                    ) {
                        uiState.sheetNames.forEach { sheet ->
                            Tab(
                                selected = uiState.selectedSheet == sheet,
                                onClick = { viewModel.onSheetSelected(sheet) },
                                text = { Text(sheet) }
                            )
                        }
                    }
                }

                Box(modifier = Modifier.weight(1f)) {
                    if (uiState.questions.isEmpty() && !uiState.isLoading) {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            Text(stringResource(R.string.no_questions_parsed))
                        }
                    } else {
                        LazyColumn(
                            modifier = Modifier.fillMaxSize(),
                            contentPadding = PaddingValues(bottom = 80.dp) // Space for FAB
                        ) {
                            itemsIndexed(
                                items = uiState.questions,
                                key = { index, question -> "${question.sourceLine}_$index" }
                            ) { index, question ->
                                QuestionPreviewItem(
                                    question = question,
                                    onClick = { viewModel.toggleQuestionInclusion(index) },
                                    onLongClick = { selectedQuestionIndexForAnswer = index }
                                )
                            }
                        }
                    }

                    FloatingActionButton(
                        onClick = { showMappingEditor = true },
                        modifier = Modifier
                            .align(Alignment.BottomEnd)
                            .padding(16.dp)
                    ) {
                        Icon(Icons.Default.Settings, contentDescription = stringResource(R.string.mapping_label))
                    }
                }
            }
        }
    }

    if (showRangeDialog) {
        RangeSelectionDialog(
            maxQuestions = uiState.questions.size,
            onDismiss = { showRangeDialog = false },
            onApply = { from, to, include ->
                viewModel.toggleQuestionsRange(from, to, include)
                showRangeDialog = false
            }
        )
    }

    selectedQuestionIndexForAnswer?.let { index ->
        val question = uiState.questions[index]
        AnswerSelectionDialog(
            question = question,
            onDismiss = { selectedQuestionIndexForAnswer = null },
            onAnswerSelected = { answerId ->
                viewModel.updateQuestionCorrectAnswer(index, answerId)
                selectedQuestionIndexForAnswer = null
            }
        )
    }

    if (showMappingEditor) {
        MappingEditorDialog(
            uiState = uiState,
            onDismiss = { showMappingEditor = false },
            onUpdateHeaderRow = { viewModel.updateHeaderRow(it) },
            onUpdateMapping = { mapping, options -> 
                viewModel.updateMapping(mapping, options)
            }
        )
    }

    if (showSaveDialog) {
        if (uiState.targetQuizId != null) {
            val targetQuiz = quizzes.find { it.id == uiState.targetQuizId }
            val fallbackTitle = stringResource(R.string.imported_quiz_fallback)
            val noneSelection = stringResource(R.string.none_selection)
            AlertDialog(
                onDismissRequest = { showSaveDialog = false },
                title = { Text(stringResource(R.string.import_review_title)) },
                text = {
                    Text(stringResource(R.string.import_into_quiz_confirm, targetQuiz?.title ?: noneSelection))
                },
                confirmButton = {
                    Button(onClick = {
                        viewModel.saveParsedQuestions(
                            targetQuiz?.title ?: fallbackTitle,
                            targetQuiz?.bookId,
                            uiState.targetQuizId
                        )
                        showSaveDialog = false
                        onDismiss()
                    }) {
                        Text(stringResource(R.string.import_label))
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showSaveDialog = false }) {
                        Text(stringResource(R.string.cancel))
                    }
                }
            )
        } else {
            val newQuizLabel = stringResource(R.string.new_quiz)
            AlertDialog(
                onDismissRequest = { showSaveDialog = false },
                title = { Text(stringResource(R.string.save_imported_questions_title)) },
                text = {
                    Column {
                        OutlinedTextField(
                            value = importTitle,
                            onValueChange = { importTitle = it },
                            label = { Text(stringResource(R.string.quiz_title_label)) },
                            modifier = Modifier.fillMaxWidth()
                        )
                        if (selectedBookId == null) {
                            Spacer(modifier = Modifier.height(12.dp))
                            OutlinedTextField(
                                value = importBookTitle,
                                onValueChange = { importBookTitle = it },
                                label = { Text(stringResource(R.string.book_title_label)) },
                                modifier = Modifier.fillMaxWidth()
                            )
                        }
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(stringResource(R.string.add_to_book_optional), style = MaterialTheme.typography.labelLarge)
                        LazyColumn(modifier = Modifier.heightIn(max = 200.dp)) {
                            item {
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clickable { selectedBookId = null }
                                        .padding(8.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    RadioButton(selected = selectedBookId == null, onClick = { selectedBookId = null })
                                    Text(stringResource(R.string.new_book), modifier = Modifier.padding(start = 8.dp))
                                }
                            }
                            items(books, key = { it.id }) { book ->
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clickable { selectedBookId = book.id }
                                        .padding(8.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    RadioButton(selected = selectedBookId == book.id, onClick = { selectedBookId = book.id })
                                    Text(book.title, modifier = Modifier.padding(start = 8.dp))
                                }
                            }
                        }
                    }
                },
                confirmButton = {
                    Button(
                        onClick = {
                            viewModel.saveParsedQuestions(
                                title = if (importTitle.isBlank()) uiState.selectedSheet ?: newQuizLabel else importTitle,
                                bookId = selectedBookId,
                                newBookTitle = if (selectedBookId == null) importBookTitle else null
                            )
                            showSaveDialog = false
                            onDismiss()
                        },
                        enabled = importTitle.isNotBlank() || uiState.selectedSheet != null
                    ) {
                        Text(stringResource(R.string.save))
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showSaveDialog = false }) {
                        Text(stringResource(R.string.cancel))
                    }
                }
            )
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

fun QuestionPreviewItem(
    question: com.ahmedyejam.mks.data.importer.model.ParsedQuestion,
    onClick: () -> Unit,
    onLongClick: () -> Unit
) {
    // Memoize the card color and alpha to avoid re-calculating on every recomposition if possible
    val containerColor = if (question.isIncluded) MaterialTheme.colorScheme.surface else MaterialTheme.colorScheme.surfaceVariant
    val alpha = if (question.isIncluded) 1f else 0.5f

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 12.dp, vertical = 6.dp)
            .alpha(alpha)
            .combinedClickable(
                onClick = onClick,
                onLongClick = onLongClick
            ),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
        colors = CardDefaults.cardColors(containerColor = containerColor)
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Text(
                text = "${stringResource(R.string.line_prefix, question.sourceLine)}: ${question.stem}",
                style = MaterialTheme.typography.bodyLarge,
                fontWeight = FontWeight.Bold,
                maxLines = 3,
                overflow = TextOverflow.Ellipsis,
                color = if (question.isIncluded) MaterialTheme.colorScheme.onSurface else MaterialTheme.colorScheme.onSurfaceVariant
            )
            Spacer(modifier = Modifier.height(4.dp))
            question.options.forEach { option ->
                val isCorrect = question.correctAnswers.contains(option.id)
                Text(
                    text = "${option.id.removePrefix("opt_")}: ${option.text}",
                    style = MaterialTheme.typography.bodySmall,
                    color = if (isCorrect) Color(0xFF4CAF50) else if (question.isIncluded) MaterialTheme.colorScheme.onSurface else MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
            if (question.imageDataUrl != null) {
                Text(
                    text = stringResource(R.string.image_attached_indicator),
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.primary
                )
            }
            if (!question.isIncluded) {
                Text(
                    text = stringResource(R.string.excluded_from_import),
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.error,
                    modifier = Modifier.padding(top = 4.dp)
                )
            }
        }
    }
}

fun RangeSelectionDialog(
    maxQuestions: Int,
    onDismiss: () -> Unit,
    onApply: (Int, Int, Boolean) -> Unit
) {
    var fromText by remember { mutableStateOf("1") }
    var toText by remember { mutableStateOf(maxQuestions.toString()) }
    var include by remember { mutableStateOf(true) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.select_range_title)) },
        text = {
            Column {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    OutlinedTextField(
                        value = fromText,
                        onValueChange = { fromText = it.filter { c -> c.isDigit() } },
                        label = { Text(stringResource(R.string.from_label)) },
                        modifier = Modifier.weight(1f)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    OutlinedTextField(
                        value = toText,
                        onValueChange = { toText = it.filter { c -> c.isDigit() } },
                        label = { Text(stringResource(R.string.to_label)) },
                        modifier = Modifier.weight(1f)
                    )
                }
                Spacer(modifier = Modifier.height(16.dp))
                Row(verticalAlignment = Alignment.CenterVertically) {
                    RadioButton(selected = include, onClick = { include = true })
                    Text(stringResource(R.string.include_label), modifier = Modifier.padding(start = 8.dp))
                    Spacer(modifier = Modifier.width(16.dp))
                    RadioButton(selected = !include, onClick = { include = false })
                    Text(stringResource(R.string.exclude_label), modifier = Modifier.padding(start = 8.dp))
                }
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    val from = fromText.toIntOrNull() ?: 1
                    val to = toText.toIntOrNull() ?: maxQuestions
                    onApply(from, to, include)
                }
            ) {
                Text(stringResource(R.string.apply_label))
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

fun AnswerSelectionDialog(
    question: com.ahmedyejam.mks.data.importer.model.ParsedQuestion,
    onDismiss: () -> Unit,
    onAnswerSelected: (String) -> Unit
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.select_correct_answer_title)) },
        text = {
            LazyColumn {
                items(question.options, key = { it.id }) { option ->
                    val isSelected = question.correctAnswers.contains(option.id)
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { onAnswerSelected(option.id) }
                            .padding(12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        RadioButton(selected = isSelected, onClick = { onAnswerSelected(option.id) })
                        Text(
                            text = "${option.id.removePrefix("opt_")}: ${option.text}",
                            modifier = Modifier.padding(start = 8.dp)
                        )
                    }
                }
            }
        },
        confirmButton = {},
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

@OptIn(ExperimentalMaterial3Api::class)

fun MappingEditorDialog(
    uiState: CompilerUiState,
    onDismiss: () -> Unit,
    onUpdateHeaderRow: (Int) -> Unit,
    onUpdateMapping: (Map<String, Int>, List<Int>) -> Unit
) {
    var currentMapping by remember { mutableStateOf(uiState.mapping) }
    var currentOptions by remember { mutableStateOf(uiState.optionColumns) }

    val stemLabel = stringResource(R.string.stem_label)
    val correctAnswerLabel = stringResource(R.string.correct_answer_label)
    val explanationLabel = stringResource(R.string.explanation_label)
    val hintLabel = stringResource(R.string.hint_label)
    val imageLabel = stringResource(R.string.image_label)
    val categoriesLabel = stringResource(R.string.categories_label)
    val referenceLabel = stringResource(R.string.reference_label)

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.mapping_settings_title)) },
        text = {
            LazyColumn(modifier = Modifier.fillMaxWidth()) {
                item {
                    Text(stringResource(R.string.header_row_index_label), style = MaterialTheme.typography.labelLarge)
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        IconButton(onClick = { if (uiState.headerRow > 0) onUpdateHeaderRow(uiState.headerRow - 1) }) {
                            Icon(Icons.Default.Remove, null)
                        }
                        Text(
                            text = uiState.headerRow.toString(),
                            modifier = Modifier.padding(horizontal = 16.dp)
                        )
                        IconButton(onClick = { onUpdateHeaderRow(uiState.headerRow + 1) }) {
                            Icon(Icons.Default.Add, null)
                        }
                    }
                    HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))
                }

                val fields = listOf(
                    "question" to stemLabel,
                    "answer" to correctAnswerLabel,
                    "explanation" to explanationLabel,
                    "hint" to hintLabel,
                    "image" to imageLabel,
                    "categories" to categoriesLabel,
                    "reference" to referenceLabel
                )

                items(fields, key = { it.first }) { (key, label) ->
                    Column(modifier = Modifier.padding(vertical = 4.dp)) {
                        Text(label, style = MaterialTheme.typography.labelMedium)
                        ColumnSelection(
                            availableColumns = uiState.availableColumns,
                            selectedIdx = currentMapping[key] ?: -1,
                            onSelect = { idx ->
                                currentMapping = currentMapping.toMutableMap().apply {
                                    if (idx == -1) remove(key) else put(key, idx)
                                }
                            }
                        )
                    }
                }

                item {
                    HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp))
                    Text(stringResource(R.string.option_columns_label), style = MaterialTheme.typography.labelLarge)
                    uiState.availableColumns.forEachIndexed { idx, name ->
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier
                                .fillMaxWidth()
                                .clickable {
                                    currentOptions = if (currentOptions.contains(idx)) {
                                        currentOptions - idx
                                    } else {
                                        (currentOptions + idx).sorted()
                                    }
                                }
                        ) {
                            Checkbox(
                                checked = currentOptions.contains(idx),
                                onCheckedChange = {
                                    currentOptions = if (it) currentOptions + idx else currentOptions - idx
                                }
                            )
                            Text("$idx: $name", style = MaterialTheme.typography.bodyMedium)
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(onClick = {
                onUpdateMapping(currentMapping, currentOptions)
                onDismiss()
            }) {
                Text(stringResource(R.string.apply_label))
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

fun ColumnSelection(
    availableColumns: List<String>,
    selectedIdx: Int,
    onSelect: (Int) -> Unit
) {
    var expanded by remember { mutableStateOf(false) }

    Box {
        OutlinedCard(
            onClick = { expanded = true },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text(
                text = if (selectedIdx == -1) stringResource(R.string.none_selection) else "$selectedIdx: ${availableColumns.getOrNull(selectedIdx) ?: ""}",
                modifier = Modifier.padding(8.dp),
                style = MaterialTheme.typography.bodyMedium
            )
        }
        DropdownMenu(expanded = expanded, onDismissRequest = { expanded = false }) {
            DropdownMenuItem(
                text = { Text(stringResource(R.string.none_selection)) },
                onClick = { onSelect(-1); expanded = false }
            )
            availableColumns.forEachIndexed { index, s ->
                DropdownMenuItem(
                    text = { Text("$index: $s") },
                    onClick = { onSelect(index); expanded = false }
                )
            }
        }
    }
}

fun ZoomableImageDialog(
    imageData: Any,
    onDismiss: () -> Unit
) {
    Dialog(
        onDismissRequest = onDismiss,
        properties = DialogProperties(
            usePlatformDefaultWidth = false,
            decorFitsSystemWindows = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.9f))
        ) {
            var scale by remember { mutableFloatStateOf(1f) }
            var offset by remember { mutableStateOf(Offset.Zero) }

            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .pointerInput(Unit) {
                        detectTransformGestures { _, pan, zoom, _ ->
                            scale = (scale * zoom).coerceIn(1f, 5f)
                            if (scale > 1f) {
                                offset += pan
                            } else {
                                offset = Offset.Zero
                            }
                        }
                    },
                contentAlignment = Alignment.Center
            ) {
                AsyncImage(
                    model = ImageRequest.Builder(LocalContext.current)
                        .data(imageData)
                        .crossfade(true)
                        .build(),
                    contentDescription = "Zoomable Image",
                    modifier = Modifier
                        .fillMaxSize()
                        .graphicsLayer(
                            scaleX = scale,
                            scaleY = scale,
                            translationX = offset.x,
                            translationY = offset.y
                        ),
                    contentScale = ContentScale.Fit
                )
            }

            IconButton(
                onClick = onDismiss,
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(top = 48.dp, end = 16.dp)
                    .background(Color.Black.copy(alpha = 0.5f), shape = androidx.compose.foundation.shape.CircleShape)
            ) {
                Icon(
                    imageVector = Icons.Default.Close,
                    contentDescription = "Close",
                    tint = Color.White
                )
            }
        }
    }
}

data class TimerState(
    val timeLeft: Int = 0,
    val quizTimeLeft: Int = 0,
    val questionTimeLeft: Int = 0,
)

/**
 * Represents the status of a question in the quiz navigation.
 */
enum class QuestionStatus {
    UNANSWERED, CORRECT, INCORRECT, CURRENT
}

/**
 * Filter options for navigating through quiz questions.
 */
enum class NavigationFilter {
    ALL, ANSWERED, UNANSWERED, MISSED, MARKED, DROPPED
}

/**
 * ViewModel for the Quiz screen, managing the state and logic of a quiz session.
 *
 * @property quizRepository The repository for accessing quiz and question data.
 * @property dataStoreManager Manager for persistent user preferences.
 */
@HiltViewModel

class QuizViewModel @Inject constructor(
    private val dataStoreManager: DataStoreManager,
    private val focusManager: FocusManager,
    private val knowledgeRepository: KnowledgeRepository,
    private val assetRepository: AssetRepository,
    private val quizRepository: QuizRepository,
    private val studyRepository: StudyRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(QuizState())
    val uiState: StateFlow<QuizState> = _uiState.asStateFlow()

    private val _timerState = MutableStateFlow(TimerState())
    val timerState: StateFlow<TimerState> = _timerState.asStateFlow()

    val themeMode: StateFlow<String> = dataStoreManager.themeMode
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), "DAWN")

    private var timerJob: Job? = null
    private var autoAdvanceJob: Job? = null
    private var autoAdvanceDelayMs: Long = 2000L

    init {
        combine(
            quizRepository.getAllCategoriesWithMetadata(),
            dataStoreManager.showCategorization,
            dataStoreManager.oneByOneMode,
            dataStoreManager.eliminationModeEnabled,
            dataStoreManager.doubleTapToSubmit,
            dataStoreManager.focusModeEnabled,
        ) { array ->
            @Suppress("UNCHECKED_CAST")
            val categories = array[0] as List<CategoryWithMetadata>
            val categorization = array[1] as Boolean
            val oneByOne = array[2] as Boolean
            val elimination = array[3] as Boolean
            val doubleTap = array[4] as Boolean
            val focus = array[5] as Boolean

            _uiState.update { 
                it.copy(
                    allCategoriesWithMetadata = categories,
                    showCategorization = categorization,
                    isOneByOne = oneByOne,
                    eliminationModeEnabled = elimination,
                    doubleTapToSubmitEnabled = doubleTap,
                    focusModeEnabled = focus,
                )
            }
            if (focus) focusManager.enableFocusMode() else focusManager.disableFocusMode()
        }.launchIn(viewModelScope)

        dataStoreManager.autoAdvanceDelay
            .onEach { delay -> autoAdvanceDelayMs = delay.toLong() }
            .launchIn(viewModelScope)
    }

    /**
     * Determines the status of a question at a specific index for UI coloring.
     */

fun getQuestionStatus(index: Int): QuestionStatus {
        val state = _uiState.value
        if (index == state.currentIndex) return QuestionStatus.CURRENT
        return when (state.questionResultsByIndex[index]) {
            true -> QuestionStatus.CORRECT
            false -> QuestionStatus.INCORRECT
            else -> QuestionStatus.UNANSWERED
        }
    }

    /**
     * Initializes and starts a quiz session.
     *
     * @param quizId The ID of the quiz to start.
     * @param sessionId Optional ID of an existing session to resume.
     */

fun startQuiz(quizId: Long, sessionId: Long? = null) {
        val currentState = _uiState.value
        if ((currentState.quizId == quizId) && (currentState.sessionId == sessionId)) {
            if (currentState.questions.isNotEmpty() || currentState.isLoading) {
                return
            }
        }

        viewModelScope.launch {
            try {
                _uiState.update { it.copy(isLoading = true, quizId = quizId, sessionId = sessionId, error = null) }

                var shuffleQ = dataStoreManager.defShuffleQuestions.first()
                var shuffleOpt = dataStoreManager.defShuffleOptions.first()
                var rapidMode = dataStoreManager.defRapidMode.first()
                var repeatWrong = dataStoreManager.defRepeatWrong.first()
                var rangeFrom = 0
                var rangeTo = -1
                var quizTimer = dataStoreManager.defQuizTimer.first()
                var qTimer = dataStoreManager.defQuestionTimer.first()
                val skipUnanswered = dataStoreManager.unansweredSkipEnabled.first()

                var startIndex = 0
                var sessionLabel: String? = null
                var sessionScore = 0
                var sessionCurrentStreak = 0
                var sessionMaxStreak = 0
                var initialResultsByIndex: Map<Int, Boolean?> = emptyMap()
                var sessionQuestionIds: List<Long>? = null
                var sessionOriginalCount = 0

                val session = sessionId?.let { quizRepository.getSessionById(it) }

                // Pre-fetch session questions if any to avoid many DB calls
                val sessionQuestionsMap = if ((session != null) && session.questionIds.isNotEmpty()) {
                    quizRepository.getQuestionsByIds(session.questionIds).associateBy { it.id }
                } else emptyMap()

                if (session != null) {
                    val validation = SessionStateValidator.validate(session)
                    startIndex = if (!validation.isValid) {
                        if (validation.canBeRepaired) {
                            session.currentQuestionIndex.coerceIn(0, (session.questionIds.size - 1).coerceAtLeast(0))
                        } else {
                            _uiState.update { it.copy(isLoading = false, error = validation.message ?: "Invalid session.") }
                            return@launch
                        }
                    } else {
                        session.currentQuestionIndex
                    }

                    // Final safety: if the current question data is missing, we must repair or block
                    val currentQId = session.questionIds.getOrNull(startIndex)
                    if ((currentQId != null) && (!sessionQuestionsMap.containsKey(currentQId))) {
                        _uiState.update { it.copy(isLoading = false, error = "Current question data is missing. This session may be corrupted.") }
                        return@launch
                    }

                    sessionLabel = session.label
                    sessionScore = session.score
                    sessionCurrentStreak = session.currentStreak
                    sessionMaxStreak = session.maxStreak
                    shuffleQ = session.shuffleQuestions
                    shuffleOpt = session.shuffleOptions
                    rapidMode = session.rapidMode
                    repeatWrong = session.repeatWrong
                    rangeFrom = session.rangeFrom
                    rangeTo = session.rangeTo
                    quizTimer = session.quizTimerSeconds
                    qTimer = session.questionTimerSeconds
                    sessionQuestionIds = session.questionIds
                    sessionOriginalCount = session.originalQuestionCount

                    initialResultsByIndex = session.answersByIndex.mapValues { (index, selection) ->
                        val qId = session.questionIds.getOrNull(index)
                        val q = sessionQuestionsMap[qId ?: -1]
                        q?.let { it.correctAnswers.toSet() == selection.toSet() }
                    }
                }

                val quizQuestions = if (!sessionQuestionIds.isNullOrEmpty()) {
                    sessionQuestionIds.mapNotNull { sessionQuestionsMap[it] }
                } else {
                    val allRawQuestions = quizRepository.getQuestionsByQuizId(quizId).first()
                        .filter { !it.isDropped }

                    val includeFilters = session?.includeFilters ?: emptyList()

                    val filteredQuestions = if (includeFilters.isNotEmpty()) {
                        allRawQuestions.filter { q ->
                            includeFilters.any { filter ->
                                when (filter) {
                                    "unanswered" -> q.attempts == 0
                                    "missed" -> (q.attempts > 0) && ((q.correctCount < q.attempts) || (q.lastAttemptResult == false))
                                    "marked" -> q.isMarked
                                    "categorized" -> q.categories.isNotEmpty()
                                    "uncategorized" -> q.categories.isEmpty()
                                    else -> true
                                }
                            }
                        }
                    } else {
                        allRawQuestions
                    }

                    // Apply range first. SessionEntity stores zero-based indices.
                    val effectiveRangeFrom = rangeFrom.coerceAtLeast(0)
                        .coerceAtMost((filteredQuestions.size - 1).coerceAtLeast(0))

                    val effectiveRangeTo = if ((rangeTo < 0) || (rangeTo >= filteredQuestions.size)) {
                        filteredQuestions.size - 1
                    } else {
                        rangeTo
                    }

                    val rangedQuestions = if ((filteredQuestions.isNotEmpty()) && (effectiveRangeFrom <= effectiveRangeTo)) {
                        filteredQuestions.subList(effectiveRangeFrom, (effectiveRangeTo + 1).coerceAtMost(filteredQuestions.size))
                    } else {
                        filteredQuestions
                    }

                    if (shuffleQ) {
                        val seed = sessionId ?: quizId
                        rangedQuestions.shuffled(java.util.Random(seed))
                    } else {
                        rangedQuestions
                    }
                }

                if (quizQuestions.isEmpty()) {
                    val errorMessage = if (session?.includeFilters?.isNotEmpty() == true) {
                        "No questions match your current filters. Try changing filters in session settings."
                    } else if (rangeFrom > 0 || rangeTo > 0) {
                        "No questions found in the selected range."
                    } else {
                        "No active questions found for this quiz."
                    }
                    _uiState.update { it.copy(isLoading = false, error = errorMessage) }
                    return@launch
                }

                val finalOriginalCount = if (sessionOriginalCount > 0) sessionOriginalCount else quizQuestions.size

                _uiState.update {
                    it.copy(
                        questions = quizQuestions,
                        currentIndex = startIndex.coerceIn(0, quizQuestions.size.coerceAtLeast(1) - 1),
                        isLoading = false,
                        initialQuestionCount = finalOriginalCount,
                        sessionId = sessionId,
                        sessionLabel = sessionLabel,
                        score = sessionScore,
                        currentStreak = sessionCurrentStreak,
                        maxStreak = sessionMaxStreak,
                        isRapidMode = rapidMode,
                        questionResultsByIndex = initialResultsByIndex,
                        shuffleQuestions = shuffleQ,
                        shuffleOptions = shuffleOpt,
                        repeatWrong = repeatWrong,
                        quizTimerSeconds = quizTimer,
                        questionTimerSeconds = qTimer,
                        skipUnansweredGlobal = skipUnanswered,
                    )
                }

            _timerState.update {
                it.copy(
                    quizTimeLeft = if (session != null && session.quizTimerSeconds > 0) {
                        val elapsedMillis = System.currentTimeMillis() - session.lastModifiedAt
                        val elapsedSeconds = (elapsedMillis / 1000).toInt()
                        (session.quizTimerSeconds - elapsedSeconds).coerceAtLeast(0)
                    } else {
                        quizTimer
                    },
                    questionTimeLeft = qTimer,
                    timeLeft = session?.let {
                        // We don't store exact total elapsed time in SessionEntity currently, 
                        // but it could be inferred or added. For now, reset or approximate.
                        0 
                    } ?: 0
                )
            }

            // Save initial sequence if new session
            if (session != null && session.questionIds.isEmpty()) {
                quizRepository.updateSession(session.copy(
                    questionIds = quizQuestions.map { it.id },
                    originalQuestionCount = finalOriginalCount
                ))
            }

            val restoredAnswers = session?.answersByIndex?.get(_uiState.value.currentIndex)?.toSet()
            val restoredDropped = session?.droppedOptionsByIndex?.get(_uiState.value.currentIndex)?.toSet()
            val restoredVisibleCount = session?.visibleOptionsCountByIndex?.get(_uiState.value.currentIndex)

            prepareQuestion(
                restoredSelection = restoredAnswers,
                restoredDropped = restoredDropped,
                restoredVisibleCount = restoredVisibleCount
            )
            startTimer()
            } catch (e: Exception) {
                e.printStackTrace()
                _uiState.update { it.copy(isLoading = false, error = "Failed to load quiz: ${e.message}") }
            }
        }
    }


    /**
     * Prepares the state for the current question, including option shuffling.
     *
     * @param restoredSelection Previously selected options if resuming.
     * @param restoredDropped Previously dropped options if resuming.
     * @param restoredVisibleCount Number of visible options if resuming in one-by-one mode.
     */

private fun prepareQuestion(
        restoredSelection: Set<Int>? = null,
        restoredDropped: Set<Int>? = null,
        restoredVisibleCount: Int? = null
    ) {
        val state = _uiState.value
        if (state.questions.isEmpty() || state.currentIndex >= state.questions.size) return

        val question = state.questions[state.currentIndex]
        val shuffleOpt = state.shuffleOptions
        val optionsWithIndices = question.options.mapIndexed { index, s -> index to s }

        // Use index in seed for unique shuffling even if question repeats
        val seed = (state.sessionId ?: state.quizId) + question.id + state.currentIndex
        val processedOptions = if (shuffleOpt) {
            optionsWithIndices.shuffled(java.util.Random(seed))
        } else {
            optionsWithIndices
        }

        val isAnswered = restoredSelection != null
        val isCorrect = restoredSelection != null && question.correctAnswers.toSet() == restoredSelection

        _uiState.update {
            it.copy(
                shuffledOptions = processedOptions.map { pair -> pair.second },
                optionMapping = processedOptions.map { pair -> pair.first },
                selectedOptions = restoredSelection ?: emptySet(),
                isAnswered = isAnswered,
                isCorrect = isCorrect,
                droppedOptions = restoredDropped ?: emptySet(),
                showHint = false,
                visibleOptionsCount = restoredVisibleCount ?: if (it.isOneByOne && !isAnswered) 0 else processedOptions.size
            )
        }

        _timerState.update {
            it.copy(questionTimeLeft = _uiState.value.questionTimerSeconds)
        }
    }

    /**
     * Starts a personalized adaptive training session.
     *
     * @param type The type of training ("BOOK", "CATEGORY", or "ALL").
     * @param id The ID associated with the type (book ID or category name).
     * @param limit Maximum number of questions to include.
     */

fun startAdaptiveTraining(type: String, id: String?, limit: Int = 20) {
        if (_uiState.value.questions.isNotEmpty() && !_uiState.value.isLoading) {
            // Simple check to avoid restart on rotation for adaptive
            return
        }
        viewModelScope.launch {
            try {
                _uiState.update { it.copy(isLoading = true, error = null) }

                val questions = when (type) {
                    "BOOK" -> id?.toLongOrNull()?.let { studyRepository.getAdaptiveQuestionsByBook(it, limit) } ?: emptyList()
                    "CATEGORY" -> if (id != null) quizRepository.getQuestionsByCategory(id) else emptyList()
                    "ALL" -> studyRepository.getAdaptiveQuestionsByBook(-1L, limit)
                    else -> emptyList()
                }.shuffled()

                _uiState.update {
                    it.copy(
                        questions = questions,
                        currentIndex = 0,
                        isLoading = false,
                        initialQuestionCount = questions.size,
                        sessionLabel = when (type) {
                            "CATEGORY" -> "Category: $id"
                            "BOOK" -> "Review: Book $id"
                            else -> "Personalized Training"
                        }
                    )
                }
                prepareQuestion()
                startTimer()
            } catch (e: Exception) {
                e.printStackTrace()
                _uiState.update { it.copy(isLoading = false, error = "Failed to load adaptive training: ${e.message}") }
            }
        }
    }

    /**
     * Toggles rapid mode where answers are submitted immediately upon selection.
     */

fun toggleRapidMode() {
        val newMode = !_uiState.value.isRapidMode
        _uiState.update { it.copy(isRapidMode = newMode) }
        viewModelScope.launch {
            _uiState.value.sessionId?.let { sessionId ->
                quizRepository.getSessionById(sessionId)?.let { session ->
                    quizRepository.updateSession(session.copy(rapidMode = newMode))
                }
            }
        }
    }

    /**
     * Toggles one-by-one mode where options are revealed one at a time.
     */

fun toggleOneByOne() {
        val newIsOneByOne = !_uiState.value.isOneByOne
        _uiState.update { 
            it.copy(
                isOneByOne = newIsOneByOne,
                visibleOptionsCount = if (newIsOneByOne && !it.isAnswered) 0 else it.shuffledOptions.size
            )
        }
        viewModelScope.launch {
            dataStoreManager.setOneByOneMode(newIsOneByOne)
        }
    }

    /**
     * Toggles elimination mode where options can be crossed out.
     */

fun toggleEliminationMode() {
        viewModelScope.launch {
            dataStoreManager.setEliminationModeEnabled(!_uiState.value.eliminationModeEnabled)
        }
    }

    /**
     * Toggles focus mode where notifications are blocked.
     */

fun toggleFocusMode() {
        val newEnabled = !_uiState.value.focusModeEnabled
        if (newEnabled && !focusManager.hasNotificationPolicyAccess()) {
            focusManager.requestNotificationPolicyAccess()
            return
        }

        viewModelScope.launch {
            dataStoreManager.setFocusModeEnabled(newEnabled)
        }
    }

    /**
     * Toggles the "marked" (flagged) status of the current question.
     */

fun toggleMarked() {
        val state = _uiState.value
        if (state.questions.isEmpty()) return
        val currentQuestion = state.questions[state.currentIndex]
        val newMarked = !currentQuestion.isMarked

        viewModelScope.launch {
            val updatedQuestion = currentQuestion.copy(isMarked = newMarked)
            assetRepository.updateQuestion(updatedQuestion)

            _uiState.update { s ->
                val newQuestions = s.questions.toMutableList()
                newQuestions[s.currentIndex] = updatedQuestion
                s.copy(questions = newQuestions)
            }
        }
    }

    /**
     * Marks the current question as dropped and moves to the next one.
     */

fun dropQuestion() {
        val currentState = _uiState.value
        if (currentState.questions.isEmpty()) return
        val currentQuestion = currentState.questions[currentState.currentIndex]
        val droppedQuestion = currentQuestion.copy(isDropped = true, updatedAt = System.currentTimeMillis())

        viewModelScope.launch {
            assetRepository.updateQuestion(droppedQuestion)
            _uiState.update { state ->
                val updatedQuestions = state.questions.toMutableList()
                updatedQuestions[state.currentIndex] = droppedQuestion
                state.copy(questions = updatedQuestions)
            }

            // Sync session if active
            currentState.sessionId?.let { sessionId ->
                quizRepository.getSessionById(sessionId)?.let { currentSession ->
                quizRepository.updateSession(
                    currentSession.copy(
                        lastModifiedAt = System.currentTimeMillis(),
                    ),
                )
            }
            }

            nextQuestion()
        }
    }

    /** Restores the current dropped question so it can rejoin normal review flows. */

fun restoreCurrentDroppedQuestion() {
        val currentState = _uiState.value
        if (currentState.questions.isEmpty()) return
        val currentQuestion = currentState.questions[currentState.currentIndex]
        if (!currentQuestion.isDropped) return
        val restoredQuestion = currentQuestion.copy(isDropped = false, updatedAt = System.currentTimeMillis())

        viewModelScope.launch {
            assetRepository.updateQuestion(restoredQuestion)
            _uiState.update { state ->
                val updatedQuestions = state.questions.toMutableList()
                updatedQuestions[state.currentIndex] = restoredQuestion
                state.copy(questions = updatedQuestions)
            }
        }
    }

    /**
     * Marks the current session as completed and saves progress.
     */

fun finishSession() {
        _uiState.update { it.copy(isCompleted = true) }
        timerJob?.cancel()
        autoAdvanceJob?.cancel()
        viewModelScope.launch {
            val state = _uiState.value
            state.sessionId?.let { sessionId ->
                val session = quizRepository.getSessionById(sessionId)
                session?.let {
                    quizRepository.updateSession(
                        it.copy(
                            isCompleted = true,
                            score = state.score,
                            currentStreak = state.currentStreak,
                            maxStreak = state.maxStreak,
                            lastModifiedAt = System.currentTimeMillis(),
                        ),
                    )
                }
            }
            dataStoreManager.clearSession()
        }
    }

    /**
     * Toggles the visibility of the categorization management UI.
     */

fun toggleCategorization() {
        val newEnabled = !_uiState.value.showCategorization
        _uiState.update { it.copy(showCategorization = newEnabled) }
        viewModelScope.launch {
            dataStoreManager.setShowCategorization(newEnabled)
        }
    }

    /**
     * Toggles a category for the current question.
     */

fun toggleQuestionCategory(category: String) {
        val currentState = _uiState.value
        val question = currentState.questions[currentState.currentIndex]
        val newCats = if (question.categories.contains(category)) {
            question.categories - category
        } else {
            question.categories + category
        }

        val updatedQuestion = question.copy(categories = newCats)
        val updatedQuestions = currentState.questions.toMutableList()
        updatedQuestions[currentState.currentIndex] = updatedQuestion

        _uiState.update { it.copy(questions = updatedQuestions) }
        viewModelScope.launch {
            assetRepository.updateQuestion(updatedQuestion)
        }
    }

    /**
     * Toggles the pinned status of a category.
     *
     * @param categoryName The name of the category to pin or unpin.
     */

fun onToggleCategoryPin(categoryName: String) {
        viewModelScope.launch {
            val metadata = _uiState.value.allCategoriesWithMetadata.find { it.name == categoryName }?.metadata
                ?: CategoryMetadataEntity(name = categoryName)
            quizRepository.updateCategoryMetadata(metadata.copy(isPinned = !metadata.isPinned))
        }
    }

    /**
     * Updates the emoji associated with a category.
     *
     * @param categoryName The name of the category.
     * @param emoji The new emoji string, or null to clear it.
     */

fun onUpdateCategoryEmoji(categoryName: String, emoji: String?) {
        viewModelScope.launch {
            val metadata = _uiState.value.allCategoriesWithMetadata.find { it.name == categoryName }?.metadata
                ?: CategoryMetadataEntity(name = categoryName)
            quizRepository.updateCategoryMetadata(metadata.copy(emoji = emoji))
        }
    }

    /**
     * Updates the theme color associated with a category.
     *
     * @param categoryName The name of the category.
     * @param color The new color integer, or null to clear it.
     */

fun onUpdateCategoryColor(categoryName: String, color: Int?) {
        viewModelScope.launch {
            val metadata = _uiState.value.allCategoriesWithMetadata.find { it.name == categoryName }?.metadata
                ?: CategoryMetadataEntity(name = categoryName)
            quizRepository.updateCategoryMetadata(metadata.copy(color = color))
        }
    }

    /**
     * Gets a preview of how many questions would be affected by merging two categories.
     *
     * @param source The source category name.
     * @param target The target category name.
     * @return The number of questions that would be updated.
     */

suspend fun getMergePreview(source: String, target: String): Int {
        return quizRepository.getMergePreview(source, target)
    }

    /**
     * Renames an existing category globally.
     *
     * @param oldName The current name of the category.
     * @param newName The new name for the category.
     */

fun renameCategory(oldName: String, newName: String) {
        viewModelScope.launch {
            quizRepository.renameCategory(oldName, newName)
        }
    }

    /**
     * Deletes a category globally from all questions and metadata.
     *
     * @param name The name of the category to delete.
     */

fun deleteCategory(name: String) {
        viewModelScope.launch {
            quizRepository.deleteCategory(name)
        }
    }

    /**
     * Merges one category into another.
     *
     * @param source The category to be merged and removed.
     * @param target The category that will receive the questions from the source.
     */

fun mergeCategory(source: String, target: String) {
        viewModelScope.launch {
            quizRepository.mergeCategory(source, target)
        }
    }

    /**
     * Sets the navigation filter for questions.
     */

fun setNavigationFilter(filter: NavigationFilter) {
        _uiState.update { it.copy(navigationFilter = filter) }
    }

    /**
     * Jumps to a specific question in the sequence.
     */

fun jumpToQuestion(index: Int) {
        val state = _uiState.value
        if (index in state.questions.indices) {
            questionStartTime = System.currentTimeMillis()
            viewModelScope.launch {
                val session = state.sessionId?.let { quizRepository.getSessionById(it) }
                val restoredAnswers = session?.answersByIndex?.get(index)?.toSet()
                val restoredDropped = session?.droppedOptionsByIndex?.get(index)?.toSet()
                val restoredVisibleCount = session?.visibleOptionsCountByIndex?.get(index)

                _uiState.update { it.copy(currentIndex = index) }

                prepareQuestion(
                    restoredSelection = restoredAnswers,
                    restoredDropped = restoredDropped,
                    restoredVisibleCount = restoredVisibleCount
                )

                // Save progress to session if active
                state.sessionId?.let {
                    session?.let { currentSession ->
                    quizRepository.updateSession(
                        currentSession.copy(
                            currentQuestionIndex = index,
                            lastModifiedAt = System.currentTimeMillis(),
                        ),
                    )
                }
                }
                dataStoreManager.saveSession(state.quizId, index)
            }
        }
    }

    /**
     * Navigates to the previous question in the sequence.
     */

fun previousQuestion() {
        val state = _uiState.value
        if (state.currentIndex > 0) {
            jumpToQuestion(state.currentIndex - 1)
        }
    }

    /**
     * Toggles the visibility of the current question's hint.
     */

fun toggleHint() {
        _uiState.update { it.copy(showHint = !it.showHint) }
    }

    /**
     * Handles option selection by the user.
     *
     * @param shuffledIndex The index of the selected option in the shuffled list.
     */

fun onOptionSelected(shuffledIndex: Int) {
        val currentState = _uiState.value
        val originalIndex = currentState.optionMapping[shuffledIndex]

        if (currentState.isAnswered || currentState.droppedOptions.contains(originalIndex)) return

        val currentQuestion = currentState.questions[currentState.currentIndex]

        if (currentState.isRapidMode && currentQuestion.type == QuestionType.SINGLE_CHOICE) {
            submitSingleChoice(originalIndex, currentQuestion, currentState)
        } else {
            _uiState.update { state ->
                val newSelection = if (currentQuestion.type == QuestionType.SINGLE_CHOICE) {
                    setOf(originalIndex)
                } else {
                    if (state.selectedOptions.contains(originalIndex)) {
                        state.selectedOptions - originalIndex
                    } else {
                        state.selectedOptions + originalIndex
                    }
                }
                state.copy(selectedOptions = newSelection)
            }
        }
    }

    /**
     * Handles option double click by the user.
     *
     * @param shuffledIndex The index of the selected option in the shuffled list.
     */

fun onOptionDoubleClicked(shuffledIndex: Int) {
        val currentState = _uiState.value
        val originalIndex = currentState.optionMapping[shuffledIndex]

        if (currentState.isAnswered || currentState.droppedOptions.contains(originalIndex)) return
        if (!currentState.doubleTapToSubmitEnabled || currentState.isRapidMode) return

        val currentQuestion = currentState.questions[currentState.currentIndex]

        if (currentQuestion.type == QuestionType.SINGLE_CHOICE) {
            submitSingleChoice(originalIndex, currentQuestion, currentState)
        }
    }

private fun submitSingleChoice(originalIndex: Int, currentQuestion: QuestionEntity, currentState: QuizState) {
        val currentIndex = currentState.currentIndex
        val isAlreadyAnswered = currentState.questionResultsByIndex.containsKey(currentIndex)
        if (isAlreadyAnswered) return

        // Merge selection and submission for Rapid Mode or Double Tap to avoid double recomposition
        val newSelection = setOf(originalIndex)
        applyAnswer(newSelection, currentQuestion, currentState)
    }

    /**
     * Submits the current selection as an answer.
     *
     * @param isTimeout Whether the submission was triggered by a timer timeout.
     */

fun submitAnswer(isTimeout: Boolean = false) {
        val currentState = _uiState.value

        // One-by-one logic: If not all options shown, "Next" (or "Reveal") shows next option
        // Skip this on timeout to immediately show the answer
        if (!isTimeout && currentState.isOneByOne && !currentState.isAnswered && currentState.visibleOptionsCount < currentState.shuffledOptions.size) {
            val nextVisibleCount = currentState.visibleOptionsCount + 1
            val currentIndex = currentState.currentIndex
            _uiState.update { it.copy(visibleOptionsCount = nextVisibleCount) }

            // Sync visible count to session
            viewModelScope.launch {
                currentState.sessionId?.let { sessionId ->
                    quizRepository.getSessionById(sessionId)?.let { session ->
                        val updatedVisible = session.visibleOptionsCountByIndex.toMutableMap()
                        updatedVisible[currentIndex] = nextVisibleCount
                        quizRepository.updateSession(session.copy(visibleOptionsCountByIndex = updatedVisible))
                    }
                }
            }
            return
        }

        if (currentState.isAnswered) {
            nextQuestion()
            return
        }

        if (currentState.selectedOptions.isEmpty() && !isTimeout) {
            if (currentState.skipUnansweredGlobal) {
                nextQuestion()
            }
            return
        }

        val currentIndex = currentState.currentIndex
        val isAlreadyAnswered = currentState.questionResultsByIndex.containsKey(currentIndex)
        if (isAlreadyAnswered) return

        val currentQuestion = currentState.questions[currentIndex]
        applyAnswer(currentState.selectedOptions, currentQuestion, currentState)
    }

private fun applyAnswer(
        newSelection: Set<Int>,
        currentQuestion: QuestionEntity,
        currentState: QuizState
    ) {
        val isCorrect = currentQuestion.correctAnswers.toSet() == newSelection
        val currentIndex = currentState.currentIndex

        val isFirstAttempt = currentIndex < currentState.initialQuestionCount
        val newStreak = if (isFirstAttempt) {
            if (isCorrect) currentState.currentStreak + 1 else 0
        } else {
            currentState.currentStreak
        }
        val newMaxStreak = maxOf(currentState.maxStreak, newStreak)
        val newScore =
            if (isCorrect && isFirstAttempt) currentState.score + 1 else currentState.score

        _uiState.update { state ->
            val updatedQuestions = if (!isCorrect && state.repeatWrong) {
                state.questions + currentQuestion
            } else {
                state.questions
            }

            state.copy(
                selectedOptions = newSelection,
                isAnswered = true,
                isCorrect = isCorrect,
                score = newScore,
                currentStreak = newStreak,
                maxStreak = newMaxStreak,
                visibleOptionsCount = state.shuffledOptions.size,
                questionResultsByIndex = state.questionResultsByIndex + (currentIndex to isCorrect),
                questions = updatedQuestions
            )
        }

        // Trigger side effects (database updates, auto-advance)
        finalizeSubmission(
            currentQuestion = currentQuestion,
            isCorrect = isCorrect,
            currentIndex = currentIndex,
            selectedOptions = newSelection,
            sessionId = currentState.sessionId,
            newScore = newScore,
            newCurrentStreak = newStreak,
            newMaxStreak = newMaxStreak,
            initialQuestionCount = currentState.initialQuestionCount,
            repeatWrong = currentState.repeatWrong,
            shuffledOptionsSize = currentState.shuffledOptions.size,
            isRapidMode = currentState.isRapidMode
        )
    }

    private var questionStartTime: Long = System.currentTimeMillis()

private fun finalizeSubmission(
        currentQuestion: QuestionEntity,
        isCorrect: Boolean,
        currentIndex: Int,
        selectedOptions: Set<Int>,
        sessionId: Long?,
        newScore: Int,
        newCurrentStreak: Int,
        newMaxStreak: Int,
        initialQuestionCount: Int,
        repeatWrong: Boolean,
        shuffledOptionsSize: Int,
        isRapidMode: Boolean
    ) {
        val timeSpent = System.currentTimeMillis() - questionStartTime
        val isFirstAttempt = currentIndex < initialQuestionCount

        viewModelScope.launch {
            // Only update long-term metrics on first attempt to avoid inflation
            if (isFirstAttempt) {
                studyRepository.updateQuestionMetrics(currentQuestion.id, isCorrect, timeSpent)
            }

            if (!isCorrect) {
                val quiz = quizRepository.getQuizById(currentQuestion.quizId)
                val selectedText = selectedOptions.asSequence().sorted().mapNotNull { currentQuestion.options.getOrNull(it) }.joinToString(", ").ifBlank { selectedOptions.joinToString(",") }
                val correctText = currentQuestion.correctAnswers.asSequence().sorted().mapNotNull { currentQuestion.options.getOrNull(it) }.joinToString(", ").ifBlank { currentQuestion.correctAnswers.joinToString(",") }
                studyRepository.autoLogWrongAnswer(
                    bookId = quiz?.bookId ?: 0L,
                    quizId = currentQuestion.quizId,
                    questionId = currentQuestion.id,
                    sessionId = sessionId,
                    selectedAnswer = selectedText,
                    correctAnswer = correctText
                )
            }

            // Save score and incorrect count to session
            sessionId?.let { sId ->
                val session = quizRepository.getSessionById(sId)
                session?.let { currentSession ->
                    val newIncorrectCount = if (!isCorrect && isFirstAttempt) currentSession.incorrectCount + 1 else currentSession.incorrectCount

                    // Update session answers map (by ID)
                    val updatedAnswersById = currentSession.answers.toMutableMap()
                    // Always update answers map to keep latest answer for summary
                    updatedAnswersById[currentQuestion.id] = selectedOptions.toList()

                    // Update session answers map (by Index)
                    val updatedAnswersByIndex = currentSession.answersByIndex.toMutableMap()
                    updatedAnswersByIndex[currentIndex] = selectedOptions.toList()

                    val updatedVisible = currentSession.visibleOptionsCountByIndex.toMutableMap()
                    updatedVisible[currentIndex] = shuffledOptionsSize

                    val updatedQuestionIds = if (!isCorrect && repeatWrong) {
                        currentSession.questionIds + currentQuestion.id
                    } else {
                        currentSession.questionIds
                    }

                    // Update result taxonomy
                    val updatedTaxonomy = currentSession.resultTaxonomy.toMutableMap()
                    if (isFirstAttempt) {
                        updatedTaxonomy[currentIndex] =
                            if (isCorrect) "CORRECT_FIRST_TRY" else "WRONG"
                    } else {
                        // For repeats, find the original index this question belongs to
                        // This is a simplification: assuming the original indices are 0..initialQuestionCount-1
                        // and repeats are appended. We need to find which original index we are repeating.
                        // In a simple sequence, we could track the original index, but here we can try to find the last 
                        // WRONG entry for this question ID.
                        val originalIndex = currentSession.questionIds.take(initialQuestionCount)
                            .indexOf(currentQuestion.id)

                        if (originalIndex != -1 && isCorrect && updatedTaxonomy[originalIndex] == "WRONG") {
                            updatedTaxonomy[originalIndex] = "CORRECTED_AFTER_REPEAT"
                        }
                    }

                    quizRepository.updateSession(
                        currentSession.copy(
                            score = newScore,
                            currentStreak = newCurrentStreak,
                            maxStreak = newMaxStreak,
                            incorrectCount = newIncorrectCount,
                            answers = updatedAnswersById,
                            answersByIndex = updatedAnswersByIndex,
                            visibleOptionsCountByIndex = updatedVisible,
                            questionIds = updatedQuestionIds,
                            resultTaxonomy = updatedTaxonomy,
                            lastModifiedAt = System.currentTimeMillis()
                        )
                    )
                }
            }

            if (isRapidMode) {
                autoAdvanceJob = launch {
                    delay(autoAdvanceDelayMs)
                    nextQuestion()
                }
            }
        }
    }

    /**
     * Drops (excludes) an option from consideration.
     *
     * @param shuffledIndex The index of the option to drop in the shuffled list.
     */

fun dropOption(shuffledIndex: Int) {
        val currentState = _uiState.value
        if (currentState.isAnswered) return

        val originalIndex = currentState.optionMapping[shuffledIndex]
        val currentQuestion = currentState.questions[currentState.currentIndex]
        val isCorrect = currentQuestion.correctAnswers.contains(originalIndex)
        val currentIndex = currentState.currentIndex

        if (isCorrect) {
            // Dropping the correct option counts as wrong outcome immediately
            val isFirstAttempt = currentIndex < currentState.initialQuestionCount
            _uiState.update {
                val newStreak = if (isFirstAttempt) 0 else it.currentStreak
                it.copy(
                    isAnswered = true,
                    isCorrect = false,
                    selectedOptions = setOf(originalIndex),
                    currentStreak = newStreak,
                    visibleOptionsCount = it.shuffledOptions.size,
                    questionResultsByIndex = it.questionResultsByIndex + (currentIndex to false)
                )
            }

            viewModelScope.launch {
                studyRepository.updateQuestionMetrics(currentQuestion.id, isCorrect = false)
                _uiState.value.sessionId?.let { sessionId ->
                    val session = quizRepository.getSessionById(sessionId)
                    session?.let { currentSession ->
                        val newIncorrectCount = if (isFirstAttempt) currentSession.incorrectCount + 1 else currentSession.incorrectCount
                        val newCurrentStreak = _uiState.value.currentStreak
                        val newMaxStreak = _uiState.value.maxStreak
                        val updatedAnswers = currentSession.answersByIndex.toMutableMap()
                        updatedAnswers[currentIndex] = listOf(originalIndex)

                        val updatedQuestionIds = if (_uiState.value.repeatWrong) {
                            session.questionIds + currentQuestion.id
                        } else {
                            session.questionIds
                        }

                        quizRepository.updateSession(session.copy(
                            incorrectCount = newIncorrectCount,
                            currentStreak = newCurrentStreak,
                            maxStreak = newMaxStreak,
                            answersByIndex = updatedAnswers,
                            questionIds = updatedQuestionIds,
                            lastModifiedAt = System.currentTimeMillis()
                        ))

                        if (_uiState.value.repeatWrong) {
                            _uiState.update { state -> state.copy(questions = state.questions + currentQuestion) }
                        }
                    }
                }

                if (currentState.isRapidMode) {
                    val delayMs = dataStoreManager.autoAdvanceDelay.first().toLong()
                    autoAdvanceJob = launch {
                        delay(delayMs)
                        nextQuestion()
                    }
                }
            }
        } else {
            val nextDropped = currentState.droppedOptions + originalIndex
            _uiState.update { 
                it.copy(
                    droppedOptions = nextDropped,
                    selectedOptions = it.selectedOptions - originalIndex
                )
            }

            // Auto-selection logic: if only one option remains (not dropped), select it
            val remainingOptions = currentState.optionMapping.filter { !nextDropped.contains(it) }
            if (remainingOptions.size == 1) {
                val lastShuffledIndex = currentState.optionMapping.indexOf(remainingOptions.first())
                if (lastShuffledIndex != -1) {
                    onOptionSelected(lastShuffledIndex)
                }
            }

            viewModelScope.launch {
                currentState.sessionId?.let { sessionId ->
                    quizRepository.getSessionById(sessionId)?.let { session ->
                        val updatedDropped = session.droppedOptionsByIndex.toMutableMap()
                        updatedDropped[currentIndex] = nextDropped.toList()
                        quizRepository.updateSession(session.copy(droppedOptionsByIndex = updatedDropped))
                    }
                }
            }
        }
    }


    /**
     * Advances to the next question in the sequence.
     */

fun nextQuestion() {
        autoAdvanceJob?.cancel()
        val currentState = _uiState.value

        val nextIndex = currentState.currentIndex + 1

        if (nextIndex < currentState.questions.size) {
            questionStartTime = System.currentTimeMillis()
            viewModelScope.launch {
                val session = currentState.sessionId?.let { quizRepository.getSessionById(it) }
                val restoredAnswers = session?.answersByIndex?.get(nextIndex)?.toSet()
                val restoredDropped = session?.droppedOptionsByIndex?.get(nextIndex)?.toSet()
                val restoredVisibleCount = session?.visibleOptionsCountByIndex?.get(nextIndex)

                // Atomically update index and prepare question state to avoid double recomposition
                val question = currentState.questions[nextIndex]
                val shuffleOpt = currentState.shuffleOptions
                val optionsWithIndices = question.options.mapIndexed { index, s -> index to s }
                val seed = (currentState.sessionId ?: currentState.quizId) + question.id + nextIndex
                val processedOptions = if (shuffleOpt) {
                    optionsWithIndices.shuffled(java.util.Random(seed))
                } else {
                    optionsWithIndices
                }

                val isAnswered = restoredAnswers != null
                val isCorrect = restoredAnswers != null && question.correctAnswers.toSet() == restoredAnswers

                _uiState.update {
                    it.copy(
                        currentIndex = nextIndex,
                        shuffledOptions = processedOptions.map { pair -> pair.second },
                        optionMapping = processedOptions.map { pair -> pair.first },
                        selectedOptions = restoredAnswers ?: emptySet(),
                        isAnswered = isAnswered,
                        isCorrect = isCorrect,
                        droppedOptions = restoredDropped ?: emptySet(),
                        showHint = false,
                        visibleOptionsCount = restoredVisibleCount ?: if (it.isOneByOne && !isAnswered) 0 else processedOptions.size
                    )
                }

                _timerState.update {
                    it.copy(questionTimeLeft = _uiState.value.questionTimerSeconds)
                }

                // Save progress to session if active
                currentState.sessionId?.let {
                    session?.let { currentSession ->
                    quizRepository.updateSession(
                        currentSession.copy(
                            currentQuestionIndex = nextIndex,
                            lastModifiedAt = System.currentTimeMillis(),
                        ),
                    )
                }
                }
                dataStoreManager.saveSession(currentState.quizId, nextIndex)
            }
        } else {
            // Check if there are any unanswered (null) results in the sequence
            val firstUnansweredIndex = (0 until currentState.questions.size).firstOrNull { 
                currentState.questionResultsByIndex[it] == null 
            }

            if (firstUnansweredIndex != null) {
                // Loop back to the first unfinished question
                jumpToQuestion(firstUnansweredIndex)
            } else {
                // Actually finished everything
                _uiState.update { it.copy(isCompleted = true) }
                viewModelScope.launch {
                    val state = _uiState.value
                    state.sessionId?.let { sessionId ->
                        val session = quizRepository.getSessionById(sessionId)
                        session?.let { currentSession ->
                            quizRepository.updateSession(
                                currentSession.copy(
                                    isCompleted = true,
                                    score = state.score,
                                    currentStreak = state.currentStreak,
                                    maxStreak = state.maxStreak,
                                    lastModifiedAt = System.currentTimeMillis(),
                                ),
                            )
                        }
                    }
                    dataStoreManager.clearSession()
                }
            }
        }
    }

    /**
     * Starts the session and question timers.
     */

private fun startTimer() {
        val initialState = _uiState.value
        if (initialState.quizTimerSeconds <= 0 && initialState.questionTimerSeconds <= 0) {
            timerJob?.cancel()
            return
        }

        timerJob?.cancel()
        timerJob = viewModelScope.launch {
            while (isActive) {
                delay(1000)
                if (_uiState.value.isCompleted) break

                var shouldSubmit = false
                var quizFinished = false

                val currentQuizState = _uiState.value

                _timerState.update { state ->
                    var newQuizTimeLeft = state.quizTimeLeft
                    var newQuestionTimeLeft = state.questionTimeLeft

                    if (currentQuizState.quizTimerSeconds > 0 && state.quizTimeLeft > 0) {
                        newQuizTimeLeft--
                        if (newQuizTimeLeft == 0) {
                            quizFinished = true
                        }
                    }

                    if (!currentQuizState.isAnswered && currentQuizState.questionTimerSeconds > 0 && state.questionTimeLeft > 0) {
                        newQuestionTimeLeft--
                        if (newQuestionTimeLeft == 0) {
                            shouldSubmit = true
                        }
                    }

                    state.copy(
                        timeLeft = state.timeLeft + 1,
                        quizTimeLeft = newQuizTimeLeft,
                        questionTimeLeft = newQuestionTimeLeft
                    )
                }
                if (shouldSubmit) submitAnswer(isTimeout = true)
                if (quizFinished) finishSession()
            }
        }
    }

    /**
     * Updates the global note for the current question.
     */

fun updateQuestionNote(note: String) {
        val state = _uiState.value
        if (state.questions.isEmpty()) return
        val index = state.currentIndex
        val currentQuestion = state.questions[index]

        val updatedQuestion = currentQuestion.copy(notes = note)

        // Update state immediately for UI responsiveness
        _uiState.update { s ->
            val newQuestions = s.questions.toMutableList()
            if (index in newQuestions.indices) {
                newQuestions[index] = updatedQuestion
            }
            s.copy(questions = newQuestions)
        }

        viewModelScope.launch {
            assetRepository.updateQuestion(updatedQuestion)
        }
    }

fun sourceDocumentsForCurrentQuiz(): Flow<List<com.ahmedyejam.mks.data.local.entity.SourceDocumentEntity>> = flow {
        val quiz = quizRepository.getQuizById(_uiState.value.quizId)
        if (quiz == null) emit(emptyList()) else emitAll(assetRepository.getSourceDocumentsByBookId(quiz.bookId))
    }

override fun onCleared() {
        super.onCleared()
        timerJob?.cancel()
        autoAdvanceJob?.cancel()
        focusManager.disableFocusMode()
    }

fun getAskAiPromptDeckId(onResult: (Long) -> Unit) {
        viewModelScope.launch {
            val quizId = uiState.value.quizId
            if (quizId == 0L) return@launch
            val quiz = quizRepository.getQuizById(quizId)
            val bookId = quiz?.bookId ?: return@launch
            val expectedDeckTitle = "Explanations of - ${quiz.title}"
            val decks = knowledgeRepository.getPromptDecksByBookId(bookId).firstOrNull() ?: emptyList()
            val existingDeck = decks.find { it.title.equals(expectedDeckTitle, ignoreCase = true) }

            if (existingDeck != null) {
                onResult(existingDeck.id)
            } else {
                val newDeckId = knowledgeRepository.createExplainPromptDeck(
                    bookId = bookId,
                    title = expectedDeckTitle,
                    description = "AI Agent configured to explain concepts and answer questions for ${quiz.title}.",
                    seedDefaultCards = true
                )
                onResult(newDeckId)
            }
        }
    }
}

class QuizQuestionsViewModel @Inject constructor(
    private val knowledgeRepository: KnowledgeRepository,
    private val assetRepository: AssetRepository,
    private val quizRepository: QuizRepository,
    private val studyRepository: StudyRepository
) : ViewModel() {

    private val _quizId = MutableStateFlow<Long?>(null)
    private val _searchQuery = MutableStateFlow("")
    private val _visibility = MutableStateFlow(VisibilityState())
    private val _isLoading = MutableStateFlow(true)
    private val _selectedQuestionIds = MutableStateFlow<Set<Long>>(emptySet())
    private val _quizSummary = MutableStateFlow<QuizKnowledgeSummary?>(null)
    private val _questionIdsWithAssets = _quizId.flatMapLatest { id ->
        if (id != null) assetRepository.getQuestionIdsWithAssetsForQuizFlow(id) else flowOf(emptyList())
    }.map { it.toSet() }
     .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptySet())

    val allQuizzes: StateFlow<List<QuizEntity>> = quizRepository.getAllQuizzesFlow()
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    private val _quiz: Flow<QuizEntity?> = _quizId.flatMapLatest { id ->
        if (id != null) {
            flow { 
                val quiz = quizRepository.getQuizById(id)
                emit(quiz) 
            }
        } else {
            flowOf(null)
        }
    }

    private val _allQuestions: Flow<List<QuestionEntity>> = _quizId.flatMapLatest { id ->
        if (id != null) {
            quizRepository.getQuestionsByQuizId(id)
        } else {
            flowOf(emptyList())
        }
    }

    val uiState: StateFlow<QuizQuestionsUiState> = combine(
        _quiz,
        _allQuestions,
        _searchQuery,
        _visibility,
        _isLoading,
        _selectedQuestionIds,
        _questionIdsWithAssets,
        _quizSummary
    ) { params ->
        @Suppress("UNCHECKED_CAST")
        val quiz = params[0] as QuizEntity?
        @Suppress("UNCHECKED_CAST")
        val questions = params[1] as List<QuestionEntity>
        @Suppress("UNCHECKED_CAST")
        val query = params[2] as String
        @Suppress("UNCHECKED_CAST")
        val vis = params[3] as VisibilityState
        @Suppress("UNCHECKED_CAST")
        val loading = params[4] as Boolean
        @Suppress("UNCHECKED_CAST")
        val selected = params[5] as Set<Long>
        @Suppress("UNCHECKED_CAST")
        val assetIds = params[6] as Set<Long>
        @Suppress("UNCHECKED_CAST")
        val summary = params[7] as QuizKnowledgeSummary?

        val validation = questions.associate { it.id to QuestionValidator.validate(it) }

        QuizQuestionsUiState(
            quiz = quiz,
            allQuestions = questions,
            filteredQuestions = applyFilter(questions, query, vis.showOnlyMarked, vis.showOnlyWithAssets, assetIds),
            searchQuery = query,
            visibility = vis,
            isLoading = loading,
            selectedQuestionIds = selected,
            questionIdsWithAssets = assetIds,
            quizSummary = summary,
            validationResults = validation
        )
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), QuizQuestionsUiState())

fun loadQuiz(quizId: Long) {
        _quizId.value = quizId
        _isLoading.value = false
        viewModelScope.launch {
            _quizSummary.value = runCatching { quizRepository.getQuizKnowledgeSummary(quizId) }.getOrNull()
        }
    }

fun setSearchQuery(query: String) {
        _searchQuery.value = query
    }

fun toggleSelection(questionId: Long) {
        val current = _selectedQuestionIds.value
        _selectedQuestionIds.value = if (current.contains(questionId)) {
            current - questionId
        } else {
            current + questionId
        }
    }

fun clearSelection() {
        _selectedQuestionIds.value = emptySet()
    }

fun deleteSelectedQuestions() {
        viewModelScope.launch {
            val selectedIds = _selectedQuestionIds.value
            val questionsToDelete = uiState.value.allQuestions.filter { selectedIds.contains(it.id) }
            questionsToDelete.forEach { quizRepository.deleteQuestion(it) }
            clearSelection()
            _quizId.value?.let { quizRepository.refreshQuizStats(it) }
        }
    }

fun moveSelectedQuestionsToQuiz(targetQuizId: Long) {
        viewModelScope.launch {
            val selectedIds = _selectedQuestionIds.value
            val currentQuizId = _quizId.value
            val questionsToMove = uiState.value.allQuestions.filter { selectedIds.contains(it.id) }
            questionsToMove.forEach { 
                assetRepository.updateQuestion(it.copy(quizId = targetQuizId))
            }
            clearSelection()
            currentQuizId?.let { quizRepository.refreshQuizStats(it) }
            quizRepository.refreshQuizStats(targetQuizId)
        }
    }

fun copySelectedQuestionsToQuiz(targetQuizId: Long) {
        viewModelScope.launch {
            val selectedIds = _selectedQuestionIds.value
            val questionsToCopy = uiState.value.allQuestions.filter { selectedIds.contains(it.id) }
            val newQuestions = questionsToCopy.map { 
                it.copy(id = 0, quizId = targetQuizId, externalId = java.util.UUID.randomUUID().toString()) 
            }
            knowledgeRepository.insertQuestions(newQuestions)
            clearSelection()
            quizRepository.refreshQuizStats(targetQuizId)
        }
    }

fun exportSelectedQuestionsToNewQuiz(title: String) {
        viewModelScope.launch {
            val quiz = uiState.value.quiz ?: return@launch
            val selectedIds = _selectedQuestionIds.value
            val questionsToExport = uiState.value.allQuestions.filter { selectedIds.contains(it.id) }

            val newQuizId = knowledgeRepository.insertQuiz(
                QuizEntity(
                    bookId = quiz.bookId,
                    externalId = java.util.UUID.randomUUID().toString(),
                    title = title,
                    description = "Exported from ${quiz.title}"
                )
            )

            val newQuestions = questionsToExport.map { 
                it.copy(id = 0, quizId = newQuizId, externalId = java.util.UUID.randomUUID().toString()) 
            }
            knowledgeRepository.insertQuestions(newQuestions)
            clearSelection()
            quizRepository.refreshQuizStats(newQuizId)
        }
    }

fun addQuestion(question: QuestionEntity) {
        if (!QuestionValidator.validate(question).isValid) return
        viewModelScope.launch {
            val quizId = _quizId.value ?: return@launch
            knowledgeRepository.insertQuestion(question.copy(quizId = quizId))
            quizRepository.refreshQuizStats(quizId)
        }
    }

fun updateQuestion(question: QuestionEntity) {
        if (!QuestionValidator.validate(question).isValid) return
        viewModelScope.launch {
            assetRepository.updateQuestion(question)
            _quizId.value?.let { quizRepository.refreshQuizStats(it) }
        }
    }

fun markSelectedQuestions(marked: Boolean) {
        viewModelScope.launch {
            val selectedIds = _selectedQuestionIds.value
            val questionsToMark = uiState.value.allQuestions.filter { selectedIds.contains(it.id) }
            questionsToMark.forEach { question ->
                assetRepository.updateQuestion(question.copy(isMarked = marked, updatedAt = System.currentTimeMillis()))
            }
            clearSelection()
        }
    }

fun toggleAllSelection() {
        val currentSelected = _selectedQuestionIds.value
        val allIds = uiState.value.filteredQuestions.map { it.id }.toSet()
        _selectedQuestionIds.value = if (currentSelected.size == allIds.size) emptySet() else allIds
    }

private fun applyFilter(questions: List<QuestionEntity>, query: String, onlyMarked: Boolean, onlyWithAssets: Boolean, questionIdsWithAssets: Set<Long>): List<QuestionEntity> {
        return questions.filter { question ->
            (query.isBlank() || question.text.contains(query, ignoreCase = true) || question.explanation?.contains(query, ignoreCase = true) == true) &&
            (!onlyMarked || question.isMarked) &&
            (!onlyWithAssets || question.id in questionIdsWithAssets)
        }
    }

fun toggleVisibility(update: VisibilityState.() -> VisibilityState) {
        _visibility.value = _visibility.value.update()
    }

fun toggleMarked(question: QuestionEntity) {
        viewModelScope.launch {
            quizRepository.updateQuestionMark(question.id, !question.isMarked)
        }
    }

fun toggleDropped(question: QuestionEntity) {
        viewModelScope.launch {
            quizRepository.updateQuestionDrop(question.id, !question.isDropped)
        }
    }

fun addQuestionAnnotation(bookId: Long, questionId: Long, selectedText: String?, noteBody: String, colorLabel: String = AnnotationColorLabel.YELLOW) {
        viewModelScope.launch {
            assetRepository.createAnnotationForOwner(
                bookId = bookId,
                ownerType = AnnotationOwnerType.QUESTION,
                ownerId = questionId,
                selectedText = selectedText,
                noteBody = noteBody,
                colorLabel = colorLabel
            )
        }
    }

fun updateAnnotation(annotation: AnnotationEntity) {
        viewModelScope.launch { studyRepository.updateAnnotation(annotation) }
    }

fun deleteAnnotation(annotation: AnnotationEntity) {
        viewModelScope.launch { assetRepository.softDeleteAnnotation(annotation.id) }
    }

fun addQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.insertQuestionAsset(asset) }
    }

fun createSourceAndAddQuestionAsset(asset: QuestionAssetEntity, source: SourceDocumentEntity) {
        viewModelScope.launch {
            val preparedSource = source.copy(
                sourceType = source.sourceType.ifBlank { SourceDocumentTypes.OTHERS },
                bookId = source.bookId ?: asset.bookId
            )
            assetRepository.createSourceDocumentAndQuestionAsset(preparedSource, asset.copy(assetType = QuestionAssetType.SOURCE_REFERENCE))
        }
    }

fun createBlueprintFromQuestion(bookId: Long, questionId: Long) {
        viewModelScope.launch { knowledgeRepository.createBlueprintFromQuestion(bookId, questionId, BlueprintMode.CONCEPT_TEMPLATE) }
    }

fun updateQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.updateQuestionAsset(asset) }
    }

fun deleteQuestionAsset(asset: QuestionAssetEntity) {
        viewModelScope.launch { assetRepository.deleteQuestionAsset(asset) }
    }

fun createFlashcardsFromSelected(title: String, clearMarksAfter: Boolean) {
        val selected = _selectedQuestionIds.value.toList()
        val quiz = uiState.value.quiz ?: return
        if (selected.isEmpty() || title.isBlank()) return
        viewModelScope.launch {
            knowledgeRepository.createFlashcardDeckFromQuestions(quiz.bookId, title, "Generated from selected questions", selected, clearMarksAfter)
            clearSelection()
        }
    }
}

fun FlashcardDeckScreen(
    deckId: Long,
    focusedCardId: Long? = null,
    onBack: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    val vm: FlashcardDeckViewModel = hiltViewModel()

    val compilerViewModel: CompilerViewModel = hiltViewModel()

    val state by vm.uiState.collectAsStateWithLifecycle()
    val elapsed by vm.elapsedSeconds.collectAsStateWithLifecycle()
    val listState = rememberLazyListState()

    BackHandler(enabled = state.isStudyMode) {
        vm.setStudyMode(false)
    }

    val lifecycleOwner = LocalLifecycleOwner.current
    DisposableEffect(lifecycleOwner, state.isStudyMode) {
        if (state.isStudyMode) {
            vm.startSessionTimer()
            val observer = LifecycleEventObserver { _, event ->
                when (event) {
                    Lifecycle.Event.ON_RESUME -> vm.startSessionTimer()
                    Lifecycle.Event.ON_PAUSE -> vm.pauseSessionTimer()
                    else -> {}
                }
            }
            lifecycleOwner.lifecycle.addObserver(observer)
            onDispose {
                lifecycleOwner.lifecycle.removeObserver(observer)
                vm.pauseSessionTimer()
            }
        } else {
            onDispose {}
        }
    }

    LaunchedEffect(focusedCardId, state.cards) {
        if (focusedCardId != null && state.cards.isNotEmpty()) {
            val index = state.cards.indexOfFirst { it.id == focusedCardId }
            if (index != -1) {
                if (tokens.isPlain) {
                    listState.scrollToItem(index + 1)
                } else {
                    listState.animateScrollToItem(index + 1)
                }
            }
        }
    }
    val snackbarHostState = remember { SnackbarHostState() }
    var showCardEditor by remember { mutableStateOf<FlashcardEntity?>(null) }
    var showAddCard by rememberSaveable { mutableStateOf(false) }
    var showDeckEditor by rememberSaveable { mutableStateOf(false) }
    var showDeckSelectionForMove by rememberSaveable { mutableStateOf(false) }
    var showDeckSelectionForCopy by rememberSaveable { mutableStateOf(false) }
    var showPasteTextDialog by rememberSaveable { mutableStateOf(false) }
    var showCompilerDialog by rememberSaveable { mutableStateOf(false) }
    var showGeneratorDialog by rememberSaveable { mutableStateOf(false) }

    val filePickerLauncher = rememberLauncherForActivityResult(ActivityResultContracts.GetContent()) { uri ->
        if (uri != null) {
            compilerViewModel.onFileSelected(uri = uri, targetDeckId = deckId)
            showCompilerDialog = true
        }
    }

    LaunchedEffect(deckId) { vm.loadDeck(deckId) }
    LaunchedEffect(state.message, state.error) {
        val text = state.message ?: state.error
        if (text != null) {
            snackbarHostState.showSnackbar(text)
            vm.clearMessage()
        }
    }

    var showAttemptsChip by rememberSaveable { mutableStateOf(true) }
    var showCorrectChip by rememberSaveable { mutableStateOf(true) }
    var showSourceChip by rememberSaveable { mutableStateOf(true) }
    var showOptionsMenu by remember { mutableStateOf(false) }
    var showExplanation by rememberSaveable { mutableStateOf(false) }
    var showReference by rememberSaveable { mutableStateOf(false) }
    var showHint by rememberSaveable { mutableStateOf(false) }
    var showAdditionalInfo by rememberSaveable { mutableStateOf(false) }

    state.deck?.let { deck ->
        if (showDeckEditor) {
            com.ahmedyejam.mks.ui.components.EntityEditDialog(
                title = "Edit deck",
                initialName = deck.title,
                initialDescription = deck.description ?: "",
                initialImage = deck.coverImage ?: "",
                showImage = true,
                onDismiss = { showDeckEditor = false },
                onSave = { title, desc, image ->
                    vm.updateDeck(title, desc.ifBlank { null }, image.ifBlank { null })
                    showDeckEditor = false
                }
            )
        }
    }

    if (showAddCard || showCardEditor != null) {
        FlashcardEditorDialog(
            card = showCardEditor,
            onDismiss = {
                showAddCard = false
                showCardEditor = null
            },
            onSave = { front, back, hint, tags ->
                val card = showCardEditor
                if (card == null) vm.addCard(front, back, hint, tags) else vm.updateCard(card, front, back, hint, tags)
                showAddCard = false
                showCardEditor = null
            }
        )
    }

    if (showGeneratorDialog) {
        FlashcardGeneratorDialog(
            quizzes = state.quizzes,
            categories = state.categories,
            onDismiss = { showGeneratorDialog = false },
            onConfirm = { source, sourceId, config, clearMarks ->
                when (source) {
                    "ALL" -> vm.generateFromBook(clearMarks, config)
                    "MARKED" -> vm.generateFromMarked("Marked question flashcards", clearMarks, config)
                    "MISSED" -> vm.generateFromMissed(config)
                    "QUIZ" -> sourceId?.toLongOrNull()?.let { vm.generateFromQuiz(it, clearMarks, config) }
                    "CATEGORY" -> sourceId?.let { vm.generateFromCategory(it, clearMarks, config) }
                }
                showGeneratorDialog = false
            }
        )
    }

    if (showDeckSelectionForMove) {
        DeckSelectionDialog(
            title = "Move cards to deck",
            decks = state.availableDecks,
            onDismiss = { showDeckSelectionForMove = false },
            onDeckSelected = { targetDeckId ->
                vm.moveSelectedCards(targetDeckId)
                showDeckSelectionForMove = false
            }
        )
    }

    if (showDeckSelectionForCopy) {
        DeckSelectionDialog(
            title = "Copy cards to deck",
            decks = state.availableDecks,
            onDismiss = { showDeckSelectionForCopy = false },
            onDeckSelected = { targetDeckId ->
                vm.copySelectedCards(targetDeckId)
                showDeckSelectionForCopy = false
            }
        )
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            if (state.selectedCardIds.isNotEmpty()) {
                TopAppBar(
                    title = { Text("${state.selectedCardIds.size} selected") },
                    navigationIcon = { IconButton(onClick = { vm.clearSelection() }) { Icon(Icons.Default.Close, contentDescription = "Clear selection") } },
                    actions = {
                        IconButton(onClick = { vm.selectAllCards() }) {
                            Icon(Icons.Default.SelectAll, contentDescription = "Select All")
                        }
                        IconButton(onClick = { showDeckSelectionForMove = true }) {
                            Icon(
                                Icons.AutoMirrored.Filled.DriveFileMove,
                                contentDescription = "Move"
                            )
                        }
                        IconButton(onClick = { showDeckSelectionForCopy = true }) {
                            Icon(Icons.Default.ContentCopy, contentDescription = "Copy")
                        }
                        IconButton(onClick = { vm.deleteSelectedCards() }) {
                            Icon(Icons.Default.Delete, contentDescription = "Delete")
                        }
                    }
                )
            } else {
                var subtitle: String? = null
                if (state.isStudyMode) {
                    val elapsed by vm.elapsedSeconds.collectAsState()
                    val minutes = elapsed / 60
                    val seconds = elapsed % 60
                    subtitle =
                        String.format(java.util.Locale.getDefault(), "%02d:%02d", minutes, seconds)
                }

                com.ahmedyejam.mks.ui.components.StudyTopAppBar(
                    title = state.deck?.title ?: "Flashcards",
                    subtitle = subtitle,
                    onNavigateBack = onBack,
                    actions = {
                        IconButton(onClick = { showOptionsMenu = true }) {
                            Icon(Icons.Default.MoreVert, contentDescription = "Options")
                        }
                        DropdownMenu(expanded = showOptionsMenu, onDismissRequest = { showOptionsMenu = false }) {
                            DropdownMenuItem(
                                text = { Text("Show Attempts") },
                                onClick = { showAttemptsChip = !showAttemptsChip },
                                trailingIcon = { if (showAttemptsChip) Icon(Icons.Default.Check, null) }
                            )
                            DropdownMenuItem(
                                text = { Text("Show Correct") },
                                onClick = { showCorrectChip = !showCorrectChip },
                                trailingIcon = { if (showCorrectChip) Icon(Icons.Default.Check, null) }
                            )
                            DropdownMenuItem(
                                text = { Text("Show Source") },
                                onClick = { showSourceChip = !showSourceChip },
                                trailingIcon = { if (showSourceChip) Icon(Icons.Default.Check, null) }
                            )
                            if (state.isStudyMode) {
                                DropdownMenuItem(
                                    text = { Text("Show Explanation") },
                                    onClick = { showExplanation = !showExplanation },
                                    trailingIcon = { if (showExplanation) Icon(Icons.Default.Check, null) }
                                )
                                DropdownMenuItem(
                                    text = { Text("Show Reference") },
                                    onClick = { showReference = !showReference },
                                    trailingIcon = { if (showReference) Icon(Icons.Default.Check, null) }
                                )
                                DropdownMenuItem(
                                    text = { Text("Show Hint") },
                                    onClick = { showHint = !showHint },
                                    trailingIcon = { if (showHint) Icon(Icons.Default.Check, null) }
                                )
                                DropdownMenuItem(
                                    text = { Text("Show Additional Info") },
                                    onClick = { showAdditionalInfo = !showAdditionalInfo },
                                    trailingIcon = { if (showAdditionalInfo) Icon(Icons.Default.Check, null) }
                                )
                            }
                        }
                        IconButton(onClick = { vm.setStudyMode(!state.isStudyMode) }) {
                            Icon(
                                if (state.isStudyMode) Icons.AutoMirrored.Filled.ViewList else Icons.Default.PlayArrow,
                                contentDescription = "Toggle study mode"
                            )
                        }
                        IconButton(onClick = { showDeckEditor = true }, enabled = state.deck != null) {
                            Icon(Icons.Default.Edit, contentDescription = "Edit deck")
                        }
                    }
                )
            }
        }
    ) { padding ->
        Box(
            Modifier
                .padding(padding)
                .fillMaxSize()
        ) {
            when {
                state.isLoading -> CircularProgressIndicator(Modifier.align(Alignment.Center))
                state.deck == null -> Text("Deck not found", Modifier.align(Alignment.Center))
                state.isStudyMode -> FlashcardStudyContent(
                    state = state, 
                    viewModel = vm,
                    showExplanation = showExplanation,
                    showReference = showReference,
                    showHint = showHint,
                    showAdditionalInfo = showAdditionalInfo
                )
                else -> FlashcardDeckDetailContent(
                    state = state,
                    showAttemptsChip = showAttemptsChip,
                    showCorrectChip = showCorrectChip,
                    showSourceChip = showSourceChip,
                    onAddCard = { showAddCard = true },
                    onEditCard = { showCardEditor = it },
                    onDeleteCard = { vm.deleteCard(it) },
                    onMoveCard = { card, direction -> vm.moveCard(card, direction) },
                    onGenerateCards = { showGeneratorDialog = true },
                    onStartStudy = { vm.setStudyMode(true) },
                    onToggleSelect = { vm.toggleCardSelection(it) },
                    onImportFile = { filePickerLauncher.launch("*/*") },
                    onPasteText = { showPasteTextDialog = true }
                )
            }
        }
    }

    if (showPasteTextDialog) {
        PasteTextDialog(
            onDismiss = { showPasteTextDialog = false },
            onImport = { text, mode ->
                vm.importFromText(text, mode)
                showPasteTextDialog = false
            }
        )
    }

    if (showCompilerDialog) {
        CompilerDialog(
            viewModel = compilerViewModel,
            books = emptyList(),
            quizzes = emptyList(),
            onDismiss = { showCompilerDialog = false }
        )
    }
}

private fun FlashcardDeckDetailContent(
    state: FlashcardDeckUiState,
    showAttemptsChip: Boolean,
    showCorrectChip: Boolean,
    showSourceChip: Boolean,
    onAddCard: () -> Unit,
    onEditCard: (FlashcardEntity) -> Unit,
    onDeleteCard: (FlashcardEntity) -> Unit,
    onMoveCard: (FlashcardEntity, Int) -> Unit,
    onGenerateCards: () -> Unit,
    onStartStudy: () -> Unit,
    onToggleSelect: (Long) -> Unit,
    onImportFile: () -> Unit,
    onPasteText: () -> Unit
) {
    val deck = state.deck ?: return
    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        item {
            DeckStatsCard(deck = deck, cardCount = state.cards.size)
        }
        item {
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                Button(onClick = onAddCard, modifier = Modifier.weight(1f)) {
                    Icon(Icons.Default.Add, contentDescription = null)
                    Spacer(Modifier.width(6.dp))
                    Text("Add card")
                }
                OutlinedButton(onClick = onStartStudy, enabled = state.cards.isNotEmpty(), modifier = Modifier.weight(1f)) {
                    Icon(Icons.Default.PlayArrow, contentDescription = null)
                    Spacer(Modifier.width(6.dp))
                    Text("Study")
                }
            }
            Spacer(Modifier.height(8.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                OutlinedButton(onClick = onImportFile, modifier = Modifier.weight(1f)) {
                    Text("Import from file")
                }
                OutlinedButton(onClick = onPasteText, modifier = Modifier.weight(1f)) {
                    Text("Paste text")
                }
            }
        }
        item {
            val tokens = LocalMksDesignTokens.current
            Button(
                onClick = onGenerateCards,
                modifier = Modifier
                    .fillMaxWidth()
                    .height(56.dp),
                shape = RoundedCornerShape(tokens.cardRadius)
            ) {
                Icon(Icons.Default.AutoAwesome, contentDescription = null)
                Spacer(Modifier.width(8.dp))
                Text("Generate from questions", fontWeight = FontWeight.Bold)
            }
        }
        if (state.cards.isEmpty()) {
            item {
                val tokens = LocalMksDesignTokens.current
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.cardRadius),
                    elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
                ) {
                    Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Text("No flashcards yet", fontWeight = FontWeight.SemiBold)
                        Text("Create cards manually or generate them from marked/missed questions.")
                    }
                }
            }
        } else {
            items(state.cards, key = { it.id }) { card ->
                FlashcardListItem(
                    card = card,
                    showAttemptsChip = showAttemptsChip,
                    showCorrectChip = showCorrectChip,
                    showSourceChip = showSourceChip,
                    isSelected = state.selectedCardIds.contains(card.id),
                    isSelectionMode = state.selectedCardIds.isNotEmpty(),
                    onToggleSelect = { onToggleSelect(card.id) },
                    onEdit = { onEditCard(card) },
                    onDelete = { onDeleteCard(card) },
                    onMoveUp = { onMoveCard(card, -1) },
                    onMoveDown = { onMoveCard(card, 1) }
                )
            }
        }
    }
}

private fun DeckStatsCard(deck: FlashcardDeckEntity, cardCount: Int) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Text(deck.title, style = MaterialTheme.typography.titleLarge, fontWeight = FontWeight.Bold)
            deck.description?.takeIf { it.isNotBlank() }?.let { Text(it) }
            Row(Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                AssistChip(onClick = {}, label = { Text("$cardCount cards") })
                AssistChip(onClick = {}, label = { Text("${deck.studiedCount} studied") })
                AssistChip(onClick = {}, label = { Text("${(deck.masteryPercentage * 100).toInt()}% mastery") })
            }
            LinearProgressIndicator(progress = { deck.masteryPercentage.coerceIn(0f, 1f) }, modifier = Modifier.fillMaxWidth())
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

private fun FlashcardListItem(
    card: FlashcardEntity,
    showAttemptsChip: Boolean = true,
    showCorrectChip: Boolean = true,
    showSourceChip: Boolean = true,
    isSelected: Boolean,
    isSelectionMode: Boolean,
    onToggleSelect: () -> Unit,
    onEdit: () -> Unit,
    onDelete: () -> Unit,
    onMoveUp: () -> Unit,
    onMoveDown: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .combinedClickable(
                onClick = { if (isSelectionMode) onToggleSelect() },
                onLongClick = onToggleSelect
            ),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                if (isSelectionMode) {
                    Checkbox(checked = isSelected, onCheckedChange = { onToggleSelect() })
                } else {
                    Icon(Icons.Default.Style, contentDescription = null)
                }
                Spacer(Modifier.width(8.dp))
                Column(Modifier.weight(1f)) {
                    Text(card.frontText, fontWeight = FontWeight.SemiBold, maxLines = 2)
                    Text(card.backText, style = MaterialTheme.typography.bodySmall, maxLines = 2)
                }
                if (!isSelectionMode) {
                    IconButton(onClick = onMoveUp) { Icon(Icons.Default.ArrowUpward, contentDescription = "Move up") }
                    IconButton(onClick = onMoveDown) { Icon(Icons.Default.ArrowDownward, contentDescription = "Move down") }
                    IconButton(onClick = onEdit) { Icon(Icons.Default.Edit, contentDescription = "Edit") }
                    IconButton(onClick = onDelete) { Icon(Icons.Default.Delete, contentDescription = "Delete") }
                }
            }
            Row(Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                if (showAttemptsChip) AssistChip(onClick = {}, label = { Text("Attempts ${card.attempts}") })
                if (showCorrectChip) AssistChip(onClick = {}, label = { Text("Correct ${card.correctCount}") })
                if (showSourceChip) card.sourceQuestionId?.let { AssistChip(onClick = {}, label = { Text("Source #$it") }) }
            }
        }
    }
}

private fun FlashcardStudyContent(
    state: FlashcardDeckUiState,
    viewModel: FlashcardDeckViewModel,
    showExplanation: Boolean,
    showReference: Boolean,
    showHint: Boolean,
    showAdditionalInfo: Boolean
) {
    val tokens = LocalMksDesignTokens.current
    val card = state.currentCard
    if (card == null) {
        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            Text("No cards to study")
        }
        return
    }

    val fullBackText = card.backText
    var displayText = if (state.isFlipped) fullBackText else card.frontText
    if (state.isFlipped) {
        val sections = fullBackText.split("\n\n")
        displayText = sections.filter { section ->
            when {
                section.startsWith("Explanation\n") -> showExplanation
                section.startsWith("Reference\n") -> showReference
                section.startsWith("Hint\n") -> showHint
                section.startsWith("Additional Info\n") -> showAdditionalInfo
                else -> true
            }
        }.joinToString("\n\n")
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(8.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        Text("${state.currentIndex + 1} / ${state.cards.size}", style = MaterialTheme.typography.labelLarge, modifier = Modifier.padding(horizontal = 8.dp))
        Surface(
            modifier = Modifier
                .weight(1f)
                .fillMaxWidth()
                .clickable { viewModel.flipCard() },
            shape = RoundedCornerShape(tokens.cardRadius),
            tonalElevation = 2.dp,
            color = MaterialTheme.colorScheme.surfaceVariant
        ) {
            Box(
                Modifier
                    .fillMaxSize()
                    .padding(16.dp)
                    .verticalScroll(rememberScrollState()), contentAlignment = Alignment.Center
            ) {
                Text(
                    text = displayText,
                    style = MaterialTheme.typography.headlineSmall
                )
            }
        }
        if (!state.isFlipped) {
            Button(onClick = { viewModel.flipCard() }, modifier = Modifier.fillMaxWidth()) { Text("Flip") }
        } else {
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                OutlinedButton(onClick = { viewModel.rateCurrentCard(FLASHCARD_RATING_AGAIN) }, modifier = Modifier.weight(1f)) { Text("Again") }
                Button(onClick = { viewModel.rateCurrentCard(FLASHCARD_RATING_GOOD) }, modifier = Modifier.weight(1f)) { Text("Good") }
                Button(onClick = { viewModel.rateCurrentCard(FLASHCARD_RATING_EASY) }, modifier = Modifier.weight(1f)) { Text("Easy") }
            }
        }
        Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
            TextButton(onClick = { viewModel.previousCard() }) { Text("Previous") }
            TextButton(onClick = { viewModel.nextCard() }) { Text("Next") }
        }
    }
}

private fun FlashcardEditorDialog(
    card: FlashcardEntity?,
    onDismiss: () -> Unit,
    onSave: (front: String, back: String, hint: String?, tags: List<String>) -> Unit
) {
    var front by rememberSaveable(card?.id) { mutableStateOf(card?.frontText ?: "") }
    var back by rememberSaveable(card?.id) { mutableStateOf(card?.backText ?: "") }
    var hint by rememberSaveable(card?.id) { mutableStateOf(card?.hint ?: "") }
    var tags by rememberSaveable(card?.id) { mutableStateOf(card?.tags?.joinToString(", ") ?: "") }
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (card == null) "Add flashcard" else "Edit flashcard") },
        text = {
            Column(Modifier.verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                OutlinedTextField(front, { front = it }, label = { Text("Front") }, modifier = Modifier.fillMaxWidth(), minLines = 3)
                OutlinedTextField(back, { back = it }, label = { Text("Back") }, modifier = Modifier.fillMaxWidth(), minLines = 4)
                OutlinedTextField(hint, { hint = it }, label = { Text("Hint") }, modifier = Modifier.fillMaxWidth())
                OutlinedTextField(tags, { tags = it }, label = { Text("Tags, comma separated") }, modifier = Modifier.fillMaxWidth())
            }
        },
        confirmButton = {
            Button(enabled = front.isNotBlank() && back.isNotBlank(), onClick = {
                onSave(
                    front.trim(),
                    back.trim(),
                    hint.trim().ifBlank { null },
                    tags.split(',').map { it.trim() }.filter { it.isNotBlank() }.distinct()
                )
            }) { Text("Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}


@OptIn(ExperimentalMaterial3Api::class)

private fun FlashcardGeneratorDialog(
    quizzes: List<com.ahmedyejam.mks.data.local.entity.QuizEntity>,
    categories: List<String>,
    onDismiss: () -> Unit,
    onConfirm: (source: String, sourceId: String?, config: FlashcardGenerationConfig, clearMarks: Boolean) -> Unit
) {
    var source by rememberSaveable { mutableStateOf("ALL") } // ALL, MARKED, MISSED, QUIZ, CATEGORY
    var sourceId by rememberSaveable { mutableStateOf<String?>(null) }

    var clearMarks by rememberSaveable { mutableStateOf(false) }

    var includeStemInFront by rememberSaveable { mutableStateOf(true) }
    var includeOptionsInFront by rememberSaveable { mutableStateOf(false) }
    var includeImageInFront by rememberSaveable { mutableStateOf(false) }

    var includeAnswerInBack by rememberSaveable { mutableStateOf(true) }
    var includeExplanationInBack by rememberSaveable { mutableStateOf(true) }
    var includeHintInBack by rememberSaveable { mutableStateOf(false) }
    var includeReferenceInBack by rememberSaveable { mutableStateOf(false) }
    var includeAdditionalInfoInBack by rememberSaveable { mutableStateOf(false) }
    var includeImageInBack by rememberSaveable { mutableStateOf(false) }

    var expandedSource by remember { mutableStateOf(false) }
    var expandedSubSource by remember { mutableStateOf(false) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Generate from questions") },
        text = {
            Column(Modifier.verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(8.dp)) {

                ExposedDropdownMenuBox(
                    expanded = expandedSource,
                    onExpandedChange = { expandedSource = it }
                ) {
                    OutlinedTextField(
                        value = when (source) {
                            "ALL" -> "All Book Questions"
                            "MARKED" -> "Marked Questions"
                            "MISSED" -> "Missed Questions"
                            "QUIZ" -> "Specific Quiz"
                            "CATEGORY" -> "Category"
                            else -> ""
                        },
                        onValueChange = {},
                        readOnly = true,
                        label = { Text("Source") },
                        trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSource) },
                        modifier = Modifier
                            .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                            .fillMaxWidth()
                    )
                    ExposedDropdownMenu(
                        expanded = expandedSource,
                        onDismissRequest = { expandedSource = false }
                    ) {
                        DropdownMenuItem(text = { Text("All Book Questions") }, onClick = { source = "ALL"; sourceId = null; expandedSource = false })
                        DropdownMenuItem(text = { Text("Marked Questions") }, onClick = { source = "MARKED"; sourceId = null; expandedSource = false })
                        DropdownMenuItem(text = { Text("Missed Questions") }, onClick = { source = "MISSED"; sourceId = null; expandedSource = false })
                        if (quizzes.isNotEmpty()) {
                            DropdownMenuItem(text = { Text("Specific Quiz") }, onClick = { source = "QUIZ"; sourceId = quizzes.firstOrNull()?.id?.toString(); expandedSource = false })
                        }
                        if (categories.isNotEmpty()) {
                            DropdownMenuItem(text = { Text("Category") }, onClick = { source = "CATEGORY"; sourceId = categories.firstOrNull(); expandedSource = false })
                        }
                    }
                }

                if (source == "QUIZ") {
                    ExposedDropdownMenuBox(
                        expanded = expandedSubSource,
                        onExpandedChange = { expandedSubSource = it }
                    ) {
                        OutlinedTextField(
                            value = quizzes.find { it.id.toString() == sourceId }?.title ?: "",
                            onValueChange = {},
                            readOnly = true,
                            label = { Text("Select Quiz") },
                            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSubSource) },
                            modifier = Modifier
                                .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                                .fillMaxWidth()
                        )
                        ExposedDropdownMenu(
                            expanded = expandedSubSource,
                            onDismissRequest = { expandedSubSource = false }
                        ) {
                            quizzes.forEach { quiz ->
                                DropdownMenuItem(text = { Text(quiz.title) }, onClick = { sourceId = quiz.id.toString(); expandedSubSource = false })
                            }
                        }
                    }
                } else if (source == "CATEGORY") {
                    ExposedDropdownMenuBox(
                        expanded = expandedSubSource,
                        onExpandedChange = { expandedSubSource = it }
                    ) {
                        OutlinedTextField(
                            value = sourceId ?: "",
                            onValueChange = {},
                            readOnly = true,
                            label = { Text("Select Category") },
                            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSubSource) },
                            modifier = Modifier
                                .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                                .fillMaxWidth()
                        )
                        ExposedDropdownMenu(
                            expanded = expandedSubSource,
                            onDismissRequest = { expandedSubSource = false }
                        ) {
                            categories.forEach { cat ->
                                DropdownMenuItem(text = { Text(cat) }, onClick = { sourceId = cat; expandedSubSource = false })
                            }
                        }
                    }
                }

                if (source != "MISSED") {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Checkbox(checked = clearMarks, onCheckedChange = { clearMarks = it })
                        Text("Clear marks after conversion")
                    }
                    Spacer(Modifier.height(8.dp))
                }

                Text("Front of card", fontWeight = FontWeight.Bold)
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeStemInFront, { includeStemInFront = it }); Text("Question Stem") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeOptionsInFront, { includeOptionsInFront = it }); Text("Options") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeImageInFront, { includeImageInFront = it }); Text("Image") }

                Spacer(Modifier.height(8.dp))
                Text("Back of card", fontWeight = FontWeight.Bold)
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeAnswerInBack, { includeAnswerInBack = it }); Text("Answer") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeExplanationInBack, { includeExplanationInBack = it }); Text("Explanation") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeHintInBack, { includeHintInBack = it }); Text("Hint") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeReferenceInBack, { includeReferenceInBack = it }); Text("Reference") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeAdditionalInfoInBack, { includeAdditionalInfoInBack = it }); Text("Additional Info") }
                Row(verticalAlignment = Alignment.CenterVertically) { Checkbox(includeImageInBack, { includeImageInBack = it }); Text("Image") }
            }
        },
        confirmButton = {
            Button(onClick = {
                onConfirm(
                    source,
                    sourceId,
                    FlashcardGenerationConfig(
                        includeStemInFront, includeOptionsInFront, includeImageInFront,
                        includeAnswerInBack, includeExplanationInBack, includeHintInBack, includeReferenceInBack, includeAdditionalInfoInBack, includeImageInBack
                    ),
                    clearMarks
                )
            }) { Text("Generate") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

