            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate cards")
            }
        }
    }

fun generateFromQuiz(quizId: Long, clearMarksAfter: Boolean, config: FlashcardGenerationConfig) {
