                    newCoverUri != null -> {
                        book.copy(coverImage = newCoverUri, updatedAt = System.currentTimeMillis())
                    }
                    else -> book.copy(updatedAt = System.currentTimeMillis())
                }
                bookRepository.updateBook(finalBook)
