fun handleImportUri(uri: Uri, targetQuizId: Long? = null, targetBookId: Long? = null) {
        val format = importViewModel.detectFormat(uri)
        if ((format == com.ahmedyejam.mks.data.importer.model.ImportFormat.XLSX) ||
            (format == com.ahmedyejam.mks.data.importer.model.ImportFormat.CSV_TSV)) {
            compilerViewModel.onFileSelected(uri, targetQuizId, activeWorkspaceId = workspaceId)
            showCompilerDialog = true
        } else if (format == com.ahmedyejam.mks.data.importer.model.ImportFormat.ZIP) {
            importViewModel.getImportPreview(
                uri = uri,
                targetBookId = targetBookId,
                targetQuizId = targetQuizId,
            )
        }
    }

    LaunchedEffect(sharedUris) {
        sharedUris?.firstOrNull()?.let { uri ->
            handleImportUri(uri)
            onConsumedSharedUris()
        }
    }

    LaunchedEffect(returnResetSignal) {
        if (returnResetSignal > 0) {
            viewModel.resetToLibraryRoot()
        }
    }

    LaunchedEffect(Unit) {
        viewModel.uiEvent.collect { event ->
            when (event) {
                is LibraryUiEvent.ShowSnackbar -> {
                    snackbarHostState.showSnackbar(event.message)
                }
            }
        }
    }

    val books by viewModel.books.collectAsStateWithLifecycle(initialValue = emptyList())
    val quizzes by viewModel.quizzes.collectAsStateWithLifecycle(initialValue = emptyList())
    val recentQuizzes by viewModel.recentQuizzes.collectAsStateWithLifecycle(initialValue = emptyList())
    val resumeQuiz by viewModel.resumeQuiz.collectAsStateWithLifecycle(initialValue = null)
    val categories by viewModel.categories.collectAsStateWithLifecycle(initialValue = emptyList())
    val searchQuery by viewModel.searchQuery.collectAsStateWithLifecycle()
    val isSearching by viewModel.isSearching.collectAsStateWithLifecycle()
    val selectedCategory by viewModel.selectedCategory.collectAsStateWithLifecycle()
    val libraryViewMode by viewModel.libraryViewMode.collectAsStateWithLifecycle()
    val bookViewMode by viewModel.bookViewMode.collectAsStateWithLifecycle()

    val currentViewMode by remember {
        derivedStateOf {
            if (selectedCategory == null) libraryViewMode else bookViewMode
        }
    }

    val showCovers by viewModel.showCovers.collectAsState()
    val sortBy by viewModel.sortBy.collectAsState()
    val bookSortBy by viewModel.bookSortBy.collectAsState()

    val showSortDialogState = remember { mutableStateOf(value = false) }
    var showSortDialog by showSortDialogState
    val showBookEditDialogState = rememberSaveable { mutableStateOf(value = false) }
    var showBookEditDialog by showBookEditDialogState
    val editingBookState = remember { mutableStateOf<BookEntity?>(null) }
    var editingBook by editingBookState
    val showQuizEditDialogState = rememberSaveable { mutableStateOf(value = false) }
    var showQuizEditDialog by showQuizEditDialogState
    val editingQuizEditState = remember { mutableStateOf<QuizEntity?>(null) }
    var editingQuizEdit by editingQuizEditState
    val showDeleteConfirmBookState = remember { mutableStateOf<BookEntity?>(null) }
    var showDeleteConfirmBook by showDeleteConfirmBookState
    val showDeleteConfirmQuizState = remember { mutableStateOf<QuizEntity?>(null) }
    var showDeleteConfirmQuiz by showDeleteConfirmQuizState

    val editingCategoryState = remember { mutableStateOf<CategoryWithMetadata?>(null) }
    var editingCategory by editingCategoryState

    var showWorkspaceManager by remember { mutableStateOf(false) }
    var showTrashBin by remember { mutableStateOf(false) }

    val menuBookState = remember { mutableStateOf<BookEntity?>(null) }
    var menuBook by menuBookState
    val menuQuizState = remember { mutableStateOf<QuizEntity?>(null) }
    var menuQuiz by menuQuizState

    var pendingExportBookId by remember { mutableStateOf<Long?>(null) }
    var pendingExportQuizId by remember { mutableStateOf<Long?>(null) }

    val categoriesExpandedState = rememberSaveable { mutableStateOf(value = true) }
    var categoriesExpanded by categoriesExpandedState
    val showCategoryBrowserState = remember { mutableStateOf(value = false) }
    var showCategoryBrowser by showCategoryBrowserState
    val previewCategories by remember(categories) {
        derivedStateOf {
            val pinned = categories.asSequence()
                .filter { it.isPinned }
                .sortedByDescending { it.lastEditedAt }
                .toList()
            val recent = categories.asSequence()
                .filter { !it.isPinned && (it.lastEditedAt > 0) }
                .sortedByDescending { it.lastEditedAt }
                .toList()
            (pinned + recent).take(10)
        }
    }
    val showOverflowMenuState = remember { mutableStateOf(value = false) }
    var showOverflowMenu by showOverflowMenuState

    val importLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenDocument(),
    ) { uri ->
        uri?.let {
            handleImportUri(it, pendingExportQuizId, pendingExportBookId)
        }
    }

    // Handle Import States
    when (val state = importState) {
        is ImportViewModel.ImportState.Review -> {
            ImportReviewDialog(
                preview = state.preview,
                onDismiss = {
                    importViewModel.resetState()
                },
            ) { strategy, allowInsecureHttpImages ->
                importViewModel.importLibrary(
                    uri = state.uri,
                    strategy = strategy,
                    targetBookId = state.targetBookId,
                    targetQuizId = state.targetQuizId,
                    allowInsecureRemoteImages = allowInsecureHttpImages,
                    activeWorkspaceId = workspaceId
                )
            }
        }
        is ImportViewModel.ImportState.Loading -> {
            AlertDialog(
                onDismissRequest = {},
                confirmButton = {},
                title = { Text(state.message) },
                text = {
                    LinearProgressIndicator(
                        progress = { state.progress },
                        modifier = Modifier.fillMaxWidth(),
                    )
                },
            )
        }
        is ImportViewModel.ImportState.Success -> {
            LaunchedEffect(state) {
                val message = if (state.result.warnings.isNotEmpty()) {
                    context.getString(
                        R.string.import_completed_with_warning_count,
                        state.result.warnings.size,
                    )
                } else if (state.result.partiallyImported) {
                    context.getString(
                        R.string.import_completed_with_skipped_count,
                        state.result.skippedRecordsCount,
                    )
                } else {
                    context.getString(R.string.import_successful)
                }
                snackbarHostState.showSnackbar(message)
                completedImportResultState.value = state.result.takeIf { (it.warnings.isNotEmpty()) || (it.skippedRecordsCount > 0) }
                importViewModel.resetState()
            }
        }
        is ImportViewModel.ImportState.Error -> {
            LaunchedEffect(state) {
                snackbarHostState.showSnackbar(context.getString(R.string.import_error, state.message))
                importViewModel.resetState()
            }
        }
        else -> {}
    }

    completedImportResult?.let { result ->
        ImportWarningsDialog(
            result = result,
        ) { completedImportResultState.value = null }
    }

    val exportLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.CreateDocument("application/zip"),
    ) { uri ->
        uri?.let { exportUri ->
            scope.launch {
                try {
                    val result = context.contentResolver.openOutputStream(exportUri)?.use { stream ->
                        pendingExportBookId?.let { bookId ->
                            viewModel.exportBook(bookId, stream)
                        } ?: pendingExportQuizId?.let { quizId ->
                            viewModel.exportQuiz(quizId, stream)
                        } ?: viewModel.exportAll(stream)
                    }
                    if (result?.success == true) {
                        val message = if (result.failedAssetCount > 0) {
                            context.getString(
                                R.string.export_completed_with_warnings,
                                result.failedAssetCount,
                            )
                        } else {
                            context.getString(R.string.export_successful)
                        }
                        snackbarHostState.showSnackbar(message)
                    } else {
                        snackbarHostState.showSnackbar(
                            context.getString(
                                R.string.export_failed,
                                result?.errorMessage ?: context.getString(R.string.unknown_error),
                            ),
                        )
                    }
                } catch (e: Exception) {
                    snackbarHostState.showSnackbar(context.getString(R.string.export_failed, e.message))
                } finally {
                    pendingExportBookId = null
                    pendingExportQuizId = null
                }
            }
        }
    }

    val fabExpandedState = remember { mutableStateOf(value = false) }
    var fabExpanded by fabExpandedState

    BackHandler(enabled = fabExpanded || (selectedCategory != null) || isSearching) {
        if (fabExpanded) {
            fabExpandedState.value = false
        } else if (isSearching) {
            viewModel.setSearching(searching = false)
        } else {
            viewModel.resetToLibraryRoot()
        }
    }

    val scrollBehavior = TopAppBarDefaults.exitUntilCollapsedScrollBehavior()
    val gridState = rememberLazyGridState()

    LaunchedEffect(selectedCategory, isSearching) {
        gridState.scrollToItem(0)
    }

    val columns by remember {
        derivedStateOf {
            if (currentViewMode == "GRID") GridCells.Fixed(2) else GridCells.Fixed(1)
        }
    }

    Scaffold(
        modifier = Modifier.nestedScroll(scrollBehavior.nestedScrollConnection),
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            LibraryTopBar(
                scrollBehavior = scrollBehavior,
                isSearching = isSearching,
                searchQuery = searchQuery,
                onSearchQueryChange = { viewModel.setSearchQuery(it) },
                selectedBookId = -1L,
                selectedCategory = selectedCategory,
                currentBookTitle = null,
                onNavigationClick = {
                    if (isSearching) viewModel.setSearching(searching = false)
                    else viewModel.resetToLibraryRoot()
                },
                onSearchClick = { viewModel.setSearching(searching = true) },
                onSettingsClick = onSettingsSelected,
                onSortClick = { showSortDialog = true },
                currentViewMode = currentViewMode,
                onToggleViewMode = {
                    if (selectedCategory == null) {
                        viewModel.toggleLibraryViewMode()
                    } else {
                        viewModel.toggleBookViewMode()
                    }
                },
                showOverflowMenu = showOverflowMenu,
                onOverflowMenuToggle = { showOverflowMenuState.value = it },
                onContactClick = {
                    val intent = Intent(
                        Intent.ACTION_VIEW,
                        "https://linktr.ee/MKSpace".toUri(),
                    )
                    context.startActivity(intent)
                },
                onWorkspaceManagerClick = { showWorkspaceManager = true },
                onTrashBinClick = { showTrashBin = true }
            )
        },
        floatingActionButton = {
            LibraryFabMenu(
                fabExpanded = fabExpanded,
                onFabExpandedChange = { fabExpandedState.value = it },
                selectedCategory = selectedCategory,
                onAdaptiveSelected = onAdaptiveSelected,
                onNewBookClick = {
                    editingBookState.value = null
                    showBookEditDialogState.value = true
                },
                onImportClick = {
                    importLauncher.launch(
                        arrayOf(
                            "application/zip",
                            "application/x-zip-compressed",
                            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                            "application/vnd.ms-excel",
                            "text/csv",
                            "text/comma-separated-values",
                            "text/tab-separated-values",
                        ),
                    )
                },
            ) {
                val timestamp = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.getDefault()).format(java.util.Date())
                pendingExportBookId = null
                exportLauncher.launch("mks_full_library_$timestamp.zip")
            }
        },
    ) { padding ->
        Box(modifier = Modifier.fillMaxSize()) {
            LibraryContentGrid(
                gridState = gridState,
                columns = columns,
                padding = padding,
                selectedCategory = selectedCategory,
                resumeQuiz = resumeQuiz,
                recentQuizzes = recentQuizzes,
                currentThemeMode = currentThemeMode,
                onQuizClick = { onQuizSelected(it) },
                onLinkClick = { url ->
                    val intent = Intent(
                        Intent.ACTION_VIEW,
                        url.toUri(),
                    )
                    context.startActivity(intent)
                },
                categoriesExpanded = categoriesExpanded,
                previewCategories = previewCategories,
                onCategorySelected = onCategorySelected,
                onCategoryLongClick = { editingCategory = it },
                showCategoryBrowser = { showCategoryBrowser = true },
                books = books,
                quizzes = quizzes,
                currentViewMode = currentViewMode,
                showCovers = showCovers,
                onBookClick = { onBookDashboardSelected(it.id) },
                onBookLongClick = { menuBook = it },
                onQuizLongClick = { menuQuiz = it },
            )

            AnimatedVisibility(
                visible = fabExpanded,
                enter = fadeIn(),
                exit = fadeOut(),
            ) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(padding)
                        .background(Color.Black.copy(alpha = 0.32f))
                        .clickable(
                            interactionSource = remember { MutableInteractionSource() },
                            indication = null,
                        ) {
                            fabExpandedState.value = false
                        },
                )
            }
        }
    }

    // Dialogs management
    menuBook?.let { book ->
        BookOptionsSheet(
            book = book,
            onDismiss = { menuBookState.value = null },
            onPinClick = { viewModel.toggleBookPinned(book) },
            onEditClick = { editingBookState.value = book; showBookEditDialogState.value = true },
            onExportClick = {
                pendingExportBookId = book.id
                pendingExportQuizId = null
                exportLauncher.launch("${book.title.replace(" ", "_")}.mks.zip")
            },
            onImportClick = {
                pendingExportQuizId = null
                pendingExportBookId = book.id
                importLauncher.launch(arrayOf("*/*"))
            },
            onDeleteClick = { showDeleteConfirmBookState.value = book },
        ) { onBookDashboardSelected(book.id) }
    }

    menuQuiz?.let { quiz ->
        QuizOptionsSheet(
            quiz = quiz,
            onDismiss = { menuQuizState.value = null },
            onBrowseQuestionsClick = { onBrowseQuestions(quiz.id) },
            onScanClick = { onScanSelected(quiz.id) },
            onPinClick = { viewModel.toggleQuizPinned(quiz) },
            onEditClick = { editingQuizEditState.value = quiz; showQuizEditDialogState.value = true },
            onExportClick = {
                pendingExportQuizId = quiz.id
                pendingExportBookId = null
                exportLauncher.launch("${quiz.title.replace(" ", "_")}.mks.zip")
            },
            onImportClick = {
                pendingExportQuizId = quiz.id
                pendingExportBookId = null
                importLauncher.launch(arrayOf("*/*"))
            },
        ) { showDeleteConfirmQuizState.value = quiz }
    }

    if (showCategoryBrowser) {
        CategoryBrowserDialog(
            categories = categories,
            onDismiss = { showCategoryBrowserState.value = false },
            onCategorySelected = {
                onCategorySelected(it.name)
                showCategoryBrowserState.value = false
            },
        ) {
            editingCategoryState.value = it
            showCategoryBrowserState.value = false
        }
    }

    editingCategory?.let { category ->
        CategoryEditDialog(
            category = category,
            allCategories = categories,
            books = books,
            onDismiss = { editingCategoryState.value = null },
            onDelete = { viewModel.deleteCategory(category.name); editingCategoryState.value = null },
            onRename = { viewModel.renameCategory(category.name, it); editingCategoryState.value = null },
            onMerge = { viewModel.mergeCategory(category.name, it); editingCategoryState.value = null },
            onGetMergePreview = { viewModel.getMergePreview(category.name, it) },
            onCreateQuiz = { title, bId -> viewModel.createQuizFromCategory(category.name, title, bId); editingCategoryState.value = null },
            onTogglePin = { viewModel.updateCategoryMetadata(category.name, category.emoji, category.color, !category.isPinned) },
            onUpdateEmoji = { viewModel.updateCategoryMetadata(category.name, it, category.color, category.isPinned) },
            onUpdateColor = { viewModel.updateCategoryMetadata(category.name, category.emoji, it, category.isPinned) },
        ) { onCategorySelected(category.name) }
    }

    if (showCompilerDialog) {
        com.ahmedyejam.mks.ui.quiz.CompilerDialog(
            viewModel = compilerViewModel,
            books = books,
            quizzes = quizzes,
        ) {
            showCompilerDialogState.value = false
        }
    }

    if (showBookEditDialog) {
        EntityEditDialog(
            title = if (editingBook == null) stringResource(R.string.new_book) else stringResource(R.string.edit),
            initialName = editingBook?.title ?: "",
            initialDescription = editingBook?.description ?: "",
            initialImage = editingBook?.coverImage ?: "",
            titleLabel = stringResource(R.string.book_title_label),
            descriptionLabel = stringResource(R.string.description_label),
            showImage = true,
            onDismiss = { showBookEditDialogState.value = false },
        ) { title, desc, cover ->
            if (editingBook == null) {
                viewModel.insertBook(
                    BookEntity(
                        workspaceId = workspaceId,
                        externalId = java.util.UUID.randomUUID().toString(),
                        title = title,
                        description = desc,
                    ),
                    coverUri = cover,
                )
            } else {
                editingBook?.let { book ->
                    viewModel.updateBook(
                        book.copy(title = title, description = desc),
                        newCoverUri = cover,
                    )
                }
            }
            showBookEditDialogState.value = false
        }
    }

    showDeleteConfirmBook?.let { book ->
        DeleteConfirmDialog(
            title = stringResource(R.string.delete_book_title),
            message = stringResource(R.string.delete_book_msg, book.title),
            onDismiss = { showDeleteConfirmBookState.value = null },
        ) { viewModel.deleteBook(book); showDeleteConfirmBookState.value = null }
    }

    showDeleteConfirmQuiz?.let { quiz ->
        DeleteConfirmDialog(
            title = stringResource(R.string.delete_quiz_title),
            message = stringResource(R.string.delete_quiz_msg, quiz.title),
            onDismiss = { showDeleteConfirmQuizState.value = null },
        ) { viewModel.deleteQuiz(quiz); showDeleteConfirmQuizState.value = null }
    }

    if (showSortDialog) {
        val isQuizzes = (selectedCategory != null)
        SortDialog(
            currentOption = if (isQuizzes) bookSortBy else sortBy,
            onOptionSelected = {
                if (isQuizzes) {
                    viewModel.setBookSortBy(it)
                } else {
                    viewModel.setSortBy(it)
                }
                showSortDialogState.value = false
            },
        ) { showSortDialogState.value = false }
    }

    if (showWorkspaceManager) {
        WorkspaceManagerDialog(
            viewModel = viewModel,
            activeWorkspaceId = workspaceId,
            onDismiss = { showWorkspaceManager = false }
        )
    }

    if (showTrashBin) {
        TrashBinDialog(
            viewModel = viewModel,
            onDismiss = { showTrashBin = false }
        )
        if (showQuizEditDialog) {
        EntityEditDialog(
            title = stringResource(R.string.edit),
            initialName = editingQuizEdit?.title ?: "",
            initialDescription = editingQuizEdit?.description ?: "",
            initialImage = editingQuizEdit?.coverImage ?: "",
            titleLabel = stringResource(R.string.quiz_title_label),
            descriptionLabel = stringResource(R.string.description_label),
            showImage = true,
            onDismiss = { showQuizEditDialog = false }
        ) { title, desc, cover ->
            editingQuizEdit?.let { quiz ->
                viewModel.updateQuiz(quiz.copy(title = title, description = desc), cover.ifBlank { null })
            }
            showQuizEditDialog = false
        }
    }
}
}

fun LibraryBanner(
    resumeQuiz: QuizEntity?,
    recentQuizzes: List<QuizEntity>,
    currentThemeMode: String,
    onQuizClick: (QuizEntity) -> Unit,
    onLinkClick: (String) -> Unit,
    modifier: Modifier = Modifier
) {
    val targetQuiz = resumeQuiz ?: recentQuizzes.firstOrNull()
    val layoutDirection = LocalLayoutDirection.current
    val isRtl = layoutDirection == LayoutDirection.Rtl
    val normalizedTheme = normalizeMksThemeMode(currentThemeMode)
    val isSystemDark = isSystemInDarkTheme()
    val isActuallyDark = when (normalizedTheme) {
        "MIDNIGHT", "PLAIN_DARK" -> true
        "SYSTEM" -> isSystemDark
        else -> false
    }
    val tokens = LocalMksDesignTokens.current
    val bannerShape = RoundedCornerShape(if (tokens.isPlain) tokens.cardRadius else 30.dp)

    val pagerState = rememberPagerState(initialPage = 501, pageCount = { 1000 })
    val currentRealPage = remember { derivedStateOf { pagerState.currentPage % 2 } }

    val isDragged by pagerState.interactionSource.collectIsDraggedAsState()

    LaunchedEffect(isDragged) {
        if (!isDragged) {
            while (true) {
                kotlinx.coroutines.delay(4000)
                pagerState.animateScrollToPage(pagerState.currentPage + 1)
            }
        }
    }

    Column(
        modifier = modifier.fillMaxWidth(),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .aspectRatio(2f), // 2:1 aspect ratio based on contact banner (1774x887)
            shape = bannerShape,
            colors = CardDefaults.cardColors(containerColor = Color.Transparent),
            elevation = CardDefaults.cardElevation(defaultElevation = 0.dp)
        ) {
            HorizontalPager(
                state = pagerState,
                modifier = Modifier.fillMaxSize()
            ) { page ->
                when (page % 2) {
                    0 -> {
                        val resumeImageRes = remember(isRtl, normalizedTheme, isActuallyDark) {
                            when {
                                normalizedTheme == "FOREST" -> if (isRtl) R.drawable.resume_banner_ar_light_forest else R.drawable.resume_banner_en_light_forest
                                normalizedTheme == "LAVENDER" || normalizedTheme == "PLAIN_LIGHT" -> if (isRtl) R.drawable.resume_banner_ar_light_lavender else R.drawable.resume_banner_en_light_lavender
                                isActuallyDark -> if (isRtl) R.drawable.resume_banner_ar_dark_midnight else R.drawable.resume_banner_en_dark_midnight
                                else -> if (isRtl) R.drawable.resume_banner_ar_light_dawn else R.drawable.resume_banner_en_light_dawn
                            }
                        }
                        ResumeBannerImageSlide(
                            imageRes = resumeImageRes,
                            shape = bannerShape,
                            modifier = Modifier
                                .fillMaxSize()
                                .clickable(enabled = targetQuiz != null) {
                                    targetQuiz?.let(onQuizClick)
                                }
                        )
                    }
                    1 -> {
                        val contactImageRes = remember(isRtl, normalizedTheme, isActuallyDark) {
                            when {
                                normalizedTheme == "FOREST" -> if (isRtl) R.drawable.contact_banner_ar_light_forest_path else R.drawable.contact_banner_en_light_forest_path
                                normalizedTheme == "LAVENDER" || normalizedTheme == "PLAIN_LIGHT" -> if (isRtl) R.drawable.contact_banner_ar_light_lavender_valley else R.drawable.contact_banner_en_light_lavender_valley
                                isActuallyDark -> if (isRtl) R.drawable.contact_banner_ar_dark_moonlit_valley else R.drawable.contact_banner_en_dark_moonlit_valley
                                else -> if (isRtl) R.drawable.contact_banner_ar_light_sunrise_valley else R.drawable.contact_banner_en_light_sunrise_valley
                            }
                        }
                        ContactBannerImageSlide(
                            imageRes = contactImageRes,
                            shape = bannerShape,
                            onContactClick = { onLinkClick("https://linktr.ee/MKSpace") },
                            modifier = Modifier.fillMaxSize()
                        )
                    }
                }
            }
        }

        Spacer(Modifier.height(8.dp))

        // Pager Indicators
        Row(
            modifier = Modifier.height(8.dp),
            horizontalArrangement = Arrangement.spacedBy(6.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            repeat(2) { iteration ->
                val color = if (currentRealPage.value == iteration) {
                    MaterialTheme.colorScheme.primary
                } else {
                    MaterialTheme.colorScheme.onSurface.copy(alpha = 0.2f)
                }
                Box(
                    modifier = Modifier
                        .size(8.dp)
                        .clip(CircleShape)
                        .background(color)
                )
            }
        }
    }
}

private fun ResumeBannerImageSlide(
    imageRes: Int,
    shape: Shape,
    modifier: Modifier = Modifier
) {
    Box(modifier = modifier.clip(shape)) {
        Image(
            painter = painterResource(imageRes),
            contentDescription = null,
            contentScale = ContentScale.Crop, // Crop to fit 2:1 aspect ratio
            modifier = Modifier.fillMaxSize()
        )
    }
}

private fun ContactBannerImageSlide(
    imageRes: Int,
    shape: Shape,
    onContactClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    Box(modifier = modifier
        .clip(shape)
        .clickable(onClick = onContactClick)
    ) {
        Image(
            painter = painterResource(imageRes),
            contentDescription = "Contact Us",
            contentScale = ContentScale.FillBounds,
            modifier = Modifier.fillMaxSize()
        )
    }
}

private fun BannerMiniArtwork(
    action: BannerAction,
    modifier: Modifier = Modifier
) {
    val colors = MaterialTheme.colorScheme
    Canvas(modifier = modifier) {
        val w = size.width
        val h = size.height
        drawRect(
            brush = Brush.verticalGradient(
                listOf(
                    colors.primaryContainer.copy(alpha = 0.46f),
                    colors.surface.copy(alpha = 0.70f),
                    colors.secondary.copy(alpha = 0.12f)
                )
            )
        )

        // Soft arch frame.
        val archLeft = w * 0.12f
        val archTop = h * 0.08f
        val archWidth = w * 0.76f
        val archHeight = h * 0.84f
        drawRoundRect(
            color = colors.primary.copy(alpha = 0.16f),
            topLeft = Offset(archLeft, archTop),
            size = Size(archWidth, archHeight),
            cornerRadius = androidx.compose.ui.geometry.CornerRadius(archWidth * 0.48f, archWidth * 0.48f)
        )
        drawRoundRect(
            color = colors.surface.copy(alpha = 0.70f),
            topLeft = Offset(archLeft + w * 0.045f, archTop + h * 0.045f),
            size = Size(archWidth - w * 0.09f, archHeight - h * 0.09f),
            cornerRadius = androidx.compose.ui.geometry.CornerRadius(archWidth * 0.40f, archWidth * 0.40f)
        )

        val sunColor = when (action) {
            BannerAction.Promotion -> colors.tertiary
            BannerAction.Feedback -> colors.secondary
            else -> colors.primary
        }
        drawCircle(
            color = sunColor.copy(alpha = 0.52f),
            radius = w * 0.13f,
            center = Offset(w * 0.66f, h * 0.27f)
        )

        val far = Path().apply {
            moveTo(w * 0.10f, h * 0.58f)
            cubicTo(w * 0.26f, h * 0.40f, w * 0.42f, h * 0.59f, w * 0.56f, h * 0.45f)
            cubicTo(w * 0.73f, h * 0.30f, w * 0.84f, h * 0.58f, w * 0.96f, h * 0.42f)
            lineTo(w * 0.96f, h)
            lineTo(w * 0.10f, h)
            close()
        }
        drawPath(far, colors.secondary.copy(alpha = 0.20f))

        val near = Path().apply {
            moveTo(w * 0.08f, h * 0.76f)
            cubicTo(w * 0.24f, h * 0.60f, w * 0.39f, h * 0.78f, w * 0.58f, h * 0.58f)
            cubicTo(w * 0.73f, h * 0.42f, w * 0.86f, h * 0.79f, w, h * 0.60f)
            lineTo(w, h)
            lineTo(w * 0.08f, h)
            close()
        }
        drawPath(near, colors.onSurface.copy(alpha = 0.10f))

        when (action) {
            BannerAction.Brand -> {
                drawLine(colors.primary.copy(alpha = 0.48f), Offset(w * 0.18f, h * 0.88f), Offset(w * 0.18f, h * 0.63f), 3.dp.toPx())
                repeat(5) { i ->
                    val y = h * (0.83f - i * 0.04f)
                    drawLine(colors.primary.copy(alpha = 0.44f), Offset(w * 0.18f, y), Offset(w * (0.10f + i * 0.01f), y - h * 0.035f), 2.dp.toPx())
                    drawLine(colors.primary.copy(alpha = 0.36f), Offset(w * 0.18f, y), Offset(w * (0.27f - i * 0.01f), y - h * 0.035f), 2.dp.toPx())
                }
            }
            BannerAction.Conversion -> {
                repeat(3) { i ->
                    drawRoundRect(
                        color = colors.primary.copy(alpha = 0.48f - i * 0.08f),
                        topLeft = Offset(w * (0.56f + i * 0.035f), h * (0.73f - i * 0.05f)),
                        size = Size(w * 0.30f, h * 0.075f),
                        cornerRadius = androidx.compose.ui.geometry.CornerRadius(9.dp.toPx(), 9.dp.toPx())
                    )
                }
            }
            BannerAction.Feedback -> {
                drawCircle(colors.primary.copy(alpha = 0.75f), radius = 5.dp.toPx(), center = Offset(w * 0.22f, h * 0.24f))
                drawCircle(colors.secondary.copy(alpha = 0.55f), radius = 4.dp.toPx(), center = Offset(w * 0.34f, h * 0.30f))
                drawCircle(colors.tertiary.copy(alpha = 0.45f), radius = 6.dp.toPx(), center = Offset(w * 0.49f, h * 0.24f))
            }
            BannerAction.Promotion -> {
                repeat(4) { i ->
                    val x = w * (0.18f + i * 0.10f)
                    drawRoundRect(
                        color = colors.primary.copy(alpha = 0.34f + i * 0.11f),
                        topLeft = Offset(x, h * (0.58f - i * 0.07f)),
                        size = Size(w * 0.06f, h * (0.20f + i * 0.07f)),
                        cornerRadius = androidx.compose.ui.geometry.CornerRadius(5.dp.toPx(), 5.dp.toPx())
                    )
                }
            }
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

fun CategoryPreviewCard(
    category: CategoryWithMetadata,
    onCategorySelected: (CategoryWithMetadata) -> Unit,
    onCategoryLongClick: (CategoryWithMetadata) -> Unit,
    modifier: Modifier = Modifier
) {
    val tokens = LocalMksDesignTokens.current
    val colors = MaterialTheme.colorScheme
    val haptic = LocalHapticFeedback.current
    val tint = category.color?.let { Color(it) } ?: colors.primary
    val displayIcon = category.emoji

    Surface(
        modifier = modifier
            .widthIn(min = 132.dp)
            .combinedClickable(
                onClick = { onCategorySelected(category) },
                onLongClick = {
                    if (!tokens.isPlain) haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                    onCategoryLongClick(category)
                }
            ),
        shape = RoundedCornerShape(tokens.cardRadius),
        color = colors.surfaceVariant.copy(alpha = 0.42f),
        border = BorderStroke(1.dp, colors.outline.copy(alpha = 0.10f)),
        shadowElevation = if (category.isPinned) tokens.cardElevation else 0.dp
    ) {
        Row(
            modifier = Modifier.padding(horizontal = 12.dp, vertical = 10.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            Surface(
                modifier = Modifier.size(42.dp),
                shape = RoundedCornerShape(tokens.chipRadius),
                color = tint.copy(alpha = 0.13f),
                contentColor = tint
            ) {
                Box(contentAlignment = Alignment.Center) {
                    if (!displayIcon.isNullOrBlank()) {
                        Text(displayIcon, style = MaterialTheme.typography.titleMedium)
                    } else {
                        Icon(Icons.Rounded.Category, contentDescription = null, modifier = Modifier.size(22.dp))
                    }
                }
            }
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = category.name,
                    style = MaterialTheme.typography.titleSmall,
                    fontWeight = FontWeight.SemiBold,
                    color = colors.onSurface
                )
                Text(
                    text = category.questionCount.toString(),
                    style = MaterialTheme.typography.labelMedium,
                    fontWeight = FontWeight.SemiBold,
                    color = tint
                )
            }
            if (category.isPinned) {
                Icon(Icons.Rounded.PushPin, contentDescription = null, modifier = Modifier.size(15.dp), tint = tint)
            }
        }
    }
}

private fun ColorScheme.onContainer(containerColor: Color): Color {
    return when (containerColor) {
        primaryContainer -> onPrimaryContainer
        secondaryContainer -> onSecondaryContainer
        tertiaryContainer -> onTertiaryContainer
        else -> onSurface
    }
}

@OptIn(ExperimentalFoundationApi::class)

fun BookItem(
    book: BookEntity,
    onClick: () -> Unit,
    onLongClick: () -> Unit,
    modifier: Modifier = Modifier,
    viewMode: String = "LIST",
    showCover: Boolean = true
) {
    val tokens = LocalMksDesignTokens.current
    val colors = MaterialTheme.colorScheme
    Card(
        modifier = modifier
            .fillMaxWidth()
            .padding(vertical = 4.dp)
            .combinedClickable(onClick = onClick, onLongClick = onLongClick),
        shape = RoundedCornerShape(tokens.cardRadius),
        colors = CardDefaults.cardColors(containerColor = colors.surface.copy(alpha = 0.96f)),
        border = BorderStroke(1.dp, colors.outline.copy(alpha = 0.11f)),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        if (viewMode == "GRID") {
            Column(modifier = Modifier.padding(13.dp)) {
                BookVisual(
                    title = book.title,
                    coverImage = book.coverImage,
                    isPinned = book.isPinned,
                    showCover = showCover,
                    modifier = Modifier
                        .fillMaxWidth()
                        .aspectRatio(1.05f)
                )
                Spacer(Modifier.height(12.dp))
                BookTextBlock(book = book, modifier = Modifier.fillMaxWidth(), isGrid = true)
                Spacer(Modifier.height(8.dp))
                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                    QuestionCountPill(count = book.questionCount)
                    IconButton(onClick = onLongClick, modifier = Modifier.size(34.dp)) {
                        Icon(Icons.Rounded.MoreVert, contentDescription = "More", tint = colors.onSurfaceVariant)
                    }
                }
            }
        } else {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(12.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(14.dp)
            ) {
                BookVisual(
                    title = book.title,
                    coverImage = book.coverImage,
                    isPinned = book.isPinned,
                    showCover = showCover,
                    modifier = Modifier.size(88.dp)
                )
                Column(modifier = Modifier.weight(1f)) {
                    BookTextBlock(book = book, modifier = Modifier.fillMaxWidth())
                    Spacer(Modifier.height(8.dp))
                    QuestionCountPill(count = book.questionCount)
                }
                IconButton(onClick = onLongClick, modifier = Modifier.size(38.dp)) {
                    Icon(Icons.Rounded.MoreVert, contentDescription = "More", tint = colors.onSurfaceVariant)
                }
            }
        }
    }
}

private fun BookTextBlock(book: BookEntity, modifier: Modifier = Modifier, isGrid: Boolean = false) {
    val colors = MaterialTheme.colorScheme
    Column(modifier = modifier) {
        Text(
            text = book.title,
            style = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
            color = colors.onSurface
        )
        if (isGrid || book.description.isNotBlank()) {
            Spacer(Modifier.height(3.dp))
            Text(
                text = book.description,
                style = MaterialTheme.typography.bodySmall,
                maxLines = 2,
                minLines = if (isGrid) 2 else 1,
                overflow = TextOverflow.Ellipsis,
                color = colors.onSurfaceVariant,
                lineHeight = 18.sp
            )
        }
    }
}

private fun QuestionCountPill(count: Int) {
    val colors = MaterialTheme.colorScheme
    Surface(
        shape = RoundedCornerShape(15.dp),
        color = colors.primary.copy(alpha = 0.10f),
        contentColor = colors.primary
    ) {
        Text(
            text = stringResource(R.string.questions_count, count),
            style = MaterialTheme.typography.labelMedium,
            modifier = Modifier.padding(horizontal = 10.dp, vertical = 5.dp),
            fontWeight = FontWeight.SemiBold,
            maxLines = 1
        )
    }
}

private fun BookVisual(
    title: String,
    coverImage: String?,
    isPinned: Boolean,
    showCover: Boolean,
    modifier: Modifier = Modifier
) {
    val colors = MaterialTheme.colorScheme
    val tokens = LocalMksDesignTokens.current
    Box(
        modifier = modifier
            .clip(RoundedCornerShape(20.dp))
            .then(
                if (tokens.useGradients) {
                    Modifier.background(
                        Brush.linearGradient(
                            listOf(
                                colors.primaryContainer.copy(alpha = 0.50f),
                                colors.surface.copy(alpha = 0.88f),
                                colors.secondaryContainer.copy(alpha = 0.26f)
                            )
                        )
                    )
                } else {
                    Modifier.background(colors.primaryContainer.copy(alpha = 0.2f))
                }
            )
            .border(1.dp, colors.outline.copy(alpha = 0.10f), RoundedCornerShape(20.dp)),
        contentAlignment = Alignment.Center
    ) {
        if (showCover && !coverImage.isNullOrBlank()) {
            AsyncImage(
                model = coverImage,
                contentDescription = title,
                contentScale = ContentScale.Crop,
                modifier = Modifier.fillMaxSize(),
                clipToBounds = true
            )
        } else {
            val brush = if (tokens.useGradients) {
                Brush.linearGradient(
                    listOf(
                        colors.primaryContainer.copy(alpha = 0.40f),
                        colors.secondaryContainer.copy(alpha = 0.30f),
                        colors.tertiaryContainer.copy(alpha = 0.20f)
                    )
                )
            } else {
                Brush.linearGradient(listOf(colors.primaryContainer.copy(alpha = 0.15f), colors.primaryContainer.copy(alpha = 0.15f)))
            }
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .background(brush),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = Icons.AutoMirrored.Rounded.MenuBook,
                    contentDescription = null,
                    tint = colors.primary.copy(alpha = 0.6f),
                    modifier = Modifier.size(42.dp)
                )
            }
        }
        if (isPinned) {
            Surface(
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(7.dp),
                shape = RoundedCornerShape(9.dp),
                color = colors.surface.copy(alpha = 0.88f)
            ) {
                Icon(
                    imageVector = Icons.Rounded.Bookmark,
                    contentDescription = "Pinned",
                    modifier = Modifier
                        .size(19.dp)
                        .padding(3.dp),
                    tint = colors.primary
                )
            }
        }
    }
}

