fun LibraryContentGrid(
    gridState: LazyGridState,
    columns: GridCells,
    padding: PaddingValues,
    selectedCategory: String?,
    resumeQuiz: QuizEntity?,
    recentQuizzes: List<QuizEntity>,
    currentThemeMode: String,
    onQuizClick: (Long) -> Unit,
    onLinkClick: (String) -> Unit,
    categoriesExpanded: Boolean,
    previewCategories: List<CategoryWithMetadata>,
    onCategorySelected: (String) -> Unit,
    onCategoryLongClick: (CategoryWithMetadata) -> Unit,
    showCategoryBrowser: () -> Unit,
    books: List<BookEntity>,
    quizzes: List<QuizEntity>,
    currentViewMode: String,
    showCovers: Boolean,
    onBookClick: (BookEntity) -> Unit,
    onBookLongClick: (BookEntity) -> Unit,
    onQuizLongClick: (QuizEntity) -> Unit,
) {
    LazyVerticalGrid(
        state = gridState,
        columns = columns,
        modifier = Modifier
            .padding(padding)
            .fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        horizontalArrangement = Arrangement.spacedBy(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp),
    ) {
        if (selectedCategory == null) {
            item(span = { GridItemSpan(maxLineSpan) }, key = "banner_header") {
                LibraryBanner(
                    resumeQuiz = resumeQuiz,
                    recentQuizzes = recentQuizzes,
                    currentThemeMode = currentThemeMode,
                    onQuizClick = { onQuizClick(it.id) },
                    onLinkClick = onLinkClick,
                )
            }



            item(span = { GridItemSpan(maxLineSpan) }, key = "categories_header") {
                CategoriesSection(
                    categoriesExpanded = categoriesExpanded,
                    previewCategories = previewCategories,
                    onCategorySelected = onCategorySelected,
                    onCategoryLongClick = onCategoryLongClick,
                    showCategoryBrowser = showCategoryBrowser,
                )
            }

            item(span = { GridItemSpan(maxLineSpan) }) {
                SectionHeader(
                    title = stringResource(R.string.books_header),
                )
            }

            if (books.isEmpty()) {
                item(span = { GridItemSpan(maxLineSpan) }, key = "empty_books") {
                    LibraryEmptyStateCard(
                        icon = Icons.AutoMirrored.Rounded.MenuBook,
                        title = stringResource(R.string.empty_books_title),
                        body = stringResource(R.string.empty_books_body),
                    )
                }
            } else {
                items(books, key = { "book_${it.id}" }) { book ->
                    BookItem(
                        book = book,
                        viewMode = currentViewMode,
                        showCover = showCovers,
                        onClick = { onBookClick(book) },
                        onLongClick = { onBookLongClick(book) },
                    )
                }
            }
        } else {
            if (quizzes.isEmpty()) {
                item(span = { GridItemSpan(maxLineSpan) }, key = "empty_quizzes") {
                    LibraryEmptyStateCard(
                        icon = Icons.AutoMirrored.Rounded.FactCheck,
                        title = stringResource(R.string.empty_quizzes_title),
                        body = stringResource(R.string.empty_quizzes_body),
                    )
                }
            } else {
                items(quizzes, key = { "quiz_${it.id}" }) { quiz ->
                    QuizItem(
                        quiz = quiz,
                        viewMode = currentViewMode,
                        showCover = showCovers,
                        onClick = { onQuizClick(quiz.id) },
                        onLongClick = { onQuizLongClick(quiz) },
                    )
                }
            }
        }
    }
}

private fun SectionHeader(title: String, subtitle: String? = null) {
    Column(modifier = Modifier.padding(top = 16.dp, bottom = 4.dp)) {
        Text(
            text = title,
            style = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
        )
        subtitle?.let {
            Text(
                text = it,
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
            )
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

private fun CategoriesSection(
    categoriesExpanded: Boolean,
    previewCategories: List<CategoryWithMetadata>,
    onCategorySelected: (String) -> Unit,
    onCategoryLongClick: (CategoryWithMetadata) -> Unit,
    showCategoryBrowser: () -> Unit,
) {
    val tokens = LocalMksDesignTokens.current
    val haptic = LocalHapticFeedback.current
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(26.dp))
            .background(MaterialTheme.colorScheme.surface.copy(alpha = 0.94f))
            .border(
                1.dp,
                MaterialTheme.colorScheme.outline.copy(alpha = 0.12f),
                RoundedCornerShape(26.dp),
            )
            .padding(16.dp),
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .combinedClickable(
                    onClick = showCategoryBrowser,
                    onLongClick = {
                        if (!tokens.isPlain) haptic.performHapticFeedback(HapticFeedbackType.LongPress)
                        showCategoryBrowser()
                    },
                ),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween,
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    stringResource(R.string.categories_header),
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                )
            }
            Row(verticalAlignment = Alignment.CenterVertically) {
                TextButton(onClick = showCategoryBrowser) {
                    Text(stringResource(R.string.view_all))
                }
            }
        }

        val tokens = LocalMksDesignTokens.current
        AnimatedVisibility(
            visible = categoriesExpanded && previewCategories.isNotEmpty(),
            enter = if (tokens.isPlain) fadeIn(snap()) else fadeIn() + expandVertically(),
            exit = if (tokens.isPlain) fadeOut(snap()) else fadeOut() + shrinkVertically(),
        ) {
            Column(modifier = Modifier.fillMaxWidth()) {
                Spacer(Modifier.height(10.dp))
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                ) {
                    previewCategories.forEach { category ->
                        CategoryPreviewCard(
                            category = category,
                            onCategorySelected = { onCategorySelected(it.name) },
                            onCategoryLongClick = { onCategoryLongClick(category) },
                        )
                    }
                }
            }
        }
    }
}

private fun LibraryEmptyStateCard(
    icon: ImageVector,
    title: String,
    body: String,
    modifier: Modifier = Modifier,
) {
    val colors = MaterialTheme.colorScheme
    Card(
        modifier = modifier.fillMaxWidth(),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = colors.surface.copy(alpha = 0.90f)),
        border = androidx.compose.foundation.BorderStroke(1.dp, colors.outline.copy(alpha = 0.14f)),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp),
    ) {
        Row(
            modifier = Modifier.padding(18.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(14.dp),
        ) {
            Surface(
                shape = RoundedCornerShape(18.dp),
                color = colors.primary.copy(alpha = 0.10f),
                contentColor = colors.primary,
            ) {
                Icon(icon, contentDescription = null, modifier = Modifier
                    .padding(14.dp)
                    .size(30.dp))
            }
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    title,
                    style = MaterialTheme.typography.titleMedium,
                    fontWeight = FontWeight.Bold,
                )
                Spacer(Modifier.height(4.dp))
                Text(
                    body,
                    style = MaterialTheme.typography.bodyMedium,
                    color = colors.onSurfaceVariant,
                )
            }
        }
    }
}

fun LibraryTopBar(
    scrollBehavior: TopAppBarScrollBehavior,
    isSearching: Boolean,
    searchQuery: String,
    onSearchQueryChange: (String) -> Unit,
    selectedBookId: Long,
    selectedCategory: String?,
    currentBookTitle: String?,
    onNavigationClick: () -> Unit,
    onSearchClick: () -> Unit,
    onSettingsClick: () -> Unit,
    onSortClick: () -> Unit,
    currentViewMode: String,
    onToggleViewMode: () -> Unit,
    showOverflowMenu: Boolean,
    onOverflowMenuToggle: (Boolean) -> Unit,
    onContactClick: () -> Unit,
    onWorkspaceManagerClick: () -> Unit,
    onTrashBinClick: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    MediumTopAppBar(
        scrollBehavior = scrollBehavior,
        title = {
            if (isSearching) {
                OutlinedTextField(
                    value = searchQuery,
                    onValueChange = onSearchQueryChange,
                    placeholder = { Text(stringResource(R.string.search_placeholder)) },
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(end = 16.dp),
                    singleLine = true,
                    shape = RoundedCornerShape(tokens.chipRadius),
                    leadingIcon = { Icon(Icons.Rounded.Search, null) },
                    trailingIcon = if (searchQuery.isNotEmpty()) {
                        {
                            IconButton(onClick = { onSearchQueryChange("") }) {
                                Icon(Icons.Rounded.Close, null)
                            }
                        }
                    } else null,
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.5f),
                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.3f),
                        focusedContainerColor = MaterialTheme.colorScheme.surface,
                        unfocusedContainerColor = MaterialTheme.colorScheme.surface,
                    )
                )
            } else {
                Text(
                    text = when {
                        selectedBookId != -1L -> currentBookTitle ?: stringResource(R.string.quizzes_title)
                        selectedCategory != null -> stringResource(R.string.category_title_prefix, selectedCategory)
                        else -> stringResource(R.string.mks_library_title)
                    },
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
            }
        },
        navigationIcon = {
            if (selectedBookId != -1L || selectedCategory != null || isSearching) {
                IconButton(onClick = onNavigationClick) {
                    Icon(
                        Icons.AutoMirrored.Rounded.ArrowBack,
                        contentDescription = stringResource(R.string.cancel)
                    )
                }
            } else {
                Box(Modifier.size(48.dp))
            }
        },
        actions = {
            if (!isSearching) {
                IconButton(onClick = onContactClick) {
                    Icon(Icons.Rounded.SupportAgent, contentDescription = "Contact")
                }
                Box {
                    IconButton(onClick = { onOverflowMenuToggle(true) }) {
                        Icon(Icons.Rounded.MoreVert, contentDescription = stringResource(R.string.settings_title))
                    }
                    DropdownMenu(
                        expanded = showOverflowMenu,
                        onDismissRequest = { onOverflowMenuToggle(false) }
                    ) {
                        DropdownMenuItem(
                            text = { Text(stringResource(R.string.sort)) },
                            leadingIcon = { Icon(Icons.AutoMirrored.Rounded.Sort, null) },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onSortClick()
                            }
                        )
                        DropdownMenuItem(
                            text = { Text(if (currentViewMode == "GRID") stringResource(R.string.list_view_label) else stringResource(R.string.grid_view_label)) },
                            leadingIcon = {
                                Icon(
                                    if (currentViewMode == "GRID") Icons.AutoMirrored.Rounded.ViewList else Icons.Rounded.GridView,
                                    null
                                )
                            },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onToggleViewMode()
                            }
                        )
                        DropdownMenuItem(
                            text = { Text(stringResource(R.string.search)) },
                            leadingIcon = { Icon(Icons.Rounded.Search, null) },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onSearchClick()
                            }
                        )
                        DropdownMenuItem(
                            text = { Text(stringResource(R.string.settings_title)) },
                            leadingIcon = { Icon(Icons.Rounded.Settings, null) },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onSettingsClick()
                            }
                        )
                        DropdownMenuItem(
                            text = { Text("Workspaces") },
                            leadingIcon = { Icon(Icons.Rounded.Workspaces, null) },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onWorkspaceManagerClick()
                            }
                        )
                        DropdownMenuItem(
                            text = { Text("Trash Bin") },
                            leadingIcon = { Icon(Icons.Rounded.Delete, null) },
                            onClick = {
                                onOverflowMenuToggle(false)
                                onTrashBinClick()
                            }
                        )
                    }
                }
            }
        },
        colors = TopAppBarDefaults.mediumTopAppBarColors(
            containerColor = MaterialTheme.colorScheme.background,
            scrolledContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.8f)
        )
    )
}

fun SortDialog(
    currentOption: SortOption,
    onOptionSelected: (SortOption) -> Unit,
    onDismiss: () -> Unit
) {
    val options = listOf(
        SortOption.TITLE to stringResource(R.string.sort_title_name),
        SortOption.LAST_EDIT to stringResource(R.string.sort_last_edit),
        SortOption.LAST_STUDIED to stringResource(R.string.sort_last_studied),
        SortOption.QUESTION_COUNT to stringResource(R.string.sort_question_count),
        SortOption.PROGRESS to stringResource(R.string.sort_progress),
        SortOption.ACCURACY to stringResource(R.string.sort_accuracy)
    )

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.sort_by_title)) },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .selectableGroup(),
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                options.forEach { (option, label) ->
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(56.dp)
                            .selectable(
                                selected = currentOption == option,
                                onClick = { onOptionSelected(option) },
                                role = Role.RadioButton
                            )
                            .padding(horizontal = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        RadioButton(
                            selected = currentOption == option,
                            onClick = null // Selected handled by Row
                        )
                        Spacer(modifier = Modifier.width(16.dp))
                        Text(
                            text = label,
                            style = MaterialTheme.typography.bodyLarge
                        )
                    }
                }
            }
        },
        confirmButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

fun LibraryFabMenu(
    fabExpanded: Boolean,
    onFabExpandedChange: (Boolean) -> Unit,
    selectedCategory: String?,
    onAdaptiveSelected: (String, String) -> Unit,
    onNewBookClick: () -> Unit,
    onImportClick: () -> Unit,
    onExportClick: () -> Unit
) {
    Column(horizontalAlignment = Alignment.End) {
        AnimatedVisibility(
            visible = fabExpanded,
            enter = fadeIn() + expandVertically(expandFrom = Alignment.Bottom),
            exit = fadeOut() + shrinkVertically(shrinkTowards = Alignment.Bottom)
        ) {
            Column(horizontalAlignment = Alignment.End) {
                SmallFloatingActionButton(
                    onClick = {
                        onFabExpandedChange(false)
                        val type = if (selectedCategory != null) "CATEGORY" else "ALL"
                        val id = selectedCategory ?: "0"
                        onAdaptiveSelected(type, id)
                    },
                    modifier = Modifier.padding(bottom = 8.dp)
                ) {
                    FabActionRow(Icons.Rounded.Psychology, stringResource(R.string.adaptive_training))
                }

                if (selectedCategory == null) {
                    SmallFloatingActionButton(
                        onClick = {
                            onFabExpandedChange(false)
                            onNewBookClick()
                        },
                        modifier = Modifier.padding(bottom = 8.dp)
                    ) {
                        FabActionRow(Icons.AutoMirrored.Rounded.MenuBook, stringResource(R.string.new_book))
                    }
                }

                SmallFloatingActionButton(
                    onClick = {
                        onFabExpandedChange(false)
                        onImportClick()
                    },
                    modifier = Modifier.padding(bottom = 8.dp)
                ) {
                    FabActionRow(Icons.Rounded.FileDownload, stringResource(R.string.import_label))
                }

                SmallFloatingActionButton(
                    onClick = {
                        onFabExpandedChange(false)
                        onExportClick()
                    },
                    modifier = Modifier.padding(bottom = 8.dp)
                ) {
                    FabActionRow(Icons.Rounded.FileUpload, stringResource(R.string.export_label))
                }
            }
        }

        FloatingActionButton(
            onClick = { onFabExpandedChange(!fabExpanded) },
            containerColor = MaterialTheme.colorScheme.primaryContainer,
            contentColor = MaterialTheme.colorScheme.onPrimaryContainer
        ) {
            Icon(
                if (fabExpanded) Icons.Rounded.Close else Icons.Rounded.Add,
                contentDescription = stringResource(R.string.app_name)
            )
        }
    }
}

private fun FabActionRow(icon: androidx.compose.ui.graphics.vector.ImageVector, label: String) {
    Row(
        modifier = Modifier.padding(horizontal = 12.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Icon(icon, null)
        Spacer(Modifier.width(8.dp))
        Text(label)
    }
}

fun DeleteConfirmDialog(
    title: String,
    message: String,
    onDismiss: () -> Unit,
