private fun LanguagePill(text: String, selected: Boolean, onClick: () -> Unit) {
    val colors = MaterialTheme.colorScheme
    val tokens = LocalMksDesignTokens.current
    val pillShape = RoundedCornerShape(tokens.chipRadius)
    Surface(
        modifier = Modifier
            .height(26.dp)
            .width(if (text == "EN") 42.dp else 66.dp)
            .clip(pillShape)
            .clickable(onClick = onClick),
        shape = pillShape,
        color = if (selected) colors.primary.copy(alpha = 0.16f) else Color.Transparent,
        contentColor = if (selected) colors.onSurface else colors.onSurfaceVariant,
        border = if (selected) null else BorderStroke(1.dp, colors.outline.copy(alpha = 0.18f))
    ) {
        Box(contentAlignment = Alignment.Center) {
            Text(
                text = text,
                style = MaterialTheme.typography.labelSmall,
                fontWeight = if (selected) FontWeight.SemiBold else FontWeight.Medium
            )
        }
    }
}

fun GlobalSearchScreen(
    viewModel: GlobalSearchViewModel,
    onBack: () -> Unit,
    onOpenRoute: (Any) -> Unit
) {
    val state by viewModel.state.collectAsState()
    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Global Search") },
                navigationIcon = { IconButton(onClick = onBack) { Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back") } }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            OutlinedTextField(
                value = state.query,
                onValueChange = viewModel::onQueryChanged,
                modifier = Modifier.fillMaxWidth(),
                label = { Text("Search books, questions, notes, assets...") },
                leadingIcon = { Icon(Icons.Default.Search, contentDescription = null) },
                singleLine = true
            )
            LoadingErrorState(state.isLoading, state.error) { viewModel.search() }
            if (state.query.trim().length < 2) {
                EmptyStateCard("Search MKS", "Type at least two characters to search across books, quizzes, questions, assets, sources, flashcards, blueprints, prompts, and mistakes.")
            } else if (!state.isLoading && state.results.isEmpty() && state.error == null) {
                EmptyStateCard("No results", "No matching learning material was found.")
            } else {
                LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    items(state.results, key = { it.type.name + it.id }) { result ->
                        SearchResultCard(result, onOpenRoute)
                    }
                }
            }
        }
    }
}

private fun SearchResultCard(result: GlobalSearchResult, onOpenRoute: (Any) -> Unit) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(enabled = result.route != null) { result.route?.let(onOpenRoute) }
    ) {
        Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                Text(result.type.name.replace('_', ' '), style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.primary)
                Text(result.title, style = MaterialTheme.typography.titleSmall, modifier = Modifier.weight(1f))
            }
            if (!result.subtitle!!.isNullOrBlank()) Text(result.subtitle!!, style = MaterialTheme.typography.bodySmall)
            if (!result.snippet!!.isNullOrBlank()) Text(result.snippet!!.take(180), style = MaterialTheme.typography.bodySmall)
        }
    }
}

class GlobalSearchViewModel @Inject constructor(private val repository: GlobalSearchRepository) : ViewModel() {
    private val _state = MutableStateFlow(GlobalSearchUiState())
    val state: StateFlow<GlobalSearchUiState> = _state.asStateFlow()
    private var searchJob: Job? = null

fun onQueryChanged(query: String) {
        _state.update { it.copy(query = query) }
        searchJob?.cancel()
        searchJob = viewModelScope.launch {
            delay(250)
            search(query)
        }
    }

fun search(query: String = _state.value.query) {
        searchJob?.cancel()
        searchJob = viewModelScope.launch {
            if (query.trim().length < 2) {
                _state.update { it.copy(isLoading = false, results = emptyList(), error = null) }
                return@launch
            }
            _state.update { it.copy(isLoading = true, error = null) }
            runCatching { repository.search(query) }
                .onSuccess { results -> _state.update { it.copy(isLoading = false, results = results) } }
                .onFailure { error -> _state.update { it.copy(isLoading = false, error = error.message ?: "Search failed") } }
        }
    }
}

data class ReviewDashboardUiState(
    val isLoading: Boolean = true,
    val summary: ReviewDashboardSummary = ReviewDashboardSummary(),
    val knowledgeSummary: KnowledgeSummary? = null,
    val queue: List<ReviewQueueItem> = emptyList(),
    val error: String? = null
)

@OptIn(ExperimentalCoroutinesApi::class)
@HiltViewModel

class ReviewDashboardViewModel @Inject constructor(
    private val repository: ReviewRepository,
    private val dataStoreManager: DataStoreManager,
    private val bookRepository: BookRepository,
    private val assetRepository: AssetRepository,
    private val studyRepository: StudyRepository
) : ViewModel() {
    private val _state = MutableStateFlow(ReviewDashboardUiState())
    val state: StateFlow<ReviewDashboardUiState> = _state.asStateFlow()

    val currentWorkspaceId = dataStoreManager.currentWorkspaceId
        .map { storedId -> storedId ?: assetRepository.getOrCreateDefaultWorkspace().id }
        .stateIn(viewModelScope, SharingStarted.Eagerly, 0L)

    val annotations = currentWorkspaceId.flatMapLatest { wsId ->
        if (wsId <= 0L) flowOf(emptyList()) else studyRepository.getAnnotationsByWorkspaceId(wsId)
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    val mistakes = currentWorkspaceId.flatMapLatest { wsId ->
        if (wsId <= 0L) flowOf(emptyList()) else studyRepository.getAllMistakes().map { list ->
            val bookIds = bookRepository.getBooksByWorkspace(wsId, SortOption.TITLE).first().map { it.id }.toSet()
            list.filter { it.bookId in bookIds && it.deletedAt == null }
        }
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    init { refresh() }

fun refresh() {
        viewModelScope.launch {
            _state.update { it.copy(isLoading = true, error = null) }
            runCatching {
                val summary = repository.loadSummary()
                val knowledgeSummary = studyRepository.getLibraryKnowledgeSummary()
                val queue = repository.loadQueues()
                Triple(summary, knowledgeSummary, queue)
            }.onSuccess { (summary, knowledgeSummary, queue) ->
                _state.update { it.copy(isLoading = false, summary = summary, knowledgeSummary = knowledgeSummary, queue = queue) }
            }.onFailure { error ->
                _state.update { it.copy(isLoading = false, error = error.message ?: "Could not load review dashboard") }
            }
        }
    }

fun markReviewed(item: ReviewQueueItem) {
        viewModelScope.launch {
            runCatching { repository.markReviewed(item) }
            refresh()
        }
    }

fun snoozeOneWeek(item: ReviewQueueItem) {
        viewModelScope.launch {
            runCatching { repository.snooze(item, 7L * 24L * 60L * 60L * 1000L) }
            refresh()
        }
    }

fun snoozeCustom(item: ReviewQueueItem, delayMillis: Long) {
        viewModelScope.launch {
            runCatching { repository.snooze(item, delayMillis) }
            refresh()
        }
    }

fun snoozeMistake(mistakeId: Long, snoozeTime: Long) {
        viewModelScope.launch {
            runCatching { studyRepository.snoozeMistake(mistakeId, snoozeTime) }
            refresh()
        }
    }

fun markMistakeFixed(mistakeId: Long) {
        viewModelScope.launch {
            runCatching { studyRepository.markMistakeFixed(mistakeId) }
            refresh()
        }
    }

fun deleteMistake(entry: MistakeLogEntryEntity) {
        viewModelScope.launch {
            runCatching { studyRepository.deleteMistake(entry) }
            refresh()
        }
    }

fun updateAnnotation(annotation: AnnotationEntity) {
        viewModelScope.launch {
            runCatching { studyRepository.updateAnnotation(annotation) }
        }
    }

fun deleteAnnotation(annotationId: Long) {
        viewModelScope.launch {
            runCatching { assetRepository.softDeleteAnnotation(annotationId) }
        }
    }
}

fun ReviewDashboardScreen(
    viewModel: ReviewDashboardViewModel,
    focusedMistakeId: Long? = null,
    onBack: () -> Unit,
    onOpenRoute: (Any) -> Unit
) {
    val state by viewModel.state.collectAsState()
    val annotations by viewModel.annotations.collectAsState(initial = emptyList())
    val mistakes by viewModel.mistakes.collectAsState(initial = emptyList())

    var selectedTab by remember { mutableStateOf(ReviewTab.QUEUE) }
    var itemToSnooze by remember { mutableStateOf<Any?>(null) } // Can be ReviewQueueItem or MistakeLogEntryEntity
    var editingAnnotation by remember { mutableStateOf<AnnotationEntity?>(null) }

    val dateFormat = remember { SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.getDefault()) }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Review Dashboard") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            TabRow(
                selectedTabIndex = selectedTab.ordinal,
                modifier = Modifier.fillMaxWidth()
            ) {
                ReviewTab.values().forEach { tab ->
                    Tab(
                        selected = selectedTab == tab,
                        onClick = { selectedTab = tab },
                        text = { Text(tab.title) }
                    )
                }
            }

            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .weight(1f)
                    .padding(16.dp)
            ) {
                when (selectedTab) {
                    ReviewTab.QUEUE -> {
                        LazyColumn(
                            verticalArrangement = Arrangement.spacedBy(10.dp),
                            modifier = Modifier.fillMaxSize()
                        ) {
                            item { LoadingErrorState(state.isLoading, state.error, viewModel::refresh) }
                            state.knowledgeSummary?.let { summary ->
                                item { KnowledgeSummaryCard(summary) }
                            }
                            if (!state.isLoading && state.queue.isEmpty()) {
                                item { EmptyStateCard("No due reviews", "There are no due review items right now.") }
                            } else {
                                items(state.queue, key = { it.type.name + it.id }) { item ->
                                    ReviewQueueCard(
                                        item = item,
                                        onMarkReviewed = { viewModel.markReviewed(item) },
                                        onSnoozeOneWeek = { viewModel.snoozeOneWeek(item) },
                                        onSnoozeCustom = { itemToSnooze = item },
                                        onOpenRoute = onOpenRoute
                                    )
                                }
                            }
                        }
                    }
                    ReviewTab.MISTAKES -> {
                        if (mistakes.isEmpty()) {
                            EmptyStateCard("No mistakes logged", "Mistakes made during quizzes will appear here.")
                        } else {
                            LazyColumn(
                                verticalArrangement = Arrangement.spacedBy(10.dp),
                                modifier = Modifier.fillMaxSize()
                            ) {
                                items(mistakes, key = { it.id }) { mistake ->
                                    MistakeCard(
                                        mistake = mistake,
                                        dateFormat = dateFormat,
                                        onToggleFixed = { viewModel.markMistakeFixed(mistake.id) },
                                        onSnooze = { itemToSnooze = mistake },
                                        onDelete = { viewModel.deleteMistake(mistake) }
                                    )
                                }
                            }
                        }
                    }
                    ReviewTab.ANNOTATIONS -> {
                        if (annotations.isEmpty()) {
                            EmptyStateCard("No annotations found", "Highlights and margin notes will show up here.")
                        } else {
                            LazyColumn(
                                verticalArrangement = Arrangement.spacedBy(10.dp),
                                modifier = Modifier.fillMaxSize()
                            ) {
                                items(annotations, key = { it.id }) { annotation ->
                                    AnnotationCard(
                                        annotation = annotation,
                                        onEdit = { editingAnnotation = annotation },
                                        onDelete = { viewModel.deleteAnnotation(annotation.id) }
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Custom Date Picker Dialog for custom snooze
    if (itemToSnooze != null) {
        CustomDatePickerDialog(
            onDismiss = { itemToSnooze = null },
            onDateSelected = { selectedDateMillis ->
                val delay = (selectedDateMillis - System.currentTimeMillis()).coerceAtLeast(0L)
                when (val item = itemToSnooze) {
                    is ReviewQueueItem -> viewModel.snoozeCustom(item, delay)
                    is MistakeLogEntryEntity -> viewModel.snoozeMistake(item.id, selectedDateMillis)
                }
                itemToSnooze = null
            }
        )
    }

    // Annotation Edit Dialog
    editingAnnotation?.let { annotation ->
        var noteBody by remember { mutableStateOf(annotation.noteBody ?: "") }

        AlertDialog(
            onDismissRequest = { editingAnnotation = null },
            title = { Text("Edit Margin Note") },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    if (!annotation.selectedText.isNullOrBlank()) {
                        Text(
                            text = "Reference Text:",
                            style = MaterialTheme.typography.labelMedium,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "\"${annotation.selectedText}\"",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                    OutlinedTextField(
                        value = noteBody,
                        onValueChange = { noteBody = it },
                        label = { Text("Note body") },
                        modifier = Modifier.fillMaxWidth()
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.updateAnnotation(annotation.copy(noteBody = noteBody.trim().takeIf { it.isNotBlank() }))
                        editingAnnotation = null
                    }
                ) {
                    Text("Save")
                }
            },
            dismissButton = {
                TextButton(onClick = { editingAnnotation = null }) {
                    Text("Cancel")
                }
            }
        )
    }
}

private fun ReviewQueueCard(
    item: ReviewQueueItem,
    onMarkReviewed: () -> Unit,
    onSnoozeOneWeek: () -> Unit,
    onSnoozeCustom: () -> Unit,
    onOpenRoute: (Any) -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(enabled = item.route != null) { item.route?.let(onOpenRoute) }
    ) {
        Column(
            modifier = Modifier.padding(12.dp),
            verticalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            Text(
                text = item.type.name.replace('_', ' '),
                style = MaterialTheme.typography.labelSmall,
                color = MaterialTheme.colorScheme.primary
            )
            Text(item.title, style = MaterialTheme.typography.titleSmall)
            if (!item.subtitle.isNullOrBlank()) {
                Text(item.subtitle!!, style = MaterialTheme.typography.bodySmall)
            }
            Row(
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                TextButton(onClick = onMarkReviewed) { Text("Reviewed") }
                TextButton(onClick = onSnoozeOneWeek) { Text("Snooze 1 week") }
                IconButton(onClick = onSnoozeCustom) {
                    Icon(
                        Icons.Default.Event,
                        contentDescription = "Snooze Custom",
                        tint = MaterialTheme.colorScheme.primary
                    )
                }
            }
        }
    }
}

fun MistakeCard(
    mistake: MistakeLogEntryEntity,
    dateFormat: SimpleDateFormat,
    onToggleFixed: () -> Unit,
    onSnooze: () -> Unit,
    onDelete: () -> Unit
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(
            modifier = Modifier.padding(12.dp),
            verticalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = if (mistake.isFixed) "FIXED" else "OPEN MISTAKE",
                    style = MaterialTheme.typography.labelSmall,
                    color = if (mistake.isFixed) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.error,
                    fontWeight = FontWeight.Bold
                )
                IconButton(onClick = onDelete) {
                    Icon(
                        Icons.Default.Delete,
                        contentDescription = "Delete Mistake",
                        tint = MaterialTheme.colorScheme.error
                    )
                }
            }

            if (!mistake.correctConcept.isNullOrBlank()) {
                Text(
                    text = mistake.correctConcept!!,
                    style = MaterialTheme.typography.titleSmall,
                    fontWeight = FontWeight.Bold
                )
            }

            if (!mistake.userReason.isNullOrBlank()) {
                Text(
                    text = "User Reason: ${mistake.userReason}",
                    style = MaterialTheme.typography.bodySmall
                )
            }

            if (!mistake.preventionNote.isNullOrBlank()) {
                Text(
                    text = "Prevention Note: ${mistake.preventionNote}",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            if (mistake.selectedAnswer != null || mistake.correctAnswer != null) {
                Text(
                    text = "Answer: ${mistake.selectedAnswer ?: "N/A"} (Correct: ${mistake.correctAnswer ?: "N/A"})",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            if (mistake.reviewAt != null) {
                Text(
                    text = "Review scheduled: ${dateFormat.format(Date(mistake.reviewAt!!))}",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.primary
                )
            }

            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                TextButton(onClick = onToggleFixed) {
                    Text(if (mistake.isFixed) "Reopen" else "Mark Fixed")
                }
                TextButton(onClick = onSnooze) {
                    Text("Snooze Custom")
                }
            }
        }
    }
}

private fun AnnotationCard(
    annotation: AnnotationEntity,
    onEdit: () -> Unit,
    onDelete: () -> Unit
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(
            modifier = Modifier.padding(12.dp),
            verticalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "Margin Note (${annotation.ownerType})",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.primary,
                    fontWeight = FontWeight.Bold
                )
                Row {
                    IconButton(onClick = onEdit) {
                        Icon(
                            Icons.Default.Edit,
                            contentDescription = "Edit Note",
                            tint = MaterialTheme.colorScheme.primary
                        )
                    }
                    IconButton(onClick = onDelete) {
                        Icon(
                            Icons.Default.Delete,
                            contentDescription = "Delete Annotation",
                            tint = MaterialTheme.colorScheme.error
                        )
                    }
                }
            }

            if (!annotation.selectedText.isNullOrBlank()) {
                Text(
                    text = "\"${annotation.selectedText}\"",
                    style = MaterialTheme.typography.bodyMedium,
