fun DataToolsScreen(
    viewModel: DataToolsViewModel,
    onBack: () -> Unit
) {
    val state by viewModel.state.collectAsState()
    val context = LocalContext.current

    val exportLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.CreateDocument("application/zip")
    ) { uri ->
        uri?.let {
            context.contentResolver.openOutputStream(it)?.use { stream ->
                viewModel.exportFullLibrary(stream)
            }
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Import / Export") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(
                            Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = "Back"
                        )
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Text("Full Library Export", style = MaterialTheme.typography.titleMedium)
            Text("Creates a Schema 7 complete ZIP backup of your library, including all embedded media and metadata.")
            Button(
                onClick = { 
                    val timestamp = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.getDefault()).format(java.util.Date())
                    exportLauncher.launch("mks_full_library_$timestamp.zip") 
                }, 
                enabled = !state.isWorking
            ) { 
                Text("Export full library") 
            }

            LoadingErrorState(state.isWorking, state.error)
            state.message?.let { Text(it, style = MaterialTheme.typography.bodySmall) }

            Text("Importing", style = MaterialTheme.typography.titleMedium, modifier = Modifier.padding(top = 16.dp))
            Text("To import a library backup, please use the '+' menu on the main Library Screen.")
        }
    }
}

data class DataToolsUiState(
    val isWorking: Boolean = false,
    val message: String? = null,
    val error: String? = null
)

@HiltViewModel

class DataToolsViewModel @Inject constructor(
    private val exportManager: com.ahmedyejam.mks.data.repository.ExportManager
) : ViewModel() {
    private val _state = MutableStateFlow(DataToolsUiState())
    val state: StateFlow<DataToolsUiState> = _state.asStateFlow()

fun exportFullLibrary(outputStream: java.io.OutputStream) {
        viewModelScope.launch {
            _state.update { it.copy(isWorking = true, error = null, message = null) }
            val result = exportManager.exportAllToZip(outputStream)
            _state.update {
                it.copy(
                    isWorking = false,
                    message = if (result.success) "Export completed successfully." else null,
                    error = if (!result.success) result.errorMessage else null
                )
            }
        }
    }
}

class ScannerViewModel @Inject constructor(
    private val knowledgeRepository: KnowledgeRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<ScannerUiState>(ScannerUiState.Idle)
    val uiState = _uiState.asStateFlow()

    private val recognizer = TextRecognition.getClient(TextRecognizerOptions.DEFAULT_OPTIONS)

fun onImageCaptured(bitmap: Bitmap, quizId: Long) {
        if (_uiState.value is ScannerUiState.Processing) return

        viewModelScope.launch {
            _uiState.value = ScannerUiState.Processing
            try {
                val image = InputImage.fromBitmap(bitmap, 0)
                val visionText = recognizer.process(image).await()

                val recognizedText = visionText.text
                if (recognizedText.isBlank()) {
                    _uiState.value = ScannerUiState.Error("No text detected. Please ensure the camera is focused on the text.")
                    return@launch
                }

                val questions = withContext(Dispatchers.Default) {
                    parseTextToQuestions(recognizedText, quizId)
                }
                if (questions.isEmpty()) {
                    _uiState.value = ScannerUiState.Error("Could not parse any questions from the text.")
                } else {
                    _uiState.value = ScannerUiState.Success(questions)
                }
            } catch (e: Exception) {
                _uiState.value = ScannerUiState.Error(e.message ?: "Unknown error during text recognition")
            }
        }
    }

private fun parseTextToQuestions(text: String, quizId: Long): List<QuestionEntity> {
        val lines = text.lines().map { it.trim() }.filter { it.isNotBlank() }
        val questions = mutableListOf<QuestionEntity>()

        var currentQuestionText = ""
        var currentOptions = mutableListOf<String>()
        var currentCorrectAnswers = mutableListOf<Int>()

        // Regex to match question starts like "1.", "1)", "Q1:", "Question 1:"
        val questionStartRegex = Regex("""^(?:Q(?:uestion)?\s*)?(\d+)[\.\)\:]\s+(.*)""", RegexOption.IGNORE_CASE)
        // Regex to match option starts like "A.", "a)", "1.", "(1)"
        val optionStartRegex = Regex("""^([\*])?\s*([A-Ea-e]|[1-5])[\.\)\-\s]\s*(.*)""")
        val bulletOptionRegex = Regex("""^([\*])?\s*[\-\•]\s+(.*)""")

        for (line in lines) {
            val qMatch = questionStartRegex.find(line)
            if (qMatch != null) {
                if (currentQuestionText.isNotBlank()) {
                    questions.add(createQuestion(quizId, currentQuestionText, currentOptions, currentCorrectAnswers))
                }
                currentQuestionText = qMatch.groupValues[2]
                currentOptions = mutableListOf()
                currentCorrectAnswers = mutableListOf()
                continue
            }

            val oMatch = optionStartRegex.find(line) ?: bulletOptionRegex.find(line)
            if (oMatch != null) {
                val isCorrectMarked = oMatch.groupValues[1] == "*"
                val optionContent = if (oMatch.groupValues.size > 2) {
                    if (oMatch.groupValues.size > 3) oMatch.groupValues[3] else oMatch.groupValues[2]
                } else ""

                if (isCorrectMarked) {
                    currentCorrectAnswers.add(currentOptions.size)
                }
                currentOptions.add(optionContent)
                continue
            }

            if (currentOptions.isEmpty()) {
                currentQuestionText = if (currentQuestionText.isEmpty()) line else "$currentQuestionText $line"
            } else {
                val lastIdx = currentOptions.size - 1
                currentOptions[lastIdx] = "${currentOptions[lastIdx]} $line"
            }
        }

        if (currentQuestionText.isNotBlank()) {
            questions.add(createQuestion(quizId, currentQuestionText, currentOptions, currentCorrectAnswers))
        }

        if (questions.isEmpty() && text.isNotBlank()) {
            val blocks = text.split("\n\n").filter { it.isNotBlank() }
            return blocks.map { block ->
                val blockLines = block.lines().map { it.trim() }.filter { it.isNotBlank() }
                createQuestion(quizId, blockLines.firstOrNull() ?: "Empty Question", blockLines.drop(1), emptyList())
            }
        }

        return questions
    }

private fun createQuestion(quizId: Long, text: String, options: List<String>, correctAnswers: List<Int>): QuestionEntity {
        val finalOptions = if (options.isEmpty()) listOf("Option A", "Option B") else options.map { it.trim() }
        val finalCorrect = if (correctAnswers.isEmpty()) listOf(0) else correctAnswers.filter { it < finalOptions.size }
        return QuestionEntity(
            externalId = java.util.UUID.randomUUID().toString(),
            quizId = quizId,
            text = text.trim(),
            type = if (finalCorrect.size > 1) QuestionType.MULTIPLE_CHOICE else QuestionType.SINGLE_CHOICE,
            options = finalOptions,
            correctAnswers = finalCorrect,
            explanation = "Imported from camera"
        )
    }

fun updateQuestion(index: Int, updatedQuestion: QuestionEntity) {
        val currentState = _uiState.value
        if (currentState is ScannerUiState.Success) {
            val updatedList = currentState.questions.toMutableList()
            updatedList[index] = updatedQuestion
            _uiState.value = ScannerUiState.Success(updatedList)
        }
    }

fun deleteQuestion(index: Int) {
        val currentState = _uiState.value
        if (currentState is ScannerUiState.Success) {
            val updatedList = currentState.questions.toMutableList()
            updatedList.removeAt(index)
            if (updatedList.isEmpty()) _uiState.value = ScannerUiState.Idle
            else _uiState.value = ScannerUiState.Success(updatedList)
        }
    }

fun saveQuestions(questions: List<QuestionEntity>) {
        viewModelScope.launch {
            knowledgeRepository.insertQuestions(questions)
            _uiState.value = ScannerUiState.Saved
        }
    }

fun reset() {
        _uiState.value = ScannerUiState.Idle
    }

override fun onCleared() {
        super.onCleared()
        recognizer.close()
    }
}

fun ScannerScreen(
    quizId: Long,
    viewModel: ScannerViewModel,
    onNavigateBack: () -> Unit
) {
    val uiState by viewModel.uiState.collectAsState()
    val cameraPermissionState = rememberPermissionState(Manifest.permission.CAMERA)

    LaunchedEffect(Unit) {
        if (!cameraPermissionState.status.isGranted) {
            cameraPermissionState.launchPermissionRequest()
        }
    }

    val context = LocalContext.current
    val cameraExecutor: ExecutorService = remember { Executors.newSingleThreadExecutor() }

    DisposableEffect(Unit) {
        onDispose {
            cameraExecutor.shutdown()
        }
    }

    val imageCapture: ImageCapture = remember { ImageCapture.Builder().build() }

    LaunchedEffect(uiState) {
        if (uiState is ScannerUiState.Saved) {
            onNavigateBack()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.scan_questions_title)) },
                navigationIcon = {
                    IconButton(onClick = onNavigateBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = stringResource(R.string.cancel))
                    }
                }
            )
        }
    ) { padding ->
        Box(modifier = Modifier.padding(padding).fillMaxSize()) {
            if (cameraPermissionState.status.isGranted) {
                when (val state = uiState) {
                    is ScannerUiState.Idle -> {
                        CameraPreview(
                            imageCapture = imageCapture,
                            cameraExecutor = cameraExecutor,
                            onImageCaptured = { bitmap ->
                                viewModel.onImageCaptured(bitmap, quizId)
                            }
                        )
                    }
                    is ScannerUiState.Processing -> {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                CircularProgressIndicator()
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(stringResource(R.string.processing_image), style = MaterialTheme.typography.bodyMedium)
                            }
                        }
                    }
                    is ScannerUiState.Success -> {
                        QuestionReviewList(
                            questions = state.questions,
                            onSave = { viewModel.saveQuestions(state.questions) },
                            onCancel = { viewModel.reset() },
                            onUpdateQuestion = { index, question -> viewModel.updateQuestion(index, question) },
                            onDeleteQuestion = { index -> viewModel.deleteQuestion(index) }
                        )
                    }
                    is ScannerUiState.Error -> {
                        Column(
                            modifier = Modifier.fillMaxSize().padding(32.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.Center
                        ) {
                            Icon(Icons.Default.ErrorOutline, contentDescription = null, modifier = Modifier.size(64.dp), tint = MaterialTheme.colorScheme.error)
                            Spacer(modifier = Modifier.height(16.dp))
                            Text(stringResource(R.string.import_error, state.message), color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.bodyLarge)
                            Spacer(modifier = Modifier.height(24.dp))
                            Button(onClick = { viewModel.reset() }) {
                                Text(stringResource(R.string.try_again))
                            }
                        }
                    }
                    else -> {}
                }
            } else {
                Column(
                    modifier = Modifier.fillMaxSize().padding(32.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    Text(stringResource(R.string.camera_permission_required), style = MaterialTheme.typography.bodyLarge)
                    Spacer(modifier = Modifier.height(16.dp))
                    Button(onClick = { cameraPermissionState.launchPermissionRequest() }) {
                        Text(stringResource(R.string.request_permission))
                    }
                }
            }
        }
    }
}

fun CameraPreview(
    imageCapture: ImageCapture,
    cameraExecutor: ExecutorService,
    onImageCaptured: (Bitmap) -> Unit
) {
    val context = LocalContext.current
    val lifecycleOwner = LocalLifecycleOwner.current
    val previewView = remember { PreviewView(context) }

    LaunchedEffect(Unit) {
        val cameraProviderFuture = androidx.camera.lifecycle.ProcessCameraProvider.getInstance(context)
        cameraProviderFuture.addListener({
            val cameraProvider = cameraProviderFuture.get()
            val preview = androidx.camera.core.Preview.Builder().build().also {
                it.setSurfaceProvider(previewView.surfaceProvider)
            }
            val cameraSelector = CameraSelector.DEFAULT_BACK_CAMERA
            try {
                cameraProvider.unbindAll()
                cameraProvider.bindToLifecycle(lifecycleOwner, cameraSelector, preview, imageCapture)
            } catch (exc: Exception) {
                MksLogger.e("ScannerScreen", "Use case binding failed", exc)
            }
        }, ContextCompat.getMainExecutor(context))
    }

    Box(modifier = Modifier.fillMaxSize()) {
        AndroidView(factory = { previewView }, modifier = Modifier.fillMaxSize())

        IconButton(
            onClick = {
                imageCapture.takePicture(
                    cameraExecutor,

override fun onCaptureSuccess(image: ImageProxy) {
                            val bitmap = image.toBitmap().rotate(image.imageInfo.rotationDegrees.toFloat())
                            image.close()
                            onImageCaptured(bitmap)
                        }

override fun onError(exception: ImageCaptureException) {
                            MksLogger.e("ScannerScreen", "Photo capture failed", exception)
                        }
                    }
                )
            },
            modifier = Modifier
                .align(Alignment.BottomCenter)
                .padding(bottom = 32.dp)
                .size(80.dp)
                .background(Color.White.copy(alpha = 0.8f), shape = CircleShape)
                .border(4.dp, Color.White, CircleShape)
        ) {
            Icon(Icons.Default.Camera, contentDescription = "Capture", tint = Color.Black, modifier = Modifier.size(48.dp))
        }
    }
}

fun QuestionReviewList(
    questions: List<QuestionEntity>,
    onSave: () -> Unit,
    onCancel: () -> Unit,
    onUpdateQuestion: (Int, QuestionEntity) -> Unit,
    onDeleteQuestion: (Int) -> Unit
) {
    var editingIndex by rememberSaveable { mutableStateOf<Int?>(null) }

    Column(modifier = Modifier.fillMaxSize()) {
        Surface(
            color = MaterialTheme.colorScheme.secondaryContainer,
            modifier = Modifier.fillMaxWidth()
        ) {
            Text(
                stringResource(R.string.review_recognized_questions, questions.size),
                style = MaterialTheme.typography.titleMedium,
                modifier = Modifier.padding(16.dp)
            )
        }

        LazyColumn(
            modifier = Modifier.weight(1f),
            contentPadding = PaddingValues(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            itemsIndexed(questions) { index, question ->
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(12.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Text(
                                stringResource(R.string.question_number_prefix, index + 1),
                                style = MaterialTheme.typography.labelLarge,
                                color = MaterialTheme.colorScheme.primary,
                                modifier = Modifier.weight(1f)
                            )
                            IconButton(onClick = { editingIndex = index }) {
                                Icon(Icons.Default.Edit, contentDescription = stringResource(R.string.edit), modifier = Modifier.size(20.dp))
                            }
                            IconButton(onClick = { onDeleteQuestion(index) }) {
                                Icon(Icons.Default.Delete, contentDescription = stringResource(R.string.delete), modifier = Modifier.size(20.dp), tint = MaterialTheme.colorScheme.error)
                            }
                        }
                        Text(question.text, style = MaterialTheme.typography.bodyLarge)
                        Spacer(modifier = Modifier.height(12.dp))
                        question.options.forEachIndexed { optIndex, option ->
                            val isCorrect = question.correctAnswers.contains(optIndex)
                            val isDark = isSystemInDarkTheme()
                            val successBg = if (isDark) Color(0xFF1B5E20).copy(alpha = 0.3f) else Color(0xFF4CAF50).copy(alpha = 0.1f)
                            val successText = if (isDark) Color(0xFFA5D6A7) else Color(0xFF2E7D32)

                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 2.dp)
                                    .background(
                                        if (isCorrect) successBg else Color.Transparent,
                                        RoundedCornerShape(4.dp)
                                    )
                                    .padding(4.dp),
                                verticalAlignment = Alignment.Top
                            ) {
                                Text(
                                    "${(optIndex + 65).toChar()}.",
                                    style = MaterialTheme.typography.bodyMedium,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.width(24.dp),
                                    color = if (isCorrect) successText else MaterialTheme.colorScheme.onSurface
                                )
                                Text(
                                    option,
                                    style = MaterialTheme.typography.bodyMedium,
                                    color = if (isCorrect) successText else MaterialTheme.colorScheme.onSurface,
                                    fontWeight = if (isCorrect) FontWeight.Bold else FontWeight.Normal
                                )
                            }
                        }
                    }
                }
            }
        }

        Row(
            modifier = Modifier.fillMaxWidth().padding(16.dp),
            horizontalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            OutlinedButton(onClick = onCancel, modifier = Modifier.weight(1f)) {
                Text(stringResource(R.string.discard))
            }
            Button(onClick = onSave, modifier = Modifier.weight(1f)) {
                Icon(Icons.Default.Check, contentDescription = null)
                Spacer(modifier = Modifier.width(8.dp))
                Text(stringResource(R.string.import_all))
            }
        }
    }

    editingIndex?.let { index ->
        EditQuestionDialog(
            question = questions[index],
            onDismiss = { editingIndex = null },
            onConfirm = { updated ->
                onUpdateQuestion(index, updated)
                editingIndex = null
            }
        )
    }
}

fun EditQuestionDialog(
    question: QuestionEntity,
    onDismiss: () -> Unit,
    onConfirm: (QuestionEntity) -> Unit
) {
    var text by rememberSaveable { mutableStateOf(question.text) }
    var options by rememberSaveable { mutableStateOf(question.options) }
    var correctAnswers by rememberSaveable { mutableStateOf(question.correctAnswers) }
    var explanation by rememberSaveable { mutableStateOf(question.explanation ?: "") }
    var hint by rememberSaveable { mutableStateOf(question.hint ?: "") }
    var reference by rememberSaveable { mutableStateOf(question.reference ?: "") }
    var additionalInfo by rememberSaveable { mutableStateOf(question.additionalInfo ?: "") }
    var weight by rememberSaveable { mutableStateOf(question.weight.toString()) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.edit_question)) },
        text = {
            Column(modifier = Modifier.verticalScroll(rememberScrollState()).fillMaxWidth()) {
                OutlinedTextField(
                    value = text,
                    onValueChange = { text = it },
                    label = { Text(stringResource(R.string.question_text_label)) },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 3
                )
                Spacer(modifier = Modifier.height(16.dp))

                Text(stringResource(R.string.options_label), style = MaterialTheme.typography.labelMedium)
                options.forEachIndexed { index, option ->
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier.padding(vertical = 4.dp)
                    ) {
                        Checkbox(
                            checked = correctAnswers.contains(index),
                            onCheckedChange = { checked ->
                                val newCorrect = if (checked) {
                                    (correctAnswers + index).distinct()
                                } else {
                                    if (correctAnswers.size > 1) correctAnswers - index else correctAnswers
                                }
                                correctAnswers = newCorrect
                            }
                        )
                        OutlinedTextField(
                            value = option,
                            onValueChange = { newVal ->
                                val newOptions = options.toMutableList()
                                newOptions[index] = newVal
                                options = newOptions
                            },
                            modifier = Modifier.weight(1f),
                            textStyle = MaterialTheme.typography.bodySmall
                        )
                    }
                }

                TextButton(
                    onClick = { options = options + "" },
                    modifier = Modifier.padding(vertical = 8.dp)
                ) {
                    Icon(Icons.Default.Add, null)
                    Spacer(Modifier.width(8.dp))
                    Text("Add Option")
                }

                Spacer(modifier = Modifier.height(16.dp))

                OutlinedTextField(
                    value = explanation,
                    onValueChange = { explanation = it },
                    label = { Text(stringResource(R.string.explanation_label)) },
                    modifier = Modifier.fillMaxWidth(),
                    minLines = 2
                )

                OutlinedTextField(
                    value = hint,
                    onValueChange = { hint = it },
                    label = { Text(stringResource(R.string.hint_label)) },
                    modifier = Modifier.fillMaxWidth()
                )

                OutlinedTextField(
                    value = reference,
                    onValueChange = { reference = it },
                    label = { Text(stringResource(R.string.reference_label)) },
                    modifier = Modifier.fillMaxWidth()
                )

                OutlinedTextField(
                    value = additionalInfo,
                    onValueChange = { additionalInfo = it },
                    label = { Text(stringResource(R.string.info_label)) },
                    modifier = Modifier.fillMaxWidth()
                )

                OutlinedTextField(
                    value = weight,
                    onValueChange = { if (it.isEmpty() || it.all { c -> c.isDigit() }) weight = it },
                    label = { Text("Weight") },
                    modifier = Modifier.fillMaxWidth(),
                    keyboardOptions = androidx.compose.foundation.text.KeyboardOptions(
                        keyboardType = androidx.compose.ui.text.input.KeyboardType.Number
                    )
                )
            }
        },
        confirmButton = {
            Button(onClick = {
                onConfirm(question.copy(
                    text = text, 
                    options = options.filter { it.isNotBlank() }, 
                    correctAnswers = correctAnswers.filter { it < options.size },
                    type = if (correctAnswers.size > 1) com.ahmedyejam.mks.data.local.entity.QuestionType.MULTIPLE_CHOICE 
                           else com.ahmedyejam.mks.data.local.entity.QuestionType.SINGLE_CHOICE,
                    explanation = explanation.ifBlank { null },
                    hint = hint.ifBlank { null },
                    reference = reference.ifBlank { null },
                    additionalInfo = additionalInfo.ifBlank { null },
                    weight = weight.toIntOrNull() ?: 1
                ))
            }) {
                Text(stringResource(R.string.save))
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

fun Bitmap.rotate(degrees: Float): Bitmap {
    val matrix = Matrix().apply { postRotate(degrees) }
    return Bitmap.createBitmap(this, 0, 0, width, height, matrix, true)
}

class SlideshowCourseViewModel @Inject constructor(
    @dagger.hilt.android.qualifiers.ApplicationContext private val appContext: android.content.Context,
    @ApplicationScope private val applicationScope: kotlinx.coroutines.CoroutineScope,
    private val bookRepository: BookRepository,
    private val knowledgeRepository: KnowledgeRepository,
    private val assetRepository: AssetRepository,
    private val quizRepository: QuizRepository,
    private val studyRepository: StudyRepository
) : ViewModel() {
    private val _uiState = MutableStateFlow(SlideshowCourseUiState())
    val uiState = _uiState.asStateFlow()
    private var courseId: Long? = null
    private var loadJob: Job? = null

    private val moshi = com.squareup.moshi.Moshi.Builder().build()
    private val sessionStateAdapter = moshi.adapter(com.ahmedyejam.mks.data.model.LearningSessionState::class.java)

    private var activeSessionId: Long? = null
    private var sessionTimeAccumulatedMs: Long = 0L
    private var sessionLastStartedTimestamp: Long = 0L
    private var isSessionTimerRunning: Boolean = false
    private val _elapsedSeconds = MutableStateFlow(0L)
    val elapsedSeconds = _elapsedSeconds.asStateFlow()
    private var timerJob: Job? = null

    private val reviewedSlideIds = mutableSetOf<Long>()

    @OptIn(ExperimentalCoroutinesApi::class)

fun loadCourseSafe(id: Long) {
        if (courseId == id && loadJob?.isActive == true) return
        courseId = id
        loadJob?.cancel()
        loadJob = viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true, error = null)
            fetchCourseAndObserve(id)
        }
    }

fun clearMessage() {
        _uiState.value = _uiState.value.copy(message = null, error = null)
    }

fun startSessionTimer() {
        if (!isSessionTimerRunning) {
            sessionLastStartedTimestamp = System.currentTimeMillis()
            isSessionTimerRunning = true
            MksLogger.d("SlideshowCourseViewModel", "Stopwatch started/resumed")
            timerJob = viewModelScope.launch {
                while (isSessionTimerRunning) {
                    _elapsedSeconds.value = getSessionElapsedTimeMs() / 1000L
                    delay(1000)
                }
            }
        }
    }

fun pauseSessionTimer() {
        if (isSessionTimerRunning) {
            val elapsed = System.currentTimeMillis() - sessionLastStartedTimestamp
            sessionTimeAccumulatedMs += elapsed
            isSessionTimerRunning = false
            MksLogger.d("SlideshowCourseViewModel", "Stopwatch paused. Accumulated: $sessionTimeAccumulatedMs ms")
            saveSessionStateIncremental()
            timerJob?.cancel()
        }
    }

fun getSessionElapsedTimeMs(): Long {
        return if (isSessionTimerRunning) {
            sessionTimeAccumulatedMs + (System.currentTimeMillis() - sessionLastStartedTimestamp)
        } else {
            sessionTimeAccumulatedMs
        }
    }

private fun saveSessionStateIncremental() {
        val sessionId = activeSessionId ?: return
        val courseId = courseId ?: return
        val current = _uiState.value
        val elapsed = getSessionElapsedTimeMs()

        val stateObj = com.ahmedyejam.mks.data.model.LearningSessionState(
            targetType = "COURSE",
            targetId = courseId,
            courseId = courseId,
            reviewedCardIds = reviewedSlideIds.toSet(),
            currentCardIndex = current.currentIndex,
            timersActive = mapOf(0L to elapsed),
            startedAt = System.currentTimeMillis() - elapsed,
            totalAttempts = current.slides.size
        )

        val json = try {
            sessionStateAdapter.toJson(stateObj)
        } catch (e: Exception) {
            ""
        }

        applicationScope.launch {
            studyRepository.getLearningSessionById(sessionId)?.let { session ->
                studyRepository.updateLearningSession(session.copy(stateJson = json))
            }
        }
    }

fun endAndSaveSession() {
        val sessionId = activeSessionId ?: return
        activeSessionId = null
        pauseSessionTimer()

        val courseId = courseId ?: return
        val current = _uiState.value
        val elapsed = getSessionElapsedTimeMs()

        val stateObj = com.ahmedyejam.mks.data.model.LearningSessionState(
            targetType = "COURSE",
            targetId = courseId,
            courseId = courseId,
            reviewedCardIds = reviewedSlideIds.toSet(),
            currentCardIndex = current.currentIndex,
            timersActive = mapOf(0L to elapsed),
            startedAt = System.currentTimeMillis() - elapsed,
            completedAt = System.currentTimeMillis(),
            totalAttempts = current.slides.size
        )

        val json = try {
            sessionStateAdapter.toJson(stateObj)
        } catch (e: Exception) {
            ""
        }

        applicationScope.launch {
            studyRepository.getLearningSessionById(sessionId)?.let { session ->
                studyRepository.updateLearningSession(session.copy(stateJson = json, isCompleted = true))
                studyRepository.completeLearningSession(sessionId)
            }
        }
    }

fun setPresentationMode(enabled: Boolean) {
        if (enabled) {
            _uiState.value = _uiState.value.copy(isPresentationMode = true, currentIndex = 0)
            reviewedSlideIds.clear()
            val currentSlide = _uiState.value.currentSlide
            if (currentSlide != null) {
                reviewedSlideIds.add(currentSlide.id)
            }
            sessionTimeAccumulatedMs = 0L
            isSessionTimerRunning = false

            viewModelScope.launch {
                val courseId = courseId ?: return@launch
                val sessionId = studyRepository.createLearningSession("COURSE", courseId, "")
                activeSessionId = sessionId
                startSessionTimer()
            }
        } else {
            endAndSaveSession()
            _uiState.value = _uiState.value.copy(isPresentationMode = false, currentIndex = 0)
        }
    }

override fun onCleared() {
        super.onCleared()
        endAndSaveSession()
    }

fun nextSlide() {
        val current = _uiState.value
        val next = if (current.slides.isEmpty()) 0 else (current.currentIndex + 1).coerceAtMost(current.slides.lastIndex)
        _uiState.value = current.copy(currentIndex = next)
        val nextSlide = _uiState.value.currentSlide
        if (nextSlide != null) {
            reviewedSlideIds.add(nextSlide.id)
        }
        saveSessionStateIncremental()
    }

fun toggleSlideStudied() {
        val current = _uiState.value
        val slide = current.currentSlide ?: return
        viewModelScope.launch {
            knowledgeRepository.updateCourseSlide(slide.copy(isCompleted = !slide.isCompleted))
        }
    }

fun setCurrentIndex(index: Int) {
        val current = _uiState.value
        if (index in current.slides.indices && index != current.currentIndex) {
            _uiState.value = current.copy(currentIndex = index)
            val slide = _uiState.value.currentSlide
            if (slide != null) {
                reviewedSlideIds.add(slide.id)
            }
            saveSessionStateIncremental()
        }
    }

fun previousSlide() {
        val current = _uiState.value
        val previous = (current.currentIndex - 1).coerceAtLeast(0)
        _uiState.value = current.copy(currentIndex = previous)
        val prevSlide = _uiState.value.currentSlide
        if (prevSlide != null) {
            reviewedSlideIds.add(prevSlide.id)
        }
        saveSessionStateIncremental()
    }

fun updateCourse(title: String, description: String?, coverImage: String?) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            knowledgeRepository.updateSlideshowCourse(course.copy(title = title, description = description, coverImage = coverImage))
            _uiState.value = _uiState.value.copy(message = "Course updated")
            // refresh course object since it's not fully observed
            val refreshed = knowledgeRepository.getSlideshowCourseById(course.id)
            _uiState.value = _uiState.value.copy(course = refreshed)
        }
    }

fun updateSlide(slide: CourseSlideEntity, title: String, body: String, notes: String?, imagePath: String?) {
        viewModelScope.launch {
            knowledgeRepository.updateCourseSlide(
                slide.copy(
                    title = title,
                    body = body,
                    speakerNotes = notes,
                    imagePath = imagePath
                )
            )
            _uiState.value = _uiState.value.copy(message = "Slide updated")
        }
    }

fun deleteSlide(slide: CourseSlideEntity) {
        viewModelScope.launch {
            knowledgeRepository.deleteCourseSlide(slide)
            _uiState.value = _uiState.value.copy(message = "Slide deleted")
        }
    }

fun moveSlide(slide: CourseSlideEntity, direction: Int) {
        val slides = _uiState.value.slides.toMutableList()
        val index = slides.indexOfFirst { it.id == slide.id }
        val target = index + direction
        if (index !in slides.indices || target !in slides.indices) return
        val moved = slides.removeAt(index)
        slides.add(target, moved)
        viewModelScope.launch { knowledgeRepository.reorderCourseSlides(slides) }
    }

fun toggleSlideSelection(id: Long) {
        val current = _uiState.value.selectedSlideIds
        val next = if (current.contains(id)) current - id else current + id
        _uiState.value = _uiState.value.copy(selectedSlideIds = next)
    }

fun clearSelection() {
        _uiState.value = _uiState.value.copy(selectedSlideIds = emptySet())
    }

fun selectAllSlides() {
        val allIds = _uiState.value.slides.map { it.id }.toSet()
        _uiState.value = _uiState.value.copy(selectedSlideIds = allIds)
    }

fun deleteSelectedSlides() {
        val ids = _uiState.value.selectedSlideIds
        if (ids.isEmpty()) return
        val slidesToDelete = _uiState.value.slides.filter { it.id in ids }
        viewModelScope.launch {
            slidesToDelete.forEach { knowledgeRepository.deleteCourseSlide(it) }
            _uiState.value = _uiState.value.copy(selectedSlideIds = emptySet(), message = "${ids.size} slides deleted")
        }
    }

fun moveSelectedSlides(targetCourseId: Long) {
        val ids = _uiState.value.selectedSlideIds
        if (ids.isEmpty()) return
        viewModelScope.launch {
            knowledgeRepository.moveCourseSlides(ids.toList(), targetCourseId)
            _uiState.value = _uiState.value.copy(selectedSlideIds = emptySet(), message = "${ids.size} slides moved")
        }
    }

fun copySelectedSlides(targetCourseId: Long) {
        val ids = _uiState.value.selectedSlideIds
        if (ids.isEmpty()) return
        viewModelScope.launch {
            knowledgeRepository.copyCourseSlides(ids.toList(), targetCourseId)
            _uiState.value = _uiState.value.copy(selectedSlideIds = emptySet(), message = "${ids.size} slides copied")
        }
    }

fun importFromText(text: String, mode: TextParseMode) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val parser = TextSlideParser()
                val orderStart = _uiState.value.slides.size
                val slides = parser.parse(text, course.id, orderStart, mode)
                if (slides.isNotEmpty()) {
                    knowledgeRepository.insertCourseSlides(slides)
                }
                slides.size
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count slide(s) imported")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to import text")
            }
        }
    }

fun importFromPptx(uri: android.net.Uri) {
        val course = _uiState.value.course ?: return
        val context = appContext
        _uiState.value = _uiState.value.copy(isLoading = true)
        viewModelScope.launch {
            runCatching {
                val parser = com.ahmedyejam.mks.data.importer.parser.PptxSlideParser()
                val orderStart = _uiState.value.slides.size
                val slides = parser.parse(context, uri, course.id, orderStart)
                if (slides.isNotEmpty()) {
                    knowledgeRepository.insertCourseSlides(slides)
                }
                slides.size
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(
                    isLoading = false,
                    message = "$count slide(s) imported from PPTX"
                )
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(
                    isLoading = false,
                    error = error.message ?: "Failed to import PPTX"
                )
            }
        }
    }

fun generateFromMarked(config: SlideGenerationConfig, clearMarksAfter: Boolean) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val markedQuestions = bookRepository.getBookStudyBundle(course.bookId)?.questions.orEmpty().filter { it.isMarked }
                val count = knowledgeRepository.addCourseSlidesFromQuestionsToCourse(course.id, markedQuestions.map { it.id }, config)
                if (clearMarksAfter) {
                    markedQuestions.forEach { question ->
                        assetRepository.updateQuestion(question.copy(isMarked = false, updatedAt = System.currentTimeMillis()))
                    }
                }
                count
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count marked-question slide(s) added")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate slides")
            }
        }
    }

fun generateFromMissed(config: SlideGenerationConfig) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val missedIds = bookRepository.getBookStudyBundle(course.bookId)?.questions.orEmpty()
                    .filter { it.attempts > 0 && (it.correctCount < it.attempts || it.lastAttemptResult == false) }
                    .map { it.id }
                knowledgeRepository.addCourseSlidesFromQuestionsToCourse(course.id, missedIds, config)
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count missed-question slide(s) added")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate slides")
            }
        }
    }

fun generateFromBook(config: SlideGenerationConfig, clearMarksAfter: Boolean) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val questions = bookRepository.getBookStudyBundle(course.bookId)?.questions.orEmpty()
                val count = knowledgeRepository.addCourseSlidesFromQuestionsToCourse(course.id, questions.map { it.id }, config)
                if (clearMarksAfter) {
                    questions.filter { it.isMarked }.forEach { question ->
                        assetRepository.updateQuestion(question.copy(isMarked = false, updatedAt = System.currentTimeMillis()))
                    }
                }
                count
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count slide(s) added from book")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate slides")
            }
        }
    }

fun generateFromQuiz(quizId: Long, config: SlideGenerationConfig, clearMarksAfter: Boolean) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val bundle = bookRepository.getBookStudyBundle(course.bookId)
                val questions = bundle?.questionsByQuiz?.get(quizId).orEmpty()
                val count = knowledgeRepository.addCourseSlidesFromQuestionsToCourse(course.id, questions.map { it.id }, config)
                if (clearMarksAfter) {
                    questions.filter { it.isMarked }.forEach { question ->
                        assetRepository.updateQuestion(question.copy(isMarked = false, updatedAt = System.currentTimeMillis()))
                    }
                }
                count
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count slide(s) added from quiz")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate slides")
            }
        }
    }

fun generateFromCategory(categoryName: String, config: SlideGenerationConfig, clearMarksAfter: Boolean) {
        val course = _uiState.value.course ?: return
        viewModelScope.launch {
            runCatching {
                val questions = bookRepository.getBookStudyBundle(course.bookId)?.questions.orEmpty()
                    .filter { it.categories.contains(categoryName) }
                val count = knowledgeRepository.addCourseSlidesFromQuestionsToCourse(course.id, questions.map { it.id }, config)
                if (clearMarksAfter) {
                    questions.filter { it.isMarked }.forEach { question ->
                        assetRepository.updateQuestion(question.copy(isMarked = false, updatedAt = System.currentTimeMillis()))
                    }
                }
                count
            }.onSuccess { count ->
                _uiState.value = _uiState.value.copy(message = "$count slide(s) added from category '$categoryName'")
            }.onFailure { error ->
                _uiState.value = _uiState.value.copy(error = error.message ?: "Failed to generate slides")
            }
        }
    }
}

fun SlideshowCourseScreen(
    courseId: Long,
    focusedSlideId: Long? = null,
    onBack: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    val vm: SlideshowCourseViewModel = hiltViewModel()

    val state by vm.uiState.collectAsStateWithLifecycle()
    val listState = rememberLazyListState()

    BackHandler(enabled = state.isPresentationMode) {
        vm.setPresentationMode(false)
    }

    val lifecycleOwner = LocalLifecycleOwner.current
    DisposableEffect(lifecycleOwner, state.isPresentationMode) {
        if (state.isPresentationMode) {
            vm.startSessionTimer()
            val observer = LifecycleEventObserver { _, event ->
                when (event) {
                    Lifecycle.Event.ON_RESUME -> vm.startSessionTimer()
                    Lifecycle.Event.ON_PAUSE -> vm.pauseSessionTimer()
                    else -> {}
                }
            }
            lifecycleOwner.lifecycle.addObserver(observer)
            onDispose {
                lifecycleOwner.lifecycle.removeObserver(observer)
                vm.pauseSessionTimer()
            }
        } else {
            onDispose {}
        }
    }

    LaunchedEffect(focusedSlideId, state.slides) {
        if (focusedSlideId != null && state.slides.isNotEmpty()) {
            val index = state.slides.indexOfFirst { it.id == focusedSlideId }
            if (index != -1) {
                if (tokens.isPlain) {
                    listState.scrollToItem(index + 1)
                } else {
                    listState.animateScrollToItem(index + 1)
                }
            }
        }
    }
    val snackbarHostState = remember { SnackbarHostState() }
    var showSlideEditor by remember { mutableStateOf<CourseSlideEntity?>(null) }
    var showAddSlide by rememberSaveable { mutableStateOf(false) }
    var showCourseEditor by rememberSaveable { mutableStateOf(false) }
    var showPasteTextDialog by rememberSaveable { mutableStateOf(false) }
    var showGeneratorDialog by rememberSaveable { mutableStateOf(false) }

    val pptxPickerLauncher = rememberLauncherForActivityResult(ActivityResultContracts.GetContent()) { uri ->
        if (uri != null) {
            vm.importFromPptx(uri)
        }
    }

    LaunchedEffect(courseId) { vm.loadCourseSafe(courseId) }
    LaunchedEffect(state.message, state.error) {
        val text = state.message ?: state.error
        if (text != null) {
            snackbarHostState.showSnackbar(text)
            vm.clearMessage()
        }
    }

    var showOptionsMenu by remember { mutableStateOf(false) }

    state.course?.let { course ->
        if (showCourseEditor) {
            com.ahmedyejam.mks.ui.components.EntityEditDialog(
                title = "Edit Course",
                initialName = course.title,
                initialDescription = course.description ?: "",
                initialImage = course.coverImage ?: "",
                showImage = true,
                onDismiss = { showCourseEditor = false },
                onSave = { title, desc, image ->
                    vm.updateCourse(title, desc.ifBlank { null }, image.ifBlank { null })
                    showCourseEditor = false
                }
            )
        }
    }

    if (showAddSlide || showSlideEditor != null) {
        SlideEditorDialog(
            slide = showSlideEditor,
            onDismiss = {
                showAddSlide = false
                showSlideEditor = null
            },
            onSave = { title, body, notes, imagePath ->
                val slide = showSlideEditor
                if (slide == null) vm.addSlide(title, body, notes, imagePath) else vm.updateSlide(slide, title, body, notes, imagePath)
                showAddSlide = false
                showSlideEditor = null
            }
        )
    }

    if (showGeneratorDialog) {
        SlideGeneratorDialog(
            quizzes = state.quizzes,
            categories = state.categories,
            onDismiss = { showGeneratorDialog = false },
            onConfirm = { source, sourceId, clearMarks ->
                when (source) {
                    "ALL" -> vm.generateFromBook(com.ahmedyejam.mks.data.model.SlideGenerationConfig.DEFAULT, clearMarks)
                    "MARKED" -> vm.generateFromMarked(com.ahmedyejam.mks.data.model.SlideGenerationConfig.DEFAULT, clearMarks)
                    "MISSED" -> vm.generateFromMissed(com.ahmedyejam.mks.data.model.SlideGenerationConfig.DEFAULT)
                    "QUIZ" -> sourceId?.toLongOrNull()?.let { vm.generateFromQuiz(it, com.ahmedyejam.mks.data.model.SlideGenerationConfig.DEFAULT, clearMarks) }
                    "CATEGORY" -> sourceId?.let { vm.generateFromCategory(it, com.ahmedyejam.mks.data.model.SlideGenerationConfig.DEFAULT, clearMarks) }
                }
                showGeneratorDialog = false
            }
        )
    }

    if (showPasteTextDialog) {
        PasteTextDialog(
            onDismiss = { showPasteTextDialog = false },
            onImport = { text, mode ->
                vm.importFromText(text, mode)
                showPasteTextDialog = false
            }
        )
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            if (state.selectedSlideIds.isNotEmpty()) {
                TopAppBar(
                    title = { Text("${state.selectedSlideIds.size} selected") },
                    navigationIcon = { IconButton(onClick = { vm.clearSelection() }) { Icon(Icons.Default.Close, contentDescription = "Clear selection") } },
                    actions = {
                        IconButton(onClick = { vm.selectAllSlides() }) {
                            Icon(Icons.Default.SelectAll, contentDescription = "Select All")
                        }
                        IconButton(onClick = { vm.deleteSelectedSlides() }) {
                            Icon(Icons.Default.Delete, contentDescription = "Delete")
                        }
                    }
                )
            } else {
                var subtitle: String? = null
                if (state.isPresentationMode) {
                    val elapsed by vm.elapsedSeconds.collectAsState()
                    val minutes = elapsed / 60
                    val seconds = elapsed % 60
                    subtitle =
                        String.format(java.util.Locale.getDefault(), "%02d:%02d", minutes, seconds)
                }

                com.ahmedyejam.mks.ui.components.StudyTopAppBar(
                    title = state.course?.title ?: stringResource(R.string.study_slides),
                    subtitle = subtitle,
                    onNavigateBack = onBack,
                    actions = {
                        IconButton(onClick = { showOptionsMenu = true }) {
                            Icon(Icons.Default.MoreVert, contentDescription = "Options")
                        }
                        DropdownMenu(expanded = showOptionsMenu, onDismissRequest = { showOptionsMenu = false }) {
                            DropdownMenuItem(
                                text = { Text("Edit Course") },
                                onClick = { showCourseEditor = true; showOptionsMenu = false }
                            )
                        }
                        IconButton(onClick = { vm.setPresentationMode(!state.isPresentationMode) }) {
                            Icon(
                                if (state.isPresentationMode) Icons.AutoMirrored.Filled.ViewList else Icons.Default.PlayArrow,
                                contentDescription = "Toggle presentation mode"
                            )
                        }
                    }
                )
            }
        }
    ) { padding ->
        Box(
            Modifier
                .padding(padding)
                .fillMaxSize()
        ) {
            when {
                state.isLoading -> CircularProgressIndicator(Modifier.align(Alignment.Center))
                state.course == null -> Text("Course not found", Modifier.align(Alignment.Center))
                state.isPresentationMode -> SlidePresentationContent(
                    state = state, 
                    viewModel = vm
                )
                else -> SlideshowCourseDetailContent(
                    state = state,
                    onAddSlide = { showAddSlide = true },
                    onEditSlide = { showSlideEditor = it },
                    onDeleteSlide = { vm.deleteSlide(it) },
                    onMoveSlide = { slide, direction -> vm.moveSlide(slide, direction) },
                    onGenerateSlides = { showGeneratorDialog = true },
                    onStartPresentation = { vm.setPresentationMode(true) },
                    onToggleSelect = { vm.toggleSlideSelection(it) },
                    onImportText = { showPasteTextDialog = true },
                    onImportPptx = { pptxPickerLauncher.launch("application/vnd.openxmlformats-officedocument.presentationml.presentation") }
                )
            }
        }
    }
}

private fun SlideshowCourseDetailContent(
    state: SlideshowCourseUiState,
    onAddSlide: () -> Unit,
    onEditSlide: (CourseSlideEntity) -> Unit,
    onDeleteSlide: (CourseSlideEntity) -> Unit,
    onMoveSlide: (CourseSlideEntity, Int) -> Unit,
    onGenerateSlides: () -> Unit,
    onStartPresentation: () -> Unit,
    onToggleSelect: (Long) -> Unit,
    onImportText: () -> Unit,
    onImportPptx: () -> Unit
) {
    val course = state.course ?: return
    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        item {
            CourseStatsCard(course = course, slideCount = state.slides.size)
        }
        item {
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth()) {
                Button(onClick = onAddSlide, modifier = Modifier.weight(1f)) {
                    Icon(Icons.Default.Add, contentDescription = null)
                    Spacer(Modifier.width(6.dp))
                    Text(stringResource(R.string.add_slide))
                }
                OutlinedButton(onClick = onStartPresentation, enabled = state.slides.isNotEmpty(), modifier = Modifier.weight(1f)) {
                    Icon(Icons.Default.PlayArrow, contentDescription = null)
                    Spacer(Modifier.width(6.dp))
                    Text("Present")
                }
            }
        }
        item {
            Row(
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                OutlinedButton(onClick = onImportText, modifier = Modifier.weight(1f)) {
                    Icon(Icons.AutoMirrored.Filled.TextSnippet, null)
                    Spacer(Modifier.width(6.dp))
                    Text(stringResource(R.string.import_text))
                }
                OutlinedButton(onClick = onImportPptx, modifier = Modifier.weight(1f)) {
                    Icon(Icons.Default.Slideshow, null)
                    Spacer(Modifier.width(6.dp))
                    Text(stringResource(R.string.import_pptx))
                }
            }
        }
        item {
            val tokens = LocalMksDesignTokens.current
            Button(
                onClick = onGenerateSlides,
                modifier = Modifier
                    .fillMaxWidth()
                    .height(56.dp),
                shape = RoundedCornerShape(tokens.cardRadius)
            ) {
                Icon(Icons.Default.AutoAwesome, contentDescription = null)
                Spacer(Modifier.width(8.dp))
                Text(stringResource(R.string.generate_from_questions), fontWeight = FontWeight.Bold)
            }
        }
        if (state.slides.isEmpty()) {
            item {
                val tokens = LocalMksDesignTokens.current
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(tokens.cardRadius),
                    elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
                ) {
                    Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Text("No slides yet", fontWeight = FontWeight.SemiBold)
                        Text("Create slides manually or generate them from marked/missed questions.")
                    }
                }
            }
        } else {
            items(state.slides, key = { it.id }) { slide ->
                SlideListItem(
                    slide = slide,
                    isSelected = state.selectedSlideIds.contains(slide.id),
                    isSelectionMode = state.selectedSlideIds.isNotEmpty(),
                    onToggleSelect = { onToggleSelect(slide.id) },
                    onEdit = { onEditSlide(slide) },
                    onDelete = { onDeleteSlide(slide) },
                    onMoveUp = { onMoveSlide(slide, -1) },
                    onMoveDown = { onMoveSlide(slide, 1) }
                )
            }
        }
    }
}

private fun CourseStatsCard(course: SlideshowCourseEntity, slideCount: Int) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Text(course.title, style = MaterialTheme.typography.titleLarge, fontWeight = FontWeight.Bold)
            course.description?.takeIf { it.isNotBlank() }?.let { Text(it) }
            Row(Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                AssistChip(onClick = {}, label = { Text("$slideCount slides") })
                AssistChip(onClick = {}, label = { Text("${course.studiedSlideCount} completed") })
                AssistChip(onClick = {}, label = { Text("${(course.progress * 100).toInt()}% progress") })
            }
            LinearProgressIndicator(progress = { course.progress.coerceIn(0f, 1f) }, modifier = Modifier.fillMaxWidth())
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

private fun SlideListItem(
    slide: CourseSlideEntity,
    isSelected: Boolean,
    isSelectionMode: Boolean,
    onToggleSelect: () -> Unit,
    onEdit: () -> Unit,
    onDelete: () -> Unit,
    onMoveUp: () -> Unit,
    onMoveDown: () -> Unit
) {
    val tokens = LocalMksDesignTokens.current
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .combinedClickable(
                onClick = { if (isSelectionMode) onToggleSelect() else onEdit() },
                onLongClick = onToggleSelect
            ),
        shape = RoundedCornerShape(tokens.cardRadius),
        elevation = CardDefaults.cardElevation(defaultElevation = tokens.cardElevation)
    ) {
        Column(Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Row(verticalAlignment = Alignment.CenterVertically) {
                if (isSelectionMode) {
                    Checkbox(checked = isSelected, onCheckedChange = { onToggleSelect() })
                } else {
                    Icon(Icons.Default.Slideshow, contentDescription = null)
                }
                Spacer(Modifier.width(8.dp))
                Column(Modifier.weight(1f)) {
                    Text(slide.title, fontWeight = FontWeight.SemiBold, maxLines = 1)
                    Text(slide.body, style = MaterialTheme.typography.bodySmall, maxLines = 2)
                    slide.speakerNotes?.takeIf { it.isNotBlank() }?.let { notes ->
                        Row(
                            horizontalArrangement = Arrangement.spacedBy(4.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.padding(top = 4.dp)
                        ) {
                            Icon(
                                Icons.Rounded.NoteAlt, null,
                                modifier = Modifier.size(14.dp),
                                tint = MaterialTheme.colorScheme.primary
                            )
                            Text(
                                notes, style = MaterialTheme.typography.labelSmall,
                                maxLines = 1, color = MaterialTheme.colorScheme.primary
                            )
                        }
                    }
                }
                if (!isSelectionMode) {
                    IconButton(onClick = onMoveUp) { Icon(Icons.Default.ArrowUpward, contentDescription = "Move up") }
                    IconButton(onClick = onMoveDown) { Icon(Icons.Default.ArrowDownward, contentDescription = "Move down") }
                    IconButton(onClick = onDelete) { Icon(Icons.Default.Delete, contentDescription = "Delete") }
                }
            }
        }
    }
}

@OptIn(ExperimentalFoundationApi::class)

private fun SlidePresentationContent(
    state: SlideshowCourseUiState,
    viewModel: SlideshowCourseViewModel
) {
    val tokens = LocalMksDesignTokens.current
    if (state.slides.isEmpty()) {
        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            Text("No slides to present")
        }
        return
    }

    val pagerState = rememberPagerState(
        initialPage = state.currentIndex,
        pageCount = { state.slides.size }
    )

    LaunchedEffect(pagerState.currentPage) {
        viewModel.setCurrentIndex(pagerState.currentPage)
    }
    LaunchedEffect(state.currentIndex) {
        if (pagerState.currentPage != state.currentIndex) {
            pagerState.animateScrollToPage(state.currentIndex)
        }
    }

    Column(Modifier.fillMaxSize()) {
        LinearProgressIndicator(
            progress = { (state.currentIndex + 1f) / state.slides.size.coerceAtLeast(1) },
            modifier = Modifier
                .fillMaxWidth()
                .height(4.dp),
            color = MaterialTheme.colorScheme.primary,
            trackColor = MaterialTheme.colorScheme.surfaceVariant
        )

        HorizontalPager(
            state = pagerState,
            modifier = Modifier.weight(1f),
            beyondViewportPageCount = 1,
            pageSpacing = 16.dp
        ) { page ->
            val slide = state.slides[page]
            SlidePageContent(slide)
        }

        val currentSlide = state.currentSlide
        if (currentSlide != null) {
            var notesExpanded by rememberSaveable(currentSlide.id) { mutableStateOf(false) }
            currentSlide.speakerNotes?.takeIf { it.isNotBlank() }?.let { notes ->
                Surface(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable { notesExpanded = !notesExpanded },
                    color = MaterialTheme.colorScheme.surfaceContainerLow,
                    shape = RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp)
                ) {
                    Column(Modifier.padding(16.dp)) {
                        Row(
                            Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Icon(Icons.Rounded.NoteAlt, null, tint = MaterialTheme.colorScheme.primary)
                                Text(
                                    stringResource(R.string.slide_notes),
                                    fontWeight = FontWeight.SemiBold,
                                    color = MaterialTheme.colorScheme.primary
                                )
                            }
                            Icon(
                                if (notesExpanded) Icons.Default.ExpandLess else Icons.Default.ExpandMore,
                                contentDescription = null
                            )
                        }
                        AnimatedVisibility(notesExpanded) {
                            Text(
                                text = notes,
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                modifier = Modifier.padding(top = 12.dp)
                            )
                        }
                    }
                }
            }

            LazyRow(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 8.dp),
                horizontalArrangement = Arrangement.Center,
                contentPadding = PaddingValues(horizontal = 16.dp)
            ) {
                items(state.slides.size) { index ->
                    val isActive = index == state.currentIndex
                    val isStudied = state.slides[index].isCompleted
                    Box(
                        Modifier
                            .padding(horizontal = 3.dp)
                            .size(if (isActive) 10.dp else 7.dp)
                            .clip(CircleShape)
                            .background(
                                when {
                                    isActive -> MaterialTheme.colorScheme.primary
                                    isStudied -> tokens.success
                                    else -> MaterialTheme.colorScheme.outlineVariant
                                }
                            )
                            .clickable { viewModel.setCurrentIndex(index) }
                    )
                }
            }

            Row(
                Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp)
                    .padding(bottom = 8.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedButton(onClick = { viewModel.previousSlide() }, enabled = state.currentIndex > 0) {
                    Icon(Icons.Default.ChevronLeft, null)
                    Spacer(Modifier.width(4.dp))
                    Text("Previous")
                }
                FilledTonalButton(onClick = { viewModel.toggleSlideStudied() }) {
                    Icon(
                        if (currentSlide.isCompleted) Icons.Rounded.CheckCircle else Icons.Rounded.RadioButtonUnchecked,
                        null
                    )
                    Spacer(Modifier.width(4.dp))
                    Text(if (currentSlide.isCompleted) "Studied" else "Mark studied")
                }
                Button(onClick = { viewModel.nextSlide() }, enabled = state.currentIndex < state.slides.size - 1) {
                    Text("Next")
                    Spacer(Modifier.width(4.dp))
                    Icon(Icons.Default.ChevronRight, null)
                }
            }
        }
    }
}

private fun SlideEditorDialog(
    slide: CourseSlideEntity?,
    onDismiss: () -> Unit,
    onSave: (title: String, body: String, notes: String?, imagePath: String?) -> Unit
) {
    var title by rememberSaveable(slide?.id) { mutableStateOf(slide?.title ?: "") }
    var body by rememberSaveable(slide?.id) { mutableStateOf(slide?.body ?: "") }
    var notes by rememberSaveable(slide?.id) { mutableStateOf(slide?.speakerNotes ?: "") }
    var imagePath by rememberSaveable(slide?.id) { mutableStateOf(slide?.imagePath ?: "") }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(if (slide == null) stringResource(R.string.add_slide) else stringResource(R.string.edit_slide)) },
        text = {
            Column(Modifier.verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                OutlinedTextField(title, { title = it }, label = { Text(stringResource(R.string.slide_header)) }, modifier = Modifier.fillMaxWidth())
                OutlinedTextField(body, { body = it }, label = { Text(stringResource(R.string.slide_body)) }, modifier = Modifier.fillMaxWidth(), minLines = 4)
                OutlinedTextField(notes, { notes = it }, label = { Text(stringResource(R.string.slide_notes)) }, modifier = Modifier.fillMaxWidth(), minLines = 2)
                OutlinedTextField(imagePath, { imagePath = it }, label = { Text("Image URL/Path") }, modifier = Modifier.fillMaxWidth())
            }
        },
        confirmButton = {
            Button(enabled = title.isNotBlank(), onClick = {
                onSave(
                    title.trim(),
                    body.trim(),
                    notes.trim().ifBlank { null },
                    imagePath.trim().ifBlank { null }
                )
            }) { Text("Save") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}


@OptIn(ExperimentalMaterial3Api::class)

private fun SlideGeneratorDialog(
    quizzes: List<QuizEntity>,
    categories: List<String>,
    onDismiss: () -> Unit,
    onConfirm: (source: String, sourceId: String?, clearMarks: Boolean) -> Unit
) {
    var source by rememberSaveable { mutableStateOf("ALL") } // ALL, MARKED, MISSED, QUIZ, CATEGORY
    var sourceId by rememberSaveable { mutableStateOf<String?>(null) }
    var clearMarks by rememberSaveable { mutableStateOf(false) }

    var expandedSource by remember { mutableStateOf(false) }
    var expandedSubSource by remember { mutableStateOf(false) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.generate_from_questions)) },
        text = {
            Column(Modifier.verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(8.dp)) {

                ExposedDropdownMenuBox(
                    expanded = expandedSource,
                    onExpandedChange = { expandedSource = it }
                ) {
                    OutlinedTextField(
                        value = when (source) {
                            "ALL" -> "All Book Questions"
                            "MARKED" -> "Marked Questions"
                            "MISSED" -> "Missed Questions"
                            "QUIZ" -> "Specific Quiz"
                            "CATEGORY" -> "Category"
                            else -> ""
                        },
                        onValueChange = {},
                        readOnly = true,
                        label = { Text("Source") },
                        trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSource) },
                        modifier = Modifier
                            .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                            .fillMaxWidth()
                    )
                    ExposedDropdownMenu(
                        expanded = expandedSource,
                        onDismissRequest = { expandedSource = false }
                    ) {
                        DropdownMenuItem(text = { Text("All Book Questions") }, onClick = { source = "ALL"; sourceId = null; expandedSource = false })
                        DropdownMenuItem(text = { Text("Marked Questions") }, onClick = { source = "MARKED"; sourceId = null; expandedSource = false })
                        DropdownMenuItem(text = { Text("Missed Questions") }, onClick = { source = "MISSED"; sourceId = null; expandedSource = false })
                        if (quizzes.isNotEmpty()) {
                            DropdownMenuItem(text = { Text("Specific Quiz") }, onClick = { source = "QUIZ"; sourceId = quizzes.firstOrNull()?.id?.toString(); expandedSource = false })
                        }
                        if (categories.isNotEmpty()) {
                            DropdownMenuItem(text = { Text("Category") }, onClick = { source = "CATEGORY"; sourceId = categories.firstOrNull(); expandedSource = false })
                        }
                    }
                }

                if (source == "QUIZ") {
                    ExposedDropdownMenuBox(
                        expanded = expandedSubSource,
                        onExpandedChange = { expandedSubSource = it }
                    ) {
                        OutlinedTextField(
                            value = quizzes.find { it.id.toString() == sourceId }?.title ?: "",
                            onValueChange = {},
                            readOnly = true,
                            label = { Text("Select Quiz") },
                            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSubSource) },
                            modifier = Modifier
                                .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                                .fillMaxWidth()
                        )
                        ExposedDropdownMenu(
                            expanded = expandedSubSource,
                            onDismissRequest = { expandedSubSource = false }
                        ) {
                            quizzes.forEach { quiz ->
                                DropdownMenuItem(text = { Text(quiz.title) }, onClick = { sourceId = quiz.id.toString(); expandedSubSource = false })
                            }
                        }
                    }
                } else if (source == "CATEGORY") {
                    ExposedDropdownMenuBox(
                        expanded = expandedSubSource,
                        onExpandedChange = { expandedSubSource = it }
                    ) {
                        OutlinedTextField(
                            value = sourceId ?: "",
                            onValueChange = {},
                            readOnly = true,
                            label = { Text("Select Category") },
                            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expandedSubSource) },
                            modifier = Modifier
                                .menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable)
                                .fillMaxWidth()
                        )
                        ExposedDropdownMenu(
                            expanded = expandedSubSource,
                            onDismissRequest = { expandedSubSource = false }
                        ) {
                            categories.forEach { cat ->
                                DropdownMenuItem(text = { Text(cat) }, onClick = { sourceId = cat; expandedSubSource = false })
                            }
                        }
                    }
                }

                if (source != "MISSED") {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Checkbox(checked = clearMarks, onCheckedChange = { clearMarks = it })
                        Text("Clear marks after conversion")
                    }
                }
            }
        },
        confirmButton = {
            Button(onClick = {
                onConfirm(
                    source,
                    sourceId,
                    clearMarks
                )
            }) { Text("Generate") }
        },
        dismissButton = { TextButton(onClick = onDismiss) { Text("Cancel") } }
    )
}

private fun PasteTextDialog(
    onDismiss: () -> Unit,
    onImport: (String, com.ahmedyejam.mks.data.importer.parser.TextParseMode) -> Unit
) {
    var text by rememberSaveable { mutableStateOf("") }
    var mode by rememberSaveable { mutableStateOf(com.ahmedyejam.mks.data.importer.parser.TextParseMode.ALTERNATING_PARAGRAPHS) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Paste text to import") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Row(
                    verticalAlignment = Alignment.CenterVertically, modifier = Modifier
                        .fillMaxWidth()
                        .clickable {
                            mode =
                                com.ahmedyejam.mks.data.importer.parser.TextParseMode.ALTERNATING_PARAGRAPHS
                        }) {
                    androidx.compose.material3.RadioButton(
                        selected = mode == com.ahmedyejam.mks.data.importer.parser.TextParseMode.ALTERNATING_PARAGRAPHS,
                        onClick = { mode = com.ahmedyejam.mks.data.importer.parser.TextParseMode.ALTERNATING_PARAGRAPHS }
                    )
                    Text("Alternating Paragraphs (odd title, even body)", style = MaterialTheme.typography.bodySmall)
                }
                Row(
                    verticalAlignment = Alignment.CenterVertically, modifier = Modifier
                        .fillMaxWidth()
                        .clickable {
                            mode =
                                com.ahmedyejam.mks.data.importer.parser.TextParseMode.EXPLICIT_LABELS
                        }) {
                    androidx.compose.material3.RadioButton(
                        selected = mode == com.ahmedyejam.mks.data.importer.parser.TextParseMode.EXPLICIT_LABELS,
                        onClick = { mode = com.ahmedyejam.mks.data.importer.parser.TextParseMode.EXPLICIT_LABELS }
                    )
                    Text("Explicit Labels (Title: ..., Body: ...)", style = MaterialTheme.typography.bodySmall)
                }
                Row(
                    verticalAlignment = Alignment.CenterVertically, modifier = Modifier
                        .fillMaxWidth()
                        .clickable {
                            mode =
                                com.ahmedyejam.mks.data.importer.parser.TextParseMode.HEADER_BODY_NOTES
                        }) {
                    androidx.compose.material3.RadioButton(
                        selected = mode == com.ahmedyejam.mks.data.importer.parser.TextParseMode.HEADER_BODY_NOTES,
                        onClick = { mode = com.ahmedyejam.mks.data.importer.parser.TextParseMode.HEADER_BODY_NOTES }
                    )
                    Text("Header/Body/Notes (or separated by ---)", style = MaterialTheme.typography.bodySmall)
                }

                OutlinedTextField(
                    value = text,
                    onValueChange = { text = it },
                    label = { Text("Slides text") },
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp),
                    maxLines = 10
                )
            }
        },
        confirmButton = {
            Button(
                onClick = { onImport(text, mode) },
                enabled = text.isNotBlank()
            ) {
                Text("Import")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("Cancel")
            }
        }
    )
}

fun SummaryScreen(
    viewModel: SummaryViewModel,
    sessionId: Long,
    onHomeClick: () -> Unit,
    onRetryClick: () -> Unit,
) {
    val state by viewModel.uiState.collectAsState()
    val context = LocalContext.current
    val showDetailSettingsState = remember { mutableStateOf(value = false) }
    var showDetailSettings by showDetailSettingsState
    var clearMarksPreviewText by remember { mutableStateOf<String?>(null) }

    LaunchedEffect(sessionId) {
        viewModel.loadSummary(sessionId)
    }

    if (state.isLoading) {
        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
            CircularProgressIndicator()
        }
        return
    }

    val session = state.session ?: return
    val totalCount = session.originalQuestionCount.coerceAtLeast(state.questions.size).coerceAtLeast(1)
    val percentage = ((session.score.toFloat() / totalCount) * 100).toInt()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(stringResource(R.string.session_summary_title)) },
                actions = {
                    IconButton(onClick = {
                        viewModel.previewClearMarks(session.quizId) { preview ->
                            clearMarksPreviewText = preview
                        }
                    }) {
                        Icon(Icons.Default.BookmarkBorder, contentDescription = "Clear Marks")
                    }
                    IconButton(onClick = {
                        val sendIntent = Intent().apply {
                            action = Intent.ACTION_SEND
                            putExtra(Intent.EXTRA_TEXT, viewModel.getExportText())
                            type = "text/plain"
                        }
                        val shareIntent = Intent.createChooser(sendIntent, context.getString(R.string.export_session_review))
                        context.startActivity(shareIntent)
                    }) {
                        Icon(Icons.Default.Share, contentDescription = stringResource(R.string.export_label))
                    }
                    IconButton(onClick = onHomeClick) {
                        Icon(Icons.Default.Close, contentDescription = stringResource(R.string.cancel))
                    }
                }
            )
        }
    ) { padding ->
        LazyColumn(
            modifier = Modifier
                .padding(padding)
                .fillMaxSize(),
            contentPadding = PaddingValues(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            item {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.primaryContainer,
                        contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(24.dp),
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Text(
                            text = "$percentage%",
                            style = MaterialTheme.typography.displayLarge,
                            fontWeight = FontWeight.ExtraBold,
                            color = MaterialTheme.colorScheme.onPrimaryContainer
                        )
                        Text(
                            text = stringResource(R.string.correct_summary, session.score, totalCount),
                            style = MaterialTheme.typography.titleLarge,
                            color = MaterialTheme.colorScheme.onPrimaryContainer
                        )
                        if (state.maxStreak > 0) {
                            Row(
                                modifier = Modifier.padding(top = 8.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Icon(
                                    Icons.Default.Whatshot,
                                    contentDescription = null,
                                    modifier = Modifier.size(24.dp),
                                    tint = if (MaterialTheme.colorScheme.primaryContainer == Color(0xFFFFB300)) Color.Black else Color(0xFFFF9800)
                                )
                                Spacer(modifier = Modifier.width(4.dp))
                                Text(
                                    text = stringResource(R.string.best_streak, state.maxStreak),
                                    style = MaterialTheme.typography.titleMedium,
                                    color = if (MaterialTheme.colorScheme.primaryContainer == Color(0xFFFFB300)) Color.Black else Color(0xFFFF9800),
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                        if (session.label.isNotBlank()) {
                            Text(
                                text = session.label,
                                style = MaterialTheme.typography.bodyMedium,
                                modifier = Modifier.padding(top = 8.dp),
                                color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.8f)
                            )
                        }

                        // Time per question metric
                        val totalTimeMs = state.questions.sumOf { it.timeSpentMs }
                        val avgTimeSec = if (state.questions.isNotEmpty()) (totalTimeMs / 1000.0 / state.questions.size) else 0.0
                        Text(
                            text = "Avg Time: ${String.format(java.util.Locale.US, "%.1f", avgTimeSec)}s / question",
                            style = MaterialTheme.typography.bodySmall,
                            modifier = Modifier.padding(top = 4.dp),
                            color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.7f)
                        )
                    }
                }
            }

            item {
                Column {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(stringResource(R.string.question_review_header), style = MaterialTheme.typography.titleMedium)
                        IconButton(onClick = { showDetailSettings = !showDetailSettings }) {
                            Icon(
                                if (showDetailSettings) Icons.Default.Settings else Icons.Default.SettingsSuggest,
                                contentDescription = stringResource(R.string.detail_settings),
                                tint = if (showDetailSettings) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }

                    AnimatedVisibility(
                        visible = showDetailSettings,
                        enter = expandVertically(),
                        exit = shrinkVertically()
                    ) {
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(vertical = 8.dp),
                            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant)
                        ) {
                            Column(modifier = Modifier.padding(12.dp)) {
                                Text(stringResource(R.string.visible_details), style = MaterialTheme.typography.labelMedium, color = MaterialTheme.colorScheme.primary)
                                FlowRow(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(top = 8.dp),
                                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                                    verticalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    ReviewDetail.entries.forEach { detail ->
                                        val label = when (detail) {
                                            ReviewDetail.STEM -> stringResource(R.string.review_detail_stem)
                                            ReviewDetail.OPTIONS -> stringResource(R.string.review_detail_options)
                                            ReviewDetail.HINT -> stringResource(R.string.review_detail_hint)
                                            ReviewDetail.HIGH_YIELD -> stringResource(R.string.review_detail_high_yield)
                                            ReviewDetail.REFERENCE -> stringResource(R.string.review_detail_reference)
                                            ReviewDetail.QUESTION_NUMBER -> stringResource(R.string.review_detail_question_number)
                                            ReviewDetail.EXPLANATION -> stringResource(R.string.review_detail_explanation)
                                        }
                                        FilterChip(
                                            selected = state.visibleDetails.contains(detail),
                                            onClick = { viewModel.toggleReviewDetail(detail) },
                                            label = { Text(label) },
                                            leadingIcon = {
                                                if (state.visibleDetails.contains(detail)) {
                                                    Icon(Icons.Default.Check, null, modifier = Modifier.size(16.dp))
                                                }
                                            }
                                        )
                                    }
                                }
                            }
                        }
                    }

                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .horizontalScroll(rememberScrollState())
                            .padding(vertical = 8.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        ReviewFilter.entries.forEach { filter ->
                            val label = when (filter) {
                                ReviewFilter.ALL -> stringResource(R.string.review_filter_all)
                                ReviewFilter.CORRECT -> stringResource(R.string.review_filter_correct)
                                ReviewFilter.WRONG -> stringResource(R.string.review_filter_wrong)
                                ReviewFilter.UNANSWERED -> stringResource(R.string.review_filter_unanswered)
                                ReviewFilter.DROPPED -> stringResource(R.string.review_filter_dropped)
                                ReviewFilter.WITH_EXPLANATION -> stringResource(R.string.review_filter_with_explanation)
                            }
                            FilterChip(
                                selected = state.reviewFilter == filter,
                                onClick = { viewModel.setReviewFilter(filter) },
                                label = { Text(label) },
                                leadingIcon = {
                                    val icon = when (filter) {
                                        ReviewFilter.ALL -> Icons.Default.AllInclusive
                                        ReviewFilter.CORRECT -> Icons.Default.CheckCircle
                                        ReviewFilter.WRONG -> Icons.Default.Cancel
                                        ReviewFilter.UNANSWERED -> Icons.AutoMirrored.Filled.Help
                                        ReviewFilter.DROPPED -> Icons.Default.DeleteSweep
                                        ReviewFilter.WITH_EXPLANATION -> Icons.Default.Lightbulb
                                    }
                                    Icon(icon, null, modifier = Modifier.size(18.dp))
                                }
                            )
                        }
                    }
                }
            }

            if (state.filteredQuestions.isEmpty()) {
                item {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(32.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            stringResource(R.string.no_questions_match_filter),
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            } else {
                itemsIndexed(state.filteredQuestions) { index, question ->
                    ReviewQuestionItem(
                        question = question,
                        session = session,
                        visibleDetails = state.visibleDetails,
                        index = index
                    )
                }
            }

            if (state.categoryPerformance.isNotEmpty()) {
                item {
                    Text(stringResource(R.string.category_performance), style = MaterialTheme.typography.titleMedium)
                }
                items(state.categoryPerformance.toList(), key = { it.first }) { (category, stats) ->
                    CategoryStatsRow(category, stats)
                }
            }

            item {
                Spacer(modifier = Modifier.height(32.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    OutlinedButton(
                        onClick = onRetryClick,
                        modifier = Modifier
                            .weight(1f)
                            .height(56.dp)
                    ) {
                        Icon(Icons.Default.Replay, contentDescription = null)
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(stringResource(R.string.retry_full))
                    }

                    Button(
                        onClick = onHomeClick,
                        modifier = Modifier
                            .weight(1f)
                            .height(56.dp)
                    ) {
                        Icon(Icons.Default.Home, contentDescription = null)
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(stringResource(R.string.library))
                    }
                }
            }
        }
    }

    clearMarksPreviewText?.let { preview ->
        AlertDialog(
            onDismissRequest = { clearMarksPreviewText = null },
            title = { Text("Clear Marks for this Quiz?") },
            text = { Text(preview) },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.applyClearMarks(session.quizId)
                        clearMarksPreviewText = null
                    }
                ) {
                    Text("Clear")
                }
            },
            dismissButton = {
                TextButton(onClick = { clearMarksPreviewText = null }) {
                    Text("Cancel")
                }
            }
        )
    }
}

fun ReviewQuestionItem(
    question: QuestionEntity,
    session: SessionEntity,
    visibleDetails: Set<ReviewDetail>,
    index: Int
) {
    val userAnswers = session.answers[question.id]
    val isCorrect = userAnswers != null && question.correctAnswers.toSet() == userAnswers.toSet()

    val statusColor = when {
        question.isDropped -> MaterialTheme.colorScheme.onSurfaceVariant
        userAnswers == null -> MaterialTheme.colorScheme.onSurfaceVariant
        isCorrect -> Color(0xFF4CAF50)
        else -> MaterialTheme.colorScheme.error
    }

    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface,
        ),
        border = BorderStroke(1.dp, statusColor.copy(alpha = 0.3f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                if (visibleDetails.contains(ReviewDetail.QUESTION_NUMBER)) {
                    Text(
                        stringResource(R.string.question_number_prefix, index + 1),
                        style = MaterialTheme.typography.labelLarge,
                        color = statusColor,
                        fontWeight = FontWeight.Bold
                    )
                }

                val statusText = when {
                    question.isDropped -> stringResource(R.string.drop).uppercase()
                    userAnswers == null -> stringResource(R.string.navigation_unanswered).uppercase()
                    isCorrect -> stringResource(R.string.navigation_answered).uppercase()
                    else -> stringResource(R.string.navigation_missed).uppercase()
                }
                Text(
                    statusText,
                    style = MaterialTheme.typography.labelSmall,
                    color = statusColor
                )
            }

            if (visibleDetails.contains(ReviewDetail.STEM)) {
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = question.text,
                    style = MaterialTheme.typography.bodyLarge,
                    fontWeight = FontWeight.Medium
                )
            }

            if (visibleDetails.contains(ReviewDetail.OPTIONS)) {
                Spacer(modifier = Modifier.height(12.dp))
                question.options.forEachIndexed { optIdx, option ->
                    val isUserSelected = userAnswers?.contains(optIdx) == true
                    val isCorrectOption = question.correctAnswers.contains(optIdx)

                    val optionBgColor = when {
                        isCorrectOption -> Color(0xFF4CAF50).copy(alpha = 0.1f)
                        isUserSelected -> MaterialTheme.colorScheme.error.copy(alpha = 0.1f)
                        else -> Color.Transparent
                    }

                    val optionBorderColor = when {
                        isCorrectOption -> Color(0xFF4CAF50).copy(alpha = 0.5f)
                        isUserSelected -> MaterialTheme.colorScheme.error.copy(alpha = 0.5f)
                        else -> MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f)
                    }

                    Surface(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 4.dp),
                        color = optionBgColor,
                        shape = RoundedCornerShape(8.dp),
                        border = BorderStroke(1.dp, optionBorderColor)
                    ) {
                        Row(
                            modifier = Modifier.padding(12.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                imageVector = when {
                                    isCorrectOption -> Icons.Default.CheckCircle
                                    isUserSelected -> Icons.Default.Cancel
                                    else -> Icons.Default.RadioButtonUnchecked
                                },
                                contentDescription = null,
                                tint = when {
                                    isCorrectOption -> Color(0xFF4CAF50)
                                    isUserSelected -> MaterialTheme.colorScheme.error
                                    else -> MaterialTheme.colorScheme.outline
                                },
                                modifier = Modifier.size(20.dp)
                            )
                            Spacer(modifier = Modifier.width(12.dp))
                            Text(
                                text = option,
                                style = MaterialTheme.typography.bodyMedium,
                                color = if (isCorrectOption || isUserSelected) MaterialTheme.colorScheme.onSurface else MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                }
            }

            if (visibleDetails.contains(ReviewDetail.EXPLANATION) && !question.explanation.isNullOrBlank()) {
                DetailSection("Explanation", question.explanation!!, Icons.Default.Lightbulb)
            }

            if (visibleDetails.contains(ReviewDetail.HINT) && !question.hint.isNullOrBlank()) {
                DetailSection("Hint", question.hint!!, Icons.Default.TipsAndUpdates)
            }

            if (visibleDetails.contains(ReviewDetail.HIGH_YIELD) && !question.additionalInfo.isNullOrBlank()) {
                DetailSection("High Yield Info", question.additionalInfo!!, Icons.Default.Star)
            }

            if (visibleDetails.contains(ReviewDetail.REFERENCE) && !question.reference.isNullOrBlank()) {
                DetailSection("Reference", question.reference!!, Icons.AutoMirrored.Filled.MenuBook)
            }
        }
    }
}

fun DetailSection(title: String, content: String, icon: androidx.compose.ui.graphics.vector.ImageVector) {
    Column(modifier = Modifier.padding(top = 16.dp)) {
        Row(verticalAlignment = Alignment.CenterVertically) {
            Icon(icon, null, modifier = Modifier.size(16.dp), tint = MaterialTheme.colorScheme.primary)
            Spacer(modifier = Modifier.width(8.dp))
            Text(title, style = MaterialTheme.typography.labelMedium, color = MaterialTheme.colorScheme.primary)
        }
        Spacer(modifier = Modifier.height(4.dp))
        Text(
            text = content,
            style = MaterialTheme.typography.bodySmall,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

fun CategoryStatsRow(category: String, stats: CategoryStats) {
    val containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
    val contentColor = MaterialTheme.colorScheme.onSurfaceVariant

    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = containerColor,
            contentColor = contentColor
        )
    ) {
        Row(
            modifier = Modifier.padding(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(category, fontWeight = FontWeight.Bold, color = contentColor)
                Text("${stats.correct}/${stats.total} correct", style = MaterialTheme.typography.bodySmall, color = contentColor.copy(alpha = 0.7f))
            }
            Text(
                "${stats.percentage}%",
                style = MaterialTheme.typography.titleMedium,
                color = when {
                    stats.percentage >= 70 -> Color(0xFF4CAF50)
                    stats.percentage >= 40 -> Color(0xFFFFC107)
                    else -> Color(0xFFF44336)
                }
            )
        }
    }
}

// Deleted HardestQuestionItem

data class CategoryStats(
    val correct: Int,
    val total: Int,
    val percentage: Int,
)

@HiltViewModel

class SummaryViewModel @Inject constructor(
    private val quizRepository: QuizRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(SummaryState())
    val uiState: StateFlow<SummaryState> = _uiState.asStateFlow()

fun loadSummary(sessionId: Long) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }
            val session = quizRepository.getSessionById(sessionId)
            if (session != null) {
                // Get all questions in the sequence (including repeats)
                val allQuestionsInQuiz = quizRepository.getQuestionsByQuizId(session.quizId).first()

                val sessionQuestions = session.questionIds.map { id -> 
                    allQuestionsInQuiz.find { it.id == id } ?: QuestionEntity(
                        id = id,
                        externalId = "missing",
                        quizId = session.quizId,
                        text = "[Missing Question Data]",
                        type = com.ahmedyejam.mks.data.local.entity.QuestionType.SINGLE_CHOICE,
                        options = emptyList(),
                        correctAnswers = emptyList(),
                    )
                }

                // Calculate category performance using taxonomy (v30+) or fallback to full history
                val catStats = mutableMapOf<String, Pair<Int, Int>>()

                if (session.resultTaxonomy.isNotEmpty()) {
                    // Modern taxonomy-based calculation
                    session.resultTaxonomy.forEach { (index, status) ->
                        val id = session.questionIds.getOrNull(index) ?: return@forEach
                        val q = allQuestionsInQuiz.find { it.id == id } ?: return@forEach

                        val isCorrect =
                            status == "CORRECT_FIRST_TRY" || status == "CORRECTED_AFTER_REPEAT"
                        q.categories.forEach { cat ->
                            val current = catStats.getOrDefault(cat, 0 to 0)
                            catStats[cat] =
                                (current.first + (if (isCorrect) 1 else 0)) to (current.second + 1)
                        }
                    }
                } else {
                    // Fallback for legacy sessions (pre-v30)
                    session.questionIds.forEachIndexed { index, id ->
                        val q = allQuestionsInQuiz.find { it.id == id } ?: return@forEachIndexed
                        val userAnswers = session.answersByIndex[index]
                        if (userAnswers != null) {
                            val isCorrect = q.correctAnswers.toSet() == userAnswers.toSet()
                            q.categories.forEach { cat ->
                                val current = catStats.getOrDefault(cat, 0 to 0)
                                catStats[cat] =
                                    (current.first + (if (isCorrect) 1 else 0)) to (current.second + 1)
                            }
                        }
                    }
                }

                val categoryPerformance = catStats.mapValues { (_, stats) ->
                    CategoryStats(stats.first, stats.second, if (stats.second > 0) ((stats.first * 100) / stats.second) else 0)
                }

                _uiState.update { 
                    it.copy(
                        session = session,
                        questions = sessionQuestions,
                        isLoading = false,
                        categoryPerformance = categoryPerformance,
                        maxStreak = session.maxStreak,
                    )
                }
                updateFilteredQuestions()
            } else {
                _uiState.update { it.copy(isLoading = false) }
            }
        }
    }

fun setReviewFilter(filter: ReviewFilter) {
        _uiState.update { it.copy(reviewFilter = filter) }
        updateFilteredQuestions()
    }

fun toggleReviewDetail(detail: ReviewDetail) {
        _uiState.update { state ->
            val newDetails = if (state.visibleDetails.contains(detail)) {
                state.visibleDetails - detail
            } else {
                state.visibleDetails + detail
            }
            state.copy(visibleDetails = newDetails)
        }
    }

private fun updateFilteredQuestions() {
        val state = _uiState.value
        val session = state.session ?: return

        // Match state.questions (full sequence) with session.answersByIndex
        val filtered = state.questions.filterIndexed { index, q ->
            val userAnswers = session.answersByIndex[index]
            val isCorrect = (userAnswers != null) && (q.correctAnswers.toSet() == userAnswers.toSet())

            when (state.reviewFilter) {
                ReviewFilter.ALL -> true
                ReviewFilter.CORRECT -> isCorrect
                ReviewFilter.WRONG -> (!isCorrect) && (userAnswers != null) && (!q.isDropped)
                ReviewFilter.UNANSWERED -> (userAnswers == null) && (!q.isDropped)
                ReviewFilter.DROPPED -> q.isDropped
                ReviewFilter.WITH_EXPLANATION -> !q.explanation.isNullOrBlank()
            }
        }

        _uiState.update { it.copy(filteredQuestions = filtered) }
    }

fun getExportText(): String {
        val state = _uiState.value
        val session = state.session ?: return ""
        val details = state.visibleDetails

        val filteredIndexedQuestions = state.questions.asSequence()
            .mapIndexed { index, question -> index to question }
            .filter { (sequenceIndex, question) ->
                val userAnswers = session.answersByIndex[sequenceIndex]
                val isCorrect = (userAnswers != null) && (question.correctAnswers.toSet() == userAnswers.toSet())

                when (state.reviewFilter) {
                    ReviewFilter.ALL -> true
                    ReviewFilter.CORRECT -> isCorrect
                    ReviewFilter.WRONG -> (!isCorrect) && (userAnswers != null) && (!question.isDropped)
                    ReviewFilter.UNANSWERED -> (userAnswers == null) && (!question.isDropped)
                    ReviewFilter.DROPPED -> question.isDropped
                    ReviewFilter.WITH_EXPLANATION -> !question.explanation.isNullOrBlank()
                }
            }

        return buildString {
            appendLine("MKS Session Review: ${session.label}")
            appendLine("Score: ${session.score} / ${session.originalQuestionCount}")
            appendLine("Filter: ${state.reviewFilter}")
            appendLine("-".repeat(20))
            appendLine()

            filteredIndexedQuestions.forEachIndexed { exportIndex, (sequenceIndex, q) ->
                val userAnswers = session.answersByIndex[sequenceIndex]
                val isCorrect = (userAnswers != null) && (q.correctAnswers.toSet() == userAnswers.toSet())

                if (details.contains(ReviewDetail.QUESTION_NUMBER)) {
                    append("Q${exportIndex + 1}: ")
                }

                val statusText = when {
                    q.isDropped -> "[DROPPED]"
                    userAnswers == null -> "[UNANSWERED]"
                    isCorrect -> "[CORRECT]"
                    else -> "[WRONG]"
                }
                appendLine(statusText)

                if (details.contains(ReviewDetail.STEM)) {
                    appendLine(q.text)
                }

                if (details.contains(ReviewDetail.OPTIONS)) {
                    q.options.forEachIndexed { optIdx, opt ->
                        val prefix = when {
                            q.correctAnswers.contains(optIdx) -> "✓ "
                            userAnswers?.contains(optIdx) == true -> "✗ "
                            else -> "  "
                        }
                        appendLine("$prefix$opt")
                    }
                }

                if (details.contains(ReviewDetail.EXPLANATION) && !q.explanation.isNullOrBlank()) {
                    appendLine("Explanation: ${q.explanation}")
                }

                if (details.contains(ReviewDetail.HINT) && !q.hint.isNullOrBlank()) {
                    appendLine("Hint: ${q.hint}")
                }

                if (details.contains(ReviewDetail.HIGH_YIELD) && !q.additionalInfo.isNullOrBlank()) {
                    appendLine("High Yield: ${q.additionalInfo}")
                }

                if (details.contains(ReviewDetail.REFERENCE) && !q.reference.isNullOrBlank()) {
                    appendLine("Reference: ${q.reference}")
                }

                appendLine()
            }
        }
    }

fun previewClearMarks(quizId: Long, onResult: (String) -> Unit) {
        viewModelScope.launch {
            val res = quizRepository.clearMarksForQuizWithPreview(quizId)
            onResult(res.summary)
        }
    }

fun applyClearMarks(quizId: Long) {
        viewModelScope.launch {
            quizRepository.applyClearMarksForQuiz(quizId)
            _uiState.value.session?.id?.let { loadSummary(it) }
        }
    }
}

fun SessionManagementScreen(
    quizId: Long,
    viewModel: SessionViewModel,
    dataStoreManager: DataStoreManager,
    isEmbedded: Boolean = false,
    onSessionSelected: (Long, Boolean) -> Unit,
    onNavigateBack: () -> Unit
) {
    val sessions by viewModel.sessions.collectAsState()
    val quizQuestionCounts by viewModel.quizQuestionCounts.collectAsState()
    var showNewLabelDialog by rememberSaveable { mutableStateOf(false) }
    var sessionPendingDelete by remember { mutableStateOf<SessionEntity?>(null) }

    val defIncludeFilters by dataStoreManager.defIncludeFilters.collectAsState(initial = emptySet())
    val defShuffleQuestions by dataStoreManager.defShuffleQuestions.collectAsState(initial = false)
    val defShuffleOptions by dataStoreManager.defShuffleOptions.collectAsState(initial = false)
    val defRapidMode by dataStoreManager.defRapidMode.collectAsState(initial = false)
    val defRepeatWrong by dataStoreManager.defRepeatWrong.collectAsState(initial = false)
    val defQuizTimer by dataStoreManager.defQuizTimer.collectAsState(initial = 0)
    val defQuestionTimer by dataStoreManager.defQuestionTimer.collectAsState(initial = 0)

    LaunchedEffect(quizId) {
        viewModel.loadSessions(quizId)
    }

    if (isEmbedded) {
        Scaffold(
            floatingActionButton = {
                FloatingActionButton(onClick = { showNewLabelDialog = true }) {
                    Icon(
                        Icons.Default.Add,
                        contentDescription = stringResource(R.string.start_new_session_title)
                    )
                }
            }
        ) { padding ->
            Box(Modifier.padding(padding)) {
                SessionManagementContent(
                    sessions = sessions,
                    quizQuestionCounts = quizQuestionCounts,
                    quizId = quizId,
                    onSessionSelected = onSessionSelected,
                    onDeleteSession = { sessionPendingDelete = it },
                    onAddSession = { showNewLabelDialog = true }
                )
            }
        }
    } else {
        Scaffold(
            topBar = {
                TopAppBar(
                    title = { Text(stringResource(R.string.quiz_sessions_title)) },
                    navigationIcon = {
                        IconButton(onClick = onNavigateBack) {
                            Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = stringResource(R.string.cancel))
                        }
                    }
                )
            },
            floatingActionButton = {
                FloatingActionButton(onClick = { showNewLabelDialog = true }) {
                    Icon(Icons.Default.Add, contentDescription = stringResource(R.string.new_quiz))
                }
            }
        ) { padding ->
            Box(Modifier.padding(padding)) {
                SessionManagementContent(
                    sessions = sessions,
                    quizQuestionCounts = quizQuestionCounts,
                    quizId = quizId,
                    onSessionSelected = onSessionSelected,
                    onDeleteSession = { sessionPendingDelete = it },
                    onAddSession = { showNewLabelDialog = true }
                )
            }
        }
    }

    sessionPendingDelete?.let { session ->
        AlertDialog(
            onDismissRequest = { sessionPendingDelete = null },
            title = { Text("Delete session?") },
            text = { Text("This removes the saved session '${session.label.ifBlank { "Untitled session" }}'. This cannot be undone.") },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.deleteSession(session)
                        sessionPendingDelete = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error)
                ) { Text("Delete") }
            },
            dismissButton = {
                TextButton(onClick = { sessionPendingDelete = null }) { Text(stringResource(R.string.cancel)) }
            }
        )
    }

    if (showNewLabelDialog) {
        val totalQuestions = quizQuestionCounts[quizId] ?: 0

        StartSessionDialog(
            totalQuestions = totalQuestions,
            defaultIncludeFilters = defIncludeFilters,
            defaultShuffleQuestions = defShuffleQuestions,
            defaultShuffleOptions = defShuffleOptions,
            defaultRapidMode = defRapidMode,
            defaultRepeatWrong = defRepeatWrong,
            defaultQuizTimerSeconds = defQuizTimer,
            defaultQuestionTimerSeconds = defQuestionTimer,
            onDismiss = { showNewLabelDialog = false },
            onConfirm = { config, saveDefaults ->
                if (saveDefaults) {
                    viewModel.saveDefaultSessionSettings(
                        filters = config.includeFilters.toSet(),
                        shuffleQ = config.shuffleQuestions,
                        shuffleO = config.shuffleOptions,
                        rapid = config.rapidMode,
                        repeatWrong = config.repeatWrong,
                        quizTimer = config.quizTimerSeconds,
                        qTimer = config.questionTimerSeconds
                    )
                }
                viewModel.createSession(
                    quizId = quizId,
                    label = config.label,
                    shuffleQuestions = config.shuffleQuestions,
                    shuffleOptions = config.shuffleOptions,
                    rapidMode = config.rapidMode,
                    repeatWrong = config.repeatWrong,
                    quizTimerSeconds = config.quizTimerSeconds,
                    questionTimerSeconds = config.questionTimerSeconds,
                    rangeFrom = config.rangeFrom,
                    rangeTo = config.rangeTo,
                    includeFilters = config.includeFilters,
                    onCreated = { sessionId ->
                        onSessionSelected(sessionId, false)
                    }
                )
                showNewLabelDialog = false
            }
        )
    }
}

private fun SessionManagementContent(
    sessions: List<SessionEntity>,
    quizQuestionCounts: Map<Long, Int>,
    quizId: Long,
    onSessionSelected: (Long, Boolean) -> Unit,
    onDeleteSession: (SessionEntity) -> Unit,
    onAddSession: () -> Unit
) {
    Column(modifier = Modifier.fillMaxSize()) {
        if (sessions.isEmpty()) {
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(18.dp),
                contentAlignment = Alignment.TopCenter
            ) {
                SessionEmptyStateCard(onClick = onAddSession)
            }
        } else {
            LazyColumn(
                modifier = Modifier.fillMaxSize(),
                contentPadding = PaddingValues(bottom = 80.dp, top = 12.dp)
            ) {
                items(sessions, key = { it.id }) { session ->
                    SessionItem(
                        session = session,
                        totalQuestions = quizQuestionCounts[quizId] ?: 0,
                        onClick = { onSessionSelected(session.id, session.isCompleted) },
                        onDelete = { onDeleteSession(session) }
                    )
                }
            }
        }
    }
}

fun StartSessionDialog(
    totalQuestions: Int,
    defaultIncludeFilters: Set<String>,
    defaultShuffleQuestions: Boolean,
    defaultShuffleOptions: Boolean,
    defaultRapidMode: Boolean,
    defaultRepeatWrong: Boolean,
    defaultQuizTimerSeconds: Int,
    defaultQuestionTimerSeconds: Int,
    onDismiss: () -> Unit,
    onConfirm: (SessionConfig, Boolean) -> Unit
) {
    val context = LocalContext.current
    var label by rememberSaveable { mutableStateOf("") }
    var shuffleQuestions by rememberSaveable { mutableStateOf(defaultShuffleQuestions) }
    var shuffleOptions by rememberSaveable { mutableStateOf(defaultShuffleOptions) }
    var rapidMode by rememberSaveable { mutableStateOf(defaultRapidMode) }
    var repeatWrong by rememberSaveable { mutableStateOf(defaultRepeatWrong) }

    var rangeFrom by rememberSaveable { mutableIntStateOf(1) }
    var rangeTo by rememberSaveable { mutableIntStateOf(totalQuestions) }

    var enableQuizTimer by rememberSaveable { mutableStateOf(defaultQuizTimerSeconds > 0) }
    var quizTimerMinutes by rememberSaveable { mutableStateOf(if (defaultQuizTimerSeconds > 0) (defaultQuizTimerSeconds / 60).toString() else "30") }

    var enableQuestionTimer by rememberSaveable { mutableStateOf(defaultQuestionTimerSeconds > 0) }
    var questionTimerSeconds by rememberSaveable { mutableStateOf(if (defaultQuestionTimerSeconds > 0) defaultQuestionTimerSeconds.toString() else "30") }

    val filterOptions = listOf(
        "unanswered" to stringResource(R.string.navigation_unanswered),
        "missed" to stringResource(R.string.navigation_missed),
        "marked" to stringResource(R.string.mark_toggle),
        "categorized" to stringResource(R.string.categories_toggle),
        "uncategorized" to stringResource(R.string.uncategorized_label)
    )
    var selectedFilters by rememberSaveable { mutableStateOf(defaultIncludeFilters) }
    var rememberDefaults by rememberSaveable { mutableStateOf(false) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text(stringResource(R.string.start_new_session_title)) },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                OutlinedTextField(
                    value = label,
                    onValueChange = { label = it },
                    label = { Text(stringResource(R.string.session_label_optional)) },
                    placeholder = { Text(stringResource(R.string.session_label_placeholder)) },
                    singleLine = true,
                    modifier = Modifier.fillMaxWidth()
                )

                Text(stringResource(R.string.include_only), style = MaterialTheme.typography.titleSmall)
                FlowRow(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    filterOptions.forEach { (key, label) ->
                        FilterChip(
                            selected = selectedFilters.contains(key),
                            onClick = {
                                selectedFilters = if (selectedFilters.contains(key)) {
                                    selectedFilters - key
                                } else {
                                    selectedFilters + key
                                }
                            },
                            label = { Text(label, style = MaterialTheme.typography.labelSmall) }
                        )
                    }
                }

                Text(stringResource(R.string.question_range), style = MaterialTheme.typography.titleSmall)
                val rangeError = remember(rangeFrom, rangeTo, totalQuestions) {
                    when {
                        rangeFrom < 1 -> context.getString(R.string.range_error_from_at_least_1)
                        totalQuestions > 0 && rangeTo > totalQuestions -> context.getString(R.string.range_error_to_at_most_n, totalQuestions)
                        rangeFrom > rangeTo -> context.getString(R.string.range_error_from_less_than_to)
                        else -> null
                    }
                }
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    OutlinedTextField(
                        value = if (rangeFrom == 0) "" else rangeFrom.toString(),
                        onValueChange = { rangeFrom = it.toIntOrNull() ?: 0 },
                        label = { Text(stringResource(R.string.from_label)) },
                        modifier = Modifier.weight(1f),
                        isError = rangeError != null,
                        keyboardOptions = androidx.compose.foundation.text.KeyboardOptions(
                            keyboardType = androidx.compose.ui.text.input.KeyboardType.Number
                        )
                    )
                    OutlinedTextField(
                        value = if (rangeTo == 0) "" else rangeTo.toString(),
                        onValueChange = { rangeTo = it.toIntOrNull() ?: 0 },
                        label = { Text(stringResource(R.string.to_label)) },
                        modifier = Modifier.weight(1f),
                        isError = rangeError != null,
                        keyboardOptions = androidx.compose.foundation.text.KeyboardOptions(
                            keyboardType = androidx.compose.ui.text.input.KeyboardType.Number
                        )
                    )
                }
                if (rangeError != null) {
                    Text(
                        text = rangeError,
                        color = MaterialTheme.colorScheme.error,
                        style = MaterialTheme.typography.bodySmall
                    )
                }

                HorizontalDivider()

                LabeledSwitch(
                    label = stringResource(R.string.shuffle_questions),
                    checked = shuffleQuestions,
                    onCheckedChange = { shuffleQuestions = it }
                )
                LabeledSwitch(
                    label = stringResource(R.string.shuffle_options),
                    checked = shuffleOptions,
                    onCheckedChange = { shuffleOptions = it }
                )
                LabeledSwitch(
                    label = stringResource(R.string.rapid_mode),
                    checked = rapidMode,
                    onCheckedChange = { rapidMode = it }
                )
                LabeledSwitch(
                    label = stringResource(R.string.repeat_wrong),
                    checked = repeatWrong,
                    onCheckedChange = { repeatWrong = it }
                )

                HorizontalDivider()

                TimerConfigRow(
                    label = stringResource(R.string.quiz_timer_min),
                    enabled = enableQuizTimer,
                    onEnabledChange = { enableQuizTimer = it },
                    value = quizTimerMinutes,
                    onValueChange = { quizTimerMinutes = it }
                )

                TimerConfigRow(
                    label = stringResource(R.string.question_timer_sec),
                    enabled = enableQuestionTimer,
                    onEnabledChange = { enableQuestionTimer = it },
                    value = questionTimerSeconds,
                    onValueChange = { questionTimerSeconds = it }
                )

                LabeledSwitch(
                    label = stringResource(R.string.remember_settings),
                    checked = rememberDefaults,
                    onCheckedChange = { rememberDefaults = it }
                )
            }
        },
        confirmButton = {
            val hasRangeError = rangeFrom < 1 || rangeTo > totalQuestions || rangeFrom > rangeTo
            TextButton(
                enabled = !hasRangeError,
                onClick = {
                    onConfirm(
                        SessionConfig(
                            label = label.ifBlank { "Session ${System.currentTimeMillis() % 10000}" },
                            shuffleQuestions = shuffleQuestions,
                            shuffleOptions = shuffleOptions,
                            rapidMode = rapidMode,
                            repeatWrong = repeatWrong,
                            quizTimerSeconds = if (enableQuizTimer) (quizTimerMinutes.toIntOrNull() ?: 30) * 60 else 0,
                            questionTimerSeconds = if (enableQuestionTimer) (questionTimerSeconds.toIntOrNull() ?: 30) else 0,
                            rangeFrom = (rangeFrom - 1).coerceAtLeast(0),
                            rangeTo = (rangeTo - 1).coerceAtLeast(0).coerceAtMost(totalQuestions - 1),
                            includeFilters = selectedFilters.toList()
                        ),
                        rememberDefaults
                    )
                }
            ) {
                Text(stringResource(R.string.start))
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text(stringResource(R.string.cancel))
            }
        }
    )
}

/**
 * A reusable row with a label and a switch.
 */

fun LabeledSwitch(
    label: String,
    checked: Boolean,
    onCheckedChange: (Boolean) -> Unit,
    modifier: Modifier = Modifier
) {
    Row(
        modifier = modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(8.dp))
            .clickable { onCheckedChange(!checked) }
            .padding(vertical = 8.dp, horizontal = 4.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Text(
            text = label,
            style = MaterialTheme.typography.bodyLarge,
            modifier = Modifier.weight(1f)
        )
        Switch(
            checked = checked,
            onCheckedChange = onCheckedChange,
            modifier = Modifier.padding(start = 16.dp)
        )
    }
}

/**
 * A row for configuring timer settings, including a checkbox to enable and an input field for the value.
 */

fun SessionItem(
    session: SessionEntity,
    totalQuestions: Int,
    onClick: () -> Unit,
    onDelete: () -> Unit
) {
    val dateFormat = remember { SimpleDateFormat("MMM dd, yyyy HH:mm", Locale.getDefault()) }
    val progress = if (totalQuestions > 0) (session.currentQuestionIndex.toFloat() / totalQuestions).coerceIn(0f, 1f) else 0f
    val answeredCount = (session.score + session.incorrectCount).coerceAtLeast(0)
    val accuracy = if (answeredCount > 0) (session.score.toFloat() / answeredCount * 100).toInt() else 0
    val remaining = (totalQuestions - answeredCount).coerceAtLeast(0)
    val colors = MaterialTheme.colorScheme
    val correctColor = if (isSystemInDarkTheme()) Color(0xFFA5D6A7) else Color(0xFF2E7D32)

    Card(
        modifier = Modifier
            .padding(horizontal = 16.dp, vertical = 7.dp)
            .fillMaxWidth()
            .clickable { onClick() },
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = colors.surface.copy(alpha = 0.94f)),
        border = BorderStroke(1.dp, colors.outline.copy(alpha = 0.12f)),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.5.dp)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(14.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Box(contentAlignment = Alignment.Center, modifier = Modifier.size(58.dp)) {
                    CircularProgressIndicator(
                        progress = { accuracy / 100f },
                        modifier = Modifier.fillMaxSize(),
                        strokeWidth = 5.dp,
                        color = colors.primary,
                        trackColor = colors.surfaceVariant.copy(alpha = 0.55f)
                    )
                    Text(
                        text = "$accuracy%",
                        style = MaterialTheme.typography.labelMedium,
                        fontWeight = FontWeight.Bold,
                        color = colors.primary
                    )
                }

                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = session.label,
                        style = MaterialTheme.typography.titleMedium,
                        fontWeight = FontWeight.Bold,
                        maxLines = 1
                    )
                    Text(
                        text = stringResource(R.string.last_active_prefix, dateFormat.format(Date(session.lastModifiedAt))),
                        style = MaterialTheme.typography.bodySmall,
                        color = colors.onSurfaceVariant,
                        maxLines = 1
                    )
                }

                Column(horizontalAlignment = Alignment.End) {
                    Surface(
                        shape = RoundedCornerShape(14.dp),
                        color = if (session.isCompleted) colors.primaryContainer else colors.secondary.copy(alpha = 0.10f),
                        contentColor = if (session.isCompleted) colors.onPrimaryContainer else colors.secondary
                    ) {
                        Text(
                            text = if (session.isCompleted) stringResource(R.string.completed_badge) else stringResource(R.string.start),
                            style = MaterialTheme.typography.labelMedium,
                            fontWeight = FontWeight.SemiBold,
                            modifier = Modifier.padding(horizontal = 10.dp, vertical = 6.dp)
                        )
                    }
                    Spacer(Modifier.height(4.dp))
                    TextButton(onClick = onDelete, contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp)) {
                        Icon(Icons.Default.Delete, contentDescription = stringResource(R.string.delete), modifier = Modifier.size(16.dp), tint = colors.error)
                    }
                }
            }

            Spacer(modifier = Modifier.height(14.dp))

            LinearProgressIndicator(
                progress = { progress },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(7.dp)
                    .clip(CircleShape),
                color = colors.primary,
                trackColor = colors.primaryContainer.copy(alpha = 0.35f)
            )

            Spacer(modifier = Modifier.height(14.dp))

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                SessionMetric(
                    label = stringResource(R.string.session_correct),
                    value = session.score,
                    icon = Icons.Default.CheckCircle,
                    color = correctColor
                )
                SessionMetric(
                    label = stringResource(R.string.session_incorrect),
                    value = session.incorrectCount,
                    icon = Icons.Default.Error,
                    color = colors.error
                )
                SessionMetric(
                    label = stringResource(R.string.session_remaining),
                    value = remaining,
                    icon = Icons.Default.PlayArrow,
                    color = colors.onSurfaceVariant
                )
            }
        }
    }
}

/**
 * A small UI component to display a specific score metric (e.g., Correct, Incorrect).
 */

fun SessionMetric(
    label: String,
    value: Int,
    icon: androidx.compose.ui.graphics.vector.ImageVector,
    color: Color
) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {
        Surface(
            shape = CircleShape,
            color = color.copy(alpha = 0.10f),
            contentColor = color
        ) {
            Row(
                modifier = Modifier.padding(horizontal = 8.dp, vertical = 5.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Icon(imageVector = icon, contentDescription = null, modifier = Modifier.size(14.dp))
                Text(
                    text = value.coerceAtLeast(0).toString(),
                    style = MaterialTheme.typography.labelLarge,
                    fontWeight = FontWeight.Bold
                )
            }
        }
        Spacer(Modifier.height(4.dp))
        Text(
            text = label,
            style = MaterialTheme.typography.labelSmall,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

private fun SessionEmptyStateCard(onClick: () -> Unit) {
    val colors = MaterialTheme.colorScheme
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(onClick = onClick),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(containerColor = colors.surface.copy(alpha = 0.92f)),
        border = BorderStroke(1.dp, colors.outline.copy(alpha = 0.14f)),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp)
    ) {
        Row(
            modifier = Modifier.padding(18.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(14.dp)
        ) {
            Surface(
                shape = RoundedCornerShape(18.dp),
                color = colors.primary.copy(alpha = 0.10f),
                contentColor = colors.primary
            ) {
                Icon(
                    Icons.Default.PlayArrow, contentDescription = null, modifier = Modifier
                        .padding(14.dp)
                        .size(30.dp)
                )
            }
            Column(modifier = Modifier.weight(1f)) {
                Text(stringResource(R.string.no_sessions_found), style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.Bold)
                Spacer(Modifier.height(4.dp))
                Text(stringResource(R.string.empty_sessions_body), style = MaterialTheme.typography.bodyMedium, color = colors.onSurfaceVariant)
            }
        }
    }
}

class SessionViewModel @Inject constructor(
    private val quizRepository: QuizRepository,
    private val studyRepository: StudyRepository,
    private val dataStoreManager: DataStoreManager
) : ViewModel() {

    private val _sessions = MutableStateFlow<List<SessionEntity>>(emptyList())
    val sessions = _sessions.asStateFlow()

    private val _quizQuestionCounts = MutableStateFlow<Map<Long, Int>>(emptyMap())
    val quizQuestionCounts = _quizQuestionCounts.asStateFlow()

fun loadSessions(quizId: Long) {
        viewModelScope.launch {
            studyRepository.getSessionsByQuizId(quizId).collect {
                _sessions.value = it
            }
        }
        viewModelScope.launch {
            val count = quizRepository.getQuestionsByQuizId(quizId).first().count { !it.isDropped }
            _quizQuestionCounts.value += (quizId to count)
        }
    }

fun deleteSession(session: SessionEntity) {
        viewModelScope.launch {
            quizRepository.deleteSession(session)
        }
    }

    /**
     * Creates a custom session containing only questions from specified categories.
     */

fun createCustomSessionFromCategories(
        quizId: Long,
        categories: List<String>,
        label: String,
        onCreated: (Long) -> Unit
    ) {
        viewModelScope.launch {
            // Fetch all questions for this quiz and filter by categories
            val questions = quizRepository.getQuestionsByQuizId(quizId).first()
                .filter { q -> q.categories.any { it in categories } }

            val questionIds = questions.map { it.id }

            val session = SessionEntity(
                quizId = quizId,
                label = label,
                questionIds = questionIds,
                originalQuestionCount = questionIds.size,
                // Ensure default filters are set or cleared as this is a custom explicit list
                includeFilters = emptyList() 
            )
            val id = quizRepository.insertSession(session)
            onCreated(id)
        }
    }

fun saveDefaultSessionSettings(
        filters: Set<String>,
        shuffleQ: Boolean,
        shuffleO: Boolean,
        rapid: Boolean,
        repeatWrong: Boolean,
        quizTimer: Int,
        qTimer: Int
    ) {
        viewModelScope.launch {
            dataStoreManager.saveDefaultSessionSettings(
                filters = filters,
                shuffleQ = shuffleQ,
                shuffleO = shuffleO,
                rapid = rapid,
                repeatWrong = repeatWrong,
                quizTimer = quizTimer,
                qTimer = qTimer
            )
        }
    }
}
